var ezk_ch_10_Verses = [
  {num:1,words:[["Ona ou vaai lea,", "Then I looked,"], ["faauta foi i le va i lagi ua i luga o ulu o kerupi,", "and,"], ["e peiseai o le maa safaira,", "behold, in the firmament that was above the head of the cherubims there appeared over them as it were a sapphire stone,"], ["e tino mai e peiseai o le faatusa o le nofoālii ua tu mai i luga ia te i latou.", "as the appearance of the likeness of a throne."]]},
  {num:2,words:[["Ua fetalai atu foi o ia i le tagata ua ofu i le ie lino,", "And he spake unto the man clothed with linen,"], ["ua faapea atu,", "and said,"], ["Ulu atu ia i le va o mea taavavale i lalo o le kerupi,", "Go in between the wheels, even under the cherub,"], ["ma e faatumuina lou lima i malala ola ai le va o kerupi,", "and fill thine hand with coals of fire from between the cherubims,"], ["ma saaluu solo ai i luga o le aai.", "and scatter them over the city."], ["Ona ulu ane lea o ia o loo ou vaai atu.", "And he went in in my sight."]]},
  {num:3,words:[["Ua tutū foi kerupi i le itu taumatau o le fale,", "Now the cherubims stood on the right side of the house,"], ["ina o ulu atu ai le tagata;", "when the man went in;"], ["ua faatumuina le lotoā tuloto i le ao.", "and the cloud filled the inner court."]]},
  {num:4,words:[["Ona alu ae lea o le pupula o Ieova nai luga o le kerupi,", "Then the glory of the LORD went up from the cherub,"], ["ua oo i le faitotoa o le fale;", "and stood over the threshold of the house;"], ["ua faatumuina foi le fale i le ao,", "and the house was filled with the cloud,"], ["ua tumu foi le lotoā i le pupula matagofie o Ieova.", "and the court was full of the brightness of the LORD'S glory."]]},
  {num:5,words:[["Ua logona foi le taalili o apaau o kerupi, ua oo lava i le lotoā aupito i fafo,", "And the sound of the cherubims' wings was heard even to the outer court,"], ["ua pei o le siufofoga o le Atua e ona le malosi uma lava pe a fetalai mai o ia.", "as the voice of the Almighty God when he speaketh."]]},
  {num:6,words:[["Ua uma foi ona ia fetalai atu i le tagata ua ofu i le ie lino,", "And it came to pass,"], ["ua faapea atu,", "that when he had commanded the man clothed with linen,"], ["Ina ave ia se afi ai le va o mea taavavale,", "saying, Take fire from between the wheels,"], ["ai le va o kerupi;", "from between the cherubims;"], ["ona ulu ane lea o ia,", "then he went in,"], ["ma tu e lata ane i le mea taavale.", "and stood beside the wheels."]]},
  {num:7,words:[["Ona tago atu lea o le lima o le kerupi ai le va o kerupi i le afi ai le va o kerupi,", "And one cherub stretched forth his hand from between the cherubims unto the fire that was between the cherubims,"], ["ua avae ai,", "and took thereof,"], ["ma avane i lima o le ua ofu i le ie lino;", "and put it into the hands of him that was clothed with linen:"], ["ua talia e ia,", "who took it,"], ["ona alu atu lea o ia.", "and went out."]]},
  {num:8,words:[["Ua iloa i kerupi le faatusa o le lima o le tagata i lalo o latou apaau.", "And there appeared in the cherubims the form of a man's hand under their wings."]]},
  {num:9,words:[["Ona ou vaai lea faauta,", "And when I looked,"], ["o mea taavavale e fa i tafatafa o kerupi,", "behold the four wheels by the cherubims,"], ["taitasi le mea taavale i tafatafa o kerupi taitasi;", "one wheel by one cherub, and another wheel by another cherub:"], ["ua tino mai foi o mea taavavale e pei o le tino o le maa tasesa.", "and the appearance of the wheels was as the colour of a beryl stone."]]},
  {num:10,words:[["O latou tino mai foi,", "And as for their appearances,"], ["ua tino faatasi i latou uma e fa,", "they four had one likeness,"], ["ua peiseai o le mea taavale i totonu o le mea taavale.", "as if a wheel had been in the midst of a wheel."]]},
  {num:11,words:[["A latou o,", "When they went,"], ["ua latou o i o latou itu e fa,", "they went upon their four sides;"], ["ua latou le liliu ina ua latou o,", "they turned not as they went,"], ["a o le mea na faasaga i ai le ulu ua latou mulimuli atu i ai;", "but to the place whither the head looked they followed it;"], ["ua latou le liliu ina ua latou o.", "they turned not as they went."]]},
  {num:12,words:[["O latou tino uma,", "And their whole body,"], ["ma o latou tua,", "and their backs,"], ["ma o latou lima,", "and their hands,"], ["ma o latou apaau,", "and their wings,"], ["atoa ma mea taavavale ua tutumu ia i mata,", "and the wheels,"], ["ua soo lava,", "were full of eyes round about,"], ["o mea taavavale lava na ia te i latou e fa.", "even the wheels that they four had."]]},
  {num:13,words:[["A o mea taavavale,", "As for the wheels,"], ["ua valaau le tasi ia te i latou, o loo ou faalogo atu,", "it was cried unto them in my hearing,"], ["Le mea taavale e.", "O wheel."]]},
  {num:14,words:[["Ua tofu i latou taitasi ma mata e fa; o le ua muamua i mata,", "And every one had four faces:"], ["o mata o le kerupi lea, o lona lua o mata,", "the first face was the face of a cherub,"], ["o mata o le tagata lea,", "and the second face was the face of a man,"], ["o lona tolu, o mata o le leona lea,", "and the third the face of a lion,"], ["o lona fa, o mata o le aeto lea.", "and the fourth the face of an eagle."]]},
  {num:15,words:[["Ua siitia foi kerupi i luga. (O le mea ola lea na ou iloa i le vaitafe o Kepara.)", "And the cherubims were lifted up. This is the living creature that I saw by the river of Chebar."]]},
  {num:16,words:[["A ō foi kerupi,", "And when the cherubims went,"], ["ua o foi mea taavavale i o latou tafatafa;", "the wheels went by them:"], ["a faloina i luga e kerupi o latou apaau ina ia o ae i luga nai le lalolagi,", "and when the cherubims lifted up their wings to mount up from the earth,"], ["e le liliu ese i o latou tafatafa ia lava mea taavavale.", "the same wheels also turned not from beside them."]]},
  {num:17,words:[["A tutū i latou,", "When they stood,"], ["ona tutū lea o i latou nei;", "these stood;"], ["a aveina ae foi i latou i luga,", "and when they were lifted up,"], ["ona aveina ae lea o i latou nei;", "these lifted up themselves also:"], ["auā ua i ai le agaga o le mea ola ia te i latou.", "for the spirit of the living creature was in them."]]},
  {num:18,words:[["Ona alu atu lea o le pupula o Ieova ai le faitotoa o le fale,", "Then the glory of the LORD departed from off the threshold of the house,"], ["ma ua tu i luga ae o kerupi.", "and stood over the cherubims."]]},
  {num:19,words:[["Ona faloina lea i luga e kerupi o latou apaau,", "And the cherubims lifted up their wings,"], ["ua o ae mai le lalolagi,", "and mounted up from the earth in my sight:"], ["o loo ou vaai i ai;", "when they went out,"], ["ua latou o atu ua faatasi ma i latou mea taavavale,", "the wheels also were beside them,"], ["ua latou tutū foi i le puipui o le faitotoa o le fale o Ieova e faasaga i sasae;", "and every one stood at the door of the east gate of the LORD'S house;"], ["ua i luga lava ia te i latou le pupula o le Atua o Isaraelu.", "and the glory of the God of Israel was over them above."]]},
  {num:20,words:[["O le mea ola lea na ou iloa i lalo o le Atua o Isaraelu i le vaitafe o Kepara;", "This is the living creature that I saw under the God of Israel by the river of Chebar;"], ["na ou iloa o kerupi lava i latou.", "and I knew that they were the cherubims."]]},
  {num:21,words:[["Ua taitasi ma ona mata e fa,", "Every one had four faces apiece,"], ["e taitasi foi ma ona apaau e fa;", "and every one four wings;"], ["o le faatusa foi o lima o le tagata na i lalo o latou apaau lea.", "and the likeness of the hands of a man was under their wings."]]},
  {num:22,words:[["O le faatusa foi o latou mata o mata ia na ou iloa e lata ane i le vaitafe o Kepara,", "And the likeness of their faces was the same faces which I saw by the river of Chebar,"], ["o latou tino mai, ma i latou lava;", "their appearances and themselves:"], ["e taitasi ma alu tonu atu i ona luma.", "they went every one straight forward."]]},
];
