var ezk_ch_11_Verses = [
  {num:1,words:[["Ua siitia foi a'u i luga e le Agaga,", "Moreover the spirit lifted me up,"], ["ua ia ave ia te au i le faitotoa o le fale o Ieova i sasae e faafesagai ma le itu i sasae;", "and brought me unto the east gate of the LORD'S house,"], ["faauta foi,", "which looketh eastward:"], ["o tagata e toaluafulu ma le toalima i le puipui o le faitotoa;", "and behold at the door of the gate five and twenty men;"], ["ua ou iloa foi o ia te i latou o Iaasenaia le atalii o Asura,", "among whom I saw Jaazaniah the son of Azur,"], ["ma Pelatia le atalii o Penaia,", "and Pelatiah the son of Benaiah,"], ["o alii o le nuu.", "princes of the people."]]},
  {num:2,words:[["Ona fetalai mai lea o ia ia te au,", "Then said he unto me,"], ["Le atalii e o le tagata,", "Son of man,"], ["o tagata ia e tautogafiti i mea leaga,", "these are the men that devise mischief,"], ["ma latou pule i pulega leaga le aai nei;", "and give wicked counsel in this city:"]]},
  {num:3,words:[["o e faapea atu,", "Which say,"], ["E le latalata mai;", "It is not near;"], ["ina fai fale ia;", "let us build houses:"], ["o le ulo lenei aai ,", "this city is the caldron,"], ["a o le tufaaga i tatou.", "and we be the flesh."]]},
  {num:4,words:[["O le mea lea ia e vavalo atu ai ia te i latou,", "Therefore prophesy against them,"], ["le atalii e o le tagata,", "prophesy,"], ["ia e vavalo atu ia.", "O son of man."]]},
  {num:5,words:[["Ona oo mai ai lea o le Agaga o Ieova ia te au,", "And the Spirit of the LORD fell upon me,"], ["ua ia fetalai mai foi ia te au,", "and said unto me,"], ["Fai atu ia,", "Speak;"], ["O loo o faapea mai Ieova,", "Thus saith the LORD; Thus have ye said,"], ["Ua faapea ona fai mai outou,", "O house of Israel:"], ["le aiga o Isaraelu e;", "for I know the things that come into your mind,"], ["auā ua ou iloa mea uma lava e tutupu i o outou manatu.", "every one of them."]]},
  {num:6,words:[["Ua outou faatoateleina o outou tagata fasiotia i lenei aai,", "Ye have multiplied your slain in this city,"], ["ua outou faatutumuina ona ala i e ua fasiotia.", "and ye have filled the streets thereof with the slain."]]},
  {num:7,words:[["O le mea lea o loo faapea mai ai le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["O outou tagata ua fasiotia,", "Your slain whom ye have laid in the midst of it,"], ["ua outou tuuina ai, o tufaaga i latou,", "they are the flesh,"], ["a o lenei aai o le ulo lea;", "and this city is the caldron:"], ["a e ou te aveeseina ai outou.", "but I will bring you forth out of the midst of it."]]},
  {num:8,words:[["Ua outou fefefe i le pelu;", "Ye have feared the sword;"], ["ou te faaoo atu lava le pelu ia te outou,", "and I will bring a sword upon you,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:9,words:[["Ou te aveeseina ai outou ma ou tuuina atu outou i lima o tagata ese,", "And I will bring you out of the midst thereof, and deliver you into the hands of strangers,"], ["ou te faaooina foi sala ia te outou.", "and will execute judgments among you."]]},
  {num:10,words:[["E oti outou i le pelu;", "Ye shall fall by the sword;"], ["ou te faasalaina outou i le tuaoi o Isaraelu;", "I will judge you in the border of Israel;"], ["ona outou iloa ai lea o a'u lava o Ieova.", "and ye shall know that I am the LORD."]]},
  {num:11,words:[["E le fai lenei aai ,", "This city shall not be your caldron,"], ["ma ulo ia te outou, e le fai foi outou ma tufaaga o i ai;", "neither shall ye be the flesh in the midst thereof;"], ["ou te faasalaina outou i le tuaoi o Isaraelu;", "but I will judge you in the border of Israel:"]]},
  {num:12,words:[["e iloa ai foi e outou o a'u lava o Ieova;", "And ye shall know that I am the LORD:"], ["aua ua outou le savavali i a'u tulafono,", "for ye have not walked in my statutes,"], ["e lei faia foi a'u faamasinoga,", "neither executed my judgments,"], ["a ua outou fai e tusa ma tu o nuu ese e vagavagaia outou.", "but have done after the manners of the heathen that are round about you."]]},
  {num:13,words:[["Ua oti Pelatia le atalii o Penaia o loo ou vavalo atu.", "And it came to pass, when I prophesied, that Pelatiah the son of Benaiah died."], ["Ona ou faapaū fao ai lea,", "Then fell I down upon my face,"], ["ma ou alaga atu ua leo tele,", "and cried with a loud voice,"], ["ua faapea atu, Aue,", "and said,"], ["le Alii e Ieova e! e te faaumatia ea e o totoe ia Isaraelu?", "Ah Lord GOD! wilt thou make a full end of the remnant of Israel?"]]},
  {num:14,words:[["Ona oo mai lea o le afioga a Ieova ia te au,", "Again the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:15,words:[["Le atalii e o le tagata,", "Son of man,"], ["o ou uso,", "thy brethren,"], ["o ou uso lava, o tagata o lou aiga,", "even thy brethren,"], ["atoa ma le aiga uma o Isaraelu,", "the men of thy kindred,"], ["o i latou uma lava,", "and all the house of Israel wholly,"], ["o i latou ia ua fai atu i ai e o nonofo i Ierusalema, Ina o ese atu ia outou,", "are they unto whom the inhabitants of Jerusalem have said,"], ["ia mamao ia Ieova;", "Get you far from the LORD:"], ["ua tuuina mai ia i matou le nuu nei e fai mo matou.", "unto us is this land given in possession."]]},
  {num:16,words:[["O le mea lea ia e fai atu ai,", "Therefore say,"], ["O loo faapea mai le Alii o Ieova;", "Thus saith the Lord GOD;"], ["E ui ina ua ou avemamaoina i latou i nuu ese,", "Although I have cast them far off among the heathen,"], ["e ui ina ua ou faataapeapeina i latou i nuu eseese,", "and although I have scattered them among the countries,"], ["e fai a'u ma malumalu ia te i latou i nai tausaga i nuu latou te o i ai.", "yet will I be to them as a little sanctuary in the countries where they shall come."]]},
  {num:17,words:[["O le mea lea ia e fai atu ai,", "Therefore say,"], ["O loo faapea mai le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Ou te faapotopotoina mai outou nai nuu ese,", "I will even gather you from the people,"], ["ma aofai mai ia te outou ai nuu esese ua faataapeapeina ai outou,", "and assemble you out of the countries where ye have been scattered,"], ["ma ou avatu ia te outou le laueleele o Isaraelu.", "and I will give you the land of Israel."]]},
  {num:18,words:[["Latou te o mai ai, ma latou aveeseina mea leaga uma o i ai,", "And they shall come thither,"], ["atoa ma mea uma e inosia.", "and they shall take away all the detestable things thereof and all the abominations thereof from thence."]]},
  {num:19,words:[["Ou te foai atu foi ia te i latou le loto e tasi,", "And I will give them one heart,"], ["ma ou foai atu le loto fou i totonu ia te outou;", "and I will put a new spirit within you;"], ["ou te aveeseina le loto fatu ai totonu i o latou tino,", "and I will take the stony heart out of their flesh,"], ["ma ou foai atu le loto aano ia te i latou;", "and will give them an heart of flesh:"]]},
  {num:20,words:[["ina ia latou savavali i a'u tulafono,", "That they may walk in my statutes,"], ["ma tausi i a'u faamasinoga,", "and keep mine ordinances,"], ["ma latou faia;", "and do them:"], ["e fai foi i latou mo'u nuu,", "and they shall be my people,"], ["e fai foi a'u mo latou Atua.", "and I will be their God."]]},
  {num:21,words:[["A o i latou o e mulimuli atu o latou loto i loto o a latou mea leaga ma a latou mea e inosia,", "But as for them whose heart walketh after the heart of their detestable things and their abominations,"], ["ou te taui atu a latou amio i luga i o latou ulu,", "I will recompense their way upon their own heads,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:22,words:[["Ona siitia lea i luga e kerupi o latou apaau,", "Then did the cherubims lift up their wings,"], ["ma mea taavavale i o latou tafatafa;", "and the wheels beside them;"], ["ua i o latou luga ae le pupula o le Atua o Isaraelu.", "and the glory of the God of Israel was over them above."]]},
  {num:23,words:[["Ona alu ae lea o le pupula o Ieova nai totonu o le aai,", "And the glory of the LORD went up from the midst of the city,"], ["ua tu i luga o le mauga o loo i le itu i sasae o le aai.", "and stood upon the mountain which is on the east side of the city."]]},
  {num:24,words:[["Ona siitia lea o a'u e le Agaga,", "Afterwards the spirit took me up, and brought me in a vision by the Spirit of God into Chaldea,"], ["ua avea foi a'u e le Agaga o le Atua i le faaaliga i Kaletaia ia te i latou o le tafeaga.", "to them of the captivity."], ["Ona alu ae lea nai ia te au le faaaliga na ou iloa.", "So the vision that I had seen went up from me."]]},
  {num:25,words:[["Ona ou tala atu ai lea ia te i latou o i le tafeaga o mea uma na faaalia mai e Ieova ia te au.", "Then I spake unto them of the captivity all the things that the LORD had shewed me."]]},
];
