var ezk_ch_12_Verses = [
  {num:1,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "The word of the LORD also came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["o loo e nofo i le aiga fouvale ua ia te i latou mata e vaai,", "thou dwellest in the midst of a rebellious house,"], ["a ua latou le vaai ai;", "which have eyes to see, and see not;"], ["ua ia te i latou taliga e faalogo a ua latou le faalogo,", "they have ears to hear,"], ["ai;", "and hear not:"], ["auā o le aiga fouvale lava i latou.", "for they are a rebellious house."]]},
  {num:3,words:[["O le mea lea,", "Therefore,"], ["le atalii e o le tagata,", "thou son of man,"], ["ia e sauni ai mo oe o mea e alu ma oe i le tafeaga,", "prepare thee stuff for removing,"], ["ma ia e alu atu i le ao i o latou luma,", "and remove by day in their sight;"], ["e te alu ese i le mea ua e mau ai i se tasi mea i o latou luma;", "and thou shalt remove from thy place to another place in their sight:"], ["e ui lava o le aiga fouvale i latou,", "it may be they will consider,"], ["atonu latou te mafaufau ai.", "though they be a rebellious house."]]},
  {num:4,words:[["E te tautuu atu foi au mea i le ao i o latou luma,", "Then shalt thou bring forth thy stuff by day in their sight,"], ["e pei o mea e ave i le tafeaga. E te alu atu foi i le pouliuli i o latou luma,", "as stuff for removing: and thou shalt go forth at even in their sight,"], ["e pei o e o atu i le tafeaga.", "as they that go forth into captivity."]]},
  {num:5,words:[["E te eli le pa i o latou luma,", "Dig thou through the wall in their sight,"], ["ma tautuu atu ai.", "and carry out thereby."]]},
  {num:6,words:[["E te faafuataina ia mea i lou ua i o latou luma,", "In their sight shalt thou bear it upon thy shoulders,"], ["ma e avatu ai i le afiafi;", "and carry it forth in the twilight:"], ["e te ufiufi ou mata ia e le iloa ai le eleele;", "thou shalt cover thy face, that thou see not the ground:"], ["auā ua ou fai oe ma faailoga i le aiga o Isaraelu.", "for I have set thee for a sign unto the house of Israel."]]},
  {num:7,words:[["Ona ou faia lea e pei ona poloaiina mai o a'u;", "And I did so as I was commanded:"], ["na ou tautuu atu a'u mea i le ao pei o mea e ave i le tafeaga;", "I brought forth my stuff by day,"], ["na ou eli le pa i le afiafi i lo'u lima;", "as stuff for captivity, and in the even I digged through the wall with mine hand;"], ["na ou tautuu atu ai i le pouliuli,", "I brought it forth in the twilight,"], ["ma ou faafuata i lo'u ua i o latou luma.", "and I bare it upon my shoulder in their sight."]]},
  {num:8,words:[["Ua oo mai ai le afioga a Ieova ia te au i le taeao,", "And in the morning came the word of the LORD unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:9,words:[["Le atalii e o le tagata,", "Son of man,"], ["e lei faapea mai ea ia te oe le aiga o Isaraelu,", "hath not the house of Israel,"], ["le aiga fouvale,", "the rebellious house, said unto thee,"], ["Se a ea le mea ua e faia?", "What doest thou?"]]},
  {num:10,words:[["Ia e fai atu ia te i latou,", "Say thou unto them,"], ["O loo faapea mai le Alii o Ieova,", "Thus saith the Lord GOD;"], ["O le avega lenei i le alii sili o Ierusalema, ma le aiga uma o Isaraelu,", "This burden concerneth the prince in Jerusalem,"], ["o e ua ia te i latou.", "and all the house of Israel that are among them."]]},
  {num:11,words:[["Fai atu ia,", "Say,"], ["O a'u nei o le faailoga ia te outou;", "I am your sign:"], ["e pei ona ou faia,", "like as I have done,"], ["e faapea ona faia ia te i latou;", "so shall it be done unto them:"], ["e o faatagataotaua i latou i le tafeaga.", "they shall remove and go into captivity."]]},
  {num:12,words:[["O le alii sili foi o loo ia te i latou,", "And the prince that is among them shall bear upon his shoulder in the twilight,"], ["na te faafuataina mea i lona ua i le pouliuli,", "and shall go forth:"], ["ma alu atu, latou te elia le pa e tautuu atu ai;", "they shall dig through the wall to carry out thereby:"], ["na te ufitia ona mata,", "he shall cover his face,"], ["ia na le iloa le eleele i ona mata.", "that he see not the ground with his eyes."]]},
  {num:13,words:[["Ou te folasia la'u upega ia te ia,", "My net also will I spread upon him,"], ["e lavea foi o ia i la'u mailei;", "and he shall be taken in my snare:"], ["ou te aumaia foi o ia i Papelonia o le nuu o Kaletaia;", "and I will bring him to Babylon to the land of the Chaldeans;"], ["e oti ai o ia,", "yet shall he not see it,"], ["a e na te le vaai i ai.", "though he shall die there."]]},
  {num:14,words:[["Ou te faataapeapeina i matāmatagi uma i latou uma o e ua ia te ia e fesoasoani ia te ia,", "And I will scatter toward every wind all that are about him to help him,"], ["atoa ma ana 'au uma;", "and all his bands;"], ["ou te to ae foi le pelu e mulimuli atu ia te i latou.", "and I will draw out the sword after them."]]},
  {num:15,words:[["Ona latou iloa ai lea o a'u lava o Ieova,", "And they shall know that I am the LORD,"], ["pe a ou faataapeapeina i latou i nuu ese,", "when I shall scatter them among the nations,"], ["ma faasalalauina i latou i nuu eseese.", "and disperse them in the countries."]]},
  {num:16,words:[["A e ou te faatotoeina ni o latou tagata e toaitiiti ai le pelu,", "But I will leave a few men of them from the sword,"], ["ma le oge,", "from the famine,"], ["ma le faamai;", "and from the pestilence;"], ["ina ia latou talatala atu i a latou mea inosia uma i nuu latou te o i ai;", "that they may declare all their abominations among the heathen whither they come;"], ["latou te iloa foi o a'u lava o Ieova.", "and they shall know that I am the LORD."]]},
  {num:17,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "Moreover the word of the LORD came to me,"], ["ua faapea mai,", "saying,"]]},
  {num:18,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia e 'ai au mea e 'ai ma le gatete,", "eat thy bread with quaking,"], ["ma e inu i lou vai ma le tetemu ma le atuatuvale.", "and drink thy water with trembling and with carefulness;"]]},
  {num:19,words:[["Ia e fai atu foi i tagata o le nuu,", "And say unto the people of the land,"], ["O loo faapea ona fetalai mai o le Alii o Ieova i e o nonofo i Ierusalema,", "Thus saith the Lord GOD of the inhabitants of Jerusalem,"], ["ma le laueleele o Isaraelu;", "and of the land of Israel;"], ["latou te aai a latou mea e 'ai ma le atuatuvale,", "They shall eat their bread with carefulness,"], ["ma feinu i o latou vai ma le fememeai,", "and drink their water with astonishment,"], ["ina ia faatafunaina lo latou nuu ia tea mea ua tumu ai,", "that her land may be desolate from all that is therein,"], ["ona o le saua o i latou uma o e nonofo ai.", "because of the violence of all them that dwell therein."]]},
  {num:20,words:[["O aai ua āina e faagaogaoina ia,", "And the cities that are inhabited shall be laid waste,"], ["e faatafunaina foi le nuu;", "and the land shall be desolate;"], ["ona outou iloa ai lea o a'u lava o Ieova.", "and ye shall know that I am the LORD."]]},
  {num:21,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "And the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:22,words:[["Le atalii e o le tagata,", "Son of man,"], ["se a ea lena faatusa ua ia te outou i le nuu o Isaraelu,", "what is that proverb that ye have in the land of Israel,"], ["ua faapea mai,", "saying,"], ["Ua faalevaleva aso,", "The days are prolonged,"], ["ua iuvale faaaliga uma?", "and every vision faileth?"]]},
  {num:23,words:[["O le mea lea ia e fai atu ai ia te i latou,", "Tell them therefore,"], ["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Ou te faate'aina lena faatusa,", "I will make this proverb to cease,"], ["latou te le toe faia lea faatusa i Isaraelu;", "and they shall no more use it as a proverb in Israel;"], ["a ia e fai atu ia te i latou,", "but say unto them,"], ["Ua latalata ona aso,", "The days are at hand,"], ["ma le taunuuga o faaaliga uma.", "and the effect of every vision."]]},
  {num:24,words:[["Auā e le toe ai lava se faaaliga faatauvaa, ma se togafiti faataulāitu faa'ole'ole i le aiga o Isaraelu.", "For there shall be no more any vain vision nor flattering divination within the house of Israel."]]},
  {num:25,words:[["Auā o a'u o Ieova ou te tautala atu,", "For I am the LORD:"], ["o le upu foi ou te tautala atu ai e taunuu lea,", "I will speak,"], ["e le toe faatuai;", "and the word that I shall speak shall come to pass;"], ["auā o outou lava aso,", "it shall be no more prolonged:"], ["le aiga fouvale e,", "for in your days, O rebellious house,"], ["ou te tautala atu ai le upu,", "will I say the word,"], ["ma ou faataunuuina lava,", "and will perform it,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:26,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "Again the word of the LORD came to me,"], ["ua faapea mai,", "saying,"]]},
  {num:27,words:[["Le atalii e o le tagata,", "Son of man,"], ["faauta,", "behold,"], ["o loo fai mai le aiga o Isaraelu, O le faaaliga o loo iloa e ia,", "they of the house of Israel say,"], ["mo aso amuli lava ia,", "The vision that he seeth is for many days to come,"], ["ua ia vavalo foi i ona po e mamao atu.", "and he prophesieth of the times that are far off."]]},
  {num:28,words:[["O le mea lea ia e fai atu ai ia te i latou,", "Therefore say unto them,"], ["O loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["E le toe faatuai lava se tasi o a'u upu;", "There shall none of my words be prolonged any more,"], ["a o le upu ua ou fai atu ai e faia lava,", "but the word which I have spoken shall be done,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
];
renderVerseSet(ezk_ch_12_Verses, 'ezk-ch12-verses');

var ezk_ch_13_Verses = [
  {num:1,words:[["Ua oo mai le afioga a Ieova ia te au,", "And the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia e vavalo i perofeta o Isaraelu o e vavalo,", "prophesy against the prophets of Israel that prophesy,"], ["ma ia e fai atu ia te i latou o vavalo mai o latou lava loto,", "and say thou unto them that prophesy out of their own hearts,"], ["Faalogologo mai ia outou i le afioga a Ieova;", "Hear ye the word of the LORD;"]]},
  {num:3,words:[["o loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Oi talofa i perofeta valelea o e usiusitai i o latou lava loto,", "Woe unto the foolish prophets, that follow their own spirit,"], ["a e lei vaaia e i latou se mea.", "and have seen nothing!"]]},
  {num:4,words:[["Isaraelu e,", "O Israel,"], ["ua faapei o alope i le vao ou perofeta.", "thy prophets are like the foxes in the deserts."]]},
  {num:5,words:[["Ua outou le o ae i mea ua lepetia, ua outou le ati ae foi le pa mo le aiga o Isaraelu,", "Ye have not gone up into the gaps,"], ["ina ia tutū ai i le taua i le aso o Ieova.", "neither made up the hedge for the house of Israel to stand in the battle in the day of the LORD."]]},
  {num:6,words:[["Ua latou vaaia le mea faatauvaa ma ua fai togafiti faataulāitu pepelo,", "They have seen vanity and lying divination,"], ["ua faapea,", "saying,"], ["O loo fetalai mai Ieova;", "The LORD saith:"], ["a e lei aauina i latou e Ieova;", "and the LORD hath not sent them:"], ["ua latou faatupuina foi le faamoemoe e faataunuuina le upu.", "and they have made others to hope that they would confirm the word."]]},
  {num:7,words:[["E lei vaaia ea e outou le faaaliga faatauvaa,", "Have ye not seen a vain vision,"], ["ma outou faia le togafiti faataulāitu ina ua outou fai atu,", "and have ye not spoken a lying divination,"], ["O loo fetalai mai Ieova;", "whereas ye say, The LORD saith it;"], ["a e ou te lei fai atu lava?", "albeit I have not spoken?"]]},
  {num:8,words:[["O le mea lea ua faapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["Ona ua outou fai atu le mea faatauvaa,", "Because ye have spoken vanity,"], ["ma ua vaaia mea pepelo;", "and seen lies,"], ["o le mea lea,", "therefore,"], ["faauta,", "behold,"], ["ou te fai ai outou mo'u fili,", "I am against you,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:9,words:[["E oo foi lo'u lima i perofeta o e vaaia le mea faatauvaa,", "And mine hand shall be upon the prophets that see vanity,"], ["ma fai togafiti faataulāitu pepelo;", "and that divine lies:"], ["e le i ai latou i le saofaiga a lo'u nuu,", "they shall not be in the assembly of my people,"], ["e le tusia foi i latou i le tusi o le aiga o Isaraelu,", "neither shall they be written in the writing of the house of Israel,"], ["latou te le oo foi i le laueleele o Isaraelu;", "neither shall they enter into the land of Israel;"], ["e iloa ai foi e outou o a'u lava o le Alii o Ieova.", "and ye shall know that I am the Lord GOD."]]},
  {num:10,words:[["Ua latou faaseseina lo'u nuu,", "Because,"], ["o loo faapea atu,", "even because they have seduced my people,"], ["E manuia;", "saying,"], ["a e leai se manuia;", "Peace;"], ["ua ati ae e le tasi le pa,", "and there was no peace;"], ["faauta foi,", "and one built up a wall,"], ["ua vali e nisi i le panisina;", "and,"], ["o le mea lea,", "lo,"], ["o le mea lava lea,", "others daubed it with untempered morter:"]]},
  {num:11,words:[["ia e fai atu ai ia te i latou o e vali i le panisina,", "Say unto them which daub it with untempered morter,"], ["e sŏloia;", "that it shall fall:"], ["e to timuga tetele;", "there shall be an overflowing shower; and ye,"], ["o oe foi le uato'a tetele,", "O great hailstones,"], ["e to ifo oe;", "shall fall;"], ["e lepetia foi le pa i le afā.", "and a stormy wind shall rend it."]]},
  {num:12,words:[["Faauta foi,", "Lo,"], ["a solo le pa,", "when the wall is fallen,"], ["e le fai atu ea ia te outou,", "shall it not be said unto you,"], ["O ifea ea le panisina na outou vali a'i?", "Where is the daubing wherewith ye have daubed it?"]]},
  {num:13,words:[["O le mea lea ua faapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["Ou te lepetia lava i le afā i lo'u ita tele,", "I will even rend it with a stormy wind in my fury;"], ["e to timuga tetele i lo'u ita, ma uato'a tetele i lo'u ita tele,", "and there shall be an overflowing shower in mine anger,"], ["e faaumatia ai.", "and great hailstones in my fury to consume it."]]},
  {num:14,words:[["Ou te lepetia ai lava le pa na outou valia i le panisina,", "So will I break down the wall that ye have daubed with untempered morter,"], ["ou te faagatasia lava ma le eleele,", "and bring it down to the ground,"], ["e aliali ai ona faavae;", "so that the foundation thereof shall be discovered,"], ["e solo lava ia,", "and it shall fall,"], ["e faaumatia ai foi outou i totonu;", "and ye shall be consumed in the midst thereof:"], ["e iloa ai e outou o a'u lava o Ieova.", "and ye shall know that I am the LORD."]]},
  {num:15,words:[["Ou te faauma atu ai lo'u ita tele i le pa,", "Thus will I accomplish my wrath upon the wall,"], ["atoa ma i latou o e na latou valia i le panisina ou te fai atu foi ia te outou,", "and upon them that have daubed it with untempered morter,"], ["Ua leai se pa,", "and will say unto you, The wall is no more,"], ["ua leai foi e na valia;", "neither they that daubed it;"]]},
  {num:16,words:[["o perofeta ia o Isaraelu o e vavalo ia Ierusalema,", "To wit,"], ["ma ē iloa faaaliga o le manuia mo ia,", "the prophets of Israel which prophesy concerning Jerusalem,"], ["a e leai se manuia,", "and which see visions of peace for her, and there is no peace,"], ["ua fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:17,words:[["O oe foi le atalii o le tagata,", "Likewise,"], ["ia e faasaga atu i fafine o lou nuu,", "thou son of man,"], ["o e vavalo mai o latou lava loto;", "set thy face against the daughters of thy people, which prophesy out of their own heart;"], ["ma ia e vavalo atu ia te i latou,", "and prophesy thou against them,"]]},
  {num:18,words:[["ma e fai atu,", "And say,"], ["O loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Oi talofa i fafine o e su'i aluga mo tulilima uma,", "Woe to the women that sew pillows to all armholes,"], ["ma fai pulou mo ulu o tupulaga uma e mailei a'i tagata. Tou te taumailei ea i tagata o lo'u nuu,", "and make kerchiefs upon the head of every stature to hunt souls! Will ye hunt the souls of my people,"], ["tou te faaolaina ea foi o i latou o e o ane ia te outou?", "and will ye save the souls alive that come unto you?"]]},
  {num:19,words:[["Tou te faaleagaina ea a'u i lo'u lava nuu ona o luutaga o karite,", "And will ye pollute me among my people for handfuls of barley and for pieces of bread,"], ["ma fāsi areto,", "to slay the souls that should not die,"], ["ina ia fasiotia ai tagata e le tatau ona oti, ma faaolaina tagata e le tatau ona ola,", "and to save the souls alive that should not live,"], ["i lo outou tala pepelo atu i lo'u nuu o e faalogo atu i la outou tala pepelo.", "by your lying to my people that hear your lies?"]]},
  {num:20,words:[["O le mea lea,", "Wherefore thus saith the Lord GOD;"], ["ua faapea ona fetalai mai ai o le Alii o Ieova,", "Behold,"], ["Faauta,", "I am against your pillows,"], ["ou te fai mo'u fili o outou aluga tou te mailei a'i agaga ina ia felelei ai i latou,", "wherewith ye there hunt the souls to make them fly,"], ["ou te saeia lava ai o outou lima,", "and I will tear them from your arms,"], ["ma tuuina atu i latou e ō,", "and will let the souls go,"], ["o agaga ia tou te taumailei ai ina ia felelei.", "even the souls that ye hunt to make them fly."]]},
  {num:21,words:[["Ou te saeia foi o outou pulou,", "Your kerchiefs also will I tear,"], ["ma laveaiina lo'u nuu ai o outou lima,", "and deliver my people out of your hand,"], ["e le toe i ai lava i latou i o outou lima ina ia mailei ai;", "and they shall be no more in your hand to be hunted;"], ["tou te iloa ai foi o a'u lava o Ieova.", "and ye shall know that I am the LORD."]]},
  {num:22,words:[["Ua outou faatigaina loto o e amiotonu i upu pepelo,", "Because with lies ye have made the heart of the righteous sad,"], ["o e ua le faatigaina e a'u;", "whom I have not made sad;"], ["ma ua outou faamalosi i lē amio leaga,", "and strengthened the hands of the wicked, that he should not return from his wicked way,"], ["ia le liliu ai o ia ai lana amio leaga ina ia faaolaina o ia.", "by promising him life:"]]},
  {num:23,words:[["O le mea lea tou te le toe vaaia le mea faatauvaa,", "Therefore ye shall see no more vanity,"], ["pe fai togafiti faataulāitu,", "nor divine divinations:"], ["auā ou te laveaiina lo'u nuu ai o outou lima;", "for I will deliver my people out of your hand:"], ["tou te iloa ai o a'u lava o Ieova.", "and ye shall know that I am the LORD."]]},
];
renderVerseSet(ezk_ch_13_Verses, 'ezk-ch13-verses');

var ezk_ch_14_Verses = [
  {num:1,words:[["Ua o mai foi ia te au nisi toeaina o Isaraelu,", "Then came certain of the elders of Israel unto me,"], ["ua nonofo mai i o'u luma.", "and sat before me."]]},
  {num:2,words:[["Ona oo mai lea o le afioga a Ieova ia te au,", "And the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:3,words:[["Le atalii e o le tagata,", "Son of man,"], ["ua faatuina e ia tagata o a latou tupua i o latou loto,", "these men have set up their idols in their heart,"], ["ma ua tuuina i o latou luma la latou agasala e tausuai ai;", "and put the stumblingblock of their iniquity before their face:"], ["latou te fesili mai ea ia te au?", "should I be enquired of at all by them?"]]},
  {num:4,words:[["O le mea lea ia e tautala atu ai ia te i latou,", "Therefore speak unto them,"], ["ma fai atu ia te i latou, O loo faapea ona fetalai mai o le Alii o Ieova,", "and say unto them,"], ["Ai se tagata o le aiga o Isaraelu na te faatuina ana tupua i lona loto,", "Thus saith the Lord GOD;"], ["ma tuuina i ona luma lana agasala e tausuai ai,", "Every man of the house of Israel that setteth up his idols in his heart,"], ["ma alu ane i le perofeta;", "and putteth the stumblingblock of his iniquity before his face,"], ["o a'u o Ieova, ou te tali atu i lē alu ane,", "and cometh to the prophet;"], ["e tusa ma le tele o ana tupua;", "I the LORD will answer him that cometh according to the multitude of his idols;"]]},
  {num:5,words:[["ina ia maua le aiga o Isaraelu i o latou lava loto,", "That I may take the house of Israel in their own heart,"], ["auā ua o ese i latou uma ia te au ona o a latou tupua.", "because they are all estranged from me through their idols."]]},
  {num:6,words:[["O le mea lea ia e fai atu ai i le aiga o Isaraelu,", "Therefore say unto the house of Israel,"], ["O loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Liliu mai ia,", "Repent,"], ["ina liliu ese i a outou tupua,", "and turn yourselves from your idols;"], ["ia liliu ese o outou mata i a outou mea inosia uma.", "and turn away your faces from all your abominations."]]},
  {num:7,words:[["Auā ai se tagata o le aiga o Isaraelu,", "For every one of the house of Israel,"], ["po o se tagata ese o āumau i Isaraelu, na te alu ese ia te au,", "or of the stranger that sojourneth in Israel,"], ["ma faatuina ana tupua i lona loto,", "which separateth himself from me,"], ["ma tuuina i ona luma lana agasala e tausuai ai,", "and setteth up his idols in his heart,"], ["ma alu ane i le perofeta e fesili atu ai ia te au,", "and putteth the stumblingblock of his iniquity before his face,"], ["o a'u o Ieova, o a'u lava,", "and cometh to a prophet to enquire of him concerning me;"], ["ou te tali atu ia te ia.", "I the LORD will answer him by myself:"]]},
  {num:8,words:[["Ou te fai lena tagata mo'u fili,", "And I will set my face against that man,"], ["ou te fai foi o ia ma faailoga,", "and will make him a sign and a proverb,"], ["ma upu faatusa, ou te vavaeeseina foi o ia i lo'u nuu;", "and I will cut him off from the midst of my people;"], ["tou te iloa ai o a'u lava o Ieova.", "and ye shall know that I am the LORD."]]},
  {num:9,words:[["A e afai e sese se perofeta i se upu ua ia fai atu ai,", "And if the prophet be deceived when he hath spoken a thing,"], ["o a'u o Ieova ua ou faaseseina lena perofeta,", "I the LORD have deceived that prophet,"], ["ou te faaloaloa atu foi lo'u lima ia te ia,", "and I will stretch out my hand upon him,"], ["ma faaumatia o ia ai lo'u nuu o Isaraelu.", "and will destroy him from the midst of my people Israel."]]},
  {num:10,words:[["E taui atu lava a latou agasala;", "And they shall bear the punishment of their iniquity:"], ["e tusa le taui o le perofeta ma le taui o lē fesili ia te ia;", "the punishment of the prophet shall be even as the punishment of him that seeketh unto him;"]]},
  {num:11,words:[["ina ia le toe sese le aiga o Isaraelu i lo latou o ese ia te au,", "That the house of Israel may go no more astray from me,"], ["ma ia le toe leaga i latou i o latou solitulafono uma;", "neither be polluted any more with all their transgressions;"], ["a ia fai i latou mo'u nuu,", "but that they may be my people,"], ["ma ia fai a'u mo latou Atua,", "and I may be their God,"], ["ua fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:12,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "The word of the LORD came again to me,"], ["ua faapea mai,", "saying,"]]},
  {num:13,words:[["Le atalii e o le tagata,", "Son of man,"], ["a agasala mai se nuu ia te au ina ua matuā amio leaga lava,", "when the land sinneth against me by trespassing grievously,"], ["ma ou faaloaloa atu i ai lo'u lima,", "then will I stretch out mine hand upon it,"], ["ma gausia le tootoo o lana mea e 'ai,", "and will break the staff of the bread thereof,"], ["ma tuu atu ai le oge,", "and will send famine upon it,"], ["ma faaumatia tagata atoa ma manu o i ai;", "and will cut off man and beast from it:"]]},
  {num:14,words:[["ana i ai tagata ia e toatolu,", "Though these three men,"], ["o Noa,", "Noah,"], ["o Tanielu,", "Daniel, and Job,"], ["ma Iopu,", "were in it,"], ["e laveaiina e i latou na o latou lava ola i la latou amiotonu,", "they should deliver but their own souls by their righteousness,"], ["ua fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:15,words:[["Afai ou te tuuina atu manu feai e ui ai i le nuu,", "If I cause noisome beasts to pass through the land,"], ["ma faaumatia ai tagata,", "and they spoil it,"], ["ia gaogao,", "so that it be desolate,"], ["ma ia le toe uia ona o manu;", "that no man may pass through because of the beasts:"]]},
  {num:16,words:[["ana i ai ia tagata e toatolu,", "Though these three men were in it,"], ["ua fetalai mai ai le Alii o Ieova,", "as I live,"], ["o loo ola a'u, e le laveaiina e i latou o atalii,", "saith the Lord GOD,"], ["po o afafine,", "they shall deliver neither sons nor daughters;"], ["na o i latou lava e laveaiina,", "they only shall be delivered,"], ["a e faagaogaoina lava le nuu.", "but the land shall be desolate."]]},
  {num:17,words:[["Afai foi ou te faaoo atu le pelu i lena nuu,", "Or if I bring a sword upon that land,"], ["ma ou fai atu,", "and say,"], ["Le pelu e,", "Sword,"], ["ina ui atu ia i le nuu;", "go through the land;"], ["ou te faaumatia ai tagata atoa ma manu;", "so that I cut off man and beast from it:"]]},
  {num:18,words:[["ana i ai ia tagata e toatolu,", "Though these three men were in it,"], ["ua fetalai mai ai le Alii o Ieova,", "as I live,"], ["o loo ola a'u,", "saith the Lord GOD,"], ["latou te le laveaiina o atalii po o afafine,", "they shall deliver neither sons nor daughters,"], ["na o i latou lava e laveaiina.", "but they only shall be delivered themselves."]]},
  {num:19,words:[["Afai foi ou te tuu atu i lena nuu se faamai,", "Or if I send a pestilence into that land,"], ["ma ou sasaaina atu i ai lo'u ita tele i le faamaligi o toto,", "and pour out my fury upon it in blood,"], ["e faaumatia ai tagata atoa ma manu;", "to cut off from it man and beast:"]]},
  {num:20,words:[["ana i ai o Noa,", "Though Noah,"], ["ma Tanielu,", "Daniel,"], ["ma Iopu,", "and Job,"], ["ua fetalai mai ai le Alii o Ieova,", "were in it,"], ["o loo ola a'u,", "as I live,"], ["e le laveaiina e i latou se atalii,", "saith the Lord GOD,"], ["po o se afafine;", "they shall deliver neither son nor daughter;"], ["latou te laveaiina na o latou lava ola i la latou amiotonu.", "they shall but deliver their own souls by their righteousness."]]},
  {num:21,words:[["O le mea lea ua faapea ona fetalai mai ai o le Alii o Ieova;", "For thus saith the Lord GOD;"], ["E le atili ai ea pe a ou tuuina atu i Ierusalema sala ogo e fa ua ia te au,", "How much more when I send my four sore judgments upon Jerusalem,"], ["o le pelu,", "the sword, and the famine,"], ["ma le oge,", "and the noisome beast,"], ["ma le manu feai,", "and the pestilence,"], ["ma le faamai e faaumatia ai tagata atoa ma manu?", "to cut off from it man and beast?"]]},
  {num:22,words:[["Faauta foi,", "Yet,"], ["e faasaoina i ai si ona toe,", "behold,"], ["e ta'ita'iina atu ai i latou,", "therein shall be left a remnant that shall be brought forth,"], ["o atalii atoa ma afafine;", "both sons and daughters:"], ["faauta,", "behold,"], ["e o mai i latou ia te outou,", "they shall come forth unto you,"], ["e iloa e outou a latou amio ma a latou mea e fai;", "and ye shall see their way and their doings:"], ["ona faamafanafanaina ai lea o outou i le leaga ua ou faaoo i Ierusalema,", "and ye shall be comforted concerning the evil that I have brought upon Jerusalem,"], ["atoa uma foi mea ua ou faaoo i ai.", "even concerning all that I have brought upon it."]]},
  {num:23,words:[["Latou te faamafanafana ia te outou pe a outou iloa a latou amio ma a latou mea e fai;", "And they shall comfort you,"], ["ona outou iloa ai lea,", "when ye see their ways and their doings:"], ["ou te lei fai fua mea uma na ou fai i ai,", "and ye shall know that I have not done without cause all that I have done in it,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
];
