var ezk_ch_15_Verses = [
  {num:1,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "And the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["se a ea le mea e sili ai le laau o le vine i laau uma,", "What is the vine tree more than any tree,"], ["po o se la lava o i laau o le vao?", "or than a branch which is among the trees of the forest?"]]},
  {num:3,words:[["E ave ea sina ona laau e fai a'i se galuega? pe fai a'i se tautaulaga e tautau ai se mea?", "Shall wood be taken thereof to do any work? or will men take a pin of it to hang any vessel thereon?"]]},
  {num:4,words:[["Faauta,", "Behold,"], ["e lafo i le afi e fai ma fafie,", "it is cast into the fire for fuel;"], ["e susunu foi i le afi ona pito e lua, e mu foi lona ogaloto;", "the fire devoureth both the ends of it,"], ["e aoga ea ia i se galuega?", "and the midst of it is burned. Is it meet for any work?"]]},
  {num:5,words:[["Faauta,", "Behold, when it was whole,"], ["sa le fai a'i se galuega ina o atoatoa,", "it was meet for no work:"], ["e le atili faapea ai ea ona le fai a'i o se galuega ina ua mu i le afi,", "how much less shall it be meet yet for any work,"], ["ma ua susunuina.", "when the fire hath devoured it, and it is burned?"]]},
  {num:6,words:[["O le mea lea o loo faapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["E pei o le laau o le vine i laau o le vao,", "As the vine tree among the trees of the forest,"], ["ua ou tuuina atu ai mo le afi e fai ma fafie,", "which I have given to the fire for fuel,"], ["e faapea foi ona ou tuuina atu e o nonofo i Ierusalema.", "so will I give the inhabitants of Jerusalem."]]},
  {num:7,words:[["Ou te fai foi i latou mo'u fili,", "And I will set my face against them;"], ["latou te o atu nai le afi,", "they shall go out from one fire,"], ["a e faaumatia i latou i le afi;", "and another fire shall devour them;"], ["ona outou iloa ai lea o a'u lava o Ieova,", "and ye shall know that I am the LORD,"], ["pe a ou fai i latou mo'u fili.", "when I set my face against them."]]},
  {num:8,words:[["Ou te tuuina atu foi le nuu ia faatafunaina,", "And I will make the land desolate,"], ["auā ua matuā agasala i latou,", "because they have committed a trespass,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
];
