var ezk_ch_16_Verses = [
  {num:1,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "Again the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia e faailoa atu ia Ierusalema o ana mea e inosia,", "cause Jerusalem to know her abominations,"]]},
  {num:3,words:[["ma e fai atu ai,", "And say,"], ["O loo faapea ona fetalai mai o le Alii o Ieova ia Ierusalema,", "Thus saith the Lord GOD unto Jerusalem;"], ["O lou tupuga ma lou fanau mai, nai le nuu o Kanana ia;", "Thy birth and thy nativity is of the land of Canaan;"], ["o lou tamā o lo sa Amorī,", "thy father was an Amorite,"], ["o lou tinā o lo sa Hetī.", "and thy mother an Hittite."]]},
  {num:4,words:[["O lou fanau mai foi,", "And as for thy nativity,"], ["o le aso na fanau ai oe na le taia lou pute,", "in the day thou wast born thy navel was not cut,"], ["e lei mulumuluina foi oe i le vai ia faamamāina ai oe;", "neither wast thou washed in water to supple thee;"], ["e lei faamasimaina oe i le masima,", "thou wast not salted at all,"], ["ma ua le auia lava oe.", "nor swaddled at all."]]},
  {num:5,words:[["E leai se na ia alofa ia te oe e fai ai se tasi o ia mea ia te oe,", "None eye pitied thee, to do any of these unto thee,"], ["e agalelei ia te oe;", "to have compassion upon thee;"], ["a e peitai na lafoaiina oe i le fogāeleele,", "but thou wast cast out in the open field,"], ["na inosia ai oe i le aso na fanau ai oe.", "to the lothing of thy person, in the day that thou wast born."]]},
  {num:6,words:[["Na ou ui ane i le mea sa e i ai,", "And when I passed by thee,"], ["na ou iloa foi oe o taatia i lou toto,", "and saw thee polluted in thine own blood,"], ["ona ou fai atu ai lea ia te oe ina ua e i lou toto,", "I said unto thee when thou wast in thy blood, Live;"], ["Ola ia;", "yea,"], ["na ou fai atu lava ia te oe ina ua e i lou toto,", "I said unto thee when thou wast in thy blood,"], ["Ola ia.", "Live."]]},
  {num:7,words:[["Na ou faatoateleina oe e pei o moemoe o le vao,", "I have caused thee to multiply as the bud of the field,"], ["na e tupu lava ua matua,", "and thou hast increased and waxen great,"], ["ma ua e matuā lalelei lava;", "and thou art come to excellent ornaments:"], ["ua popona ou susu,", "thy breasts are fashioned,"], ["ua tupu ou fulufulu,", "and thine hair is grown,"], ["a o oe sa le ufitia ma le lavalavā.", "whereas thou wast naked and bare."]]},
  {num:8,words:[["Na ou ui ane i le mea sa e i ai,", "Now when I passed by thee,"], ["ma ou vaai ia te oe,", "and looked upon thee,"], ["faauta,", "behold,"], ["o lou tausaga,", "thy time was the time of love;"], ["o le tausaga o le alofa lea,", "and I spread my skirt over thee, and covered thy nakedness:"], ["ona ou faaafu lea ia te oe i lo'u pito ofu e ufitia ai lou le lavalavā;", "yea,"], ["na ou tauto foi ia te oe,", "I sware unto thee,"], ["ma ta osia le feagaiga ma'u,", "and entered into a covenant with thee,"], ["ona fai ai lea oe mo'u,", "saith the Lord GOD,"], ["ua fetalai mai ai le Alii o Ieova.", "and thou becamest mine."]]},
  {num:9,words:[["Na ou mulumulu ia te oe i le vai,", "Then washed I thee with water; yea,"], ["ma ou faamamāina ou toto sa ia te oe ma ou uu ia te oe i le suāuu.", "I throughly washed away thy blood from thee, and I anointed thee with oil."]]},
  {num:10,words:[["Na ou faaofuina oe i le ofu lanu eseese,", "I clothed thee also with broidered work,"], ["ma ou faaseeina oe i le pa'u takesa,", "and shod thee with badgers' skin,"], ["ma ou fusi ia te oe i le ie vavae,", "and I girded thee about with fine linen,"], ["ma ou ufiufi ia te oe i le silika.", "and I covered thee with silk."]]},
  {num:11,words:[["Na ou teu foi ia te oe i mea e matagofie a'i,", "I decked thee also with ornaments,"], ["ma ou avane taulima i ou lima,", "and I put bracelets upon thy hands,"], ["ma le asoa i lou ua.", "and a chain on thy neck."]]},
  {num:12,words:[["Na ou avane foi le mama i lou isu,", "And I put a jewel on thy forehead,"], ["ma mama taliga i ou taliga,", "and earrings in thine ears,"], ["ma le pale lalelei i lou ulu.", "and a beautiful crown upon thine head."]]},
  {num:13,words:[["Na teua lava oe i auro ma ario;", "Thus wast thou decked with gold and silver;"], ["o ou ofu foi,", "and thy raiment was of fine linen,"], ["o le ie vavae,", "and silk,"], ["ma le silika,", "and broidered work;"], ["ma le ie lanu eseese; o le falaoa lelei foi,", "thou didst eat fine flour,"], ["ma le meli,", "and honey,"], ["ma le uu na e 'ai ai;", "and oil:"], ["na matuā lalelei lava oe,", "and thou wast exceeding beautiful,"], ["na manuia foi oe na fai ma malo.", "and thou didst prosper into a kingdom."]]},
  {num:14,words:[["Na oo atu foi i nuu ese le logo o lou lalelei;", "And thy renown went forth among the heathen for thy beauty:"], ["auā sa atoa lea i lou matagofie na ou tuuina atu ai ia te oe,", "for it was perfect through my comeliness, which I had put upon thee,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:15,words:[["A e peitai na e faatuatua i lou lalelei,", "But thou didst trust in thine own beauty,"], ["ma e mulilua ona o lou logo,", "and playedst the harlot because of thy renown,"], ["ma sasaa atu au muliluaga ia te i latou uma na ui ane;", "and pouredst out thy fornications on every one that passed by;"], ["na fai ia mo i latou.", "his it was."]]},
  {num:16,words:[["Na e avea foi ni ou ofu ma teteuina ai au mea maualuluga lanu eseese,", "And of thy garments thou didst take,"], ["ma e talitane ai;", "and deckedst thy high places with divers colours,"], ["e lei oo mea faapea ,", "and playedst the harlot thereupon: the like things shall not come,"], ["i le e le faia lava.", "neither shall it be so."]]},
  {num:17,words:[["Ua e avea foi au mea matagofie na fai i a'u auro,", "Thou hast also taken thy fair jewels of my gold and of my silver,"], ["ma a'u ario na ou avatu ia te oe,", "which I had given thee,"], ["ma ua e faia faatusa o tane ma oe,", "and madest to thyself images of men,"], ["ma talitane ia i latou.", "and didst commit whoredom with them,"]]},
  {num:18,words:[["Ua e avea foi ou ofu lanu eseese,", "And tookest thy broidered garments,"], ["ma faaofu a'i i latou,", "and coveredst them:"], ["ma ua e tuuina atu o'u uu ma a'u mea manogi i luma ia te i latou.", "and thou hast set mine oil and mine incense before them."]]},
  {num:19,words:[["O a'u mea e 'ai foi na ou foai atu ia te oe,", "My meat also which I gave thee,"], ["o falaoa lelei,", "fine flour, and oil,"], ["ma uu,", "and honey,"], ["ma meli na ou fagaina ai oe,", "wherewith I fed thee,"], ["ua e laulauina foi i o latou luma e fai a'i se mea manogi lelei. Sa faapea lava,", "thou hast even set it before them for a sweet savour: and thus it was,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:20,words:[["Ua e avea foi au tama tane,", "Moreover thou hast taken thy sons and thy daughters,"], ["ma au tama teine na e fanau mai ia te au,", "whom thou hast borne unto me,"], ["ma ua e fai i latou ma taulaga ia te i latou ina ia faaumatia ai.", "and these hast thou sacrificed unto them to be devoured."], ["O le mea māmā ea lea i lou talitane, ina ua e fasioti i la'u fanau;", "Is this of thy whoredoms a small matter,"]]},
  {num:21,words:[["ma ua e tuuina atu i latou ia faaui ane i latou i le afi mo i latou?", "That thou hast slain my children, and delivered them to cause them to pass through the fire for them?"]]},
  {num:22,words:[["O au mea e inosia uma ma lou talitane uma, na e le manatua ona aso a o te teine itiiti,", "And in all thine abominations and thy whoredoms thou hast not remembered the days of thy youth,"], ["ina ua le ufitia ai oe,", "when thou wast naked and bare,"], ["ma ua le lavalavā, ma ua taatia i lou toto.", "and wast polluted in thy blood."]]},
  {num:23,words:[["Ua uma foi ona e fai o au amio leaga uma,", "And it came to pass after all thy wickedness,"], ["(Oi talofa,", "(woe,"], ["oi talofa ia te oe! o loo fetalai mai ai le Alii o Ieova;", "woe unto thee! saith the Lord GOD;"], [")", ")"]]},
  {num:24,words:[["ona e fai ai lea mo oe o le fale taā,", "That thou hast also built unto thee an eminent place,"], ["ma ua e fai mea maualuluga i malae uma.", "and hast made thee an high place in every street."]]},
  {num:25,words:[["Ua e fai au mea maualuluga i tuluiga o ala uma,", "Thou hast built thy high place at every head of the way,"], ["ua e faainosia lou lalelei,", "and hast made thy beauty to be abhorred,"], ["ua talia foi i latou uma na ui ane ai,", "and hast opened thy feet to every one that passed by,"], ["ma ua e faateleina lava lou talitane.", "and multiplied thy whoredoms."]]},
  {num:26,words:[["Ua e mulilua i tagata Aikupito ua outou tuaoi,", "Thou hast also committed fornication with the Egyptians thy neighbours,"], ["o e tino latetele,", "great of flesh; and hast increased thy whoredoms,"], ["ma ua faateleina lou talitane e faaonoono mai ai ia te au.", "to provoke me to anger."]]},
  {num:27,words:[["Faauta foi,", "Behold,"], ["ua ou faaloaloa atu lo'u lima i luga ia te oe,", "therefore I have stretched out my hand over thee,"], ["ma ua ou faaitiitia au mea e 'ai e tatau mā oe,", "and have diminished thine ordinary food, and delivered thee unto the will of them that hate thee,"], ["ua ou tuuina atu foi oe i le pule a e ua 'ino'ino ia te oe,", "the daughters of the Philistines,"], ["o afafine ia o Filisitia o e ua mamā i au amio ulavale.", "which are ashamed of thy lewd way."]]},
  {num:28,words:[["Ua e talitane foi i tagata Asuria ina ua e le mălie lava,", "Thou hast played the whore also with the Assyrians, because thou wast unsatiable;"], ["ua e talitane lava ia te i latou,", "yea,"], ["a e te le āu mălie lava.", "thou hast played the harlot with them, and yet couldest not be satisfied."]]},
  {num:29,words:[["Ua e faateleina foi lou talitane i le nuu o Kanana ua oo i Kaletaia,", "Thou hast moreover multiplied thy fornication in the land of Canaan unto Chaldea;"], ["a ua e le mălie ai lava.", "and yet thou wast not satisfied herewith."]]},
  {num:30,words:[["Ua faapea ona vaivai o lou loto! o loo fetalai mai ai le Alii o Ieova,", "How weak is thine heart,"], ["ina ua e faia o ia mea uma,", "saith the Lord GOD, seeing thou doest all these things,"], ["o mea lava ua fai e le fafine talitane ma le faamatāitu;", "the work of an imperious whorish woman;"]]},
  {num:31,words:[["ina ua e fai lou fale taā i tuluiga o ala uma,", "In that thou buildest thine eminent place in the head of every way,"], ["ma ua e fai au mea maualuluga i malae uma,", "and makest thine high place in every street; and hast not been as an harlot,"], ["mona ua e le faapei o se talitane le ua tetee i le totogi;", "in that thou scornest hire;"]]},
  {num:32,words:[["a e pei o le avā ua mulilua,", "But as a wife that committeth adultery,"], ["o lē talia tane ese a e tuu lana lava tane.", "which taketh strangers instead of her husband!"]]},
  {num:33,words:[["E avatua totogi i fafine talitane uma,", "They give gifts to all whores:"], ["a o oe ua e foai atu au totogi ia te i latou uma o e mananao ia te oe,", "but thou givest thy gifts to all thy lovers, and hirest them,"], ["ma ua e taui ia te i latou ia latou o ane ia te oe mai itu uma ona o au muliluaga.", "that they may come unto thee on every side for thy whoredom."]]},
  {num:34,words:[["Ua ese lava oe i nisi fafine i lou talitane,", "And the contrary is in thee from other women in thy whoredoms,"], ["ina ua leai se mulimuli atu ia te oe e faitaaga ai;", "whereas none followeth thee to commit whoredoms:"], ["ma ua e avatu se totogi,", "and in that thou givest a reward,"], ["a e leai se totogi e avane ia te oe;", "and no reward is given unto thee,"], ["o le mea lea ua ese ai oe.", "therefore thou art contrary."]]},
  {num:35,words:[["O le mea lea,", "Wherefore,"], ["le fafine talitane e,", "O harlot,"], ["ia e faalogo mai ai i le afioga a Ieova.", "hear the word of the LORD:"]]},
  {num:36,words:[["O loo faapea ona fetalai mai o le Alii o Ieova;", "Thus saith the Lord GOD;"], ["ua e sasaa atu au tupe,", "Because thy filthiness was poured out,"], ["ma ua faaalia lou tino i lou talitane ua fai ma ē ua e manao i ai,", "and thy nakedness discovered through thy whoredoms with thy lovers,"], ["atoa ma au tupua uma e inosia,", "and with all the idols of thy abominations,"], ["ma le toto o au fanau,", "and by the blood of thy children,"], ["na e avatu ia te i latou;", "which thou didst give unto them;"]]},
  {num:37,words:[["faauta,", "Behold,"], ["o le mea lea ou te faapotopotoina ai i latou uma ua e manao i ai,", "therefore I will gather all thy lovers,"], ["o i latou ua e fiafia i ai,", "with whom thou hast taken pleasure,"], ["ma i latou uma ua e naunau i ai,", "and all them that thou hast loved,"], ["atoa ma i latou uma ua e 'ino'ino i ai;", "with all them that thou hast hated;"], ["ou te faapotopotoina lava i latou ia te oe mai itu uma ia leaga ai oe,", "I will even gather them round about against thee,"], ["ma ou faaalia ia te i latou lou tino,", "and will discover thy nakedness unto them,"], ["ina ia latou iloa lou tino uma.", "that they may see all thy nakedness."]]},
  {num:38,words:[["Ou te faasala foi ia te oe,", "And I will judge thee,"], ["e pei ona faasalaina o fafine mulilulua, ma e ua faamaligi toto,", "as women that break wedlock and shed blood are judged;"], ["ma ou avatu ia te oe le toto i le ita tele ma le fuā.", "and I will give thee blood in fury and jealousy."]]},
  {num:39,words:[["Ou te tuuina atu foi oe i o latou lima,", "And I will also give thee into their hand,"], ["latou te lepetia lou fale taā,", "and they shall throw down thine eminent place,"], ["ma lafo i lalo au mea maualuluga;", "and shall break down thy high places:"], ["latou te toeseina foi ou ofu,", "they shall strip thee also of thy clothes,"], ["ma ave au mea matagofie,", "and shall take thy fair jewels,"], ["latou te tuua oe e le ufiufitia ma le le lavalavā.", "and leave thee naked and bare."]]},
  {num:40,words:[["Latou te ta'ita'iina ae le motu o tagata ia te oe,", "They shall also bring up a company against thee,"], ["latou te fetogi ia te oe i maa,", "and they shall stone thee with stones,"], ["ma latou fasiotia oe i a latou pelu.", "and thrust thee through with their swords."]]},
  {num:41,words:[["Latou te susunu foi ou fale i le afi,", "And they shall burn thine houses with fire,"], ["latou te faasalaina foi oe i luma o fafine e toatele;", "and execute judgments upon thee in the sight of many women:"], ["ou te faagataina lou talitane,", "and I will cause thee to cease from playing the harlot,"], ["e te le toe avatu lava se totogi.", "and thou also shalt give no hire any more."]]},
  {num:42,words:[["Ou te faaiuina ai lo'u ita tele ia te oe,", "So will I make my fury toward thee to rest,"], ["ona mavae ai lea o lo'u fuā ia te oe;", "and my jealousy shall depart from thee,"], ["ona ou filemu ai lea,", "and I will be quiet,"], ["ma ou le toe ita lava.", "and will be no more angry."]]},
  {num:43,words:[["Ua e le manatua aso ina o e teine itiiti,", "Because thou hast not remembered the days of thy youth,"], ["a ua e faaonoono mai ia te au i ia mea uma;", "but hast fretted me in all these things;"], ["faauta,", "behold, therefore I also will recompense thy way upon thine head,"], ["o le mea lea ou te taui atu ai lau amio i luga o lou ulu o loo fetalai mai ai le Alii o Ieova,", "saith the Lord GOD:"], ["e le toe fai lea mea leaga e faaopoopo i au mea uma e inosia.", "and thou shalt not commit this lewdness above all thine abominations."]]},
  {num:44,words:[["Faauta,", "Behold,"], ["o i latou uma o e fai upu faatusa latou te fai le faatusa ia te oe,", "every one that useth proverbs shall use this proverb against thee,"], ["e faapea ane,", "saying, As is the mother,"], ["E pei o le tinā lana tama.", "so is her daughter."]]},
  {num:45,words:[["O le tama oe a lou tinā,", "Thou art thy mother's daughter,"], ["o le na 'ino'ino i lana tane ma lana fanau;", "that lotheth her husband and her children;"], ["o le uso foi oe o ou uso o e na 'ino'ino i a latou tane ma a latou fanau;", "and thou art the sister of thy sisters, which lothed their husbands and their children:"], ["o lo outou tinā o lo sa Hetī,", "your mother was an Hittite,"], ["o lo outou tamā o lo sa Amorī.", "and your father an Amorite."]]},
  {num:46,words:[["O lou uso e matua,", "And thine elder sister is Samaria,"], ["o Samaria lea,", "she and her daughters that dwell at thy left hand:"], ["o ia ma ana tama fafine ua nofo i lou itu tauagavale;", "and thy younger sister,"], ["ma lou uso itiiti o lē nofo i lou itu taumatau,", "that dwelleth at thy right hand,"], ["o Sotoma lea ma ana tama.", "is Sodom and her daughters."]]},
  {num:47,words:[["A ua e le savali i o latou ala,", "Yet hast thou not walked after their ways,"], ["ua e le fai foi e tusa ma a latou mea e inosia,", "nor done after their abominations:"], ["a ua e 'ino'ino i lea e peiseai se mea itiiti,", "but, as if that were a very little thing,"], ["e sili lava ona leaga o au amio uma i a latou.", "thou wast corrupted more than they in all thy ways."]]},
  {num:48,words:[["Ua fetalai mai le Alii o Ieova,", "As I live,"], ["O loo ola a'u,", "saith the Lord GOD,"], ["e lei faia e Sotoma lou uso,", "Sodom thy sister hath not done, she nor her daughters,"], ["o ia ma ana tama,", "as thou hast done,"], ["e pei ona faia e oe ma au tama.", "thou and thy daughters."]]},
  {num:49,words:[["Faauta,", "Behold,"], ["o le agasala nei a lou uso o Sotoma, na ia te ia ma ana tama,", "this was the iniquity of thy sister Sodom,"], ["o le faamaualuga,", "pride,"], ["o le tele o mea e 'ai,", "fulness of bread,"], ["ma le matuā nofonofo faatalanoa, na ia le fesoasoani foi i lē puapuaga,", "and abundance of idleness was in her and in her daughters,"], ["ma lē mativa.", "neither did she strengthen the hand of the poor and needy."]]},
  {num:50,words:[["Sa latou faamaualuluga,", "And they were haughty,"], ["ma fai mea e inosia i o'u luma;", "and committed abomination before me:"], ["o le mea lea na ou aveeseina ai i latou e tusa ma mea na ou iloa.", "therefore I took them away as I saw good."]]},
  {num:51,words:[["E lei faia e Samaria le vaeluagalemu o au agasala;", "Neither hath Samaria committed half of thy sins;"], ["a ua e faateleina au mea e inosia, ua sili lava ia te i latou;", "but thou hast multiplied thine abominations more than they,"], ["o au mea e inosia uma ua e faia ua ta'uamiotonuina ai ou uso.", "and hast justified thy sisters in all thine abominations which thou hast done."]]},
  {num:52,words:[["O oe foi o le ua faasalaina atu ou uso,", "Thou also,"], ["ia ia te oe lou lava mā ona o au agasala uma ua e fai,", "which hast judged thy sisters, bear thine own shame for thy sins that thou hast committed more abominable than they:"], ["e sili ona leaga i ā latou;", "they are more righteous than thou:"], ["e sili ona amiotonu i latou ia te oe;", "yea,"], ["o oe foi ia e masiasi,", "be thou confounded also, and bear thy shame,"], ["ma ia ia te oe lou mā ina ua e ta'uamiotonuina ou uso.", "in that thou hast justified thy sisters."]]},
  {num:53,words:[["Ou te faafoisia la latou tafeaga,", "When I shall bring again their captivity,"], ["o le tafeaga foi a Sotoma ma ana tama,", "the captivity of Sodom and her daughters,"], ["ma le tafeaga a Samaria ma ana tama;", "and the captivity of Samaria and her daughters,"], ["atoa ma le tafeaga a lou nuu ua tafea e faatasi ma i latou;", "then will I bring again the captivity of thy captives in the midst of them:"]]},
  {num:54,words:[["ina ia e mā lava,", "That thou mayest bear thine own shame,"], ["ma ia e masiasi,", "and mayest be confounded in all that thou hast done,"], ["ona o mea uma ua e faia i lou faamafanafana atu ia te i latou.", "in that thou art a comfort unto them."]]},
  {num:55,words:[["E toe foi ou uso o Sotoma ma ana tama i ona tuga tuai,", "When thy sisters, Sodom and her daughters,"], ["o Samaria foi ma ana tama e toe foi i ona tuga tuai i latou;", "shall return to their former estate,"], ["o oe foi ma au tama e toe foi outou i ona tuga tuai.", "and Samaria and her daughters shall return to their former estate, then thou and thy daughters shall return to your former estate."]]},
  {num:56,words:[["A e lei ta'ua lou uso o Sotoma i lou gutu i ona po o lou faamaualuga,", "For thy sister Sodom was not mentioned by thy mouth in the day of thy pride,"]]},
  {num:57,words:[["a o lei faaalia lau amio leaga,", "Before thy wickedness was discovered,"], ["e pei o ona po na faifaia ai oe e tama fafine a Suria,", "as at the time of thy reproach of the daughters of Syria,"], ["atoa ma i latou i ona itu uma,", "and all that are round about her,"], ["o afafine o Filisitia,", "the daughters of the Philistines,"], ["o e na 'ino'ino ia te oe i itu uma.", "which despise thee round about."]]},
  {num:58,words:[["O lau amio leaga ma au mea e inosia ua tauia ia te oe,", "Thou hast borne thy lewdness and thine abominations,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:59,words:[["Auā ua faapea ona fetalai mai o le Alii o Ieova,", "For thus saith the Lord GOD;"], ["Ou te fai lava ia te oe e pei ona e faia,", "I will even deal with thee as thou hast done,"], ["ua e faaleaogaina le tauto i lou soli o le feagaiga.", "which hast despised the oath in breaking the covenant."]]},
  {num:60,words:[["A e ou te manatua la ta feagaiga ma a'u i ona po ina o e teine itiiti,", "Nevertheless I will remember my covenant with thee in the days of thy youth,"], ["ou te faatumauina foi ia te oe le feagaiga e faavavau.", "and I will establish unto thee an everlasting covenant."]]},
  {num:61,words:[["Ona e manatua ai lea au amio,", "Then thou shalt remember thy ways, and be ashamed,"], ["ona e masiasi ai lea pe a e talia ou uso o e matutua ia te oe atoa ma e iti ia te oe;", "when thou shalt receive thy sisters,"], ["ou te avatua foi i latou ia te oe e fai ma au tama,", "thine elder and thy younger:"], ["a e le o lau feagaiga e ala ai.", "and I will give them unto thee for daughters, but not by thy covenant."]]},
  {num:62,words:[["Ou te faatumauina foi la ta feagaiga ma oe;", "And I will establish my covenant with thee;"], ["e te iloa ai o a'u lava o Ieova;", "and thou shalt know that I am the LORD:"]]},
  {num:63,words:[["ina ia e manatunatu,", "That thou mayest remember,"], ["ma ia e mā,", "and be confounded,"], ["ma ia le toe tautala lava ona o lou masiasi,", "and never open thy mouth any more because of thy shame,"], ["pe a ou faamagalo atu ia te oe i mea uma ua e faia,", "when I am pacified toward thee for all that thou hast done,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
];
renderVerseSet(ezk_ch_16_Verses, 'ezk-ch16-verses');

var ezk_ch_17_Verses = [
  {num:1,words:[["Ua oo mai le afioga a Ieova ia te au,", "And the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia e fai atu se tupua, ma sauni atu se faataoto i le aiga o Isaraelu;", "put forth a riddle,"], ["ia faapea atu,", "and speak a parable unto the house of Israel;"]]},
  {num:3,words:[["O loo faapea ona fetalai mai o le Alii o Ieova,", "And say,"], ["O le aeto tele,", "Thus saith the Lord GOD;"], ["ua tetele ona apaau,", "A great eagle with great wings,"], ["ma fulu apaau uumi,", "longwinged,"], ["ua uluulu ona fulufulu,", "full of feathers,"], ["ma pulepule,", "which had divers colours,"], ["na sau i Lepanona,", "came unto Lebanon,"], ["ma na ave le moemoe o le arasi.", "and took the highest branch of the cedar:"]]},
  {num:4,words:[["Na ia fati le tumutumu o ona moemoe,", "He cropped off the top of his young twigs,"], ["ma na avea i le nuu faatauoa;", "and carried it into a land of traffick;"], ["ua ia tuu ai i le aai o tagata faatauoa.", "he set it in a city of merchants."]]},
  {num:5,words:[["Na ia ave foi nisi fatu o le nuu,", "He took also of the seed of the land,"], ["mana totōina ai i le fanua lafulemu,", "and planted it in a fruitful field;"], ["ua ia tuuina i tafatafa o le vai tele,", "he placed it by great waters,"], ["ua tuu ai e pei o se sapasapa.", "and set it as a willow tree."]]},
  {num:6,words:[["Ua tupu foi,", "And it grew,"], ["ma ua avea ma vine sosolo,", "and became a spreading vine of low stature,"], ["ua maulalo lona tumutumu,", "whose branches turned toward him,"], ["ua sasau ane ona la ia te ia, ua i ai foi ona aa i lalo ia te ia;", "and the roots thereof were under him:"], ["ua avea ma vine,", "so it became a vine,"], ["ua tutupu ai la,", "and brought forth branches,"], ["ma matala mai ona lau.", "and shot forth sprigs."]]},
  {num:7,words:[["Na i ai foi le tasi aeto tele,", "There was also another great eagle with great wings and many feathers:"], ["ua tetele ona apaau,", "and,"], ["e tele foi ona fulufulu; faauta foi,", "behold,"], ["o lea vine ua sosolo atu ona aa ia te ia,", "this vine did bend her roots toward him,"], ["ua sasau atu foi ona la ia te ia,", "and shot forth her branches toward him,"], ["ia na faasūsū i ai i utu o lana faatoaga.", "that he might water it by the furrows of her plantation."]]},
  {num:8,words:[["Na totōina i le fanua lelei e lata ane i le vai tele,", "It was planted in a good soil by great waters,"], ["ina ia tutupu ona la,", "that it might bring forth branches,"], ["ma ia fua mai,", "and that it might bear fruit,"], ["ia fai foi ia ma vine tele.", "that it might be a goodly vine."]]},
  {num:9,words:[["Ia e fai atu,", "Say thou,"], ["o loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["E manuia ea ia? E le liaiina ea e ia ona aa, ma salaesea ona fua,", "Shall it prosper? shall he not pull up the roots thereof,"], ["ina ia mago ai? E mago lau uma lava i ona la laau,", "and cut off the fruit thereof,"], ["a e le o le lima malosi,", "that it wither? it shall wither in all the leaves of her spring,"], ["po o tagata e toatele e liaiina ai ona aa.", "even without great power or many people to pluck it up by the roots thereof."]]},
  {num:10,words:[["Faauta foi,", "Yea, behold,"], ["e manuia ea ia ina ua totōina? E le matuā mago ea pe a agi mai i ai le matagi mai sasae? E mago lava i utu na ia tupu ai.", "being planted, shall it prosper? shall it not utterly wither, when the east wind toucheth it? it shall wither in the furrows where it grew."]]},
  {num:11,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "Moreover the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:12,words:[["Ina fai atu ia i le aiga fouvale,", "Say now to the rebellious house,"], ["Ua outou le iloa ea le uiga o ia mea? fai atu ia,", "Know ye not what these things mean? tell them,"], ["Faauta,", "Behold,"], ["na sau le tupu o Papelonia i Ierusalema,", "the king of Babylon is come to Jerusalem,"], ["na ia avea lona tupu,", "and hath taken the king thereof,"], ["ma ona alii,", "and the princes thereof,"], ["na ia ave ia te i latou faatasi ma ia i Papelonia;", "and led them with him to Babylon;"]]},
  {num:13,words:[["na ia ave foi le tasi o le fanau a le tupu,", "And hath taken of the king's seed,"], ["ma osia le feagaiga ma ia,", "and made a covenant with him,"], ["ma fai atu ia te ia ia tauto;", "and hath taken an oath of him:"], ["na ia avea foi alii sili o le nuu;", "he hath also taken the mighty of the land:"]]},
  {num:14,words:[["ina ia fai ma malo faatauvaa,", "That the kingdom might be base,"], ["ia le toe faamaualuga o ia,", "that it might not lift itself up,"], ["a ia tumau pe a anaana i lana feagaiga.", "but that by keeping of his covenant it might stand."]]},
  {num:15,words:[["A ua ia fouvale ia te ia i lona aauina atu o lana sāvali i Aikupito ina ia tuu mai ia te ia o solofanua ma tagata e toatele.", "But he rebelled against him in sending his ambassadors into Egypt, that they might give him horses and much people."], ["E manuia ea ia? E sao ea lē fai mea faapea? E soli ea e ia le feagaiga a e faasaoina?", "Shall he prosper? shall he escape that doeth such things? or shall he break the covenant, and be delivered?"]]},
  {num:16,words:[["Ua fetalai mai le Alii o Ieova,", "As I live,"], ["O loo ola a'u,", "saith the Lord GOD,"], ["e moni, o le mea o i ai le tupu na tofia o ia ma tupu,", "surely in the place where the king dwelleth that made him king,"], ["e ana le tautoga na ia faaleaoga i ai,", "whose oath he despised,"], ["e ana foi le feagaiga na ia solia,", "and whose covenant he brake,"], ["e oti o ia i Papelonia i le mea o i ai o ia.", "even with him in the midst of Babylon he shall die."]]},
  {num:17,words:[["O Farao foi,", "Neither shall Pharaoh with his mighty army and great company make for him in the war,"], ["ma lana itu taua e toatele,", "by casting up mounts,"], ["ma ana 'au e tele, e le aoga ia ia te ia i le taua i le tanu o mea mautietie,", "and building forts,"], ["ma le faiga o 'olo e faaumatia ai tagata e toatele.", "to cut off many persons:"]]},
  {num:18,words:[["Ua ia faaleaoga le tauto i lona soli o le feagaiga;", "Seeing he despised the oath by breaking the covenant,"], ["faauta foi,", "when,"], ["na ia avatu lava lona lima,", "lo, he had given his hand,"], ["ua ia faia ia mea uma,", "and hath done all these things,"], ["na te le sao lava.", "he shall not escape."]]},
  {num:19,words:[["O le mea lea ua faapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["O loo ola a'u,", "As I live,"], ["e moni, o le tauto i lo'u igoa ua ia faaleaogaina,", "surely mine oath that he hath despised,"], ["ma la'u feagaiga ua ia solia,", "and my covenant that he hath broken,"], ["ou te matuā taui atu ai i lona ulu.", "even it will I recompense upon his own head."]]},
  {num:20,words:[["Ou te folasia la'u upega ia te ia,", "And I will spread my net upon him,"], ["e lāvea o ia i la'u mailei,", "and he shall be taken in my snare,"], ["ou te ave foi ia te ia i Papelonia, ma ou faasalaina o ia i lea mea,", "and I will bring him to Babylon,"], ["ona o lana agasala ua ia agasala mai ai ia te au.", "and will plead with him there for his trespass that he hath trespassed against me."]]},
  {num:21,words:[["O ona tagata uma e sosola,", "And all his fugitives with all his bands shall fall by the sword,"], ["ma ana 'au uma e oti i latou i le pelu; e faataapeapeina foi e o totoe i matāmatagi uma,", "and they that remain shall be scattered toward all winds:"], ["tou te iloa ai o a'u lava o Ieova ua ou fai atu ai.", "and ye shall know that I the LORD have spoken it."]]},
  {num:22,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Ou te ave e a'u le moemoe o le arasi maualuga,", "I will also take of the highest branch of the high cedar,"], ["ma ou totōina;", "and will set it;"], ["ou te fati foi se mea mu'amu'a ai le tumutumu o ona moemoe,", "I will crop off from the top of his young twigs a tender one,"], ["ma ou totōina i le mauga e sili ona maualuga.", "and will plant it upon an high mountain and eminent:"]]},
  {num:23,words:[["O le mauga maualuga o Isaraelu ou te totōina ai;", "In the mountain of the height of Israel will I plant it:"], ["e tutupu ai la,", "and it shall bring forth boughs,"], ["ma fua mai,", "and bear fruit,"], ["e avea foi ma arasi tele;", "and be a goodly cedar:"], ["e i ona lalo ifo o manu felelei uma e uiga eseese,", "and under it shall dwell all fowl of every wing;"], ["latou te aofaga i le paolo o ona la.", "in the shadow of the branches thereof shall they dwell."]]},
  {num:24,words:[["E iloa ai laau uma o le vao, o a'u o Ieova,", "And all the trees of the field shall know that I the LORD have brought down the high tree,"], ["ua ou faamaulaloina le laau maualuga,", "have exalted the low tree,"], ["ma ou faamaualugaina le laau maulalo, ua ou faamagoina le laau mata,", "have dried up the green tree,"], ["ma ou faalauolaolaina le laau na mago. O a'u o Ieova,", "and have made the dry tree to flourish:"], ["na ou fai atu, ma ou faia lava.", "I the LORD have spoken and have done it."]]},
];
renderVerseSet(ezk_ch_17_Verses, 'ezk-ch17-verses');

var ezk_ch_18_Verses = [
  {num:1,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "The word of the LORD came unto me again,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Se a le mea ua outou fai ai lenei faatusa i le laueleele o Isaraelu,", "What mean ye,"], ["e faapea,", "that ye use this proverb concerning the land of Israel,"], ["Ua 'aina e tamā o vine moto,", "saying, The fathers have eaten sour grapes,"], ["a e magiagia ai nifo o le fanau?", "and the children's teeth are set on edge?"]]},
  {num:3,words:[["O loo ola a'u,", "As I live,"], ["o loo fetalai mai le Alii o Ieova,", "saith the Lord GOD,"], ["e le toe fai lava e outou lena faatusa i Isaraelu.", "ye shall not have occasion any more to use this proverb in Israel."]]},
  {num:4,words:[["Faauta,", "Behold,"], ["o agaga uma,", "all souls are mine;"], ["o o'u lava i latou;", "as the soul of the father,"], ["e pei o le agaga o le tamā ona fai mo'u,", "so also the soul of the son is mine:"], ["e faapea foi le agaga o le atalii;", "the soul that sinneth,"], ["o le agaga e agasala e oti ia.", "it shall die."]]},
  {num:5,words:[["A e afai e amiotonu le tagata, ma ua faia e ia le amio e tatau,", "But if a man be just,"], ["ma le amiotonu,", "and do that which is lawful and right,"]]},
  {num:6,words:[["ua ia le 'ai i luga o mauga,", "And hath not eaten upon the mountains,"], ["ua ia le tepa ae i tupua o le aiga o Isaraelu,", "neither hath lifted up his eyes to the idols of the house of Israel,"], ["ua ia le faaleagaina le avā a le tasi tagata,", "neither hath defiled his neighbour's wife,"], ["ua ia le faalatalata ane i se fafine o loo ona o faia le ma'i,", "neither hath come near to a menstruous woman,"]]},
  {num:7,words:[["ua ia le faasaua i se tasi,", "And hath not oppressed any,"], ["ua ia toe avatu le mea na tuu faafaatau e le ua aitalafu ia te ia,", "but hath restored to the debtor his pledge,"], ["ua ia le fao se mea a se tasi,", "hath spoiled none by violence,"], ["ua avatu ana mea e 'ai i le ua fia 'ai,", "hath given his bread to the hungry,"], ["ua faaofuina foi le ua le lavalavā;", "and hath covered the naked with a garment;"]]},
  {num:8,words:[["e lei avatu se mea e au mai ai se totogi faasili,", "He that hath not given forth upon usury,"], ["e lei talia se mea e faasili,", "neither hath taken any increase,"], ["ua faafoi lona lima ai le amioletonu,", "that hath withdrawn his hand from iniquity,"], ["ma ua ai faamasinoga tonu i lea tagata ma lea tagata,", "hath executed true judgment between man and man,"]]},
  {num:9,words:[["ua ia savali i a'u tulafono,", "Hath walked in my statutes,"], ["ua anaana i a'u faamasinoga;", "and hath kept my judgments,"], ["e faia ma le faamaoni,", "to deal truly;"], ["ua amiotonu o ia;", "he is just,"], ["e ola lava ia,", "he shall surely live,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:10,words:[["Afai e fanaua e ia se atalii e saua,", "If he beget a son that is a robber,"], ["ma le faamaligi toto,", "a shedder of blood,"], ["ma ua faia se tasi o ia mea,", "and that doeth the like to any one of these things,"]]},
  {num:11,words:[["ua ia le faia foi ia mea tatau uma,", "And that doeth not any of those duties,"], ["a ua 'ai i luga o mauga,", "but even hath eaten upon the mountains,"], ["ma ua faaleagaina le avā a le tasi tagata,", "and defiled his neighbour's wife,"]]},
  {num:12,words:[["ua ia faasaua i le ua puapuaga ma le ua mativa,", "Hath oppressed the poor and needy,"], ["ua ia fao mea,", "hath spoiled by violence,"], ["e lei toe avatu le mea na tuu faafaatau,", "hath not restored the pledge,"], ["ua tepa ae i tupua,", "and hath lifted up his eyes to the idols,"], ["ma ua fai mea e inosia,", "hath committed abomination,"]]},
  {num:13,words:[["ua ia avatu mea e au mai ai se totogi faasili,", "Hath given forth upon usury,"], ["ua ia talia foi mea e faasili,", "and hath taken increase:"], ["pe ola ea ia? E le ola lava;", "shall he then live? he shall not live:"], ["ua ia faia ia mea uma e inosia,", "he hath done all these abominations;"], ["e matuā oti lava o ia;", "he shall surely die;"], ["e ia te ia lava lona toto.", "his blood shall be upon him."]]},
  {num:14,words:[["Faauta foi,", "Now,"], ["a fanaua e ia sona atalii,", "lo,"], ["a vaai e ia i agasala uma e faia e lona tamā,", "if he beget a son, that seeth all his father's sins which he hath done,"], ["ma ua mafaufau,", "and considereth,"], ["ma ua le faia e ia mea faapea;", "and doeth not such like,"]]},
  {num:15,words:[["e lei 'ai i luga o mauga,", "That hath not eaten upon the mountains,"], ["e lei tepa ae i tupua o le aiga o Isaraelu,", "neither hath lifted up his eyes to the idols of the house of Israel,"], ["e lei faaleagaina le avā a le tasi tagata,", "hath not defiled his neighbour's wife,"]]},
  {num:16,words:[["e lei faasaua foi o ia i se tasi,", "Neither hath oppressed any,"], ["e lei taofia le mea na tuu faafaatau,", "hath not withholden the pledge,"], ["e lei faoa foi se mea,", "neither hath spoiled by violence,"], ["a ua foai atu ana mea e 'ai i le fia 'ai,", "but hath given his bread to the hungry,"], ["ma ua faaofuina e ia le ua le lavalavā,", "and hath covered the naked with a garment,"]]},
  {num:17,words:[["ua ia faafoi lona lima ai le ua puapuagatia,", "That hath taken off his hand from the poor,"], ["ua le talia se totogi faasili,", "that hath not received usury nor increase,"], ["po o se mea e faasili, ua usiusitai i a'u faamasinoga,", "hath executed my judgments,"], ["ma savali i a'u tulafono;", "hath walked in my statutes;"], ["e le oti o ia ona o le agasala a lona tamā,", "he shall not die for the iniquity of his father,"], ["a e ola lava ia.", "he shall surely live."]]},
  {num:18,words:[["A o lona tamā,", "As for his father,"], ["ona ua ia matuā faasaua,", "because he cruelly oppressed,"], ["ua ia faoa mea a le tasi tagata;", "spoiled his brother by violence,"], ["ma ua fai le mea e le lelei i lona nuu,", "and did that which is not good among his people,"], ["faauta,", "lo,"], ["e oti o ia i lana agasala.", "even he shall die in his iniquity."]]},
  {num:19,words:[["A ua outou fai mai,", "Yet say ye,"], ["E le tauia i se a i le atalii le agasala a le tamā? Afai e faia e le atalii le amio tatau ma le amiotonu,", "Why? doth not the son bear the iniquity of the father? When the son hath done that which is lawful and right,"], ["ua tausi i a'u tulafono uma,", "and hath kept all my statutes,"], ["ma ua faia,", "and hath done them,"], ["e ola lava ia.", "he shall surely live."]]},
  {num:20,words:[["O le agaga e agasala e oti lava ia;", "The soul that sinneth,"], ["e le tauia le agasala a le tamā i le atalii,", "it shall die. The son shall not bear the iniquity of the father,"], ["e le tauia foi le agasala a le atalii i le tamā;", "neither shall the father bear the iniquity of the son:"], ["o le amiotonu a le ua amiotonu e i ona luga lava lea,", "the righteousness of the righteous shall be upon him,"], ["o le amio leaga foi a le ua amio leaga e i ona luga lava lea.", "and the wickedness of the wicked shall be upon him."]]},
  {num:21,words:[["A e afai e liliu ese le ua amio leaga ai ana agasala uma ua na faia,", "But if the wicked will turn from all his sins that he hath committed,"], ["ma tausi i a'u tulafono uma,", "and keep all my statutes,"], ["ma faia e ia le amio tatau ma le amiotonu,", "and do that which is lawful and right,"], ["e ola lava ia,", "he shall surely live,"], ["e le oti.", "he shall not die."]]},
  {num:22,words:[["O ana solitulafono uma na ia faia e le ta'uta'ua ia te ia;", "All his transgressions that he hath committed,"], ["o lana amiotonu ua ia faia,", "they shall not be mentioned unto him:"], ["e ola ai o ia.", "in his righteousness that he hath done he shall live."]]},
  {num:23,words:[["O loo fetalai mai le Alii o Ieova,", "Have I any pleasure at all that the wicked should die? saith the Lord GOD: and not that he should return from his ways,"], ["Ou te fiafia ea i le oti o le ua amio leaga? ou te le fiafia ea pe a liliu ese i lona ala ia ola ai o ia?", "and live?"]]},
  {num:24,words:[["A e afai e liliu ese le ua amiotonu i lana amiotonu,", "But when the righteous turneth away from his righteousness,"], ["ma ua fai amio leaga,", "and committeth iniquity,"], ["ma ua fai e tusa ma mea uma e inosia e faia e le ua amio leaga,", "and doeth according to all the abominations that the wicked man doeth,"], ["e ola ea ia? O lana amiotonu uma na ia faia, e le manatua;", "shall he live? All his righteousness that he hath done shall not be mentioned:"], ["o lana agasala ua ia agasala ai,", "in his trespass that he hath trespassed,"], ["ma ona sese ua ia sese ai,", "and in his sin that he hath sinned,"], ["ona o ia mea e oti ai o ia.", "in them shall he die."]]},
  {num:25,words:[["A ua outou fai mai,", "Yet ye say,"], ["E le tusa le ala o le Alii. Ina faalogologo mai ia,", "The way of the Lord is not equal. Hear now,"], ["le aiga o Isaraelu e,", "O house of Israel;"], ["E le tusa ea lo'u ala? E le ua le tutusa ea o outou ala?", "Is not my way equal? are not your ways unequal?"]]},
  {num:26,words:[["A liliu ese le ua amiotonu i lana amio,", "When a righteous man turneth away from his righteousness,"], ["ma ua fai amio leaga,", "and committeth iniquity,"], ["ma oti ai;", "and dieth in them;"], ["o lana lava amio leaga ua ia fai e oti ai o ia.", "for his iniquity that he hath done shall he die."]]},
  {num:27,words:[["A liliu ese foi le ua amio leaga i lana amio leaga na ia faia,", "Again,"], ["ma ua fai le amio tatau ma le amiotonu,", "when the wicked man turneth away from his wickedness that he hath committed, and doeth that which is lawful and right,"], ["e faaolaina e ia lona agaga.", "he shall save his soul alive."]]},
  {num:28,words:[["Auā ua ia mafaufau,", "Because he considereth,"], ["ma liliu ese i lona solitulafono uma na ia faia,", "and turneth away from all his transgressions that he hath committed,"], ["e ola lava ia,", "he shall surely live,"], ["e le oti.", "he shall not die."]]},
  {num:29,words:[["A ua fai mai le aiga o Isaraelu,", "Yet saith the house of Israel,"], ["E le tusa le ala o le Alii. Le aiga o Isaraelu e,", "The way of the Lord is not equal. O house of Israel,"], ["e le tutusa ea o'u ala? E le ua le tutusa ea o outou ala?", "are not my ways equal? are not your ways unequal?"]]},
  {num:30,words:[["O le mea lea ou te faamasino ai ia te outou,", "Therefore I will judge you,"], ["le aiga o Isaraelu,", "O house of Israel,"], ["taitoatasi e tusa ma ona ala,", "every one according to his ways,"], ["o loo fetalai mai ai le Alii o Ieova. Liliu mai ia,", "saith the Lord GOD. Repent,"], ["ina liliu ese i o outou solitulafono uma;", "and turn yourselves from all your transgressions;"], ["ona le faia lea o le agasala ma mea e tausuai ai outou.", "so iniquity shall not be your ruin."]]},
  {num:31,words:[["Ina lafoai ia o outou solitulafono uma ua outou solitulafono ai,", "Cast away from you all your transgressions,"], ["ma ia fai mo outou se loto fou,", "whereby ye have transgressed;"], ["ma se agaga fou;", "and make you a new heart and a new spirit:"], ["auā pe se a ea le mea tou te fia oti ai,", "for why will ye die,"], ["le aiga o Isaraelu e?", "O house of Israel?"]]},
  {num:32,words:[["Auā ou te le fiafia lava i le oti o lē oti,", "For I have no pleasure in the death of him that dieth,"], ["o loo fetalai mai ai le Alii o Ieova;", "saith the Lord GOD:"], ["o lenei,", "wherefore turn yourselves,"], ["liliu mai ia outou tou te ola ai.", "and live ye."]]},
];
renderVerseSet(ezk_ch_18_Verses, 'ezk-ch18-verses');

var ezk_ch_19_Verses = [
  {num:1,words:[["O oe foi, ia e sauni se pese e aualofa a'i ona o alii sili o Isaraelu, ma ia faapea atu,", "Moreover take thou up a lamentation for the princes of Israel,"]]},
  {num:2,words:[["Po o ai lou tinā? O le leona fafine;", "And say,"], ["na ia taoto faatasi ma leona,", "What is thy mother? A lioness: she lay down among lions,"], ["na ia tausi ana tama faatasi ma leona taanoa.", "she nourished her whelps among young lions."]]},
  {num:3,words:[["Na ia avatu le tasi o ana tama;", "And she brought up one of her whelps:"], ["ua avea ia ma leona taanoa,", "it became a young lion,"], ["ua a'oa'o i saei manu,", "and it learned to catch the prey;"], ["ua 'ai tagata.", "it devoured men."]]},
  {num:4,words:[["Ua oo lona logo i nuu ese;", "The nations also heard of him;"], ["na maua o ia i la latou lua,", "he was taken in their pit,"], ["ona latou ave lea ia te ia ma le mama e ta'i a'i i le nuu o Aikupito.", "and they brought him with chains unto the land of Egypt."]]},
  {num:5,words:[["Ua iloa foi e ia ua ia faatalitali a ua faaumatia lona faatuatuaga,", "Now when she saw that she had waited,"], ["ona avea lea e ia o le tasi o ana tama,", "and her hope was lost, then she took another of her whelps,"], ["ua fai ai o ia ma leona taanoa.", "and made him a young lion."]]},
  {num:6,words:[["Ona fealualuai lea o ia faatasi ma leona,", "And he went up and down among the lions,"], ["ua avea ma leona taanoa,", "he became a young lion,"], ["ua a'oa'o i saei manu,", "and learned to catch the prey,"], ["ua 'ai tagata.", "and devoured men."]]},
  {num:7,words:[["Na ia iloa o latou maota ua gaogao,", "And he knew their desolate palaces,"], ["na ia faatafunaina foi o latou aai,", "and he laid waste their cities;"], ["o le taalili foi o lona tagi na gaogao ai le nuu,", "and the land was desolate, and the fulness thereof,"], ["ma mea ua tumu ai.", "by the noise of his roaring."]]},
  {num:8,words:[["Ona faasaga lea ia te ia o nuu mai itu malo i itu uma,", "Then the nations set against him on every side from the provinces,"], ["ua folasia lo latou upega ia te ia;", "and spread their net over him:"], ["ua maua o ia i la latou lua.", "he was taken in their pit."]]},
  {num:9,words:[["Ona latou tuu lea ia te ia i le fale puipui ma le mama i lona isu ,", "And they put him in ward in chains,"], ["ua latou ave foi ia te ia i le tupu o Papelonia;", "and brought him to the king of Babylon:"], ["na latou ave ia te ia i 'olo,", "they brought him into holds,"], ["ina ia le toe logona lava lona leo i mauga o Isaraelu.", "that his voice should no more be heard upon the mountains of Israel."]]},
  {num:10,words:[["E tusa lou tinā ma le vine e pei o oe, sa totō e lata ane i vai,", "Thy mother is like a vine in thy blood,"], ["na fua ia,", "planted by the waters:"], ["ua lauolaola ona la, auā o vai ina tele.", "she was fruitful and full of branches by reason of many waters."]]},
  {num:11,words:[["Na ia te ia o laau malolosi e fai ma tootoo o faipule,", "And she had strong rods for the sceptres of them that bare rule,"], ["na maualuga foi lona umi i totonu o la felefele;", "and her stature was exalted among the thick branches,"], ["na tu mai foi o ia i lona maualuga i totonu o la tetele.", "and she appeared in her height with the multitude of her branches."]]},
  {num:12,words:[["A e peitai na liaiina ia i le ita tele,", "But she was plucked up in fury,"], ["na lafotuina i le eleele,", "she was cast down to the ground,"], ["ua mago lona fua i le matagi mai sasaē, ua gauia ona laau malolosi,", "and the east wind dried up her fruit:"], ["ua mamago,", "her strong rods were broken and withered;"], ["ua susunuina i le afi.", "the fire consumed them."]]},
  {num:13,words:[["A o ona po nei ua totōina ia i le vao, o le nuu naumati,", "And now she is planted in the wilderness,"], ["ua leai se vai.", "in a dry and thirsty ground."]]},
  {num:14,words:[["Na alu atu foi le afi ai le laau i ona la,", "And fire is gone out of a rod of her branches,"], ["ua susunu ai ona fua;", "which hath devoured her fruit,"], ["o le mea lea e le toe ai se laau malosi ia te ia e fai ma tootoo e pule; o le mea e tagi ai lea,", "so that she hath no strong rod to be a sceptre to rule. This is a lamentation,"], ["e fai pea foi ma mea e tagi ai.", "and shall be for a lamentation."]]},
  {num:15,words:[["O a'u foi,", "I am also"], ["1181", "1181"]]},
];
renderVerseSet(ezk_ch_19_Verses, 'ezk-ch19-verses');

var ezk_ch_20_Verses = [
  {num:1,words:[["O lona fitu o tausaga,", "And it came to pass in the seventh year,"], ["o lona lima foi o masina o le aso e sefulu o le masina,", "in the fifth month,"], ["na o mai ai nisi toeaina o Isaraelu e fesili ia Ieova,", "the tenth day of the month, that certain of the elders of Israel came to enquire of the LORD,"], ["ua latou nonofo mai i o'u luma.", "and sat before me."]]},
  {num:2,words:[["Ona oo mai ai lea o le afioga a Ieova ia te ua,", "Then came the word of the LORD unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:3,words:[["Le atalii e o le tagata,", "Son of man,"], ["fai atu ia i toeaina o Isaraelu,", "speak unto the elders of Israel,"], ["ia faapea atu ia te i latou,", "and say unto them,"], ["O loo faapea ona fetalai mai o Ieova,", "Thus saith the Lord GOD;"], ["Ua outou o mai ea e fesili mai ia te au? O loo ola a'u,", "Are ye come to enquire of me? As I live,"], ["ou te le mafai ona outou fesili mai ia te au,", "saith the Lord GOD,"], ["o loo fetalai mai ai le Alii o Ieova.", "I will not be enquired of by you."]]},
  {num:4,words:[["E te le faamasino ea ia te i latou,", "Wilt thou judge them,"], ["le atalii e o le tagata,", "son of man,"], ["e te le faamasino ea? Faailoa atu ia ia te i latou mea e inosia na faia e o latou tamā;", "wilt thou judge them? cause them to know the abominations of their fathers:"]]},
  {num:5,words:[["ma ia e faapea atu ia te i latou,", "And say unto them,"], ["O loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["O le aso na ou filifili ai ia Isaraelu,", "In the day when I chose Israel,"], ["ma ou sii ai lo'u lima i le fanau a le aiga o Iakopo,", "and lifted up mine hand unto the seed of the house of Jacob,"], ["ma ou faailoaina atu o a'u ia te i latou i le nuu o Aikupito,", "and made myself known unto them in the land of Egypt,"], ["ina ua ou sii lo'u lima ia te i latou,", "when I lifted up mine hand unto them,"], ["ua faapea atu,", "saying,"], ["O a'u o Ieova lo outou Atua.", "I am the LORD your God;"]]},
  {num:6,words:[["O lea lava aso na ou sii ai lo'u lima ia te i latou e aumaia i latou ai le nuu o Aikupito e o atu i le nuu na ou sailia mo i latou,", "In the day that I lifted up mine hand unto them,"], ["e tafe ai le suāsusu ma le meli,", "to bring them forth of the land of Egypt into a land that I had espied for them, flowing with milk and honey,"], ["ua sili ona matagofie o lea nuu i nuu uma.", "which is the glory of all lands:"]]},
  {num:7,words:[["Na au fai atu foi ia te i latou,", "Then said I unto them,"], ["Ia taitasi le tagata ma lafoai mea inosia ua i ona luma,", "Cast ye away every man the abominations of his eyes,"], ["aua foi le faaleaga outou ia te outou i tupua o Aikupito;", "and defile not yourselves with the idols of Egypt:"], ["o a'u o Ieova lo outou Atua.", "I am the LORD your God."]]},
  {num:8,words:[["A ua latou fouvale ia te au,", "But they rebelled against me,"], ["ua le mafafai foi ona faalogo mai ia te au;", "and would not hearken unto me:"], ["ua le taitasi ma lafoaiina e i latou o mea inosia sa i o latou luma,", "they did not every man cast away the abominations of their eyes, neither did they forsake the idols of Egypt:"], ["ua le tuua foi tupua o Aikupito. Ona ou fai atu ai lea,", "then I said,"], ["Ou te sasaa atu lo'u ita tele i luga ia te i latou,", "I will pour out my fury upon them,"], ["e faataunuu atu ai lo'u ita ia te i latou i le nuu o Aikupito.", "to accomplish my anger against them in the midst of the land of Egypt."]]},
  {num:9,words:[["A e peitai na ou faia ona o lo'u igoa,", "But I wrought for my name's sake, that it should not be polluted before the heathen,"], ["ina ia le faaleagaina ai i luma o nuu ese sa latou i ai,", "among whom they were,"], ["na ou faailoaina atu ai foi a'u ia te i latou i o latou luma i lo'u aumaia o i latou ai le nuu o Aikupito.", "in whose sight I made myself known unto them, in bringing them forth out of the land of Egypt."]]},
  {num:10,words:[["Na ou aumaia i latou ai le nuu o Aikupito,", "Wherefore I caused them to go forth out of the land of Egypt,"], ["ma ou ta'ita'iina i latou i le vao.", "and brought them into the wilderness."]]},
  {num:11,words:[["Na ou tuuina atu foi ia te i latou a'u tulafono,", "And I gave them my statutes,"], ["ma ou faailoa atu ia te i latou a'u faamasinoga,", "and shewed them my judgments,"], ["o mea ia a faia e le tagata,", "which if a man do,"], ["e ola ai lava ia.", "he shall even live in them."]]},
  {num:12,words:[["Na ou avatu foi ia te i latou o'u sapati,", "Moreover also I gave them my sabbaths,"], ["e fai ma faailoga ia te au ma i latou,", "to be a sign between me and them,"], ["ia latou iloa ai o a'u o Ieova lē faapaiaina i latou.", "that they might know that I am the LORD that sanctify them."]]},
  {num:13,words:[["A ua fouvale le aiga o Isaraelu ia te au i le vao,", "But the house of Israel rebelled against me in the wilderness:"], ["ua le savavali i latou i a'u tulafono,", "they walked not in my statutes, and they despised my judgments,"], ["a ua latou 'ino'ino i a'u faamasinoga,", "which if a man do,"], ["o mea ia a faia e le tagata,", "he shall even live in them;"], ["e ola ai lava ia;", "and my sabbaths they greatly polluted:"], ["ua latou matuā solia foi o'u sapati. Ona ou fai atu ai lea,", "then I said, I would pour out my fury upon them in the wilderness,"], ["Ou te sasaa atu lo'u ita tele i luga ia te i latou i le vao e faaumatia ai i latou.", "to consume them."]]},
  {num:14,words:[["A e peitai na ou faia ona o lo'u igoa,", "But I wrought for my name's sake,"], ["ina ne'i faaleagaina ai i luma o nuu ese,", "that it should not be polluted before the heathen,"], ["na ou aumaia i latou i o latou luma.", "in whose sight I brought them out."]]},
  {num:15,words:[["O a'u foi,", "Yet also I lifted up my hand unto them in the wilderness,"], ["na ou sii lo'u lima ia te i latou i le vao,", "that I would not bring them into the land which I had given them,"], ["ou te le faaoo ia te i latou i le nuu na ou foaiina atu ai ia te i latou , e tafe ai le suāsusu ma le meli,", "flowing with milk and honey,"], ["ua sili ona matagofie o lea nuu i nuu uma;", "which is the glory of all lands;"]]},
  {num:16,words:[["auā na latou 'ino'ino i a'u faamasinoga,", "Because they despised my judgments,"], ["ma ua le savavali i a'u tulafono;", "and walked not in my statutes,"], ["a ua latou solia o'u sapati,", "but polluted my sabbaths:"], ["auā na mulimuli atu o latou loto i a latou tupua.", "for their heart went after their idols."]]},
  {num:17,words:[["A e ui lava i lea na ou faasaoina i latou ia le fano i latou,", "Nevertheless mine eye spared them from destroying them,"], ["ma ou le faaumatia i latou i le vao.", "neither did I make an end of them in the wilderness."]]},
  {num:18,words:[["Na ou fai atu foi i a latou fanau i le vao,", "But I said unto their children in the wilderness,"], ["Aua tou te savavali i tu a o outou tamā,", "Walk ye not in the statutes of your fathers,"], ["aua foi le usiusitai i a latou masani,", "neither observe their judgments,"], ["aua ne'i faaleagaina outou i a latou tupua.", "nor defile yourselves with their idols:"]]},
  {num:19,words:[["O a'u o Ieova lo outou Atua,", "I am the LORD your God;"], ["ia outou savavali i a'u tulafono,", "walk in my statutes,"], ["ma tausi i a'u faamasinoga,", "and keep my judgments,"], ["ma outou faia.", "and do them;"]]},
  {num:20,words:[["Ia outou faapaiaina foi o'u sapati;", "And hallow my sabbaths;"], ["e fai foi ia ma faailoga ia te au ma outou, ia iloa ai e outou,", "and they shall be a sign between me and you,"], ["o a'u lava o Ieova lo outou Atua.", "that ye may know that I am the LORD your God."]]},
  {num:21,words:[["A ua fouvale le fanau ia te au;", "Notwithstanding the children rebelled against me:"], ["ua latou le savavali i a'u tulafono,", "they walked not in my statutes,"], ["ma ua le tausi i a'u faamasinoga ia usiusitai i ai,", "neither kept my judgments to do them,"], ["o mea ia a faia e le tagata,", "which if a man do,"], ["e ola ai lava ia;", "he shall even live in them; they polluted my sabbaths:"], ["na latou solia o'u sapati. Ona ou fai atu i lea,", "then I said,"], ["Ou te sasaa atu lo'u ita tele i luga ia te i latou,", "I would pour out my fury upon them,"], ["e faaiuina atu ai lo'u ita ia te i latou i le vao.", "to accomplish my anger against them in the wilderness."]]},
  {num:22,words:[["A e ui lava i lea na ou faafoisia lo'u lima,", "Nevertheless I withdrew mine hand,"], ["ma ou faia ona o lo'u igoa,", "and wrought for my name's sake, that it should not be polluted in the sight of the heathen,"], ["ina ne'i faaleagaina ai i luma o nuu ese na ou aveina atu ai i latou i o latou luma.", "in whose sight I brought them forth."]]},
  {num:23,words:[["Na ou sii foi lo'u lima ia te i latou i le vao,", "I lifted up mine hand unto them also in the wilderness,"], ["ou te faataapeapeaina i latou i nuu ese,", "that I would scatter them among the heathen,"], ["ma ou faasalalauina i latou i nuu eseese;", "and disperse them through the countries;"]]},
  {num:24,words:[["auā na latou le faia a'u faamasinoga,", "Because they had not executed my judgments,"], ["ma ua latou 'ino'ino i a'u tulafono,", "but had despised my statutes,"], ["ma latou solia o'u sapati,", "and had polluted my sabbaths,"], ["na faasaga foi o latou mata i tupua a o latou tamā.", "and their eyes were after their fathers' idols."]]},
  {num:25,words:[["O le mea lea na ou tuuina atu ai ia te i latou o tulafono e le lelei,", "Wherefore I gave them also statutes that were not good,"], ["ma faamasinoga latou te le ola ai", "and judgments whereby they should not live;"]]},
  {num:26,words:[["na ou faaleaga foi ia te i latou i a latou lava taulaga i lo latou faaui ane i ulumatua uma i le afi ,", "And I polluted them in their own gifts,"], ["ina ia ou faatafunaina i latou,", "in that they caused to pass through the fire all that openeth the womb, that I might make them desolate,"], ["ina ia latou iloa o a'u lava o Ieova.", "to the end that they might know that I am the LORD."]]},
  {num:27,words:[["O le mea lea,", "Therefore,"], ["le atalii e o le tagata,", "son of man,"], ["ia e fai atu ai i le aiga o Isaraelu,", "speak unto the house of Israel,"], ["ia faapea atu ia te i latou,", "and say unto them,"], ["O loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Na faifaia lava a'u e o outou tamā i lenei mea foi,", "Yet in this your fathers have blasphemed me,"], ["ua latou matuā agasala lava ia te au.", "in that they have committed a trespass against me."]]},
  {num:28,words:[["Na ou aumaia i latou i le nuu na ou sii ai lo'u lima ou te avatua mo i latou,", "For when I had brought them into the land,"], ["ona latou vaavaai atu lea i mauga maualuluga uma,", "for the which I lifted up mine hand to give it to them,"], ["ma laau tauuluuluola uma,", "then they saw every high hill,"], ["na latou osi ai a latou taulaga,", "and all the thick trees, and they offered there their sacrifices,"], ["ma latou avatu ai a latou taulaga e faaonoono ai;", "and there they presented the provocation of their offering:"], ["na latou tuu atu ai foi a latou mea manogi lelei,", "there also they made their sweet savour,"], ["ma latou liligi ai a latou taulaga i mea e inu.", "and poured out there their drink offerings."]]},
  {num:29,words:[["Ona au fai atu ai lea ia te i latou, Se a le mea maualuga tou te o atu i ai? Ua ta'ua lona igoa o Le mea maualuga,", "Then I said unto them,"], ["ua oo mai i le aso nei.", "What is the high place whereunto ye go? And the name thereof is called Bamah unto this day."]]},
  {num:30,words:[["O le mea lea ia e fai atu ai i le aiga o Isaraelu,", "Wherefore say unto the house of Israel,"], ["O loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Ua leaga ea outou e pei o le tu a outou tamā? Ua mulilulua ea foi outou o mulimuli atu i a latou mea inosia?", "Are ye polluted after the manner of your fathers? and commit ye whoredom after their abominations?"]]},
  {num:31,words:[["Auā o lo outou avatua o a outou taulaga,", "For when ye offer your gifts,"], ["ma lo outou faaui ane o a outou fanau i le afi ua outou faaleagaina ai outou i a outou tupua uma,", "when ye make your sons to pass through the fire,"], ["ua oo mai i lenei aso;", "ye pollute yourselves with all your idols,"], ["tou te fesili mai ea ia te au nei,", "even unto this day: and shall I be enquired of by you,"], ["le aiga o Isaraelu e? O loo fetalai mai ai le Alii o Ieova,", "O house of Israel? As I live,"], ["O loo ola a'u,", "saith the Lord GOD,"], ["ou te le mafai lava ona outou fesili mai ia te au.", "I will not be enquired of by you."]]},
  {num:32,words:[["O le mea foi e tupu i o outou manatu,", "And that which cometh into your mind shall not be at all,"], ["e le oo lava,", "that ye say,"], ["ua outou faapea ane,", "We will be as the heathen,"], ["E avea i matou e pei o nuu ese,", "as the families of the countries,"], ["e pei o aiga o nuu eseese e auauna i laau ma maa.", "to serve wood and stone."]]},
  {num:33,words:[["O loo fetalai mai le Alii o Ieova,", "As I live,"], ["O loo ola a'u,", "saith the Lord GOD,"], ["ou te pule lava ia te outou ma le lima malosi,", "surely with a mighty hand, and with a stretched out arm,"], ["ma le lima faaloaloa,", "and with fury poured out,"], ["ma le ita tele ua sasaaina atu.", "will I rule over you:"]]},
  {num:34,words:[["Ou te aumaia outou ai nuu ese,", "And I will bring you out from the people,"], ["ma ou faapotopotoina outou ai nuu eseese ua faataapeapeina ai outou,", "and will gather you out of the countries wherein ye are scattered,"], ["ma le lima malosi,", "with a mighty hand,"], ["ma le lima faaloaloa,", "and with a stretched out arm,"], ["ma le ita tele ua sasaaina atu.", "and with fury poured out."]]},
  {num:35,words:[["Ou te aumaia foi outou i le vao o nuu, ma ou faamasino ia te outou i lea mea,", "And I will bring you into the wilderness of the people,"], ["o tatou o fesagai ma a'u.", "and there will I plead with you face to face."]]},
  {num:36,words:[["E pei ona ou faamasino i o outou tamā i le vao o le nuu o Aikupito,", "Like as I pleaded with your fathers in the wilderness of the land of Egypt,"], ["e faapea ona ou faamasinoga ia te outou,", "so will I plead with you,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:37,words:[["Ou te faaui ane foi ia te outou i lalo o le tootoo,", "And I will cause you to pass under the rod,"], ["ma ou faaooina outou i le noataga o le feagaiga;", "and I will bring you into the bond of the covenant:"]]},
  {num:38,words:[["ou te faate'aeseina foi ia te outou o e fouvale,", "And I will purge out from among you the rebels,"], ["ma ē agasala ia te au;", "and them that transgress against me:"], ["ou te aveina atu i latou ai le nuu o loo latou āumau ai,", "I will bring them forth out of the country where they sojourn,"], ["a e latou te le o mai i le laueleele o Isaraelu;", "and they shall not enter into the land of Israel:"], ["tou te iloa ai o a'u lava o Ieova.", "and ye shall know that I am the LORD."]]},
  {num:39,words:[["O loo faapea ona fetalai mai o le Alii o Ieova,", "As for you,"], ["O outou le aiga o Isaraelu;", "O house of Israel, thus saith the Lord GOD;"], ["ō ia outou,", "Go ye,"], ["ina taitasi ma auauna i ana tupua;", "serve ye every one his idols,"], ["a e mulimuli ane,", "and hereafter also,"], ["afai tou te le faalogo mai ia te au,", "if ye will not hearken unto me: but pollute ye my holy name no more with your gifts,"], ["aua tou te toe faaleagaina lo'u igoa paia i a outou taulaga ma a outou tupua.", "and with your idols."]]},
  {num:40,words:[["Aua o lo'u mauga paia,", "For in mine holy mountain,"], ["o le mauga maualuga i Isaraelu,", "in the mountain of the height of Israel,"], ["o loo fetalai mai le Alii o Ieova,", "saith the Lord GOD,"], ["e auauna mai ai le aiga uma o Isaraelu ia te au,", "there shall all the house of Israel,"], ["o i latou uma foi i le nuu;", "all of them in the land, serve me:"], ["ou te talia i latou i lea mea,", "there will I accept them,"], ["ma ou fai atu e au mai i lea mea a outou taulaga,", "and there will I require your offerings,"], ["ma mea faapolopoloina i a outou taulaga,", "and the firstfruits of your oblations,"], ["atoa ma a outou mea paia uma.", "with all your holy things."]]},
  {num:41,words:[["Ou te talia outou ona o la outou mea manogi lelei,", "I will accept you with your sweet savour,"], ["pe a ou aumaia outou ai nuu,", "when I bring you out from the people,"], ["ma faapotopotoina outou mai nuu eseese na faataapeapeina ai outou;", "and gather you out of the countries wherein ye have been scattered;"], ["e faapaiaina foi a'u e outou i luma o nuu ese.", "and I will be sanctified in you before the heathen."]]},
  {num:42,words:[["Tou te iloa o a'u lava o Ieova,", "And ye shall know that I am the LORD,"], ["pe a ou aumaia outou i le laueleele o Isaraelu, o le nuu na ou sii ai lo'u lima,", "when I shall bring you into the land of Israel,"], ["ou te avatua i o outou tamā.", "into the country for the which I lifted up mine hand to give it to your fathers."]]},
  {num:43,words:[["Tou te manatunatu ai i a outou amio uma,", "And there shall ye remember your ways,"], ["ma a outou mea uma na fai,", "and all your doings,"], ["sa leaga ai outou;", "wherein ye have been defiled;"], ["ona 'ino'ino ai lea o outou ia te outou ona o a outou mea leaga uma ua outou faia.", "and ye shall lothe yourselves in your own sight for all your evils that ye have committed."]]},
  {num:44,words:[["E iloa foi e outou,", "And ye shall know that I am the LORD,"], ["o a'u lava o Ieova pe a ou faia ia te outou ona o lo'u igoa,", "when I have wrought with you for my name's sake,"], ["e le tusa ma a outou amio leaga,", "not according to your wicked ways,"], ["ma a outou mea leaga ua fai,", "nor according to your corrupt doings,"], ["le aiga o Isaraelu e,", "O ye house of Israel,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:45,words:[["Ua oo mai foi le afioga e Ieova ia te au,", "Moreover the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:46,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia e faasaga atu ou mata i le itu i toga,", "set thy face toward the south,"], ["ma faapaū atu lau upu i le itu i toga,", "and drop thy word toward the south,"], ["ma vavalo atu i le vao matua i le fanua i le itu i toga;", "and prophesy against the forest of the south field;"]]},
  {num:47,words:[["ma fai atu i le vao matua i le itu i toga,", "And say to the forest of the south,"], ["Faalogo mai ia i le afioga a Ieova,", "Hear the word of the LORD;"], ["O loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Faauta,", "Behold,"], ["ou te tŭtŭ le afi ia te oe, e susunuina ai laau mata uma ua ia te oe,", "I will kindle a fire in thee,"], ["atoa ma laau mamago uma;", "and it shall devour every green tree in thee,"], ["e le tineia le afi e mu saesae,", "and every dry tree:"], ["e mu ai mata uma i le itu i toga,", "the flaming flame shall not be quenched,"], ["e oo i le itu i matu.", "and all faces from the south to the north shall be burned therein."]]},
  {num:48,words:[["E iloa foi e tagata uma o a'u o Ieova, ua ou tŭtŭina;", "And all flesh shall see that I the LORD have kindled it:"], ["e le tineia lava.", "it shall not be quenched."]]},
  {num:49,words:[["Ona ou fai atu ai lea,", "Then said I,"], ["Aue, le Alii e Ieova e! ua latou fai mai ia te au,", "Ah Lord GOD! they say of me,"], ["E le tautala mai ea o ia i faataoto?", "Doth he not speak parables?"]]},
];
renderVerseSet(ezk_ch_20_Verses, 'ezk-ch20-verses');

var ezk_ch_21_Verses = [
  {num:1,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "And the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia faasaga ou mata i Ierusalema,", "set thy face toward Jerusalem,"], ["ma faapaū atu lau upu i mea paia,", "and drop thy word toward the holy places,"], ["ma ē vavalo atu i le laueleele o Isaraelu,", "and prophesy against the land of Israel,"]]},
  {num:3,words:[["ma ē fai atu i le laueleele o Isaraelu,", "And say to the land of Israel,"], ["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Faauta, ua ou fai oe mo'u fili,", "Behold,"], ["ou te to ae la'u pelu ai lona faamoega,", "I am against thee,"], ["ma ou faaumatia le ua amiotonu,", "and will draw forth my sword out of his sheath,"], ["ma le ua amio leaga ua ia te oe.", "and will cut off from thee the righteous and the wicked."]]},
  {num:4,words:[["O le a ou faaumatia le ua amiotonu, ma le ua amio leaga ua ia te oe,", "Seeing then that I will cut off from thee the righteous and the wicked,"], ["o le mea lava lea e alu atu ai la'u pelu ai lona faamoega i tagata uma, e pau mai i le itu i toga, e pau mai i le itu i matu;", "therefore shall my sword go forth out of his sheath against all flesh from the south to the north:"]]},
  {num:5,words:[["e iloa ai e tagata uma, o a'u o Ieova,", "That all flesh may know that I the LORD have drawn forth my sword out of his sheath:"], ["ua ou toina ae la'u pelu ai lona faamoega; e le toe foi ane ai lava.", "it shall not return any more."]]},
  {num:6,words:[["O oe foi,", "Sigh therefore,"], ["le atalii o le tagata,", "thou son of man,"], ["ia e mapuitiga ona ua gau o lou papatua;", "with the breaking of thy loins;"], ["ia e mapuitiga ma le oono tele i o latou luma.", "and with bitterness sigh before their eyes."]]},
  {num:7,words:[["A latou fai mai foi ia te oe,", "And it shall be,"], ["Pe se a le mea e te mapuitiga ai? E te tali atu,", "when they say unto thee,"], ["Ona o le tala,", "Wherefore sighest thou? that thou shalt answer,"], ["auā o le a oo mai;", "For the tidings;"], ["e liu suāvai loto uma,", "because it cometh:"], ["e vaivai lima uma,", "and every heart shall melt,"], ["e faavaivai loto uma,", "and all hands shall be feeble, and every spirit shall faint,"], ["e liu suāvai foi tulivae uma;", "and all knees shall be weak as water:"], ["faauta,", "behold,"], ["o loo sau,", "it cometh,"], ["e faataunuuina lava,", "and shall be brought to pass,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:8,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "Again the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:9,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia e vavalo,", "prophesy,"], ["ia faapea atu,", "and say,"], ["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Fai atu ia,", "Say,"], ["O le pelu,", "A sword,"], ["o le pelu ua faamaaia,", "a sword is sharpened,"], ["ma ua faapupulaina.", "and also furbished:"]]},
  {num:10,words:[["Ua faamaaia ina ia tele ai le fasi,", "It is sharpened to make a sore slaughter;"], ["ua faapupulaina,", "it is furbished that it may glitter:"], ["ia pupula;", "should we then make mirth? it contemneth the rod of my son,"], ["a tatou olioli ea? O le tootoo o lo'u atalii ua faaleaogaina ai laau uma.", "as every tree."]]},
  {num:11,words:[["Ua ia avatu ai ia faapupulaina,", "And he hath given it to be furbished,"], ["ina ia umia i le lima;", "that it may be handled:"], ["ua faamaaia lenei pelu,", "this sword is sharpened,"], ["ma ua faapupulaina,", "and it is furbished,"], ["ina ia tuuina atu i le lima o le na te fasioti.", "to give it into the hand of the slayer."]]},
  {num:12,words:[["Alaga ia,", "Cry and howl,"], ["ma uio,", "son of man:"], ["le atalii e o le tagata, auā e i ai ia i lo'u nuu,", "for it shall be upon my people,"], ["e i ai i alii sili uma o Isaraelu;", "it shall be upon all the princes of Israel:"], ["ua tuuina atu i latou i le pelu faatasi ma lo'u nuu;", "terrors by reason of the sword shall be upon my people:"], ["o le mea lea ia e pōpō ai i lou vae.", "smite therefore upon thy thigh."]]},
  {num:13,words:[["Auā ua tofotofoina ia. I le faapefea pe a faaleaogaina le tootoo e le pelu? E mavae lava ia,", "Because it is a trial, and what if the sword contemn even the rod? it shall be no more,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:14,words:[["O oe na foi,", "Thou therefore,"], ["le atalii o le tagata,", "son of man,"], ["ia e vavalo atu, ma ia e pati lima,", "prophesy,"], ["ma ia foi faalua le pelu,", "and smite thine hands together,"], ["ia faatolu lava,", "and let the sword be doubled the third time,"], ["o le pelu ua oti ai e ua fasia; o le pelu lea o le ua fasia,", "the sword of the slain:"], ["le ua sili,", "it is the sword of the great men that are slain,"], ["e puipui atu ia te i latou.", "which entereth into their privy chambers."]]},
  {num:15,words:[["Ua ou tuu atu le pelu matautia i o latou faitotoa uma,", "I have set the point of the sword against all their gates,"], ["ina ia faavaivai ai o latou loto,", "that their heart may faint,"], ["ma ia faateleina le malaia. Aue! ua faapupulaina ia,", "and their ruins be multiplied: ah! it is made bright,"], ["ua saunia e fasi a'i.", "it is wrapped up for the slaughter."]]},
  {num:16,words:[["Alu ia i lea itu po o lea itu,", "Go thee one way or other,"], ["o le itu taumatau,", "either on the right hand,"], ["po o le itu tauagavale,", "or on the left,"], ["so se mea ua faasaga i ai ou mata.", "whithersoever thy face is set."]]},
  {num:17,words:[["O a'u foi, ou te pati lima,", "I will also smite mine hands together,"], ["ma ou faaiuina lo'u ita;", "and I will cause my fury to rest:"], ["o a'u o Ieova, ua ou fai atu ai.", "I the LORD have said it."]]},
  {num:18,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "The word of the LORD came unto me again,"], ["ua faapea mai,", "saying,"]]},
  {num:19,words:[["O oe na foi,", "Also,"], ["le atalii o le tagata,", "thou son of man,"], ["ia e totofi i ala e lua e oo mai ai le pelu a le tupu o Papelonia;", "appoint thee two ways, that the sword of the king of Babylon may come:"], ["e o mai i laua mai le nuu e tasi,", "both twain shall come forth out of one land:"], ["filifili ia oe i se mea,", "and choose thou a place,"], ["filifili i le tuluiga o le ala i le aai.", "choose it at the head of the way to the city."]]},
  {num:20,words:[["Ina totofi ia se ala e oo mai ai le pelu i Rapa o le fanauga a Amoni,", "Appoint a way, that the sword may come to Rabbath of the Ammonites,"], ["ma Iuta i Ierusalema ua nofo 'olo.", "and to Judah in Jerusalem the defenced."]]},
  {num:21,words:[["Auā na tu le tupu o Papelonia i fetaulaigāala i le mea e vala lua ai le ala,", "For the king of Babylon stood at the parting of the way,"], ["e fai togafiti faataulāitu,", "at the head of the two ways,"], ["na ia luluina ana u fanafana,", "to use divination: he made his arrows bright,"], ["na ia fesili atu i tupua,", "he consulted with images,"], ["na ia iloilo i le ate.", "he looked in the liver."]]},
  {num:22,words:[["Na i lona itu taumatau le togafiti faataulāitu ia Ierusalema e faatu atu ai mea e lepeti a'i,", "At his right hand was the divination for Jerusalem,"], ["e tautala atu ai i le taua,", "to appoint captains,"], ["e alalaga atu ai ma le leo tele,", "to open the mouth in the slaughter, to lift up the voice with shouting,"], ["e faatu atu i faitotoa o mea e lepeti a'i,", "to appoint battering rams against the gates,"], ["e tanu ai se mea mautietie,", "to cast a mount,"], ["ma fai ai se 'olo.", "and to build a fort."]]},
  {num:23,words:[["E fai foi lea ia te i latou e peiseai se togafiti faataulāitu pepelo i le manatu o e na tauto i tautoga ia te i latou;", "And it shall be unto them as a false divination in their sight, to them that have sworn oaths:"], ["a e manatua e ia o amio leaga ina ia pūea i latou.", "but he will call to remembrance the iniquity, that they may be taken."]]},
  {num:24,words:[["O le mea lea o loo faapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["Ua manatua a outou amio leaga ona o outou,", "Because ye have made your iniquity to be remembered, in that your transgressions are discovered,"], ["ina ua mānu a outou solitulafono,", "so that in all your doings your sins do appear;"], ["ma ua aliali mai a outou agasala i a outou mea uma e fai;", "because,"], ["ona ua manatua outou,", "I say, that ye are come to remembrance,"], ["e pūea outou i le lima.", "ye shall be taken with the hand."]]},
  {num:25,words:[["O oe na foi,", "And thou,"], ["le alii sili o Isaraelu,", "profane wicked prince of Israel,"], ["o lē faalematau ma le amio leaga, ua oo mai lona aso,", "whose day is come,"], ["o ona po e iu ai le amio leaga.", "when iniquity shall have an end,"]]},
  {num:26,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Ave ese ia le pulou ie,", "Remove the diadem,"], ["to ese ia le palealii;", "and take off the crown:"], ["e le o lea lenei mea;", "this shall not be the same:"], ["e faamaualugaina le ua maulalo,", "exalt him that is low,"], ["a e faamaulaloina le ua maualuga.", "and abase him that is high."]]},
  {num:27,words:[["Ou te fulisia,", "I will overturn,"], ["fulisia,", "overturn,"], ["fulisia,", "overturn, it:"], ["e le toe i ai lava lea,", "and it shall be no more,"], ["seia afio mai o ia ua i ai le tonu,", "until he come whose right it is;"], ["ona ou avatua ai lea ia te ia.", "and I will give it him."]]},
  {num:28,words:[["O oe na foi,", "And thou,"], ["le atalii o le tagata,", "son of man,"], ["ia e vavalo,", "prophesy and say,"], ["ia faapea atu,", "Thus saith the Lord GOD concerning the Ammonites,"], ["O loo faapea ona fetalai mai o le Alii o Ieova i le fanauga a Amoni, ma la latou faifai,", "and concerning their reproach;"], ["fai atu lava i ai,", "even say thou,"], ["O le pelu,", "The sword,"], ["o le pelu,", "the sword is drawn:"], ["ua to ae e fasi a'i;", "for the slaughter it is furbished,"], ["ua faapupulaina e faaumatia ai ona o le pupula;", "to consume because of the glittering:"]]},
  {num:29,words:[["ina o latou vaaia le mea faatauvaa e fai atu ai ia te oe,", "Whiles they see vanity unto thee,"], ["ina o latou valoia le mea pepelo ia te oe,", "whiles they divine a lie unto thee,"], ["e tuu atu oe i luga o ua o e ua fasia,", "to bring thee upon the necks of them that are slain,"], ["e ua amio leaga,", "of the wicked,"], ["o e ua oo mai lo latou aso,", "whose day is come,"], ["o ona po e iu ai le amio leaga.", "when their iniquity shall have an end."]]},
  {num:30,words:[["Ou te faafoisia ea le pelu i lona faamoega? Ou te faasalaina oe i le mea na tupu ai oe,", "Shall I cause it to return into his sheath? I will judge thee in the place where thou wast created,"], ["o le nuu na fanau ai oe.", "in the land of thy nativity."]]},
  {num:31,words:[["Ou te sasaa foi lo'u ita i luga ia te oe,", "And I will pour out mine indignation upon thee,"], ["ou te tapili le afi o lo'u ita ia te oe,", "I will blow against thee in the fire of my wrath,"], ["ma ou tuuina atu oe i lima o tagata valelea,", "and deliver thee into the hand of brutish men,"], ["ua popoto i fasi tagata.", "and skilful to destroy."]]},
  {num:32,words:[["E fai oe ma fafie mo le afi;", "Thou shalt be for fuel to the fire;"], ["e i ai lou toto i totonu o le nuu;", "thy blood shall be in the midst of the land;"], ["e le toe manatua lava oe;", "thou shalt be no more remembered:"], ["auā o a'u o Ieova ua ou fai atu ai.", "for I the LORD have spoken it."]]},
];
renderVerseSet(ezk_ch_21_Verses, 'ezk-ch21-verses');

var ezk_ch_22_Verses = [
  {num:1,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "Moreover the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["O oe na,", "Now, thou son of man,"], ["le atalii o le tagata,", "wilt thou judge,"], ["e te faamasino ea? e te faamasino ea i le aai o e totolima? e te faaali atu ia te ia o ana mea inosia uma,", "wilt thou judge the bloody city? yea, thou shalt shew her all her abominations."]]},
  {num:3,words:[["ma e faapea atu,", "Then say thou,"], ["O loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD,"], ["Ua faamaligi le toto e le aai i totonu ia te ia, ia oo mai ai ona aso,", "The city sheddeth blood in the midst of it,"], ["ma ua faia foi tupua mo ia,", "that her time may come,"], ["ia leaga ai o ia.", "and maketh idols against herself to defile herself."]]},
  {num:4,words:[["Ua e nofo sala i le toto ua e faamaligiina;", "Thou art become guilty in thy blood that thou hast shed;"], ["ua leaga foi oe ia te oe i tupua ua e faia;", "and hast defiled thyself in thine idols which thou hast made;"], ["ua faalatalataina e oe ou aso,", "and thou hast caused thy days to draw near,"], ["ua e oo lava i ou tausaga;", "and art come even unto thy years:"], ["o le mea lea ou te tuu atu ai oe e fai ma luma i nuu ese,", "therefore have I made thee a reproach unto the heathen,"], ["ma tauemuga i nuu uma.", "and a mocking to all countries."]]},
  {num:5,words:[["O e latalata mai ia te oe,", "Those that be near,"], ["atoa ma ē mamao,", "and those that be far from thee,"], ["latou te tauemu ia te oe lē ua ta'uleagaina,", "shall mock thee,"], ["ma ua tele lou atuatuvale.", "which art infamous and much vexed."]]},
  {num:6,words:[["Faauta,", "Behold, the princes of Israel,"], ["o alii o Isaraelu o ia te oe e taitasi ma faamalosi e faamaligi i ai le toto.", "every one were in thee to their power to shed blood."]]},
  {num:7,words:[["Ua ia te oe i latou o e faaletaualoa i le tamā ma le tinā;", "In thee have they set light by father and mother:"], ["ua ia te oe i latou o e faasaua i le tagata ese;", "in the midst of thee have they dealt by oppression with the stranger:"], ["ua ia te oe i latou o e faasaunoa i le ua aumatuā ma le fafine ua oti lana tane.", "in thee have they vexed the fatherless and the widow."]]},
  {num:8,words:[["O a'u mea paia ua e 'ino'ino i ai,", "Thou hast despised mine holy things,"], ["ma o'u sapati ua e solia.", "and hast profaned my sabbaths."]]},
  {num:9,words:[["O ia te oe tagata e feaveaveai ia faamaligi ai le toto;", "In thee are men that carry tales to shed blood:"], ["o ia te oe foi o e aai i luga o mauga;", "and in thee they eat upon the mountains:"], ["o ia te oe o e fai mea leaga lava.", "in the midst of thee they commit lewdness."]]},
  {num:10,words:[["O ia te oe foi ē faatelenoa i o latou tamā;", "In thee have they discovered their fathers' nakedness:"], ["o ia te oe ē faaleaga le fafine o faanofoeseina ona o lona leaga.", "in thee have they humbled her that was set apart for pollution."]]},
  {num:11,words:[["Ua fai foi e le tasi mea e inosia i le avā a le tasi tagata;", "And one hath committed abomination with his neighbour's wife;"], ["ma ua faaleaga e le tasi i le ulavale le avā a lona lava atalii;", "and another hath lewdly defiled his daughter in law;"], ["ua ia te oe foi le ua ia faaleagaina iona lava tuafafine,", "and another in thee hath humbled his sister,"], ["o le afafine o lona tamā.", "his father's daughter."]]},
  {num:12,words:[["O ia te oe e ua talia mea,", "In thee have they taken gifts to shed blood;"], ["alofa e faamaligi ai le toto;", "thou hast taken usury and increase,"], ["ua e talia foi le totogi faasili ma mea faasili; ma ua e fao faasaua mea a le tasi tagata,", "and thou hast greedily gained of thy neighbours by extortion,"], ["a ua e faagalogalo mai ia te au,", "and hast forgotten me,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:13,words:[["Faauta foi,", "Behold,"], ["ua ou pati lima i au mea ua maua i le faamanumanu,", "therefore I have smitten mine hand at thy dishonest gain which thou hast made,"], ["atoa ma le toto o loo i totonu ia te oe.", "and at thy blood which hath been in the midst of thee."]]},
  {num:14,words:[["E lavā ea e lou loto? E malolosi ea ou lima i le aso ou te faasala ai ia te oe? O a'u o Ieova,", "Can thine heart endure,"], ["ua ou fai atu ai,", "or can thine hands be strong, in the days that I shall deal with thee? I the LORD have spoken it,"], ["ou te faia lava.", "and will do it."]]},
  {num:15,words:[["Ou te faataapeapeaina oe i nuu ese,", "And I will scatter thee among the heathen,"], ["ma ou faasalalauina oe i nuu eseese,", "and disperse thee in the countries,"], ["ma ou faaumatia lou leaga ia te'a ma oe.", "and will consume thy filthiness out of thee."]]},
  {num:16,words:[["E faaleagaina lava oe e oe i luma o nuu ese,", "And thou shalt take thine inheritance in thyself in the sight of the heathen,"], ["e te iloa ai o a'u lava o Ieova.", "and thou shalt know that I am the LORD."]]},
  {num:17,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "And the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:18,words:[["Le atalii e o le tagata,", "Son of man,"], ["ua avea le aiga o Isaraelu,", "the house of Israel is to me become dross:"], ["ma otaota o uamea ia te au;", "all they are brass,"], ["o 'apa memea i latou uma,", "and tin,"], ["ma 'apa sinasina,", "and iron,"], ["ma uamea,", "and lead,"], ["ma pulu i totonu o le ogaumu;", "in the midst of the furnace;"], ["o otaota o ario lava i latou.", "they are even the dross of silver."]]},
  {num:19,words:[["O le mea lea ua faapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["ua avea outou uma ma otaota o uamea,", "Because ye are all become dross,"], ["o le mea lea, faauta,", "behold,"], ["ou te faapotopotoina ai lava outou i totonu o Ierusalema.", "therefore I will gather you into the midst of Jerusalem."]]},
  {num:20,words:[["E pei ona faapotopotoina o ario,", "As they gather silver,"], ["ma 'apa memea,", "and brass, and iron,"], ["ma uamea,", "and lead,"], ["ma pulu,", "and tin, into the midst of the furnace,"], ["ma 'apa sinasina i totonu o le umu,", "to blow the fire upon it,"], ["e tapili ai le afi ia liu suāvai;", "to melt it;"], ["e faapea ona ou faapotopotoina o outou i lo'u ita ma lo'u tiga,", "so will I gather you in mine anger and in my fury, and I will leave you there,"], ["ma ou tuu ai outou ia liu suāvai.", "and melt you."]]},
  {num:21,words:[["Ou te faapotopotoina lava outou,", "Yea,"], ["ma ou tapili i le afi o lo'u ita ia te outou,", "I will gather you, and blow upon you in the fire of my wrath,"], ["e liu suāvai outou i totonu ia te ia.", "and ye shall be melted in the midst thereof."]]},
  {num:22,words:[["E pei ona liu suāvai o ario i totonu o le ogaumu, e faapea foi ona liu suāvai o outou i totonu ia te ia;", "As silver is melted in the midst of the furnace,"], ["e iloa ai e outou,", "so shall ye be melted in the midst thereof;"], ["o a'u o Ieova, ua ou sasaa atu lo'u ita tele i luga ia te outou.", "and ye shall know that I the LORD have poured out my fury upon you."]]},
  {num:23,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "And the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:24,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia e fai atu ia te ia,", "say unto her,"], ["O oe na o le laueleele e le faamamāina,", "Thou art the land that is not cleansed,"], ["ma le le timuia i le aso o le toatamai.", "nor rained upon in the day of indignation."]]},
  {num:25,words:[["E i ai le fouvalega o ana perofeta i totonu ia te ia,", "There is a conspiracy of her prophets in the midst thereof,"], ["e pei o le leona tagi ona saeia o mea;", "like a roaring lion ravening the prey;"], ["ua latou faaumatia tagata;", "they have devoured souls;"], ["ua latou ave oloa ma mea tāua;", "they have taken the treasure and precious things;"], ["ua latou faatoateleina ona fafine ua oti a latou tane i totonu ia te ia.", "they have made her many widows in the midst thereof."]]},
  {num:26,words:[["Ua solia e ana faitaulaga o la'u tulafono,", "Her priests have violated my law,"], ["ua latou faaleaga foi a'u mea paia, ua latou le faailogaina mea paia,", "and have profaned mine holy things:"], ["ma mea e le paia,", "they have put no difference between the holy and profane,"], ["ua latou le faailoa foi ona eseese o mea leaga,", "neither have they shewed difference between the unclean and the clean,"], ["ma mea e mamā, ua latou liliu ese o latou mata i o'u sapati,", "and have hid their eyes from my sabbaths,"], ["ma ua solia a'u e i latou.", "and I am profaned among them."]]},
  {num:27,words:[["O ona alii i totonu ia te ia,", "Her princes in the midst thereof are like wolves ravening the prey,"], ["latou te faapei o luko o loo saei manu,", "to shed blood,"], ["e faamaligi toto,", "and to destroy souls,"], ["ma faaumatia tagata ia maua ai mea i le saua.", "to get dishonest gain."]]},
  {num:28,words:[["Ua vali foi ana perofeta ia te i latou i le panisina,", "And her prophets have daubed them with untempered morter,"], ["ua vaaia mea faatauvaa,", "seeing vanity,"], ["ma vavalo i mea pepelo ia te i latou,", "and divining lies unto them,"], ["ua faapea atu,", "saying,"], ["O loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD,"], ["a e lei fetalai mai lava Ieova.", "when the LORD hath not spoken."]]},
  {num:29,words:[["Ua faasaua lava tagata o le nuu,", "The people of the land have used oppression,"], ["ma ua latou fao mea;", "and exercised robbery,"], ["ua latou faatiga i e ua puapuagatia ma e ua matitiva;", "and have vexed the poor and needy: yea,"], ["ua latou faasaua foi i le tagata ese a e lei faamasinoina.", "they have oppressed the stranger wrongfully."]]},
  {num:30,words:[["Na ou saili ia te i latou se tagata na te atiaeina le pa,", "And I sought for a man among them,"], ["ma tu i le mea ua lepetia i o'u luma mo le nuu,", "that should make up the hedge,"], ["ina ia ou le faaumatia ai;", "and stand in the gap before me for the land, that I should not destroy it:"], ["a e ou te lei maua lava.", "but I found none."]]},
  {num:31,words:[["O le mea lea ou te liligi atu ai lo'u ita i luga ia te i latou,", "Therefore have I poured out mine indignation upon them;"], ["ma ou faaumatia i latou i le afi o lo'u ita;", "I have consumed them with the fire of my wrath:"], ["ou te tauia a latou amio i luga i o latou ulu,", "their own way have I recompensed upon their heads,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
];
renderVerseSet(ezk_ch_22_Verses, 'ezk-ch22-verses');

var ezk_ch_23_Verses = [
  {num:1,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "The word of the LORD came again unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["o fafine e toalua,", "there were two women,"], ["o tama a le fafine e toatasi,", "the daughters of one mother:"]]},
  {num:3,words:[["na la talitane i Aikupito;", "And they committed whoredoms in Egypt;"], ["na la talitane a o teine muli i laua;", "they committed whoredoms in their youth:"], ["na omia ai o laua susu;", "there were their breasts pressed,"], ["na tatao ai susu o laua o taupou.", "and there they bruised the teats of their virginity."]]},
  {num:4,words:[["O la igoa foi,", "And the names of them were Aholah the elder,"], ["o Aola le matua,", "and Aholibah her sister:"], ["ma Aolipa lona uso; na fai foi i laua ma'u,", "and they were mine,"], ["na la fananau foi tama tane ma tama teine.", "and they bare sons and daughters."], ["A o laua igoa,", "Thus were their names;"], ["o Aola o Samaria lea,", "Samaria is Aholah,"], ["o Aolipa o Ierusalema lea.", "and Jerusalem Aholibah."]]},
  {num:5,words:[["Na mulilua Aola ina o fai ma'u;", "And Aholah played the harlot when she was mine;"], ["na ia tu'inanau atu foi i e na mananao ia te ia,", "and she doted on her lovers,"], ["o Asuria o e vāvā lalata ma ia .", "on the Assyrians her neighbours,"]]},
  {num:6,words:[["Ua oofu i latou i ofu uli,", "Which were clothed with blue,"], ["o ta'ita'i,", "captains and rulers,"], ["ma faipule, o taulelea aulelei i latou uma,", "all of them desirable young men,"], ["o 'au o tietie i solofanua.", "horsemen riding upon horses."]]},
  {num:7,words:[["Na ia talitane ia i latou,", "Thus she committed her whoredoms with them,"], ["o i latou uma o aupito sili i tagata o Asuria,", "with all them that were the chosen men of Assyria,"], ["ma i latou uma na ia tu'inanau i ai;", "and with all on whom she doted:"], ["na faaleagaina o ia e ia i a latou tupua uma.", "with all their idols she defiled herself."]]},
  {num:8,words:[["Na ia le tuua lona talitane mai Aikupito;", "Neither left she her whoredoms brought from Egypt:"], ["auā na latou momoe ma ia ina o teine muli,", "for in her youth they lay with her,"], ["na latou tatao foi ona susu o taupou o ia,", "and they bruised the breasts of her virginity,"], ["ma sasaa a latou faitaaga i luga ia te ia.", "and poured their whoredom upon her."]]},
  {num:9,words:[["O le mea lea na ou tuuina atu ai o ia i lima o e na mananao ia te ia,", "Wherefore I have delivered her into the hand of her lovers,"], ["o lima lava o tagata o Asuria,", "into the hand of the Assyrians,"], ["na ia tu'inanau i ai.", "upon whom she doted."]]},
  {num:10,words:[["O i latou ua latou faatelenoa ia te ia;", "These discovered her nakedness:"], ["na latou ave foi ana tama tane ma ana tama teine;", "they took her sons and her daughters,"], ["na latou fasioti foi ia te ia i le pelu,", "and slew her with the sword: and she became famous among women;"], ["ona logologoa lea o ia i fafine ina ua latou faasalaina o ia.", "for they had executed judgment upon her."]]},
  {num:11,words:[["Ua iloa e lona uso o Aolipa,", "And when her sister Aholibah saw this,"], ["ona faasili lea e ia o lona tu'inanau i le tu'inanau o lona uso,", "she was more corrupt in her inordinate love than she,"], ["ma lona talitane na sili i le talitane o lona uso.", "and in her whoredoms more than her sister in her whoredoms."]]},
  {num:12,words:[["Na ia tu'inanau i tagata o Asuria,", "She doted upon the Assyrians her neighbours,"], ["o e vava lalata ma ia ,", "captains and rulers clothed most gorgeously,"], ["o ta'ita'i ma faipule o loo oofu faamatagofie lava, o 'au o tietie i solofanua,", "horsemen riding upon horses,"], ["o taulelea 'aulelei i latou uma.", "all of them desirable young men."]]},
  {num:13,words:[["Ona ou iloa lea ua leaga o ia,", "Then I saw that she was defiled,"], ["ua tasi lava lo laua ala.", "that they took both one way,"]]},
  {num:14,words:[["Ua faateleina e ia lona talitane;", "And that she increased her whoredoms:"], ["auā na ia iloa tane na tusia i le pa, o faatagata foi o Kaletaia,", "for when she saw men pourtrayed upon the wall,"], ["ua tusia i le vali mūmū,", "the images of the Chaldeans pourtrayed with vermilion,"]]},
  {num:15,words:[["ua fusia o latou sulugatiti i fusi,", "Girded with girdles upon their loins,"], ["ua i o latou ulu o pulou lanu eseese,", "exceeding in dyed attire upon their heads,"], ["e tino mai i alii ta'ita'i 'au i latou uma,", "all of them princes to look to,"], ["e pei o tagata Papelonia o Kaletaia ia,", "after the manner of the Babylonians of Chaldea,"], ["o le nuu na fanau ai i latou.", "the land of their nativity:"]]},
  {num:16,words:[["Ua ia vaai atu i ai,", "And as soon as she saw them with her eyes,"], ["ona ia tu'inanau atu ai lea ia te i latou;", "she doted upon them,"], ["na ia aauina atu foi auauna ia te i latou i Kaletaia.", "and sent messengers unto them into Chaldea."]]},
  {num:17,words:[["Ona o mai ai lea o tagata o Papelonia ia te ia i le moega e faatasi ai,", "And the Babylonians came to her into the bed of love,"], ["ona latou faaleaga lea ia te ia i a latou faitaaga,", "and they defiled her with their whoredom,"], ["ona leaga ai lea o ia ia te i latou,", "and she was polluted with them,"], ["ona liliu ese ai lea o lona loto ia te i latou.", "and her mind was alienated from them."]]},
  {num:18,words:[["Na ia faaalia lona talitane,", "So she discovered her whoredoms,"], ["na ia faaalia foi lona le lavalavā;", "and discovered her nakedness:"], ["ona liliu ese ai lea o lo'u loto ia te ia,", "then my mind was alienated from her,"], ["e pei ona liliu ese o lo'u loto i lona uso.", "like as my mind was alienated from her sister."]]},
  {num:19,words:[["A ua ia faateleina lona talitane i lona manatu i ona po ina o teine muli o ia,", "Yet she multiplied her whoredoms, in calling to remembrance the days of her youth,"], ["na ia talitane ai i le nuu o Aikupito.", "wherein she had played the harlot in the land of Egypt."]]},
  {num:20,words:[["Auā na ia tu'inanau atu ia latou momoe ma ia,", "For she doted upon their paramours,"], ["o latou tino e pei o le tino o le asini,", "whose flesh is as the flesh of asses,"], ["ma le sua o latou tino e pei o le sua o le tino o le solofanua.", "and whose issue is like the issue of horses."]]},
  {num:21,words:[["Ua e toe manatua mea leaga na e faia ina o e teine muli,", "Thus thou calledst to remembrance the lewdness of thy youth,"], ["ina ua omia ou susu e tagata o Aikupito ona o ou susu ina o e teine muli.", "in bruising thy teats by the Egyptians for the paps of thy youth."]]},
  {num:22,words:[["O le mea lea,", "Therefore,"], ["Aolipa e,", "O Aholibah,"], ["o loo faapea ona fetalai mai ai o le Alii o Ieova,", "thus saith the Lord GOD;"], ["Faauta, ou te faaoso e tau ma oe e sa mananao ia te oe,", "Behold,"], ["o e ua liliu ese ai lou loto,", "I will raise up thy lovers against thee,"], ["ou te aumaia i latou mai itu uma,", "from whom thy mind is alienated,"], ["latou te tau ma oe;", "and I will bring them against thee on every side;"]]},
  {num:23,words:[["o tagata o Papelonia,", "The Babylonians,"], ["atoa ma Kaletaia uma,", "and all the Chaldeans,"], ["o Pekota,", "Pekod,"], ["ma Soa,", "and Shoa,"], ["ma Koa, o tagata uma o Asuria e faatasi ma i latou;", "and Koa,"], ["o taulelea aulelei,", "and all the Assyrians with them:"], ["o ta'ita'i,", "all of them desirable young men,"], ["ma faipule i latou uma,", "captains and rulers,"], ["o e ave 'au ma e ta'ua,", "great lords and renowned,"], ["o tietie i latou uma i solofanua.", "all of them riding upon horses."]]},
  {num:24,words:[["E o mai i latou ia te oe ma auupega,", "And they shall come against thee with chariots,"], ["ma kariota, ma mea taavavale,", "wagons,"], ["ma 'au o nuu;", "and wheels,"], ["latou te vagaia oe ma le talipupuni,", "and with an assembly of people,"], ["ma le talita,", "which shall set against thee buckler and shield and helmet round about:"], ["ma le puloutau; ou te tuuina foi le faamasinoga i o latou luma,", "and I will set judgment before them,"], ["latou te faamasino ia te oe e tusa ma a latou faamasinoga.", "and they shall judge thee according to their judgments."]]},
  {num:25,words:[["Ou te faaoo atu lo'u fuā ia te oe,", "And I will set my jealousy against thee,"], ["latou te faasaua lava ia te oe;", "and they shall deal furiously with thee:"], ["latou te fisiesea lou isu, ma ou taliga;", "they shall take away thy nose and thine ears;"], ["e oti i le pelu e ua totoe ia te oe;", "and thy remnant shall fall by the sword:"], ["latou te ave au tama tane ma au tama fafine,", "they shall take thy sons and thy daughters;"], ["e faaumatia foi i le afi e ua totoe ia te oe.", "and thy residue shall be devoured by the fire."]]},
  {num:26,words:[["Latou te toese foi ia te oe ou ofu,", "They shall also strip thee out of thy clothes,"], ["ma ave au teuga matagofie.", "and take away thy fair jewels."]]},
  {num:27,words:[["Ou te faaiuina lou leaga ma lou talitane mai le nuu o Aikupito;", "Thus will I make thy lewdness to cease from thee,"], ["ona e le toe faasaga ae lea o ou mata ia te i latou,", "and thy whoredom brought from the land of Egypt: so that thou shalt not lift up thine eyes unto them,"], ["ma ē le toe manatua lava Aikupito.", "nor remember Egypt any more."]]},
  {num:28,words:[["Auā o loo faapea ona fetalai mai o le Alii o Ieova,", "For thus saith the Lord GOD;"], ["Faauta,", "Behold,"], ["ou te tuuina atu oe i lima o e ua e 'ino'ino i ai,", "I will deliver thee into the hand of them whom thou hatest,"], ["o lima o e ua liliu ese ai lou loto.", "into the hand of them from whom thy mind is alienated:"]]},
  {num:29,words:[["Latou te 'ino'ino lava ia te oe,", "And they shall deal with thee hatefully,"], ["latou te ave foi au mea uma sa e tautiga ai,", "and shall take away all thy labour,"], ["latou te tuua oe e le ufiufitia ma le le lavalavā;", "and shall leave thee naked and bare:"], ["e faaalia foi le leaga o lou talitane,", "and the nakedness of thy whoredoms shall be discovered,"], ["o lou ulavale atoa ma au faitaaga.", "both thy lewdness and thy whoredoms."]]},
  {num:30,words:[["Ou te faia ia mea ia te oe,", "I will do these things unto thee,"], ["auā ua e mulimuli atu i nuu ese e faitaaga ai,", "because thou hast gone a whoring after the heathen,"], ["o i latou ia ua leaga ai oe i a latou tupua.", "and because thou art polluted with their idols."]]},
  {num:31,words:[["Ua e savali i le ala o lou uso;", "Thou hast walked in the way of thy sister;"], ["o le mea lea ou te tuuina atu ai lana ipu i lou lima.", "therefore will I give her cup into thine hand."]]},
  {num:32,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["E te inu i le ipu a lou uso,", "Thou shalt drink of thy sister's cup deep and large:"], ["e loloto ma le tele, e fai oe ma mea e featani ai ma tauemuina ai;", "thou shalt be laughed to scorn and had in derision;"], ["e tele lava mea o i ai.", "it containeth much."]]},
  {num:33,words:[["E faatumuina oe i le onaga ma le faanoanoa,", "Thou shalt be filled with drunkenness and sorrow,"], ["o le ipu o le fememeai ma le faatafunuaga,", "with the cup of astonishment and desolation,"], ["o le ipu a lou uso o Samaria.", "with the cup of thy sister Samaria."]]},
  {num:34,words:[["E te inu ai ma mitia lava,", "Thou shalt even drink it and suck it out,"], ["e te taei foi i ona taega ipu,", "and thou shalt break the sherds thereof,"], ["ma e saeia ou lava susu;", "and pluck off thine own breasts:"], ["auā o a'u ua ou fai atu ai,", "for I have spoken it,"], ["o loo faapea mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:35,words:[["O le mea lea o loo faapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["Ua e faagalogalo mai ia te au,", "Because thou hast forgotten me,"], ["ma ua e lafoaiina a'u i ou tua, o le mea lea ia taui ai ia te oe o lou ulavale,", "and cast me behind thy back,"], ["ma au faitaaga.", "therefore bear thou also thy lewdness and thy whoredoms."]]},
  {num:36,words:[["Ua fetalai mai foi Ieova ia te au,", "The LORD said moreover unto me;"], ["Le atalii e o le tagata,", "Son of man,"], ["e te le faamasino ea ia Aola ma Aolipa,", "wilt thou judge Aholah and Aholibah? yea,"], ["ma e faaali ia te i laua mea e inosia?", "declare unto them their abominations;"]]},
  {num:37,words:[["Auā ua la mulilulua,", "That they have committed adultery,"], ["ua i ai foi le toto i o laua lima;", "and blood is in their hands,"], ["ua la mulilulua i a la tupua;", "and with their idols have they committed adultery, and have also caused their sons,"], ["o a laua fanau foi na la fanau mai ai ia te au,", "whom they bare unto me,"], ["ua la faaui ane i le afi ,", "to pass for them through the fire,"], ["ia faaumatia ai mo i latou.", "to devour them."]]},
  {num:38,words:[["Ua la faia foi lenei mea ia te au;", "Moreover this they have done unto me:"], ["ua la faaleagaina lo'u malumalu i lea lava aso,", "they have defiled my sanctuary in the same day,"], ["ma o'u sapati ua la solia;", "and have profaned my sabbaths."]]},
  {num:39,words:[["ua la fasia a laua fanau mo tupua,", "For when they had slain their children to their idols,"], ["ona o mai ai lea o i laua i lo'u malumalu i lea lava aso e soli ai;", "then they came the same day into my sanctuary to profane it;"], ["faauta foi,", "and, lo,"], ["na faapea ona la faia i totonu o lo'u fale.", "thus have they done in the midst of mine house."]]},
  {num:40,words:[["I le ma lea foi,", "And furthermore,"], ["ua oulua feauina tane ia o mai i le mea mamao,", "that ye have sent for men to come from far,"], ["na auina atu ia te i latou le auauna,", "unto whom a messenger was sent;"], ["faauta foi,", "and,"], ["na latou o mai;", "lo, they came:"], ["na e taele ona o i latou,", "for whom thou didst wash thyself,"], ["ma e valia ou mata,", "paintedst thy eyes,"], ["ma e teuteu i mea e faamatagofie a'i.", "and deckedst thyself with ornaments,"]]},
  {num:41,words:[["Na e nofo foi i luga o le moega lalelei,", "And satest upon a stately bed,"], ["ua saunia le laulau i ona luma, na e faaeeina i ona luga a'u mea manogi,", "and a table prepared before it,"], ["ma a'u suāuu.", "whereupon thou hast set mine incense and mine oil."]]},
  {num:42,words:[["Na ia te ia foi le leo o le vao tagata ua nonofo faatalanoa;", "And a voice of a multitude being at ease was with her:"], ["na aumaia foi ia te ia e faatasi ma tagata lautele,", "and with the men of the common sort were brought Sabeans from the wilderness,"], ["o tagata Sepea mai le vao, sa i ai taulima i o latou lima,", "which put bracelets upon their hands,"], ["ma pale matagofie i o latou ulu.", "and beautiful crowns upon their heads."]]},
  {num:43,words:[["Ona ou fai atu ai lea ia te ia le ua loa ona fai pea o muliluaga,", "Then said I unto her that was old in adulteries,"], ["Latou te faitaaga lava ea ma ia,", "Will they now commit whoredoms with her,"], ["o ia foi ma i latou?", "and she with them?"]]},
  {num:44,words:[["A ua latou o ane lava ia te ia,", "Yet they went in unto her,"], ["e pei ona latou o ane i le fafine talitane,", "as they go in unto a woman that playeth the harlot:"], ["na faapea ona latou o ane ia Aola ma Aolipa,", "so went they in unto Aholah and unto Aholibah,"], ["o fafine ulavavale.", "the lewd women."]]},
  {num:45,words:[["O tagata amiotonu latou te faamasino ia te i laua,", "And the righteous men,"], ["e pei ona faamasino o fafine mulilulua,", "they shall judge them after the manner of adulteresses,"], ["e pei ona faamasino foi o fafine e faamaligi toto;", "and after the manner of women that shed blood;"], ["auā o fafine mulilulua i laua,", "because they are adulteresses,"], ["ua i ai foi le toto i o laua lima.", "and blood is in their hands."]]},
  {num:46,words:[["Auā o loo faapea ona fetalai mai o le Alii o Ieova,", "For thus saith the Lord GOD;"], ["Ou te aveina ae le motu o tagata ia te i laua, ou te tuuina atu foi i laua ia faasaunoaina,", "I will bring up a company upon them,"], ["ma ia vetea a laua mea .", "and will give them to be removed and spoiled."]]},
  {num:47,words:[["E fetogia i laua e le motu o tagata i maa,", "And the company shall stone them with stones,"], ["e taia i laua i a latou pelu;", "and dispatch them with their swords;"], ["latou te fasiotia foi a laua tama tane ma a laua tama fafine,", "they shall slay their sons and their daughters,"], ["ma susunuina o laua fale i le afi.", "and burn up their houses with fire."]]},
  {num:48,words:[["Ona ou faagataina lea o le ulavale i le nuu,", "Thus will I cause lewdness to cease out of the land,"], ["ina ia a'oa'o ai fafine uma ia le toe fai e pei o lo oulua ulavale.", "that all women may be taught not to do after your lewdness."]]},
  {num:49,words:[["Latou te taui atu lava lo oulua ulavale ia te oulua,", "And they shall recompense your lewdness upon you,"], ["e taui foi ia te oulua le agasala i a oulua tupua;", "and ye shall bear the sins of your idols:"], ["ona oulua iloa ai lea o a'u lava o le Alii o Ieova.", "and ye shall know that I am the Lord GOD."]]},
];
renderVerseSet(ezk_ch_23_Verses, 'ezk-ch23-verses');

var ezk_ch_24_Verses = [
  {num:1,words:[["Ua oo mai foi le afioga a Ieova ia te au i le iva o tausaga i le sefulu o masina,", "Again in the ninth year, in the tenth month,"], ["i le aso e sefulu o le masina,", "in the tenth day of the month,"], ["ua faapea mai,", "the word of the LORD came unto me, saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia e tusia le igoa o le aso,", "write thee the name of the day,"], ["o lenei lava aso;", "even of this same day:"], ["na papai le tupu o Papelonia i Ierusalema i lenei lava aso.", "the king of Babylon set himself against Jerusalem this same day."]]},
  {num:3,words:[["Sauni atu ia se faataoto i le aiga fouvale,", "And utter a parable unto the rebellious house,"], ["ma fai atu ia te i latou,", "and say unto them,"], ["O loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Faaee ia se ulo,", "Set on a pot,"], ["ina faaee ia,", "set it on,"], ["ma liligi i ai se vai.", "and also pour water into it:"]]},
  {num:4,words:[["Faapotopoto i ai ona tufaaga,", "Gather the pieces thereof into it,"], ["o tufaaga lelei uma;", "even every good piece,"], ["o le alagavae,", "the thigh,"], ["ma le alagalima,", "and the shoulder;"], ["ina faatumu ia i ivi e sili ona lelei.", "fill it with the choice bones."]]},
  {num:5,words:[["Ina ave ia e ua sili ona lelei o le lafu mamoe,", "Take the choice of the flock,"], ["ma faaputuina ivi i ona lalo,", "and burn also the bones under it,"], ["ia faavevela ia, ia pupuna,", "and make it boil well,"], ["ma ia latou tunua ivi o i ai.", "and let them seethe the bones of it therein."]]},
  {num:6,words:[["O le mea lea ua faapea ona fetalai mai ai o le Alii o Ieova,", "Wherefore thus saith the Lord GOD;"], ["Oi talofa i le aai o e totolima,", "Woe to the bloody city,"], ["o le ulo ua i ai lona otaota,", "to the pot whose scum is therein,"], ["ma ua le te'a ese ai lona otaota. Ina to ae ia tufaaga taitasi,", "and whose scum is not gone out of it! bring it out piece by piece;"], ["aua ne'i fai i ai se vili.", "let no lot fall upon it."]]},
  {num:7,words:[["Auā o loo i totonu ia te ia le toto o lana fasi;", "For her blood is in the midst of her;"], ["na ia tuu ai i luga lava o le papa iila;", "she set it upon the top of a rock; she poured it not upon the ground,"], ["ua ia le sasaa i ai i le eleele e ufitia ai i le efuefu.", "to cover it with dust;"]]},
  {num:8,words:[["Ua ou tuuina le toto o lana fasi i luga o le papa iila,", "That it might cause fury to come up to take vengeance;"], ["ia le ufitia, ina ia faatupuina ai le ita,", "I have set her blood upon the top of a rock,"], ["ia matuā taui atu ai.", "that it should not be covered."]]},
  {num:9,words:[["O le mea lea o loo faapea ona fetalai mai ai o le Alii o Ieova, Oi talofa i le aai o e totolima;", "Therefore thus saith the Lord GOD;"], ["o a'u, ou te faateleina le faaputuga fafie .", "Woe to the bloody city! I will even make the pile for fire great."]]},
  {num:10,words:[["La'u tele ane ia o fafie,", "Heap on wood,"], ["ina faamumū ia le afi,", "kindle the fire,"], ["ia faaumatia le aano,", "consume the flesh,"], ["ia matuā faamanogi i ai,", "and spice it well,"], ["o ivi foi ia susunuina.", "and let the bones be burned."]]},
  {num:11,words:[["I le faaee ane ai e le sua,", "Then set it empty upon the coals thereof,"], ["i luga i ona malala,", "that the brass of it may be hot,"], ["ina ia vevela lona 'apa memea, ma ia aasa,", "and may burn,"], ["ia usi ai lona leaga i totonu,", "and that the filthiness of it may be molten in it,"], ["ia faaumatia lona otaota.", "that the scum of it may be consumed."]]},
  {num:12,words:[["Ua lailoa lava ia i galuega mamafa,", "She hath wearied herself with lies,"], ["a e lei mavae atu lona otaota tele ia te ia;", "and her great scum went not forth out of her:"], ["e i le afi lona otaota.", "her scum shall be in the fire."]]},
  {num:13,words:[["E i ai le ulavale i lou leaga,", "In thy filthiness is lewdness:"], ["auā ua ou faamamāina oe,", "because I have purged thee,"], ["a e lei mamā oe;", "and thou wast not purged,"], ["e le toe faamamāina lava oe i lou leaga,", "thou shalt not be purged from thy filthiness any more,"], ["seia ou faataunuu atu lo'u ita ia te oe.", "till I have caused my fury to rest upon thee."]]},
  {num:14,words:[["O a'u o Ieova ua ou fai atu,", "I the LORD have spoken it:"], ["e oo lava,", "it shall come to pass,"], ["ou te faia lava;", "and I will do it;"], ["ou te le tuua,", "I will not go back,"], ["ou te le faasaoina,", "neither will I spare, neither will I repent;"], ["ou te le salamo;", "according to thy ways,"], ["latou te faamasino ia te oe e tusa ma ou ala,", "and according to thy doings,"], ["ma au mea ua e faia,", "shall they judge thee,"], ["ua fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:15,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "Also the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:16,words:[["Le atalii e o le tagata, faauta,", "Son of man,"], ["o le a ou aveeseina ia te oe,", "behold,"], ["i le mala, le ua e fiafia i ai;", "I take away from thee the desire of thine eyes with a stroke:"], ["a e te le tagitu'i,", "yet neither shalt thou mourn nor weep,"], ["e te le tagi, e le maligi ifo foi ou loimata.", "neither shall thy tears run down."]]},
  {num:17,words:[["Ia e oi lemu,", "Forbear to cry,"], ["aua le faanoanoa i e ua oti,", "make no mourning for the dead,"], ["nonoa ia lou pale ia te oe,", "bind the tire of thine head upon thee,"], ["ma faasee ou vae,", "and put on thy shoes upon thy feet,"], ["aua le ufitia lou laugutu aupitoaluga,", "and cover not thy lips,"], ["aua foi e te 'ai le mea e 'ai a tagata.", "and eat not the bread of men."]]},
  {num:18,words:[["Ona ou tautala atu lea i le nuu i le taeao,", "So I spake unto the people in the morning:"], ["na oti foi la'u avā i le afiafi;", "and at even my wife died;"], ["ona ou fai lea i le taeao e pei ona poloaiina mai ai o a'u.", "and I did in the morning as I was commanded."]]},
  {num:19,words:[["Ona fai mai ai lea o le nuu ia te au,", "And the people said unto me,"], ["E te le faaali mai ea ia te i matou,", "Wilt thou not tell us what these things are to us,"], ["po o a ea ia mea ia te i matou ua e faia?", "that thou doest so?"]]},
  {num:20,words:[["Ona ou fai atu ai lea ia te i latou,", "Then I answered them,"], ["Na oo mai le afioga a Ieova ia te au,", "The word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:21,words:[["Fai atu ia i le aiga o Isaraelu,", "Speak unto the house of Israel,"], ["O loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Faauta,", "Behold,"], ["ou te faaleagaina lo'u malumalu,", "I will profane my sanctuary,"], ["o lo outou malosi tou te mitamita ai, o le mea ua outou fiafia i ai,", "the excellency of your strength,"], ["ma le mea ua naunau i ai o outou loto;", "the desire of your eyes,"], ["o outou atalii foi ma o outou afafine o e ua tuua e outou,", "and that which your soul pitieth;"], ["e oti i latou i le pelu.", "and your sons and your daughters whom ye have left shall fall by the sword."]]},
  {num:22,words:[["Tou te fai foi e pei ona faia e a'u;", "And ye shall do as I have done:"], ["tou te le ufitia o outou laugutu aupitoaluga,", "ye shall not cover your lips,"], ["tou te le aai foi le mea e 'ai a tagata.", "nor eat the bread of men."]]},
  {num:23,words:[["E i ai o outou pale i o outou ulu,", "And your tires shall be upon your heads,"], ["ma o outou seevae i o outou vae;", "and your shoes upon your feet:"], ["tou te le tagitu'i, tou te le fetagisi;", "ye shall not mourn nor weep;"], ["a e tauāu ina faaumatia outou ona o a outou agasala,", "but ye shall pine away for your iniquities,"], ["tou te feoi foi le tasi i le tasi.", "and mourn one toward another."]]},
  {num:24,words:[["O lea e fai ai Esekielu ma faailoga ia te outou;", "Thus Ezekiel is unto you a sign:"], ["e faapei o mea uma ua faia e ia e faapea foi ona faia e outou;", "according to all that he hath done shall ye do:"], ["a oo mai lea mea,", "and when this cometh,"], ["ona outou iloa ai lea o a'u lava o le Alii o Ieova.", "ye shall know that I am the Lord GOD."]]},
  {num:25,words:[["O oe na foi le atalii o le tagata,", "Also,"], ["o le aso ou te aveeseina ai ia te i latou lo latou malosi,", "thou son of man,"], ["o le fiafia i lo latou mamalu,", "shall it not be in the day when I take from them their strength, the joy of their glory,"], ["o le mea ua latou fiafia i ai,", "the desire of their eyes,"], ["o le mea ua naunau i ai o latou loto,", "and that whereupon they set their minds,"], ["o latou atalii ma o latou afafine,", "their sons and their daughters,"]]},
  {num:26,words:[["e le sau ea ia te oe le ua sao i lea aso e logologo ai ia te oe?", "That he that escapeth in that day shall come unto thee, to cause thee to hear it with thine ears?"]]},
  {num:27,words:[["O le aso lea e faagaganaina ai oe i le ua sao mai,", "In that day shall thy mouth be opened to him which is escaped,"], ["ona e tautala lea,", "and thou shalt speak,"], ["ma e le toe faalologo;", "and be no more dumb:"], ["e fai foi oe ma faailoga ia te i latou;", "and thou shalt be a sign unto them;"], ["ona iloa ai lea e i latou o a'u lava o Ieova.", "and they shall know that I am the LORD."]]},
];
renderVerseSet(ezk_ch_24_Verses, 'ezk-ch24-verses');

var ezk_ch_25_Verses = [
  {num:1,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "The word of the LORD came again unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia faasaga ou mata i le fanauga a Amoni,", "set thy face against the Ammonites,"], ["ma vavalo atu ia te i latou;", "and prophesy against them;"]]},
  {num:3,words:[["ma fai atu i le fanauga a Amoni,", "And say unto the Ammonites, Hear the word of the Lord GOD;"], ["Faalogo mai ia i le afioga a le Alii o Ieova. O loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD; Because thou saidst,"], ["Sa e fai mai,", "Aha, against my sanctuary,"], ["Ue! i lo'u malumalu ina ua faaleagaina,", "when it was profaned;"], ["ma le laueleele o Isaraelu ina ua faatafunaina,", "and against the land of Israel, when it was desolate;"], ["ma le aiga o Iuta ina ua latou o i le tafeaga;", "and against the house of Judah, when they went into captivity;"]]},
  {num:4,words:[["o le mea lea,", "Behold,"], ["faauta,", "therefore I will deliver thee to the men of the east for a possession,"], ["ou te tuuina atu ai oe i tagata mai sasae e fai mo latou tofi, latou te faatuina o latou 'olo i lou nuu ,", "and they shall set their palaces in thee,"], ["ma fai o latou fale i lou nuu;", "and make their dwellings in thee:"], ["latou te aai foi i au fua,", "they shall eat thy fruit,"], ["ma inu i lau suāsusu.", "and they shall drink thy milk."]]},
  {num:5,words:[["Ou te tuuina foi Rapa e fai ma lotoā a kamela,", "And I will make Rabbah a stable for camels,"], ["ma le laueleele o le fanauga a Amoni e fai ma mea e taooto ai lafu mamoe;", "and the Ammonites a couchingplace for flocks:"], ["tou te iloa ai o a'u lava o Ieova.", "and ye shall know that I am the LORD."]]},
  {num:6,words:[["Auā ua faapea ona fetalai mai o le Alii o Ieova,", "For thus saith the Lord GOD;"], ["Na e pati lima,", "Because thou hast clapped thine hands,"], ["ma tatū lou vae,", "and stamped with the feet,"], ["ma ua e olioli ma le matuā 'ino'ino lava o lou loto i le laueleele o Isaraelu;", "and rejoiced in heart with all thy despite against the land of Israel;"]]},
  {num:7,words:[["o le mea lea,", "Behold,"], ["faauta,", "therefore I will stretch out mine hand upon thee,"], ["ou te faaloaloa ai lo'u lima i luga ia te oe,", "and will deliver thee for a spoil to the heathen;"], ["ma ou tuuina atu oe e fai ma vete mo nuu ese, ou te vavae ese ia te oe i nuu,", "and I will cut thee off from the people,"], ["e fano foi oe ia te au ai atu nuu;", "and I will cause thee to perish out of the countries:"], ["ou te faaumatia oe;", "I will destroy thee;"], ["ona e iloa ai lea o a'u lava o Ieova.", "and thou shalt know that I am the LORD."]]},
  {num:8,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Ua fai mai Moapi ma Seira,", "Because that Moab and Seir do say,"], ["Faauta,", "Behold,"], ["e tusa le aiga o Iuta ma nuu uma.", "the house of Judah is like unto all the heathen;"]]},
  {num:9,words:[["O le mea lea,", "Therefore,"], ["faauta,", "behold,"], ["ou te faaavanoaina ai le itu o Moapi i aai,", "I will open the side of Moab from the cities,"], ["o ona aai foi i ona tuaoi,", "from his cities which are on his frontiers,"], ["o le matagofie foi o le nuu,", "the glory of the country,"], ["o Petesemota,", "Beth-jeshimoth,"], ["o Paalameona,", "Baal-meon,"], ["ma Kiriataima;", "and Kiriathaim,"]]},
  {num:10,words:[["ou te faaavanoa ai i tagata mai sasae,", "Unto the men of the east with the Ammonites,"], ["ma ou tuuina atu ai e faatasi ma le fanauga a Amoni e fai mo latou tofi,", "and will give them in possession,"], ["ina ia le toe manatua le fanauga a Amoni i nuu.", "that the Ammonites may not be remembered among the nations."]]},
  {num:11,words:[["Ou te faasalaina foi ia Moapi;", "And I will execute judgments upon Moab;"], ["ona latou iloa ai lea o a'u lava o Ieova.", "and they shall know that I am the LORD."]]},
  {num:12,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Ua matuā taui ma sui e Etoma i le aiga o Iuta,", "Because that Edom hath dealt against the house of Judah by taking vengeance,"], ["ma ua matuā nofo sala lava,", "and hath greatly offended,"], ["ua latou taui atu lava ia te i latou;", "and revenged himself upon them;"]]},
  {num:13,words:[["o le mea lea ua faapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["Ou te faaloaloa atu foi lo'u lima i luga o Etoma, ma ou faaumatia tagata atoa ma manu o i ai;", "I will also stretch out mine hand upon Edom,"], ["ou te faatafunaina ai,", "and will cut off man and beast from it;"], ["e pau mai i Timanu, e pau atu i Titana,", "and I will make it desolate from Teman;"], ["e oti i latou i le pelu.", "and they of Dedan shall fall by the sword."]]},
  {num:14,words:[["Ou te faaoo foi le taui ia Etoma i le lima o lo'u nuu o Isaraelu;", "And I will lay my vengeance upon Edom by the hand of my people Israel:"], ["latou te faia ia Etoma e tusa ma lo'u ita,", "and they shall do in Edom according to mine anger and according to my fury;"], ["e tusa foi ma lo'u ita tele, latou te iloa ai le taui mai ia te au,", "and they shall know my vengeance,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:15,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Ua taui atu e Filisitia,", "Because the Philistines have dealt by revenge, and have taken vengeance with a despiteful heart,"], ["ua matuā taui ma sui ma le 'ino'ino o le loto e faaumatia ai i le itatuu;", "to destroy it for the old hatred;"]]},
  {num:16,words:[["o le mea lea ua faapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["Faauta,", "Behold,"], ["ou te faaloaloa atu lo'u lima i luga o Filisitia,", "I will stretch out mine hand upon the Philistines,"], ["ma ou faaumatia Kereti,", "and I will cut off the Cherethims,"], ["e fano foi ia te au e o totoe i nuu tu matafaga.", "and destroy the remnant of the sea coast."]]},
  {num:17,words:[["Ou te faaoo atu ia te i latou le taui tele ma aoaiga e ogo lava;", "And I will execute great vengeance upon them with furious rebukes;"], ["latou te iloa ai o a'u lava o Ieova,", "and they shall know that I am the LORD,"], ["pe a ou faaoo atu ia te i latou le taui mai ia te au.", "when I shall lay my vengeance upon them."]]},
];
