var ezk_ch_26_Verses = [
  {num:1,words:[["O lona sefulu ma le tasi o tausaga,", "And it came to pass in the eleventh year,"], ["o le aso muamua o le masina,", "in the first day of the month,"], ["na oo mai ai le afioga a Ieova ia te au,", "that the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["ua fai mai Turo ia Ierusalema,", "because that Tyrus hath said against Jerusalem,"], ["Ue! ua lepetia o ia na fai ma faitotoa o nuu,", "Aha, she is broken that was the gates of the people:"], ["ua liliu mai o ia ia te au,", "she is turned unto me:"], ["e faatamaoaigaina ai a'u;", "I shall be replenished,"], ["ua faatafunaina ia.", "now she is laid waste:"]]},
  {num:3,words:[["O le mea lea na faapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["Turo e,", "Behold,"], ["faauta, ou te fai oe mo'u fili,", "I am against thee,"], ["ou te aveina ae nuu e tele,", "O Tyrus,"], ["latou te tau ma oe,", "and will cause many nations to come up against thee,"], ["e pei ona fafati mai o galu o le sami.", "as the sea causeth his waves to come up."]]},
  {num:4,words:[["Latou te sŏloia pa o Turo,", "And they shall destroy the walls of Tyrus,"], ["ma lepetia ona 'olo,", "and break down her towers:"], ["ou te tafiesea lona laueleele,", "I will also scrape her dust from her,"], ["ou te faia foi o ia ma papa iila.", "and make her like the top of a rock."]]},
  {num:5,words:[["E avea ia ma mea e fofola ai upega i totonu o le sami;", "It shall be a place for the spreading of nets in the midst of the sea:"], ["auā o a'u ua ou fai atu,", "for I have spoken it,"], ["o loo fetalai mai ai le Alii o Ieova;", "saith the Lord GOD:"], ["e avea foi o ia ma vete mo nuu ese.", "and it shall become a spoil to the nations."]]},
  {num:6,words:[["O ana tama teine foi o e o i uta e fasiotia i latou i le pelu;", "And her daughters which are in the field shall be slain by the sword;"], ["ona latou iloa ai lea o a'u lava o Ieova.", "and they shall know that I am the LORD."]]},
  {num:7,words:[["Auā ua faapea ona fetalai mai o le Alii o Ieova,", "For thus saith the Lord GOD;"], ["Faauta,", "Behold,"], ["ou te ta'ita'iina mai i Turo o Nepukanesa le tupu o Papelonia,", "I will bring upon Tyrus Nebuchadrezzar king of Babylon,"], ["o le tupu o tupu,", "a king of kings,"], ["mai le itu i matu,", "from the north,"], ["ma solofanua,", "with horses,"], ["ma kariota,", "and with chariots,"], ["ma e tietie i solofanua,", "and with horsemen,"], ["ma 'au,", "and companies,"], ["ma tagata e toatele.", "and much people."]]},
  {num:8,words:[["Na te fasiotia au tama teine o i uta;", "He shall slay with the sword thy daughters in the field:"], ["na te faia se 'olo ia te oe,", "and he shall make a fort against thee,"], ["ma tanu se mea mautietie ia te oe,", "and cast a mount against thee,"], ["ma faatuina se talipupuni ia te oe.", "and lift up the buckler against thee."]]},
  {num:9,words:[["Na te faatuina atu foi i au pa o mea e lepeti a'i,", "And he shall set engines of war against thy walls,"], ["na te lepetia foi ou 'olo i ana mea maamaai.", "and with his axes he shall break down thy towers."]]},
  {num:10,words:[["O ana solofanua ina tele e ufitia ai oe i le efuefu;", "By reason of the abundance of his horses their dust shall cover thee:"], ["o le taalili o e tietie i solofanua,", "thy walls shall shake at the noise of the horsemen,"], ["ma mea taavavale,", "and of the wheels, and of the chariots,"], ["ma kariota e luluina ai au pa i lona ulu atu i ou faitotoa,", "when he shall enter into thy gates,"], ["e pei ona ulu atu o tagata i le aai ua lepetia.", "as men enter into a city wherein is made a breach."]]},
  {num:11,words:[["E solia ou ala uma i atigivae o ana solofanua;", "With the hoofs of his horses shall he tread down all thy streets:"], ["na te fasiotia ou tagata i le pelu,", "he shall slay thy people by the sword,"], ["e lafoina i lalo i le eleele tupua e i ai lou malosi.", "and thy strong garrisons shall go down to the ground."]]},
  {num:12,words:[["Latou te faoa lou oa,", "And they shall make a spoil of thy riches,"], ["ma fai ma vete au mea e faatau; latou te lepetia au pa,", "and make a prey of thy merchandise:"], ["ma sofaia ou fale lalelei;", "and they shall break down thy walls,"], ["o ou maa foi, ma ou laau,", "and destroy thy pleasant houses:"], ["ma lou eleele latou te lafo i totonu o le sami.", "and they shall lay thy stones and thy timber and thy dust in the midst of the water."]]},
  {num:13,words:[["Ou te faaiuina le taalili o au pese;", "And I will cause the noise of thy songs to cease;"], ["o le leo foi o ou kitara e le toe lagona lava.", "and the sound of thy harps shall be no more heard."]]},
  {num:14,words:[["Ou te faia oe ma papa iila;", "And I will make thee like the top of a rock:"], ["e avea oe ma mea e folasia ai upega;", "thou shalt be a place to spread nets upon;"], ["e le toe faia lava oe;", "thou shalt be built no more:"], ["auā o a'u o Ieova ua ou fai atu ai,", "for I the LORD have spoken it,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:15,words:[["Ua faapea ona fetalai mai o le Alii o Ieova ia Turo,", "Thus saith the Lord GOD to Tyrus;"], ["E le luluina ea nuu tu matafaga i le taalili o lou paū,", "Shall not the isles shake at the sound of thy fall,"], ["pe a uio ē manunua,", "when the wounded cry,"], ["pe a to fasi i totonu ia te oe?", "when the slaughter is made in the midst of thee?"]]},
  {num:16,words:[["Ona o ifo ai lea o alii sili uma o nuu tu matafaga ai o latou nofoālii,", "Then all the princes of the sea shall come down from their thrones,"], ["ma latou tuueseina o latou ofu talaloa,", "and lay away their robes,"], ["ma toeseina o latou ofu lanu eseese;", "and put off their broidered garments:"], ["latou te oofu i le gatete,", "they shall clothe themselves with trembling;"], ["latou te nonofo i le eleele,", "they shall sit upon the ground,"], ["ma saga gatete pea,", "and shall tremble at every moment,"], ["ma fememeai ona o oe.", "and be astonished at thee."]]},
  {num:17,words:[["Latou te sauni foi se pese e aualofa a'i ia te oe,", "And they shall take up a lamentation for thee,"], ["ma latou fai ane ia te oe,", "and say to thee,"], ["E! ua faaumatia oe,", "How art thou destroyed,"], ["sa mau ai tautai,", "that wast inhabited of seafaring men,"], ["o le aai ta'ua,", "the renowned city,"], ["o le na malosi i le sami,", "which wast strong in the sea,"], ["o ia ma e na nonofo ai,", "she and her inhabitants,"], ["o e na faaoo lo latou matautia ia te i latou uma o e na nonofo ai.", "which cause their terror to be on all that haunt it!"]]},
  {num:18,words:[["Ona gatete ai lea o nuu tu loto i le aso e paū ai oe;", "Now shall the isles tremble in the day of thy fall;"], ["o nuu tu loto o i le sami,", "yea,"], ["latou te atuatuvale ina ua e mavae atu.", "the isles that are in the sea shall be troubled at thy departure."]]},
  {num:19,words:[["Auā ua faapea ona fetalai mai o le Alii o Ieova,", "For thus saith the Lord GOD;"], ["A oo ina ou fai oe ma aai faatafunaina e pei o aai ua le āina;", "When I shall make thee a desolate city,"], ["a oo ina ou faaaluina ae le moana i luga ia te oe,", "like the cities that are not inhabited; when I shall bring up the deep upon thee,"], ["ma ufiufitia ai oe i le sami tele;", "and great waters shall cover thee;"]]},
  {num:20,words:[["ma ou ave ifo ia te oe i lalo,", "When I shall bring thee down with them that descend into the pit,"], ["e faatasi ma e ō ifo i le lua,", "with the people of old time,"], ["o nuu o le vavau ia,", "and shall set thee in the low parts of the earth,"], ["ma tuuina oe i mea aupitoalalo o le eleele, o mea ua gaogao talu anamua,", "in places desolate of old,"], ["e faatasi ma e ō ifo i le lua,", "with them that go down to the pit,"], ["ina ia le āina oe;", "that thou be not inhabited;"], ["ou te tuuina foi le mamalu i le nuu o tagata ola.", "and I shall set glory in the land of the living;"]]},
  {num:21,words:[["Ona ou faia lea o oe ma mea e ala ai le mata'u,", "I will make thee a terror,"], ["e le toe ai lava oe;", "and thou shalt be no more:"], ["e sailia oe a e le toe maua lava e faavavau,", "though thou be sought for, yet shalt thou never be found again,"], ["ua fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
];
