var ezk_ch_27_Verses = [
  {num:1,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "The word of the LORD came again unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["O oe na le atalii o le tagata,", "Now, thou son of man,"], ["ia e sauni se pese e aualofa a'i ia Turo;", "take up a lamentation for Tyrus;"]]},
  {num:3,words:[["ma ia e fai atu ia Turo,", "And say unto Tyrus,"], ["O oe o lē nofo i le mea e ui atu ai i le sami,", "O thou that art situate at the entry of the sea,"], ["o le faatauoa o nuu mo nuu tu matafaga e tele,", "which art a merchant of the people for many isles,"], ["ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Turo e,", "O Tyrus,"], ["ua e fai mai,", "thou hast said,"], ["O a'u ua atoatoa lo'u matagofie.", "I am of perfect beauty."]]},
  {num:4,words:[["Ua i totonu o le sami ou tuaoi,", "Thy borders are in the midst of the seas,"], ["ua faaatoatoaina e ou tufuga lou matagofie.", "thy builders have perfected thy beauty."]]},
  {num:5,words:[["Na latou faia ou laupapa uma i perosi mai Senira;", "They have made all thy ship boards of fir trees of Senir:"], ["na latou ave foi arasi mai Lepanona e fai a'i ou fanā.", "they have taken cedars from Lebanon to make masts for thee."]]},
  {num:6,words:[["O aluna mai Vasana na latou fai a'i ou foe;", "Of the oaks of Bashan have they made thine oars; the company of the Ashurites have made thy benches of ivory,"], ["ua faia ou nofoa i nifo elefane ua faamatagofie a'i i tasura mai nuu tu loto o Kitimo.", "brought out of the isles of Chittim."]]},
  {num:7,words:[["O le ie vavae lanu eseese mai Aikupito na e sisi e fai ai mou la;", "Fine linen with broidered work from Egypt was that which thou spreadest forth to be thy sail;"], ["o le ie uli ma le ie pāuli mai nuu tuloto o Elisa na ufitia ai oe.", "blue and purple from the isles of Elishah was that which covered thee."]]},
  {num:8,words:[["O tagata o Saitonu ma Arati,", "The inhabitants of Zidon and Arvad were thy mariners:"], ["na fai i latou mou auvaa;", "thy wise men,"], ["o ou tagata popoto, Turo e,", "O Tyrus,"], ["o e na ia te oe,", "that were in thee,"], ["sa fai mou tautai.", "were thy pilots."]]},
  {num:9,words:[["O toeaina o Kavali ma ona tagata popoto na fai mou tufuga monomono vaa;", "The ancients of Gebal and the wise men thereof were in thee thy calkers:"], ["o vaa uma o le sami ma o latou auvaa na ia te oe e faatau ai lou oloa.", "all the ships of the sea with their mariners were in thee to occupy thy merchandise."]]},
  {num:10,words:[["Sa i lou itu taua o tagata o Peresia, ma Luti,", "They of Persia and of Lud and of Phut were in thine army,"], ["ma Futu,", "thy men of war:"], ["e fai mou tagata tau;", "they hanged the shield and helmet in thee;"], ["na latou tautau le talita ma le puloutau i totonu ia te oe; na latou faamatagofie ai oe.", "they set forth thy comeliness."]]},
  {num:11,words:[["O tagata o Arati ma lou itu taua,", "The men of Arvad with thine army were upon thy walls round about,"], ["sa latou i ai i luga i ou pa i itu uma,", "and the Gammadims were in thy towers:"], ["na i ai foi o Kamati i ou 'olo; na latou tautau faataaliolio o latou talita i ou pa;", "they hanged their shields upon thy walls round about;"], ["na latou faaatoatoaina lou matagofie.", "they have made thy beauty perfect."]]},
  {num:12,words:[["O Tasesa,", "Tarshish was thy merchant by reason of the multitude of all kind of riches;"], ["o le faatauoa lea ia te oe, ina ua tele o oloa uma;", "with silver,"], ["o ario,", "iron,"], ["o uamea,", "tin,"], ["o 'apa sisina, ma pulu,", "and lead,"], ["na latou faatau ai i au faataugāoa.", "they traded in thy fairs."]]},
  {num:13,words:[["O Iavana o Tupalu,", "Javan,"], ["ma Meseko,", "Tubal,"], ["o faatauoa ia ia te oe,", "and Meshech,"], ["na latou faatau tagata,", "they were thy merchants:"], ["ma ipu 'apa memea i ou faataugāoa.", "they traded the persons of men and vessels of brass in thy market."]]},
  {num:14,words:[["Na faatau sa Tokaremo i ou faataugāoa, o solofanua, ma solofanua e tietie ai atoa ma falata.", "They of the house of Togarmah traded in thy fairs with horses and horsemen and mules."]]},
  {num:15,words:[["O le fanauga a Titana o faatauoa i latou ia te oe;", "The men of Dedan were thy merchants;"], ["o nuu tu matafaga e tele na fai ma mea e faatau ai au mea na fai,", "many isles were the merchandise of thine hand:"], ["na latou au mai ia te oe o nifo elefane ma apeni e taui a'i.", "they brought thee for a present horns of ivory and ebony."]]},
  {num:16,words:[["O Suria o le faatauoa lea ia te oe ina ua tele o au mea na e faia,", "Syria was thy merchant by reason of the multitude of the wares of thy making:"], ["na latou faatau i ou faataugāoa,", "they occupied in thy fairs with emeralds,"], ["o le nofeka,", "purple,"], ["ma ie pāuli, ma ofu lanu eseese,", "and broidered work,"], ["ma ie vavae,", "and fine linen,"], ["ma ramuta,", "and coral,"], ["ma maa mūmū.", "and agate."]]},
  {num:17,words:[["O Iuta foi ma le nuu o Isaraelu,", "Judah,"], ["o faatauoa ia ia te oe;", "and the land of Israel,"], ["na latou faatau i ou faataugāoa o le saito Meniti,", "they were thy merchants:"], ["ma panaka,", "they traded in thy market wheat of Minnith, and Pannag,"], ["ma meli,", "and honey,"], ["ma suāuu,", "and oil,"], ["ma pulu pasama.", "and balm."]]},
  {num:18,words:[["O Tamaseko o le faatauoa lea ia te oe i le tele o au mea na e faia,", "Damascus was thy merchant in the multitude of the wares of thy making,"], ["ina ua tele foi o oloa uma,", "for the multitude of all riches;"], ["o uaina o Elepona,", "in the wine of Helbon,"], ["ma fulufulu mamoe sina.", "and white wool."]]},
  {num:19,words:[["O Vetana ma Iavanameusala,", "Dan also and Javan going to and fro occupied in thy fairs:"], ["na latou faatau i ou faataugāoa,", "bright iron,"], ["o uamea gaosia,", "cassia,"], ["ma kesia,", "and calamus,"], ["ma kani sa i ai i ou faataugāoa.", "were in thy market."]]},
  {num:20,words:[["O Titana o le faatauoa lea ia te oe i ofu matagofie mo e tietie i solofanua .", "Dedan was thy merchant in precious clothes for chariots."]]},
  {num:21,words:[["O Arapi,", "Arabia,"], ["ma alii uma o Kitara,", "and all the princes of Kedar,"], ["o faatauoa ia ia te oe, o tamai mamoe,", "they occupied with thee in lambs,"], ["ma mamoe poa,", "and rams,"], ["ma 'oti poa;", "and goats:"], ["o mea ia na latou faatau ai ia te oe.", "in these were they thy merchants."]]},
  {num:22,words:[["O tagata faatauoa o Seepa ma Ragama,", "The merchants of Sheba and Raamah,"], ["o faatauoa ia ia te oe;", "they were thy merchants:"], ["o mea manogi uma e sili,", "they occupied in thy fairs with chief of all spices,"], ["ma maa tāua uma,", "and with all precious stones,"], ["ma auro na latou avane i ou faataugāoa.", "and gold."]]},
  {num:23,words:[["O Karana,", "Haran,"], ["ma Kane,", "and Canneh,"], ["ma Etena,", "and Eden,"], ["o faatauoa o Seepa,", "the merchants of Sheba,"], ["ma Asura,", "Asshur,"], ["ma Kilemata,", "and Chilmad,"], ["o faatauoa ia ia te oe.", "were thy merchants."]]},
  {num:24,words:[["O i latou ia na faatau ia te oe o mea matagofie,", "These were thy merchants in all sorts of things,"], ["o ofu uli,", "in blue clothes,"], ["ma ofu lanu eseese,", "and broidered work, and in chests of rich apparel,"], ["ma ofu lelei silisili ua saisaitia i maea,", "bound with cords,"], ["ua mau,", "and made of cedar,"], ["sa i ai i au mea faatau.", "among thy merchandise."]]},
  {num:25,words:[["O vaa o Tasesa na latou pepese ia te oe i lou faataugāoa;", "The ships of Tarshish did sing of thee in thy market:"], ["na faatamaoaigaina foi oe,", "and thou wast replenished,"], ["na matuā mamalu lava oe i totonu o le sami.", "and made very glorious in the midst of the seas."]]},
  {num:26,words:[["O lou auvaa ua latou aveina oe i le moana sausau;", "Thy rowers have brought thee into great waters:"], ["ua lepetia lava oe i totonu o le sami i le matagi mai sasae.", "the east wind hath broken thee in the midst of the seas."]]},
  {num:27,words:[["O lou oloa,", "Thy riches,"], ["ma ou faataugāoa,", "and thy fairs,"], ["o au mea faatau,", "thy merchandise,"], ["o lou auvaa,", "thy mariners,"], ["ma ou tautai,", "and thy pilots, thy calkers,"], ["o ou tufuga monomono vaa,", "and the occupiers of thy merchandise,"], ["ma tagata e faatau lou oloa,", "and all thy men of war,"], ["ma ou tagata tau uma o ia te oe,", "that are in thee,"], ["atoa ma ou tagata uma lava o loo ia te oe,", "and in all thy company which is in the midst of thee,"], ["e fano i latou i totonu o le sami i le aso e malaia ai oe.", "shall fall into the midst of the seas in the day of thy ruin."]]},
  {num:28,words:[["O le taalili o le alaga o ou tautai e luluina ai ou tuafanua.", "The suburbs shall shake at the sound of the cry of thy pilots."]]},
  {num:29,words:[["O i latou uma foi o e alo foe,", "And all that handle the oar,"], ["o auvaa,", "the mariners,"], ["ma tautai uma o le sami e o ae i latou ai o latou vaa,", "and all the pilots of the sea, shall come down from their ships,"], ["ma tutū i le laueleele.", "they shall stand upon the land;"]]},
  {num:30,words:[["Latou te leo tetele ona o oe,", "And shall cause their voice to be heard against thee,"], ["ma tagiaue faalotulotu,", "and shall cry bitterly,"], ["latou te asu ae le efuefu i o latou ulu;", "and shall cast up dust upon their heads,"], ["latou te taafilifili i le lefulefu.", "they shall wallow themselves in the ashes:"]]},
  {num:31,words:[["Latou te selemamaina o latou lauulu ona o oe,", "And they shall make themselves utterly bald for thee,"], ["ma latou lavalava i ie talatala; latou te fetagisi foi ona o oe ma le tiga tele o le loto,", "and gird them with sackcloth,"], ["ma le tagitu'i faalotulotu.", "and they shall weep for thee with bitterness of heart and bitter wailing."]]},
  {num:32,words:[["Latou te faia le pese e aualofa a'i ona o oe,", "And in their wailing they shall take up a lamentation for thee,"], ["o latou o pepese,", "and lament over thee,"], ["e faapea ane ,", "saying,"], ["O se fea nuu e tusa ma Turo,", "What city is like Tyrus,"], ["e tusa ma le ua fano i totonu o le sami?", "like the destroyed in the midst of the sea?"]]},
  {num:33,words:[["O le tautuu ae o lou oloa ai le sami na e faamalilie ai nuu e tele;", "When thy wares went forth out of the seas, thou filledst many people;"], ["o lou oloa ma au mea faatau ina tele na e faatamaoaigaina ai tupu o le lalolagi.", "thou didst enrich the kings of the earth with the multitude of thy riches and of thy merchandise."]]},
  {num:34,words:[["A ua lepetia nei oe i le sami i le loloto o le moana; ua fano ai au mea faatau, ma ou tagata uma i totonu ia te oe.", "In the time when thou shalt be broken by the seas in the depths of the waters thy merchandise and all thy company in the midst of thee shall fall."]]},
  {num:35,words:[["O i latou uma o e nonofo i nuu tu matafaga ua fememeai i latou ona o oe,", "All the inhabitants of the isles shall be astonished at thee,"], ["o latou tupu foi ua matuā fefefe,", "and their kings shall be sore afraid,"], ["ua soona gatete lava.", "they shall be troubled in their countenance."]]},
  {num:36,words:[["O tagata faatauoa i nuu ua uisa i latou ia te oe;", "The merchants among the people shall hiss at thee;"], ["ua avea oe ma mea e ala ai le mata'u,", "thou shalt be a terror,"], ["e le toe ai lava oe e faavavau.", "and never shalt be any more."]]},
];
renderVerseSet(ezk_ch_27_Verses, 'ezk-ch27-verses');

var ezk_ch_28_Verses = [
  {num:1,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "The word of the LORD came again unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia e fai atu i le alii o Turo,", "say unto the prince of Tyrus,"], ["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Ua faamaualuga lou loto,", "Because thine heart is lifted up,"], ["ma ua e fai mai,", "and thou hast said, I am a God,"], ["O a'u o le atua,", "I sit in the seat of God,"], ["ua ou nofo i le nofoa o le atua i le sami;", "in the midst of the seas;"], ["ua e faatusa foi lou loto i le finagalo o le Atua,", "yet thou art a man,"], ["a o le tagata lava oe,", "and not God,"], ["e le o le Atua.", "though thou set thine heart as the heart of God:"]]},
  {num:3,words:[["Faauta,", "Behold,"], ["ua sili lou poto i lo Tanielu;", "thou art wiser than Daniel;"], ["e leai foi se mea lilo e lilo ia te oe.", "there is no secret that they can hide from thee:"]]},
  {num:4,words:[["O lou poto ma lou faautauta ua e maua ai oloa;", "With thy wisdom and with thine understanding thou hast gotten thee riches,"], ["ua e maua auro ma ario i au mea e teu ai oloa.", "and hast gotten gold and silver into thy treasures:"]]},
  {num:5,words:[["O lou poto ina tele, ma lou faatauina o mea ua e faateleina ai au oloa,", "By thy great wisdom and by thy traffick hast thou increased thy riches,"], ["ma ua faamaualugaina lou loto i au oloa.", "and thine heart is lifted up because of thy riches:"]]},
  {num:6,words:[["O le mea lea o loo faapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["Ua e faatusa lou loto i le finagalo o le Atua;", "Because thou hast set thine heart as the heart of God;"]]},
  {num:7,words:[["faauta,", "Behold,"], ["o le mea lea ou te au mai ai tagata ese ia te oe,", "therefore I will bring strangers upon thee,"], ["o e ua matautia i nuu;", "the terrible of the nations:"], ["latou te to ae foi a latou pelu ia leaga ai le matagofie o lou poto,", "and they shall draw their swords against the beauty of thy wisdom,"], ["latou te faaleagaina lou matagofie.", "and they shall defile thy brightness."]]},
  {num:8,words:[["Latou te ave ifo oe i le lua,", "They shall bring thee down to the pit,"], ["e te oti oe e pei ona oti o e ua fasia i totonu o le sami.", "and thou shalt die the deaths of them that are slain in the midst of the seas."]]},
  {num:9,words:[["E te fai mai pea ea i luma o lē fasioti ia te oe,", "Wilt thou yet say before him that slayeth thee,"], ["O a'u o le atua? a o le tagata lava oe i le lima o lē fasi ia te oe,", "I am God? but thou shalt be a man, and no God,"], ["a e le o le Atua.", "in the hand of him that slayeth thee."]]},
  {num:10,words:[["E te oti e pei ona oti o e lē peritomeina i lima o tagata ese;", "Thou shalt die the deaths of the uncircumcised by the hand of strangers:"], ["auā o a'u nei ua ou fai atu ai,", "for I have spoken it,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:11,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "Moreover the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:12,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia e sauni atu se pese e aualofa a'i i le tupu o Turo,", "take up a lamentation upon the king of Tyrus,"], ["ma fai atu ia te ia,", "and say unto him,"], ["O loo faapea ona fetalai mai o le Alii o Ieova, O oe na,", "Thus saith the Lord GOD;"], ["ua e faamau faailogaina le atoatoa;", "Thou sealest up the sum,"], ["ua tumu oe i le poto,", "full of wisdom,"], ["ua atoatoa foi lou matagofie.", "and perfect in beauty."]]},
  {num:13,words:[["Sa i Etena oe i le faatoaga a le Atua,", "Thou hast been in Eden the garden of God;"], ["na liloia oe i maa tāua uma,", "every precious stone was thy covering,"], ["o le salikea,", "the sardius,"], ["ma le topasi,", "topaz,"], ["ma le ialoma,", "and the diamond,"], ["ma le tasesa,", "the beryl,"], ["ma le soama, ma le iasepi,", "the onyx,"], ["ma le safaira,", "and the jasper,"], ["ma le nofeka,", "the sapphire,"], ["ma le pereketa,", "the emerald,"], ["atoa ma auro;", "and the carbuncle,"], ["na fai au topa ma au fagufagu;", "and gold:"], ["na saunia ia i le aso na faia ai oe.", "the workmanship of thy tabrets and of thy pipes was prepared in thee in the day that thou wast created."]]},
  {num:14,words:[["O oe o le kerupi ua faauuina,", "Thou art the anointed cherub that covereth;"], ["o lē faamalumalu;", "and I have set thee so:"], ["na ou tuuina oe, sa e i luga o le mauga paia o le Atua;", "thou wast upon the holy mountain of God;"], ["sa e fealualuai i le va o maa o le afi.", "thou hast walked up and down in the midst of the stones of fire."]]},
  {num:15,words:[["Na atoatoa ona lelei o au sauniga talu le aso na faia oe,", "Thou wast perfect in thy ways from the day that thou wast created,"], ["ua oo i le aso na iloa ai lau amio leaga.", "till iniquity was found in thee."]]},
  {num:16,words:[["O lou faatauina o oa ina tele ua faatumuina ai oe i le saua,", "By the multitude of thy merchandise they have filled the midst of thee with violence,"], ["ma ua e agasala;", "and thou hast sinned:"], ["o le mea lea ou te faaleagaina ai oe,", "therefore I will cast thee as profane out of the mountain of God: and I will destroy thee,"], ["ia te'a ese i le mauga o le Atua;", "O covering cherub,"], ["ou te faaumatia oe le kerupi faamalumalu nai le va o maa o le afi.", "from the midst of the stones of fire."]]},
  {num:17,words:[["Na faamaualugaina lou loto i lou matagofie;", "Thine heart was lifted up because of thy beauty,"], ["ua e faamaumau lou poto ma lou matagofie;", "thou hast corrupted thy wisdom by reason of thy brightness:"], ["ou te lafoina oe i lalo i le eleele;", "I will cast thee to the ground, I will lay thee before kings,"], ["ou te tuuina atu oe i luma o tupu ina ia latou vaavaai ia te oe.", "that they may behold thee."]]},
  {num:18,words:[["O au amio leaga ina tele,", "Thou hast defiled thy sanctuaries by the multitude of thine iniquities,"], ["ma le pepelo i lou faatauina o mea,", "by the iniquity of thy traffick;"], ["ua e faaleagaina au mea paia, o le mea lea ou te faatupuina ai se afi ai totonu ia te oe,", "therefore will I bring forth a fire from the midst of thee,"], ["e faaumatia ai oe,", "it shall devour thee,"], ["ou te avea oe ma lefulefu i le fogāeleele i luma o i latou atoa o e vaavaai ia te oe.", "and I will bring thee to ashes upon the earth in the sight of all them that behold thee."]]},
  {num:19,words:[["O nuu uma e iloa oe e fememeai i latou uma ona o oe;", "All they that know thee among the people shall be astonished at thee: thou shalt be a terror,"], ["e avea foi oe ma mea e ala ai le mata'u e le toe ai lava oe e faavavau.", "and never shalt thou be any more."]]},
  {num:20,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "Again the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:21,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia e faasaga i Saitonu,", "set thy face against Zidon,"], ["ma vavalo atu i ai;", "and prophesy against it,"]]},
  {num:22,words:[["ma e fai atu,", "And say,"], ["O loo faapea ona fetalai mai o le Alii o Ieova;", "Thus saith the Lord GOD;"], ["Faauta,", "Behold,"], ["Saitonu e,", "I am against thee,"], ["ou te fai oe mo'u fili;", "O Zidon; and I will be glorified in the midst of thee:"], ["e viia foi a'u i totonu ia te oe;", "and they shall know that I am the LORD,"], ["latou te iloa foi o a'u lava o Ieova pe a uma ona ou faaoo sala ia te ia,", "when I shall have executed judgments in her,"], ["ma ua faapaiaina o a'u i totonu ia te ia.", "and shall be sanctified in her."]]},
  {num:23,words:[["Auā ou te auina atu ia te ia le faamai ma le toto i ona ala;", "For I will send into her pestilence,"], ["o e ua manunua e oti i latou i totonu ia te ia i le pelu e faasaga mai i itu uma;", "and blood into her streets; and the wounded shall be judged in the midst of her by the sword upon her on every side;"], ["latou te iloa ai o a'u lava o Ieova.", "and they shall know that I am the LORD."]]},
  {num:24,words:[["E le toe ai i le aiga o Isaraelu se laau talatala e tiga ai,", "And there shall be no more a pricking brier unto the house of Israel,"], ["po o se laau matuitui e ogotia ai mai ia te i latou uma o e vagavagai ia te i latou,", "nor any grieving thorn of all that are round about them,"], ["o e 'ino'ino ia te i latou;", "that despised them;"], ["latou te iloa ai foi o a'u lava o le Alii o Ieova.", "and they shall know that I am the Lord GOD."]]},
  {num:25,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["A ou faapotopotoina le aiga o Isaraelu ai nuu o loo faataapeapeina ai i latou,", "When I shall have gathered the house of Israel from the people among whom they are scattered,"], ["ma faapaiaina a'u ia te i latou i luma o nuu ese;", "and shall be sanctified in them in the sight of the heathen,"], ["ona latou nonofo ai lea i lo latou laueleele na ou foai atu ai i la'u auauna o Iakopo.", "then shall they dwell in their land that I have given to my servant Jacob."]]},
  {num:26,words:[["Latou te nonofo ai foi ma le filemu,", "And they shall dwell safely therein,"], ["latou te fai fale,", "and shall build houses,"], ["latou te fai tovine foi,", "and plant vineyards; yea,"], ["ma latou nonofo ma le filemu,", "they shall dwell with confidence,"], ["pe a uma ona ou faaoo sala ia te i latou uma o e 'ino'ino ia te i latou i itu uma;", "when I have executed judgments upon all those that despise them round about them;"], ["ona latou iloa ai lea o a'u lava o Ieova lo latou Atua.", "and they shall know that I am the LORD their God."]]},
];
renderVerseSet(ezk_ch_28_Verses, 'ezk-ch28-verses');

var ezk_ch_29_Verses = [
  {num:1,words:[["O lona sefulu o tausaga,", "In the tenth year,"], ["o lona sefulu foi o masina ,", "in the tenth month,"], ["o le aso e sefulu ma le lua o le masina,", "in the twelfth day of the month,"], ["na oo mai ai le afioga a Ieova ia te au,", "the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia e faasaga atu ia Farao le tupu o Aikupito,", "set thy face against Pharaoh king of Egypt, and prophesy against him,"], ["ma vavalo atu ia te ia atoa ma Aikupito uma;", "and against all Egypt:"]]},
  {num:3,words:[["ia e fai atu,", "Speak,"], ["ia faapea atu, O loo faapea ona fetalai mai o le Alii o Ieova,", "and say,"], ["Faauta,", "Thus saith the Lord GOD;"], ["ou te fai oe mo'u fili,", "Behold,"], ["Farao e,", "I am against thee,"], ["le tupu o Aikupito, le tanimo tele,", "Pharaoh king of Egypt,"], ["o lē taoto i totonu o ona vaitafe,", "the great dragon that lieth in the midst of his rivers,"], ["o le fai mai,", "which hath said,"], ["O lo'u vaitafe, o lo'u lava lea,", "My river is mine own,"], ["na ou faia mo a'u.", "and I have made it for myself."]]},
  {num:4,words:[["Ou te tuu ane mātau i ou auvae,", "But I will put hooks in thy jaws,"], ["ma ou faapipiiina i'a o i ou vaitafe i ou una,", "and I will cause the fish of thy rivers to stick unto thy scales,"], ["ou te avae foi ia te oe ai totonu o ou vaitafe;", "and I will bring thee up out of the midst of thy rivers,"], ["o i'a uma foi o ou vaitafe e pipii ia i ou una.", "and all the fish of thy rivers shall stick unto thy scales."]]},
  {num:5,words:[["Ou te tuua foi oe i le vao,", "And I will leave thee thrown into the wilderness,"], ["o oe ma i'a uma o ou vaitafe;", "thee and all the fish of thy rivers:"], ["e paū oe i le fogāeleele, e le faapotopotoina oe,", "thou shalt fall upon the open fields;"], ["e le aofia foi;", "thou shalt not be brought together,"], ["ua ou tuuina atu oe e fai ma mea e 'ai a manu feai e tataa,", "nor gathered:"], ["ma manu felelei.", "I have given thee for meat to the beasts of the field and to the fowls of the heaven."]]},
  {num:6,words:[["E iloa ai foi ē nonofo i Aikupito uma o a'u lava o Ieova,", "And all the inhabitants of Egypt shall know that I am the LORD,"], ["auā sa fai i latou ma tootoo u i le aiga o Isaraelu.", "because they have been a staff of reed to the house of Israel."]]},
  {num:7,words:[["Na latou tago atu i lou lima,", "When they took hold of thee by thy hand,"], ["ona gausia lea o oe,", "thou didst break,"], ["ona masae ai lea o latou tau'au uma;", "and rend all their shoulder:"], ["ua latou totoo ia te oe,", "and when they leaned upon thee,"], ["ona gausia lea o oe,", "thou brakest,"], ["ona tuu atu lea o i latou e tutū na o i latou lava.", "and madest all their loins to be at a stand."]]},
  {num:8,words:[["O le mea lea o loo faapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["Faauta,", "Behold,"], ["ou te faaooina atu le pelu ia te oe,", "I will bring a sword upon thee,"], ["ma ou faaumatia ai tagata atoa ma manu o ia te oe.", "and cut off man and beast out of thee."]]},
  {num:9,words:[["E faatafunaina,", "And the land of Egypt shall be desolate and waste;"], ["ma faagaogaoina le nuu o Aikupito;", "and they shall know that I am the LORD:"], ["latou te iloa ai foi o a'u lava o Ieova; auā na ia fai ane,", "because he hath said,"], ["E o'u le vaitafe,", "The river is mine,"], ["na ou faia.", "and I have made it."]]},
  {num:10,words:[["Faauta,", "Behold,"], ["o le mea lea ou te fai ai oe mo'u fili atoa ma ou vaitafe;", "therefore I am against thee,"], ["ou te matua faagaogaoina ma faatafunaina le nuu o Aikupito,", "and against thy rivers,"], ["e pau atu i Mekatala e pau mai i Seveni,", "and I will make the land of Egypt utterly waste and desolate,"], ["e oo lava i le tuaoi o Aitiope.", "from the tower of Syene even unto the border of Ethiopia."]]},
  {num:11,words:[["E le ui atu ai vae o tagata;", "No foot of man shall pass through it,"], ["e le ui atu ai foi vae o manu;", "nor foot of beast shall pass through it,"], ["e le āina foi ia i tausaga e fagafulu.", "neither shall it be inhabited forty years."]]},
  {num:12,words:[["Ou te faatafunaina le nuu o Aikupito faatasi ma nuu ua faatafunaina;", "And I will make the land of Egypt desolate in the midst of the countries that are desolate,"], ["o ona aai foi faatasi ma aai ua faagaogaoina;", "and her cities among the cities that are laid waste shall be desolate forty years:"], ["e faatafunaina ai i tausaga e fagafulu; ou te faataapeapeina Aikupito i nuu,", "and I will scatter the Egyptians among the nations,"], ["ma ou faasalalauina i latou i nuu eseese.", "and will disperse them through the countries."]]},
  {num:13,words:[["A ua faapea ona fetalai mai o le Alii o Ieova, A mavae tausaga e fagafulu,", "Yet thus saith the Lord GOD;"], ["ona ou faapotopotoina lea o Aikupito ai nuu na faataapeapeina ai i latou.", "At the end of forty years will I gather the Egyptians from the people whither they were scattered:"]]},
  {num:14,words:[["Ou te faaea le tafeaga o Aikupito,", "And I will bring again the captivity of Egypt,"], ["ma ou faafoisia i latou i le nuu o Patoro,", "and will cause them to return into the land of Pathros,"], ["o le nuu o lo latou tupuaga,", "into the land of their habitation;"], ["e avea foi i latou i lea mea ma malo faatauvaa.", "and they shall be there a base kingdom."]]},
  {num:15,words:[["E sili ona faatauvaa ia i malo,", "It shall be the basest of the kingdoms;"], ["e le toe faamaualuga ia i nuu;", "neither shall it exalt itself any more above the nations:"], ["auā ou te faatoaitiitiina i latou,", "for I will diminish them,"], ["ia latou le toe pule i nuu.", "that they shall no more rule over the nations."]]},
  {num:16,words:[["E le toe fai foi i latou ma faatuatuaga o le aiga o Isaraelu,", "And it shall be no more the confidence of the house of Israel,"], ["e faamanatuina ai a latou amio leaga i lo latou faasaga atu i ai;", "which bringeth their iniquity to remembrance, when they shall look after them:"], ["a e iloa e i latou o a'u lava o le Alii o Ieova.", "but they shall know that I am the Lord GOD."]]},
  {num:17,words:[["O lona lua o sefulu ma le fitu o tausaga,", "And it came to pass in the seven and twentieth year,"], ["o lona masina muamua,", "in the first month,"], ["o le aso muamua o le masina,", "in the first day of the month,"], ["na oo mai ai le afioga a Ieova ia te au,", "the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:18,words:[["Le atalii e o le tagata,", "Son of man, Nebuchadrezzar king of Babylon caused his army to serve a great service against Tyrus:"], ["na pule Nepukanesa le tupu o Papelonia itu lana ia taua i latou faia le galuega tele i Turo;", "every head was made bald,"], ["na tutula ai ulu uma,", "and every shoulder was peeled: yet had he no wages,"], ["na fatuamoa foi o latou ua;", "nor his army,"], ["a e leai se totogi ia te ia ma lana itu taua i Turo i le galuega na ia fai ai.", "for Tyrus, for the service that he had served against it:"]]},
  {num:19,words:[["O le mea lea ua fāapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["Faauta,", "Behold,"], ["ou te avatu ia Nepukanesa le tupu o Papelonia le nuu o Aikupito;", "I will give the land of Egypt unto Nebuchadrezzar king of Babylon; and he shall take her multitude,"], ["na te avea lona vao tagata,", "and take her spoil,"], ["na te vetea foi le vete ma faoa le oloa;", "and take her prey;"], ["e fai foi ia ma totogi i lana itu taua.", "and it shall be the wages for his army."]]},
  {num:20,words:[["Ua ou avatu ia te ia le nuu o Aikupito ona o le galuega na ia faia;", "I have given him the land of Egypt for his labour wherewith he served against it,"], ["auā na latou galulue mo a'u,", "because they wrought for me,"], ["ua fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:21,words:[["O lea lava aso ou te faatupuina ai le nifo o le aiga o Isaraelu;", "In that day will I cause the horn of the house of Israel to bud forth,"], ["ou te tuu atu foi ia te oe e tautala ia te i latou;", "and I will give thee the opening of the mouth in the midst of them;"], ["ona latou iloa ai lea o a'u lava o Ieova.", "and they shall know that I am the LORD."]]},
];
renderVerseSet(ezk_ch_29_Verses, 'ezk-ch29-verses');

var ezk_ch_30_Verses = [
  {num:1,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "The word of the LORD came again unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia e vavalo atu,", "prophesy and say,"], ["ma ia e fai atu, Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Ina uio ia outou,", "Howl ye,"], ["Aue le aso e!", "Woe worth the day!"]]},
  {num:3,words:[["Auā ua latalata mai le aso;", "For the day is near,"], ["ua latalata mai le aso o Ieova,", "even the day of the LORD is near,"], ["o le aso faamalumalu;", "a cloudy day;"], ["e fai lea ma ona po o nuu ese.", "it shall be the time of the heathen."]]},
  {num:4,words:[["E oo foi le pelu i Aikupito;", "And the sword shall come upon Egypt,"], ["e i ai foi le mata'u tele i Aitiope pe a pauu e ua fasia i Aikupito;", "and great pain shall be in Ethiopia,"], ["latou te avea foi lona vao tagata;", "when the slain shall fall in Egypt, and they shall take away her multitude,"], ["o ona faavae foi e fulisia ia.", "and her foundations shall be broken down."]]},
  {num:5,words:[["O Aitiope,", "Ethiopia,"], ["ma Futu,", "and Libya,"], ["ma Luti,", "and Lydia,"], ["ma tagata eseese atoa uma,", "and all the mingled people,"], ["ma Kupu,", "and Chub,"], ["ma tagata o le nuu o le feagaiga,", "and the men of the land that is in league,"], ["e oti faatasi ma i latou i le pelu.", "shall fall with them by the sword."]]},
  {num:6,words:[["Ua faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["O i latou o e lagolago ia Aikupito e pauu i latou;", "They also that uphold Egypt shall fall;"], ["e mavae foi lona malosi e mitamita ai; e pau atu i Mekatala e pau mai i Seveni,", "and the pride of her power shall come down:"], ["e oti ai i latou i le pelu,", "from the tower of Syene shall they fall in it by the sword,"], ["ua fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:7,words:[["E faatafunaina foi i latou faatasi ma nuu ua faatafunaina,", "And they shall be desolate in the midst of the countries that are desolate,"], ["e faatasia foi ona aai i aai ua faagaogaoina.", "and her cities shall be in the midst of the cities that are wasted."]]},
  {num:8,words:[["Latou te iloa ai o a'u lava o Ieova pe a ou tuuina atu se afi i Aikupito,", "And they shall know that I am the LORD, when I have set a fire in Egypt,"], ["pe a momomo foi ona fesoasoani uma.", "and when all her helpers shall be destroyed."]]},
  {num:9,words:[["O lea aso e o atu ai a'u sāvali i vaa,", "In that day shall messengers go forth from me in ships to make the careless Ethiopians afraid,"], ["e faagateteina ai Aitiope faatalanoa,", "and great pain shall come upon them,"], ["e oo foi le mata'u tele ia te i latou,", "as in the day of Egypt:"], ["e pei o le aso o Aikupito;", "for,"], ["auā faauta,", "lo,"], ["o loo o saū.", "it cometh."]]},
  {num:10,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Ou te faaumatia le vao tagata o Aikupito i le lima o Nepukanesa le tupu o Papelonia.", "I will also make the multitude of Egypt to cease by the hand of Nebuchadrezzar king of Babylon."]]},
  {num:11,words:[["E ta'ita'iina o ia ma ona tagata e faatasi ma ia,", "He and his people with him,"], ["o e ua matautia i nuu,", "the terrible of the nations,"], ["e faaumatia ai le nuu;", "shall be brought to destroy the land:"], ["latou te to ae a latou pelu i Aikupito,", "and they shall draw their swords against Egypt,"], ["ma faatumuina le nuu i le fasi.", "and fill the land with the slain."]]},
  {num:12,words:[["Ou te faamamate i vaitafe,", "And I will make the rivers dry, and sell the land into the hand of the wicked:"], ["ou te faatauina atu foi le nuu i lima o tagata amio leaga;", "and I will make the land waste,"], ["ma ou faatafunaina i lima o tagata ese le nuu ma mea ua tumu ai;", "and all that is therein,"], ["o a'u o Ieova ua ou fai atu ai.", "by the hand of strangers: I the LORD have spoken it."]]},
  {num:13,words:[["O loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Ou te faaumatia tupua,", "I will also destroy the idols,"], ["ou te faaiuina lava tupua ai Nafi;", "and I will cause their images to cease out of Noph;"], ["e le toe ai foi se alii o le nuu o Aikupito;", "and there shall be no more a prince of the land of Egypt:"], ["ou te faatupuina foi le mata'u i le nuu o Aikupito.", "and I will put a fear in the land of Egypt."]]},
  {num:14,words:[["Ou te faatafunaina foi Patoro,", "And I will make Pathros desolate,"], ["ma ou tuuina atu le afi i Soana,", "and will set fire in Zoan,"], ["ma faaoo sala i No.", "and will execute judgments in No."]]},
  {num:15,words:[["Ou te sasaaina atu foi lo'u ita tele i luga o Sina,", "And I will pour my fury upon Sin,"], ["le malosi o Aikupito;", "the strength of Egypt;"], ["ou te faaumatia foi le vao tagata o No.", "and I will cut off the multitude of No."]]},
  {num:16,words:[["Ou te tuu atu foi le afi i Aikupito;", "And I will set fire in Egypt:"], ["e faatigateleina Sina;", "Sin shall have great pain,"], ["e lepetia No;", "and No shall be rent asunder,"], ["e puapuagatia foi Nafi i aso fai soo.", "and Noph shall have distresses daily."]]},
  {num:17,words:[["O taulelea o Avane ma Pepeseta e oti i latou i le pelu;", "The young men of Aven and of Pi-beseth shall fall by the sword:"], ["e tāfea foi ia nuu .", "and these cities shall go into captivity."]]},
  {num:18,words:[["E faapouliuligia foi le ao i Tapenesa,", "At Tehaphnehes also the day shall be darkened,"], ["pe a ou gausia amo a Aikupito i lea mea,", "when I shall break there the yokes of Egypt:"], ["e faaiuina foi lona malosi e mitamita ai;", "and the pomp of her strength shall cease in her: as for her,"], ["e ufitia ia i le ao,", "a cloud shall cover her,"], ["o ana tama fafine foi e tāfea i latou.", "and her daughters shall go into captivity."]]},
  {num:19,words:[["Ou te faaoo lava sala i Aikupito;", "Thus will I execute judgments in Egypt:"], ["ona latou iloa ai lea o a'u lava o Ieova.", "and they shall know that I am the LORD."]]},
  {num:20,words:[["O lona tausaga e sefulu ma le tasi,", "And it came to pass in the eleventh year,"], ["o le masina muamua,", "in the first month,"], ["o le aso e fitu o le masina,", "in the seventh day of the month,"], ["na oo mai ai le afioga a Ieova ia te au,", "that the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:21,words:[["Le atalii e o le tagata,", "Son of man,"], ["ua ou gausia le lima o Farao le tupu o Aikupito;", "I have broken the arm of Pharaoh king of Egypt; and,"], ["faauta foi,", "lo,"], ["e le fusia ia malolo ai;", "it shall not be bound up to be healed, to put a roller to bind it,"], ["e le avane foi i ai se fusi e fusi ai ia malosi ai e 'u'u ai le pelu.", "to make it strong to hold the sword."]]},
  {num:22,words:[["O le mea lea ua faapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["Faauta,", "Behold,"], ["ou te faia Farao le tupu o Aikupito mo'u fili,", "I am against Pharaoh king of Egypt,"], ["ou te gagauina ona lima,", "and will break his arms,"], ["o le ua malosi,", "the strong,"], ["atoa ma le na gagauina;", "and that which was broken;"], ["ou te faapaūina foi le pelu ai lona lima.", "and I will cause the sword to fall out of his hand."]]},
  {num:23,words:[["Ou te faataapeapeina foi Aikupito i nuu,", "And I will scatter the Egyptians among the nations,"], ["ou te faasalalauina foi i latou i nuu eseese.", "and will disperse them through the countries."]]},
  {num:24,words:[["A e ou te faamalosia foi lima o le tupu o Papelonia,", "And I will strengthen the arms of the king of Babylon,"], ["ma ou tuu ane la'u pelu i lona lima;", "and put my sword in his hand:"], ["a e ou te gagauina lima o Farao, ona oi ai lea o ia i ona luma,", "but I will break Pharaoh's arms,"], ["i le oi o le ua manua.", "and he shall groan before him with the groanings of a deadly wounded man."]]},
  {num:25,words:[["A e ou te faamalosia lima o le tupu o Papelonia,", "But I will strengthen the arms of the king of Babylon,"], ["a o lima o Farao e gagase lava ia;", "and the arms of Pharaoh shall fall down;"], ["latou te iloa ai o a'u o Ieova,", "and they shall know that I am the LORD,"], ["pe a ou tuu atu la'u pelu i le lima o le tupu o Papelonia,", "when I shall put my sword into the hand of the king of Babylon,"], ["a e faaloaloa atu ai e ia i le nuu o Aikupito.", "and he shall stretch it out upon the land of Egypt."]]},
  {num:26,words:[["Ou te faataapeapeina foi Aikupito i nuu,", "And I will scatter the Egyptians among the nations,"], ["ma faasalalau ia te i latou i nuu eseese;", "and disperse them among the countries;"], ["ona latou iloa ai lea o a'u lava o Ieova.", "and they shall know that I am the LORD."]]},
];
renderVerseSet(ezk_ch_30_Verses, 'ezk-ch30-verses');

var ezk_ch_31_Verses = [
  {num:1,words:[["O lona sefulu ma le tasi o tausaga,", "And it came to pass in the eleventh year,"], ["o lona tolu o masina ,", "in the third month,"], ["o le aso muamua o le masina,", "in the first day of the month,"], ["na oo mai ai le afioga a Ieova ia te au,", "that the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia e fai atu ia Farao le tupu o Aikupito,", "speak unto Pharaoh king of Egypt, and to his multitude;"], ["ma ona tagata e toatele. Pe faatusaina oe ia te ai i lou mamalu?", "Whom art thou like in thy greatness?"]]},
  {num:3,words:[["Faauta,", "Behold,"], ["o Asuria o le arasi ia i Lepanona,", "the Assyrian was a cedar in Lebanon with fair branches,"], ["ua matagofie ona la, ua malu foi lona paolo,", "and with a shadowing shroud,"], ["ua tele foi lona maualuga;", "and of an high stature;"], ["sa i totonu o la felefele lona tumutumu.", "and his top was among the thick boughs."]]},
  {num:4,words:[["O le vai na tupu tele ai o ia,", "The waters made him great,"], ["o vai loloto foi na maualuga ai o ia, o ona vaitafe na tafe faataamilomilo i lana faatoaga,", "the deep set him up on high with her rivers running round about his plants,"], ["ma ona vaita'i na tafe atu i laau uma o le vao.", "and sent out her little rivers unto all the trees of the field."]]},
  {num:5,words:[["O le mea lea na faasilisili ai lona maualuga i laau uma o le vao,", "Therefore his height was exalted above all the trees of the field,"], ["na tele foi ona lālā,", "and his boughs were multiplied, and his branches became long because of the multitude of waters,"], ["ma ona la na loloa i le vai tetele i lona tupu atu.", "when he shot forth."]]},
  {num:6,words:[["Na ofaga manu felelei uma i ona lālā,", "All the fowls of heaven made their nests in his boughs,"], ["na fanafanau foi manu tataa uma i lalo ifo o ona la;", "and under his branches did all the beasts of the field bring forth their young,"], ["sa nonofo foi nuu tetele uma i lalo ifo o lona paolo.", "and under his shadow dwelt all great nations."]]},
  {num:7,words:[["Na matagofie foi o ia i lona tele,", "Thus was he fair in his greatness,"], ["ma le loloa o ona la;", "in the length of his branches:"], ["auā na i ai ona aa i tafatafa o vai tetele.", "for his root was by great waters."]]},
  {num:8,words:[["Na le lilo lava ia i arasi o i le faatoaga o le Atua;", "The cedars in the garden of God could not hide him:"], ["na le tutusa perosi ma ona lālā;", "the fir trees were not like his boughs,"], ["na le tutusa foi aremoni i ona la;", "and the chesnut trees were not like his branches;"], ["e leai foi se tasi laau i le faatoaga o le Atua na tusa ma ia i lona matagofie.", "nor any tree in the garden of God was like unto him in his beauty."]]},
  {num:9,words:[["Na ou faamatagofieina o ia i le tele o ona la,", "I have made him fair by the multitude of his branches: so that all the trees of Eden,"], ["na matataua ai ia te ia o laau uma o Etena i le faatoaga o le Atua.", "that were in the garden of God, envied him."]]},
  {num:10,words:[["O le mea lea o loo faapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["Na faasilisili oe i lou maualuga,", "Because thou hast lifted up thyself in height,"], ["ma ua avea i luga lona tumutumu i totonu o la felefele,", "and he hath shot up his top among the thick boughs,"], ["ua faamaualugaina foi lona loto i lona sili.", "and his heart is lifted up in his height;"]]},
  {num:11,words:[["O le mea lea ua ou tuuina atu ai o ia i le lima o le ua malosi silisili i nuu;", "I have therefore delivered him into the hand of the mighty one of the heathen;"], ["na te faia lona lava loto ia te ia; ua ou tulieseina o ia,", "he shall surely deal with him:"], ["ona o lana amio leaga.", "I have driven him out for his wickedness."]]},
  {num:12,words:[["O tagata ese o e ua matautia i nuu,", "And strangers,"], ["na latou tuu i lalo ia te ia,", "the terrible of the nations,"], ["ma latou tuua o ia;", "have cut him off,"], ["ua pauu foi ona la i mauga ma vanu uma,", "and have left him: upon the mountains and in all the valleys his branches are fallen,"], ["ua gauia foi ona la i tafatafa o vaitafe uma o le nuu;", "and his boughs are broken by all the rivers of the land;"], ["ua o ese foi tagata uma o le nuu nai lalo ifo o lona paolo,", "and all the people of the earth are gone down from his shadow,"], ["ma latou tuua lava o ia.", "and have left him."]]},
  {num:13,words:[["E nonofo foi manu felelei uma i ona luga a o taatia;", "Upon his ruin shall all the fowls of the heaven remain,"], ["e i ai foi i ona la o manu tataa uma.", "and all the beasts of the field shall be upon his branches:"]]},
  {num:14,words:[["Ina ia le faasilisili se tasi lava laau i tafatafa o vai ona o lo latou maualuluga,", "To the end that none of all the trees by the waters exalt themselves for their height,"], ["pe avea i luga o latou tumutumu i totonu o la felefele;", "neither shoot up their top among the thick boughs, neither their trees stand up in their height,"], ["pe tutū i luga i latou ia te i latou i lo latou sili o i latou uma o e inu vai;", "all that drink water:"], ["auā ua tuuina atu i latou uma ia mamate i mea maulalo o le lalolagi,", "for they are all delivered unto death,"], ["e faatasi ma le fanau a tagata,", "to the nether parts of the earth, in the midst of the children of men,"], ["e faatasi foi ma e o ifo i le lua.", "with them that go down to the pit."]]},
  {num:15,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["O le aso na alu ifo ai o ia i seoli na ou faatupuina ai le faanoanoa;", "In the day when he went down to the grave I caused a mourning:"], ["na ou ufiufitia vai loloto ona o ia,", "I covered the deep for him,"], ["na ou taofi ona tafega,", "and I restrained the floods thereof,"], ["na punitia foi vai tetele,", "and the great waters were stayed:"], ["na ou faatupuina foi le faanoanoa o Lepanona ona o ia;", "and I caused Lebanon to mourn for him,"], ["na matapogia ai laau uma o le vao ona o ia.", "and all the trees of the field fainted for him."]]},
  {num:16,words:[["Na ou faagateteina foi nuu i le taalili o lona paū,", "I made the nations to shake at the sound of his fall,"], ["ina ua ou lafoina o ia i lalo i seoli faatasi ma e o ifo i le lua;", "when I cast him down to hell with them that descend into the pit:"], ["o laau uma foi o Etena o e silisili ma lelei i Lepanona,", "and all the trees of Eden, the choice and best of Lebanon,"], ["o i latou uma e inu vai,", "all that drink water,"], ["ua faamafanafanaina i latou i mea maulalo o le lalolagi.", "shall be comforted in the nether parts of the earth."]]},
  {num:17,words:[["O i latou lava,", "They also went down into hell with him unto them that be slain with the sword;"], ["na latou o ifo faatasi ma ia i seoli ia te i latou o e ua fasia i le pelu; o lona lima foi,", "and they that were his arm,"], ["o e sa nonofo i lalo ifo o lona paolo i nuu.", "that dwelt under his shadow in the midst of the heathen."]]},
  {num:18,words:[["Pe faatusaina oe ia te ai i le mamalu ma le tele i laau o Etena? a e lafoina oe i lalo faatasi ma laau o Etena i mea maulalo o le lalolagi; e te taatia faatasi ma ē le peritomeina,", "To whom art thou thus like in glory and in greatness among the trees of Eden? yet shalt thou be brought down with the trees of Eden unto the nether parts of the earth:"], ["ma e ua fasia i le pelu.", "thou shalt lie in the midst of the uncircumcised with them that be slain by the sword."], ["O Farao lea ma lona vao tagata uma,", "This is Pharaoh and all his multitude,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
];
renderVerseSet(ezk_ch_31_Verses, 'ezk-ch31-verses');

var ezk_ch_32_Verses = [
  {num:1,words:[["O lona tausaga e tasi le sefulu ma le lua,", "And it came to pass in the twelfth year,"], ["o lona masina e tasi le sefulu ma le lua,", "in the twelfth month,"], ["o le aso muamua o le masina,", "in the first day of the month,"], ["na oo mai ai le afioga a Ieova ia te au,", "that the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia e sauni atu se pese e aualofa a'i ia Farao le tupu o Aikupito,", "take up a lamentation for Pharaoh king of Egypt,"], ["ma ia e faapea atu ia te ia,", "and say unto him,"], ["Ua tusa oe ma se tamai leona i nuu,", "Thou art like a young lion of the nations,"], ["ua e tusa foi ma le tanimo i le vai;", "and thou art as a whale in the seas:"], ["ua e oso ae i ou vaitafe,", "and thou camest forth with thy rivers,"], ["ma faagaepuina le vai i ou vae,", "and troubledst the waters with thy feet,"], ["ma solia o latou vaitafe.", "and fouledst their rivers."]]},
  {num:3,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["O le mea lea ou te folasia ai la'u upega i luga ia te oe, o i ai le aofia o nuu e tele,", "I will therefore spread out my net over thee with a company of many people;"], ["latou te aveina ae oe i la'u upega.", "and they shall bring thee up in my net."]]},
  {num:4,words:[["Ona ou tuua lea o oe i le nuu,", "Then will I leave thee upon the land,"], ["ou te lafoaiina oe i le fogaeleele,", "I will cast thee forth upon the open field,"], ["ou te faanonofoina manu felelei uma ia te oe,", "and will cause all the fowls of the heaven to remain upon thee,"], ["ma ou fafaga ia maoona ia te oe manu tataa o le lalolagi uma.", "and I will fill the beasts of the whole earth with thee."]]},
  {num:5,words:[["Ou te tuuina lou tino i luga o mauga,", "And I will lay thy flesh upon the mountains,"], ["ma ou faatumuina vanu i lou maualuga.", "and fill the valleys with thy height."]]},
  {num:6,words:[["Ou te faasūsūina i lou toto le nuu ua e aau ai,", "I will also water with thy blood the land wherein thou swimmest,"], ["e oo lava i mauga;", "even to the mountains;"], ["e tutumu foi vaitafe ia te oe.", "and the rivers shall be full of thee."]]},
  {num:7,words:[["Ou te ufiufitia le lagi pe a ou tineia oe,", "And when I shall put thee out,"], ["ou te faapogisaina foi ona fetu;", "I will cover the heaven,"], ["ou te ufitia le la i le ao,", "and make the stars thereof dark; I will cover the sun with a cloud,"], ["e le susulu mai foi le masina.", "and the moon shall not give her light."]]},
  {num:8,words:[["O malamalama pupula uma o le lagi,", "All the bright lights of heaven will I make dark over thee,"], ["ou te faapouliuligia ia i luga ia te oe, ou te tuuina atu foi le pouliuli i lou nuu,", "and set darkness upon thy land,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:9,words:[["Ou te faatigaina foi loto o nuu e tele pe a ou faaooina atu lou malaia i nuu ese,", "I will also vex the hearts of many people, when I shall bring thy destruction among the nations,"], ["o nuu eseese foi ua e le iloa.", "into the countries which thou hast not known."]]},
  {num:10,words:[["Ou te faafememeaiina nuu e tele ona o oe,", "Yea,"], ["e matuā fefefe lava o latou tupu ona o oe,", "I will make many people amazed at thee, and their kings shall be horribly afraid for thee,"], ["pe a ou feliuliuai la'u pelu i o latou luma;", "when I shall brandish my sword before them;"], ["e taitasi i latou ma saga gatete pea ona o lona lava ola,", "and they shall tremble at every moment, every man for his own life,"], ["i le aso o lou paū.", "in the day of thy fall."]]},
  {num:11,words:[["Auā ua faapea ona fetalai mai o le Alii o Ieova,", "For thus saith the Lord GOD;"], ["E oo atu le pelu a le tupu o Papelonia ia te oe.", "The sword of the king of Babylon shall come upon thee."]]},
  {num:12,words:[["Ou te fasiotia le vao tagata ua ia te oe i pelu a e malolosi,", "By the swords of the mighty will I cause thy multitude to fall,"], ["o e ua matautia i nuu,", "the terrible of the nations,"], ["o i latou uma;", "all of them:"], ["latou te faaumatia le mamalu o Aikupito;", "and they shall spoil the pomp of Egypt,"], ["e fano foi lona vao tagata.", "and all the multitude thereof shall be destroyed."]]},
  {num:13,words:[["Ou te faaumatia foi ana manu uma ai tafatafa o vai tetele;", "I will destroy also all the beasts thereof from beside the great waters;"], ["e le toe faagaepuina lava e vae o tagata,", "neither shall the foot of man trouble them any more,"], ["e le faagaepuina foi e atigivae o manu.", "nor the hoofs of beasts trouble them."]]},
  {num:14,words:[["Ona ou faatoaina ai lea o latou vai ia manino ,", "Then will I make their waters deep,"], ["ma ou faatafeina o latou vaitafe faapei o le suāuu,", "and cause their rivers to run like oil,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:15,words:[["A ou faatafunaina le nuu o Aikupito,", "When I shall make the land of Egypt desolate,"], ["ma ua aunoa le nuu ma mea sa tumu ai,", "and the country shall be destitute of that whereof it was full,"], ["a ou fasiotia i latou uma ua nonofo ai,", "when I shall smite all them that dwell therein,"], ["ona latou iloa ai lea o a'u lava o Ieova.", "then shall they know that I am the LORD."]]},
  {num:16,words:[["O le pese a aualofa a'i lea latou te pepese ai ona o ia;", "This is the lamentation wherewith they shall lament her:"], ["o tama fafine a nuu ese latou te lagi le pese e aualofa a'i ona o ia;", "the daughters of the nations shall lament her:"], ["latou te lagi le pese e aualofa a'i ona o ia,", "they shall lament for her,"], ["ona o Aikupito,", "even for Egypt,"], ["ma lona vao tagata uma,", "and for all her multitude,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:17,words:[["O lona tausaga e tasi le sefulu ma le lua,", "It came to pass also in the twelfth year,"], ["o lona aso e tasi le sefulu ma le lima o le masina,", "in the fifteenth day of the month,"], ["na oo mai ai le afioga a Ieova ia te au,", "that the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:18,words:[["Le atalii e o le tagata,", "Son of man, wail for the multitude of Egypt,"], ["ia e aue ona o le vao tagata o Aikupito,", "and cast them down, even her,"], ["ma lafo ia te i latou o ia atoa ma tama fafine o nuu malolosi i mea maulalo o le lalolagi,", "and the daughters of the famous nations,"], ["faatasi ma ē ō ifo i le lua.", "unto the nether parts of the earth, with them that go down into the pit."]]},
  {num:19,words:[["Ua sili ea oe ia te ai i le matagofie? Alu ifo ia;", "Whom dost thou pass in beauty? go down,"], ["ia e taatia faatasi ma e ua le peritomeina.", "and be thou laid with the uncircumcised."]]},
  {num:20,words:[["Latou te pauu faatasi ma e ua fasia i le pelu;", "They shall fall in the midst of them that are slain by the sword:"], ["ua tuuina atu o ia i le pelu;", "she is delivered to the sword:"], ["ina tosoina atu o ia atoa ma lona vao tagata uma.", "draw her and all her multitudes."]]},
  {num:21,words:[["O e ua sili ona malolosi i le au malolosi latou te tautala mai totonu o seoli ia te ia,", "The strong among the mighty shall speak to him out of the midst of hell with them that help him:"], ["atoa ma e fesoasoani ia te ia;", "they are gone down,"], ["ua o ifo i latou, ua taatia ua le peritomeina,", "they lie uncircumcised,"], ["ua fasia i le pelu.", "slain by the sword."]]},
  {num:22,words:[["O i ai Asuria ma ona tagata uma;", "Asshur is there and all her company:"], ["ua vagavagai ona tuugamau ia te ia;", "his graves are about him:"], ["ua fasia uma i latou,", "all of them slain,"], ["ua oti i le pelu.", "fallen by the sword:"]]},
  {num:23,words:[["O loo i ai ona tuugamau i itu o le lua,", "Whose graves are set in the sides of the pit,"], ["o loo vagavagai foi ona tagata i lona tuugamau;", "and her company is round about her grave:"], ["ua fasia i latou uma,", "all of them slain,"], ["ua oti i le pelu,", "fallen by the sword,"], ["o e na faatupuina le mata'u i le nuu o tagata ola.", "which caused terror in the land of the living."]]},
  {num:24,words:[["O i ai Elama ma lona vao tagata uma o loo vagavagai i lona tuugamau,", "There is Elam and all her multitude round about her grave,"], ["ua fasia uma i latou,", "all of them slain,"], ["ua oti i le pelu,", "fallen by the sword,"], ["o e ua o ifo ua le peritomeina i mea maulalo i le eleele;", "which are gone down uncircumcised into the nether parts of the earth,"], ["o e na faatupuina lo latou matautia i le nuu o tagata ola;", "which caused their terror in the land of the living;"], ["a ua oo ia te i latou lo latou mā e faatasi ma e ua o ifo i le lua.", "yet have they borne their shame with them that go down to the pit."]]},
  {num:25,words:[["Ua fai e i latou lona moega faatasi ma e ua fasia,", "They have set her a bed in the midst of the slain with all her multitude:"], ["atoa ma lona vao tagata uma;", "her graves are round about him:"], ["ua vagavagai ona tuugamau ia te ia;", "all of them uncircumcised,"], ["o i latou uma e le peritomeina, ua fasia i le pelu;", "slain by the sword:"], ["auā sa i ai lo latou matautia i le nuu o tagata ola;", "though their terror was caused in the land of the living,"], ["ua oo foi ia te i latou lo latou mā e faatasi ma ē ō ifo i le lua;", "yet have they borne their shame with them that go down to the pit:"], ["ua tuuina atu o ia faatasi ma e ua fasia.", "he is put in the midst of them that be slain."]]},
  {num:26,words:[["O i ai Meseko,", "There is Meshech,"], ["ma Tupalu,", "Tubal,"], ["ma lona vao tagata uma;", "and all her multitude:"], ["o loo vagavagai o latou tuugamau ia te ia;", "her graves are round about him:"], ["o i latou uma e le peritomeina,", "all of them uncircumcised,"], ["ua fasia i le pelu;", "slain by the sword,"], ["auā sa i ai lo latou matautia i le nuu o tagata ola.", "though they caused their terror in the land of the living."]]},
  {num:27,words:[["Latou te le taatitia ea faatasi ma e malolosi e ua pauu ua le peritomeina,", "And they shall not lie with the mighty that are fallen of the uncircumcised,"], ["o e ua o ifo i seoli ma a latou auupega? ua avane a latou pelu e aluga a'i,", "which are gone down to hell with their weapons of war:"], ["a ua i ai a latou agasala i luga o latou ivi;", "and they have laid their swords under their heads, but their iniquities shall be upon their bones,"], ["auā sa i ai lo latou matautia i e malolosi i le nuu o tagata ola.", "though they were the terror of the mighty in the land of the living."]]},
  {num:28,words:[["E gāugau lava oe e faatasi ma e ua le peritomeina,", "Yea, thou shalt be broken in the midst of the uncircumcised,"], ["e te taatia faatasi ma e ua fasia i le pelu.", "and shalt lie with them that are slain with the sword."]]},
  {num:29,words:[["E i ai Etoma,", "There is Edom,"], ["ma ona tupu,", "her kings,"], ["ma ona alii sili uma o e ua tuuina ma lo latou malosi faatasi ma e ua fasia i le pelu;", "and all her princes, which with their might are laid by them that were slain by the sword:"], ["latou te taatitia faatasi ma e ua le peritomeina,", "they shall lie with the uncircumcised,"], ["atoa ma i latou o e ō ifo i le lua.", "and with them that go down to the pit."]]},
  {num:30,words:[["O i ai foi alii o le itu i matu,", "There be the princes of the north,"], ["o i latou uma,", "all of them,"], ["atoa ma Saitonu uma,", "and all the Zidonians,"], ["o e ua o ifo faatasi ma e ua fasia; o lo latou matautia ona o lo latou malosi ua latou masiasi ai;", "which are gone down with the slain;"], ["ua latou taatitia foi ua le peritomeina,", "with their terror they are ashamed of their might;"], ["faatasi ma e ua fasia i le pelu,", "and they lie uncircumcised with them that be slain by the sword,"], ["ua oo foi ia te i latou lo latou mā faatasi ma e ua o ifo i le lua.", "and bear their shame with them that go down to the pit."]]},
  {num:31,words:[["E iloa i latou e Farao,", "Pharaoh shall see them,"], ["ona faamafanafanaina ai lea o ia i lona vao tagata uma o e ua fasia i le pelu,", "and shall be comforted over all his multitude,"], ["o Farao ma lana itu taua uma,", "even Pharaoh and all his army slain by the sword,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:32,words:[["Auā ua ou faaooina atu lo'u matautia i le nuu o tagata ola;", "For I have caused my terror in the land of the living:"], ["e faataatiaina o ia faatasi ma e ua le peritomeina,", "and he shall be laid in the midst of the uncircumcised with them that are slain with the sword,"], ["e faatasi ma e ua fasia i le pelu, o Farao atoa ma lona vao tagata uma,", "even Pharaoh and all his multitude,"], ["ua fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
];
renderVerseSet(ezk_ch_32_Verses, 'ezk-ch32-verses');

var ezk_ch_33_Verses = [
  {num:1,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "Again the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["fai atu ia i tagata o lou nuu,", "speak to the children of thy people,"], ["ia faapea atu ia te i latou,", "and say unto them,"], ["A ou faaooina atu le pelu i se nuu,", "When I bring the sword upon a land,"], ["afai e avea e tagata o lea nuu se tagata o lo latou nuu,", "if the people of the land take a man of their coasts,"], ["ma latou tofia o ia e fai mo latou tagata vaai;", "and set him for their watchman:"]]},
  {num:3,words:[["a iloa atu e ia le pelu o loo sau i le nuu,", "If when he seeth the sword come upon the land,"], ["afai na te ilia le pu,", "he blow the trumpet,"], ["ma faailoa atu i le nuu;", "and warn the people;"]]},
  {num:4,words:[["o se na te lagona le leo o le pu,", "Then whosoever heareth the sound of the trumpet,"], ["a e le anaana i ai;", "and taketh not warning;"], ["a oo ane le pelu,", "if the sword come,"], ["ma oti ai o ia,", "and take him away,"], ["e i luga o lona lava ulu lona toto.", "his blood shall be upon his own head."]]},
  {num:5,words:[["Na ia lagona le leo o le pu,", "He heard the sound of the trumpet,"], ["a ua le anaana i ai; e ia te ia lava lona toto;", "and took not warning;"], ["a o Ie na te anaana e faasaoina e ia lona ola.", "his blood shall be upon him. But he that taketh warning shall deliver his soul."]]},
  {num:6,words:[["A e afai e iloa e le tagata vaai le pelu o loo sau,", "But if the watchman see the sword come,"], ["a e le ilia e ia le pu,", "and blow not the trumpet,"], ["ma ua le faailoa atu i le nuu;", "and the people be not warned;"], ["a oo mai le pelu,", "if the sword come,"], ["ma oti ai se tasi o i latou,", "and take any person from among them,"], ["ua oti o ia i lana amio leaga;", "he is taken away in his iniquity;"], ["a o lona toto ou te tauiatua lea i le tagata vaai.", "but his blood will I require at the watchman's hand."]]},
  {num:7,words:[["O oe foi le atalii o le tagata,", "So thou,"], ["ua ou tofia oe e fai ma tagata vaai i le aiga o Isaraelu;", "O son of man,"], ["o le mea lea ia e faalogo mai ai i le upu a lo'u gutu,", "I have set thee a watchman unto the house of Israel; therefore thou shalt hear the word at my mouth,"], ["ma e apoapoai atu ia te i latou i upu atu ia te au.", "and warn them from me."]]},
  {num:8,words:[["A ou fai atu i le ua amio leaga,", "When I say unto the wicked,"], ["Le tagata amio leaga e,", "O wicked man,"], ["e te oti lava oe; afai e te le tautala atu e apoapoai atu ai i le ua amio leaga,", "thou shalt surely die;"], ["ia liliu ese i lona ala;", "if thou dost not speak to warn the wicked from his way,"], ["e oti lena tagata amio leaga i lana amio leaga;", "that wicked man shall die in his iniquity;"], ["a o lona toto ou te tauiatua lea ia te oe.", "but his blood will I require at thine hand."]]},
  {num:9,words:[["A o oe,", "Nevertheless,"], ["afai e te apoapoai atu i le ua amio leaga,", "if thou warn the wicked of his way to turn from it;"], ["ia liliu ese o ia i lona ala; afai na te le liliu ese i lona ala,", "if he do not turn from his way,"], ["e oti o ia i lana amio leaga;", "he shall die in his iniquity;"], ["a ua faasaoina e oe lou lava agaga.", "but thou hast delivered thy soul."]]},
  {num:10,words:[["O oe na foi,", "Therefore,"], ["le atalii o le tagata,", "O thou son of man,"], ["fai atu ia i le aiga o Isaraelu,", "speak unto the house of Israel;"], ["Ua fai mai la outou upu,", "Thus ye speak,"], ["ua faapea mai, Afai ua ia te i matou o matou solitulafono,", "saying,"], ["ma a matou agasala,", "If our transgressions and our sins be upon us,"], ["ma tauāu ina faaumatia ai i matou,", "and we pine away in them,"], ["pe matou te ola ea faapefea?", "how should we then live?"]]},
  {num:11,words:[["Fai atu ia ia te i latou,", "Say unto them,"], ["O loo fetalai mai le Alii o Ieova,", "As I live,"], ["Ou te ola a'u,", "saith the Lord GOD,"], ["ou te le fiafia lava i le oti o lē amio leaga,", "I have no pleasure in the death of the wicked;"], ["a ia liliu mai lē amio leaga ai lona ala, ma ola ai;", "but that the wicked turn from his way and live:"], ["liliu ia outou,", "turn ye,"], ["ina outou liliu ese ia i o outou ala leaga;", "turn ye from your evil ways;"], ["auā pe se a ea le mea tou te fia oti ai,", "for why will ye die,"], ["le aiga o Isaraelu e?", "O house of Israel?"]]},
  {num:12,words:[["O oe foi le atalii o le tagata,", "Therefore,"], ["fai atu ia i tagata o lou nuu,", "thou son of man, say unto the children of thy people,"], ["E le laveaiina le ua amiotonu i lana amiotonu i le aso e solitulafono ai o ia;", "The righteousness of the righteous shall not deliver him in the day of his transgression:"], ["e le paū foi le ua amio leaga i lana amio leaga i le aso e liliu ese ai o ia i lana amio leaga;", "as for the wickedness of the wicked, he shall not fall thereby in the day that he turneth from his wickedness;"], ["e le ola foi le ua amiotonu i lana amiotonu i le aso e agasala ai o ia.", "neither shall the righteous be able to live for his righteousness in the day that he sinneth."]]},
  {num:13,words:[["A ou fai atu i le ua amiotonu,", "When I shall say to the righteous,"], ["e ola lava ia;", "that he shall surely live;"], ["afai e faalagolago ia i lana amiotonu,", "if he trust to his own righteousness, and commit iniquity,"], ["ma ua fai le amio leaga,", "all his righteousnesses shall not be remembered;"], ["ona le manatua lea o ana amiotonu uma,", "but for his iniquity that he hath committed,"], ["a e oti o ia ona o amio leaga ua ia faia.", "he shall die for it."]]},
  {num:14,words:[["A ou fai atu foi i le ua amio leaga,", "Again,"], ["E oti lava oe;", "when I say unto the wicked,"], ["afai e liliu ese ia i lana agasala,", "Thou shalt surely die; if he turn from his sin,"], ["ma ua fai e ia le amio tatau ma le amiotonu;", "and do that which is lawful and right;"]]},
  {num:15,words:[["afai e faafoi le ua amio leaga le mea e tuu faafaatau,", "If the wicked restore the pledge,"], ["ma toe avane le mea na ia fao,", "give again that he had robbed,"], ["ma ia savali i sauniga e ola ai,", "walk in the statutes of life,"], ["ma ua le fai le amio leaga;", "without committing iniquity;"], ["e ola lava ia,", "he shall surely live,"], ["e le oti.", "he shall not die."]]},
  {num:16,words:[["O ana agasala ua ia faia e le ta'uta'ua ia te ia;", "None of his sins that he hath committed shall be mentioned unto him:"], ["ua ia fai le amio tatau ma le tonu;", "he hath done that which is lawful and right;"], ["e ola lava ia.", "he shall surely live."]]},
  {num:17,words:[["A ua fai mai tagata o lou nuu,", "Yet the children of thy people say,"], ["E le tusa le ala o le Alii;", "The way of the Lord is not equal:"], ["a o i latou,", "but as for them,"], ["e le tusa lo latou ala.", "their way is not equal."]]},
  {num:18,words:[["A liliu ese le ua amiotonu i lana amiotonu,", "When the righteous turneth from his righteousness,"], ["ma ua faia e ia le amio leaga,", "and committeth iniquity,"], ["ona oti ai lava lea o ia.", "he shall even die thereby."]]},
  {num:19,words:[["A e afai e liliu ese le ua amio leaga ai lana amio leaga,", "But if the wicked turn from his wickedness,"], ["ma ua faia e ia le amio tatau ma le amiotonu,", "and do that which is lawful and right,"], ["ona ola ai lava lea o ia.", "he shall live thereby."]]},
  {num:20,words:[["A ua outou fai mai,", "Yet ye say,"], ["E le tusa le ala o le Alii. Le aiga o Isaraelu e,", "The way of the Lord is not equal. O ye house of Israel,"], ["ou te faamasinoina outou taitoatasi e tusa ma ona ala.", "I will judge you every one after his ways."]]},
  {num:21,words:[["O lona sefulu ma le lua o tausaga o lo matou tafeaga,", "And it came to pass in the twelfth year of our captivity,"], ["o lona sefulu o masina ,", "in the tenth month,"], ["o le aso e lima o le masina,", "in the fifth day of the month,"], ["na sau ai ia te au le tasi na sao mai Ierusalema,", "that one that had escaped out of Jerusalem came unto me,"], ["ua faapea mai,", "saying,"], ["Ua fasia le aai.", "The city is smitten."]]},
  {num:22,words:[["Na i ai foi le aao o Ieova ia te au i le afiafi,", "Now the hand of the LORD was upon me in the evening,"], ["a o lei oo mai le na sao;", "afore he that was escaped came;"], ["na ia faagaganaina foi a'u,", "and had opened my mouth,"], ["ua oo ina sau o ia ia te au i le taeao;", "until he came to me in the morning;"], ["ua faagaganaina a'u,", "and my mouth was opened,"], ["ua ou le toe faalologo.", "and I was no more dumb."]]},
  {num:23,words:[["Ona oo mai lea o le afioga a Ieova ia te au,", "Then the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:24,words:[["Le atalii e o le tagata,", "Son of man,"], ["o loo fai mai i latou o e o nonofo i mea gaogao i le laueleele o Isaraelu,", "they that inhabit those wastes of the land of Israel speak,"], ["ua faapea mai,", "saying,"], ["Sa toatasi Aperaamo,", "Abraham was one,"], ["na fai foi mona le nuu;", "and he inherited the land:"], ["a e toatele i tatou;", "but we are many;"], ["ua tuuina mai le nuu mo i tatou e fai mo tatou.", "the land is given us for inheritance."]]},
  {num:25,words:[["O le mea lea ia e fai atu ai ia te i latou. O loo faapea ona fetalai mai o le Alii o Ieova,", "Wherefore say unto them,"], ["Ua outou aai mea o i ai le toto,", "Thus saith the Lord GOD;"], ["ma ua outou vaavaai i o outou tupua,", "Ye eat with the blood, and lift up your eyes toward your idols,"], ["ma outou faamaligi toto;", "and shed blood:"], ["a e fai ea mo outou le nuu?", "and shall ye possess the land?"]]},
  {num:26,words:[["Ua outou tutū ma a outou pelu,", "Ye stand upon your sword,"], ["ua outou fai mea e inosia,", "ye work abomination,"], ["ua outou taitasi ma faaleagaina le avā a le tasi tagata;", "and ye defile every one his neighbour's wife:"], ["a e fai ea mo outou le nuu?", "and shall ye possess the land?"]]},
  {num:27,words:[["Ia faapea ona e fai atu ia te i latou,", "Say thou thus unto them,"], ["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Ou te ola a'u,", "As I live,"], ["o i latou o e ua i ai i mea gaogao e oti lava i latou i le pelu,", "surely they that are in the wastes shall fall by the sword,"], ["o le ua i le vao ou te tuuina atu lava o ia i manu feai ia 'aina;", "and him that is in the open field will I give to the beasts to be devoured,"], ["o i latou foi o e ua i 'olo ma ana e oti lava i latou i le faamai.", "and they that be in the forts and in the caves shall die of the pestilence."]]},
  {num:28,words:[["Ou te matuā faatafunaina lava le nuu,", "For I will lay the land most desolate,"], ["ma ou faaiuina lona malosi e mitamita ai;", "and the pomp of her strength shall cease;"], ["e faatafunaina foi mauga o Isaraelu,", "and the mountains of Israel shall be desolate,"], ["e le uia lava e se tasi.", "that none shall pass through."]]},
  {num:29,words:[["Ona latou iloa ai lea o a'u lava o Ieova,", "Then shall they know that I am the LORD,"], ["pe a ou matuā faatafunaina le nuu ona o a latou mea uma e inosia ua latou faia.", "when I have laid the land most desolate because of all their abominations which they have committed."]]},
  {num:30,words:[["O oe foi le atalii o le tagata,", "Also, thou son of man,"], ["o loo tautalatala pea tagata o lou nuu ia te oe e lata ane i pa ma faitotoa o fale,", "the children of thy people still are talking against thee by the walls and in the doors of the houses,"], ["o loo fetautalatalai i latou o le tasi i le tasi,", "and speak one to another,"], ["ua faapea,", "every one to his brother, saying,"], ["O mai ia,", "Come, I pray you,"], ["se'i faalogologo pe se a se afioga ua tŭlei mai mai ia Ieova.", "and hear what is the word that cometh forth from the LORD."]]},
  {num:31,words:[["Latou te o mai foi ia te oe pei ona o mai o lo'u nuu,", "And they come unto thee as the people cometh,"], ["latou te nonofo foi i ou luma e pei o lo'u nuu,", "and they sit before thee as my people,"], ["latou te faalogologo foi i au upu,", "and they hear thy words,"], ["a e latou te le mafafai ona anaana i ai;", "but they will not do them:"], ["auā ua latou alolofa fua i o latou gutu,", "for with their mouth they shew much love,"], ["a ua mafuli o latou loto i lo latou manumanu.", "but their heart goeth after their covetousness."]]},
  {num:32,words:[["Faauta foi,", "And,"], ["ua tusa oe ia te i latou ma se pese mālie a le ua leo mālie,", "lo,"], ["ma lē ta mālie i le laaupese;", "thou art unto them as a very lovely song of one that hath a pleasant voice, and can play well on an instrument:"], ["auā latou te faalogologo i au upu,", "for they hear thy words,"], ["a e latou te le anaana i ai.", "but they do them not."]]},
  {num:33,words:[["A taunuu lea mea,", "And when this cometh to pass,"], ["faauta e taunuu lava,", "(lo, it will come,"], ["ona latou iloa ai lea sa i ai le perofeta ia te i latou.", ") then shall they know that a prophet hath been among them."]]},
  {num:34,words:[["Ua oo mai foi le afioga", "it came to pass from also the a word"], ["a le ALII ia te au,", "but the Lord unto I"], ["ua faapea mai,", "saying"]]},
];
renderVerseSet(ezk_ch_33_Verses, 'ezk-ch33-verses');

var ezk_ch_34_Verses = [
  {num:1,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "And the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia e vavalo atu i leoleo mamoe o Isaraelu,", "prophesy against the shepherds of Israel,"], ["ina vavalo atu ia, ma e fai atu ia te i latou,", "prophesy,"], ["o leoleo mamoe lava,", "and say unto them,"], ["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD unto the shepherds;"], ["Oi talofa i leoleo mamoe o Isaraelu o e fafaga ia te i latou lava! E le tatau ea i leoleo mamoe ona fagaina o le lafu?", "Woe be to the shepherds of Israel that do feed themselves! should not the shepherds feed the flocks?"]]},
  {num:3,words:[["Ua outou aai le ga'o,", "Ye eat the fat,"], ["ma oofu i le fulufulu,", "and ye clothe you with the wool,"], ["ua outou fasia e ua pepeti,", "ye kill them that are fed:"], ["a ua outou le fafaga i le lafu.", "but ye feed not the flock."]]},
  {num:4,words:[["Ua outou le faamalosia e ua vaivai;", "The diseased have ye not strengthened,"], ["ua outou le faamalolo i le ua ma'i;", "neither have ye healed that which was sick,"], ["ua outou le fusia foi le ua gau;", "neither have ye bound up that which was broken,"], ["o le ua tulia ua outou le toe aumaia,", "neither have ye brought again that which was driven away,"], ["o le ua sē ua outou le sailia;", "neither have ye sought that which was lost;"], ["a ua outou pule faamalosi ma faasaua ia te i latou.", "but with force and with cruelty have ye ruled them."]]},
  {num:5,words:[["Na faataapeapeina foi i latou ina ua leai se leoleo mamoe;", "And they were scattered,"], ["na fai foi i latou ma mea e 'ai ma manu feai uma o le vao,", "because there is no shepherd: and they became meat to all the beasts of the field,"], ["ina ua faataapeapeina i latou.", "when they were scattered."]]},
  {num:6,words:[["Na sē la'u lafu i mauga uma,", "My sheep wandered through all the mountains,"], ["ma mea maualuluga uma;", "and upon every high hill:"], ["na faataapeapeina foi la'u lafu i le fogāeleele uma,", "yea,"], ["a e leai se na suesue i ai ,", "my flock was scattered upon all the face of the earth,"], ["e leai foi se na sailia.", "and none did search or seek after them."]]},
  {num:7,words:[["O le mea lea,", "Therefore,"], ["leoleo mamoe e,", "ye shepherds,"], ["ia outou faalogo mai ai i le afioga a Ieova;", "hear the word of the LORD;"]]},
  {num:8,words:[["ua fetalai mai le Alii o Ieova,", "As I live,"], ["Ou te ola a'u,", "saith the Lord GOD,"], ["na avea lava la'u lafu ma mea e saeia,", "surely because my flock became a prey,"], ["na avea foi la'u lafu ma mea e 'ai a manu feai uma o le vao,", "and my flock became meat to every beast of the field,"], ["ina ua leai se leoleo mamoe,", "because there was no shepherd,"], ["ua le sueina foi e a'u leoleo mamoe la'u lafu,", "neither did my shepherds search for my flock,"], ["a o leoleo mamoe ua fafaga i latou ia te i latou lava,", "but the shepherds fed themselves,"], ["a e lei fagaina e i latou la'u lafu;", "and fed not my flock;"]]},
  {num:9,words:[["o le mea lea,", "Therefore,"], ["leoleo mamoe e,", "O ye shepherds,"], ["ia outou faalogo mai ai i le afioga a Ieova;", "hear the word of the LORD;"]]},
  {num:10,words:[["ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Faauta,", "Behold,"], ["ou te faia ia leoleo mamoe mo'u fili;", "I am against the shepherds;"], ["ou te sueina atu foi la'u lafu ia te i latou,", "and I will require my flock at their hand,"], ["ou te faate'aina i latou ia le toe fafaga le lafu;", "and cause them to cease from feeding the flock;"], ["o leoleo mamoe foi latou te le toe fafaga lava ia te i latou;", "neither shall the shepherds feed themselves any more;"], ["auā ou te laveaiina la'u lafu i o latou gutu,", "for I will deliver my flock from their mouth,"], ["ina ia le fai i latou ma mea e 'ai mā latou.", "that they may not be meat for them."]]},
  {num:11,words:[["Auā ua faapea ona fetalai mai o le Alii o Ieova,", "For thus saith the Lord GOD;"], ["Faauta,", "Behold,"], ["o a'u,", "I,"], ["o a'u lava,", "even I,"], ["ou te sueina la'u lafu,", "will both search my sheep,"], ["ou te matuā suesue lava i ai.", "and seek them out."]]},
  {num:12,words:[["E pei o le leoleo mamoe ona sueina o lana lafu i le aso o i ai o ia i lana lafu ua taapeape;", "As a shepherd seeketh out his flock in the day that he is among his sheep that are scattered;"], ["e faapea ona ou sueina la'u lafu,", "so will I seek out my sheep,"], ["ma ou laveaiina i latou ai mea uma ua salalau ai i latou i le aso faamalumalu ma le pogisa.", "and will deliver them out of all places where they have been scattered in the cloudy and dark day."]]},
  {num:13,words:[["Ou te aumaia foi i latou nai nuu,", "And I will bring them out from the people,"], ["ma ou faapotopotoina i latou mai nuu eseese;", "and gather them from the countries,"], ["ou te aumaia i latou i lo latou lava laueleele, ma fagaina i latou i mauga o Isaraelu,", "and will bring them to their own land,"], ["i tafatafa o vaitafe,", "and feed them upon the mountains of Israel by the rivers,"], ["ma mea uma e āina o le nuu.", "and in all the inhabited places of the country."]]},
  {num:14,words:[["Ou te fafaga ia te i latou i le taaga lelei,", "I will feed them in a good pasture,"], ["e i ai o latou lotoā i mauga maualuluga o Isaraelu;", "and upon the high mountains of Israel shall their fold be:"], ["latou te taooto ai i le lotoā lelei,", "there shall they lie in a good fold,"], ["o le taaga lelei foi e aai ai i latou i mauga o Isaraelu.", "and in a fat pasture shall they feed upon the mountains of Israel."]]},
  {num:15,words:[["Ou te fagaina la'u lafu,", "I will feed my flock,"], ["o a'u foi e taooto ai i latou,", "and I will cause them to lie down,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:16,words:[["Ou te sailia foi le ua sē,", "I will seek that which was lost,"], ["ou te aumaia le ua tulia,", "and bring again that which was driven away,"], ["ou te fusia le ua gau,", "and will bind up that which was broken,"], ["ou te faamalosia le ua vaivai;", "and will strengthen that which was sick:"], ["a o le ua peti ma le ua malosi ou te faaumatia ia,", "but I will destroy the fat and the strong;"], ["ou te fagaina i latou i le faamasinoga.", "I will feed them with judgment."]]},
  {num:17,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "And as for you,"], ["O outou o la'u lafu e,", "O my flock,"], ["faauta,", "thus saith the Lord GOD; Behold,"], ["ou te faamasino i manu ma manu,", "I judge between cattle and cattle,"], ["o mamoe poa ma 'oti poa.", "between the rams and the he goats."]]},
  {num:18,words:[["O le mea māmā ea ia te outou ina ua le na ona outou aai i taaga lelei,", "Seemeth it a small thing unto you to have eaten up the good pasture,"], ["a ua outou solia i o outou vae o mea ua totoe i taaga; ua le na ona outou inu foi i vai manino,", "but ye must tread down with your feet the residue of your pastures? and to have drunk of the deep waters,"], ["a ua outou faagaepu i o outou vae o vai ua totoe?", "but ye must foul the residue with your feet?"]]},
  {num:19,words:[["O la'u lafu foi ua latou aai mea ua solia i o outou vae;", "And as for my flock, they eat that which ye have trodden with your feet;"], ["ma latou inu le vai ua faagaepuina i o outou vae.", "and they drink that which ye have fouled with your feet."]]},
  {num:20,words:[["O le mea lea ua faapea ona fetalai mai ai o le Alii o Ieova ia te i latou,", "Therefore thus saith the Lord GOD unto them;"], ["Faauta,", "Behold,"], ["o a'u,", "I,"], ["o a'u lava,", "even I,"], ["ou te faamasino i manu pepeti ma manu paeee.", "will judge between the fat cattle and between the lean cattle."]]},
  {num:21,words:[["Ua outou tūlei i o outou itu,", "Because ye have thrust with side and with shoulder,"], ["ma outou alagalima, ma ua outou suatia e ua vaivai uma i o outou nifo,", "and pushed all the diseased with your horns,"], ["ua oo ina outou faataapeapeina i latou i tuāpa.", "till ye have scattered them abroad;"]]},
  {num:22,words:[["O le mea lea ou te faaolaina ai la'u lafu,", "Therefore will I save my flock,"], ["e le toe fai lava i latou ma mea e saeia;", "and they shall no more be a prey;"], ["ou te faamasino foi i lea manu ma lea manu.", "and I will judge between cattle and cattle."]]},
  {num:23,words:[["Ou te faatuina foi le leoleo mamoe e tasi ia te i latou,", "And I will set up one shepherd over them,"], ["na te fagaina i latou,", "and he shall feed them,"], ["o la'u auauna o Tavita;", "even my servant David;"], ["o ia na te fagaina i latou,", "he shall feed them,"], ["e fai foi o ia ma leoleo mamoe ia te i latou;", "and he shall be their shepherd."]]},
  {num:24,words:[["o a'u nei foi o Ieova e fai a'u mo latou Atua,", "And I the LORD will be their God,"], ["o la'u auauna foi o Tavita e fai o ia ma alii sili ia te i latou;", "and my servant David a prince among them;"], ["o a'u o Ieova ua ou fai atu ai.", "I the LORD have spoken it."]]},
  {num:25,words:[["Ou te osia foi ma i latou le feagaiga e manuia ai,", "And I will make with them a covenant of peace,"], ["ou te faaumatia manu feai i le nuu;", "and will cause the evil beasts to cease out of the land:"], ["latou te nonofo fifilemu ai i le vao,", "and they shall dwell safely in the wilderness,"], ["ma momoe i le vao matua.", "and sleep in the woods."]]},
  {num:26,words:[["O i latou ma mea o vagavagai lo'u mauga ou te avea ia ma mea o manuia ai;", "And I will make them and the places round about my hill a blessing;"], ["ou te faatotō ifo le ua i ona lava po;", "and I will cause the shower to come down in his season;"], ["e i ai uaga e manuia ai.", "there shall be showers of blessing."]]},
  {num:27,words:[["E fua mai le laau o le fanua lona fua;", "And the tree of the field shall yield her fruit,"], ["e fua mai foi le laueleele lona fua;", "and the earth shall yield her increase,"], ["latou te nonofo filemu foi i lo latou nuu;", "and they shall be safe in their land, and shall know that I am the LORD,"], ["ona latou iloa ai lea o a'u lava o Ieova pe a ou gagauina a latou amo,", "when I have broken the bands of their yoke,"], ["ma ou laveaiina i latou ai lima o e na faapologaina i latou.", "and delivered them out of the hand of those that served themselves of them."]]},
  {num:28,words:[["E le toe fai lava i latou ma mea e saeia i nuu ese,", "And they shall no more be a prey to the heathen,"], ["e le 'aina foi i latou e manu feai e tataa;", "neither shall the beast of the land devour them;"], ["a e latou te nonofo fifilemu,", "but they shall dwell safely,"], ["e leai foi se na te faamatau ia te i latou .", "and none shall make them afraid."]]},
  {num:29,words:[["Ou te faatupuina foi mo i latou le faatoaga e ta'ua,", "And I will raise up for them a plant of renown,"], ["e le toe faaumatia i latou i le fia 'ai i le nuu,", "and they shall be no more consumed with hunger in the land,"], ["e le toe oo lava ia te i latou le faamasiasiga o nuu ese.", "neither bear the shame of the heathen any more."]]},
  {num:30,words:[["Ona latou iloa ai lea o a'u lava o Ieova lo latou Atua,", "Thus shall they know that I the LORD their God am with them,"], ["ou te ia te i latou;", "and that they,"], ["o i latou foi le aiga o Isaraelu o lo'u nuu lava i latou ,", "even the house of Israel, are my people,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:31,words:[["O outou foi la'u lafu,", "And ye my flock,"], ["o le lafu o la'u taaga,", "the flock of my pasture,"], ["o tagata lava outou;", "are men,"], ["o a'u foi o lo outou Atua,", "and I am your God,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
];
renderVerseSet(ezk_ch_34_Verses, 'ezk-ch34-verses');

var ezk_ch_35_Verses = [
  {num:1,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "Moreover the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia e faasaga atu i le mauga o Seira, ma vavalo atu i ai,", "set thy face against mount Seir,"], ["fai atu foi i ai,", "and prophesy against it,"]]},
  {num:3,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "And say unto it,"], ["Faauta,", "Thus saith the Lord GOD;"], ["le mauga o Seira e,", "Behold, O mount Seir,"], ["ua ou fai oe mo'u fili,", "I am against thee,"], ["ou te faaloaloa atu foi lo'u lima i luga ia te oe,", "and I will stretch out mine hand against thee,"], ["ma ou matuā faatafunaina lava oe.", "and I will make thee most desolate."]]},
  {num:4,words:[["Ou te faagaogaoina ou aai,", "I will lay thy cities waste,"], ["e faatafunaina lava oe,", "and thou shalt be desolate,"], ["ona e iloa ai lea o a'u lava o Ieova.", "and thou shalt know that I am the LORD."]]},
  {num:5,words:[["Auā ua ia te oe le itatuu,", "Because thou hast had a perpetual hatred,"], ["ma ua e tuuina atu le fanauga a Isaraelu i le malosi o le pelu i ona po o lo latou malaia,", "and hast shed the blood of the children of Israel by the force of the sword in the time of their calamity,"], ["o ona po foi na iu ai le amio leaga.", "in the time that their iniquity had an end:"]]},
  {num:6,words:[["O le mea lea o loo fetalai mai ai le Alii o Ieova,", "Therefore,"], ["Ou te ola a'u,", "as I live,"], ["o'u te tuuina atu oe i le toto,", "saith the Lord GOD, I will prepare thee unto blood,"], ["e tuliloa foi le toto ia te oe;", "and blood shall pursue thee:"], ["na e le 'ino'ino i le toto,", "sith thou hast not hated blood,"], ["o lea e tuliloa ai le toto ia te oe.", "even blood shall pursue thee."]]},
  {num:7,words:[["Ou te matuā faatafunaina le mauga o Seira, ma ou faaumatia o ia o le alu atu i ai,", "Thus will I make mount Seir most desolate,"], ["atoa ma le toe foi mai.", "and cut off from it him that passeth out and him that returneth."]]},
  {num:8,words:[["Ou te faatutumuina foi ona mauga i ona tagata ua fasia;", "And I will fill his mountains with his slain men:"], ["o ou mauga,", "in thy hills,"], ["ma ou vanu,", "and in thy valleys,"], ["ma ou vaitafe uma,", "and in all thy rivers,"], ["e pauu ai i latou o e ua fasia i le pelu.", "shall they fall that are slain with the sword."]]},
  {num:9,words:[["Ou te faatafunaina oe e faavavau,", "I will make thee perpetual desolations,"], ["e le toe āina ou aai;", "and thy cities shall not return:"], ["ona outou iloa ai lea o a'u lava o Ieova.", "and ye shall know that I am the LORD."]]},
  {num:10,words:[["Ua e faapea,", "Because thou hast said,"], ["O ia nuu e lua,", "These two nations and these two countries shall be mine,"], ["ma o la laueleele e lua e fai mo'u, matou te nonofo ai;", "and we will possess it;"], ["a e peitai ua i ai Ieova.", "whereas the LORD was there:"]]},
  {num:11,words:[["O le mea lea ua fetalai mai ai le Alii o Ieova,", "Therefore,"], ["Ou te ola a'u,", "as I live,"], ["ou te faia ia te oe e tusa ma lou ita,", "saith the Lord GOD, I will even do according to thine anger,"], ["e tusa foi ma lou mataua na e faia i lou 'ino'ino ia te i latou;", "and according to thine envy which thou hast used out of thy hatred against them;"], ["ou te faailoa atu foi o a'u ua ia te i latou,", "and I will make myself known among them,"], ["pe a ou faasalaina oe.", "when I have judged thee."]]},
  {num:12,words:[["Ona e iloa ai lea o a'u lava o Ieova,", "And thou shalt know that I am the LORD,"], ["ua ou faalogoina au upu faifai uma ua e fai atu ai i mauga o Isaraelu,", "and that I have heard all thy blasphemies which thou hast spoken against the mountains of Israel,"], ["ua faapea,", "saying,"], ["Ua faatafunaina ia,", "They are laid desolate,"], ["ua tuuina mai ia te i matou e fai ma mea e 'ai.", "they are given us to consume."]]},
  {num:13,words:[["Ua outou tautala faasausili ia te au,", "Thus with your mouth ye have boasted against me,"], ["ua faateleina foi a outou upu ia te au;", "and have multiplied your words against me:"], ["ua ou faalogo ai lava.", "I have heard them."]]},
  {num:14,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["A olioli le lalolagi uma,", "When the whole earth rejoiceth,"], ["ou te faatafunaina oe.", "I will make thee desolate."]]},
  {num:15,words:[["E pei ona e olioli ina ua faatafunaina o le tofi o le aiga o Isaraelu,", "As thou didst rejoice at the inheritance of the house of Israel,"], ["e faapea ona ou faia ia te oe;", "because it was desolate, so will I do unto thee:"], ["e faatafunaina oe le mauga o Seira,", "thou shalt be desolate,"], ["atoa ma Etoma uma,", "O mount Seir,"], ["o le nuu uma lava;", "and all Idumea, even all of it:"], ["ona latou iloa ai lea o a'u lava o Ieova.", "and they shall know that I am the LORD."]]},
];
renderVerseSet(ezk_ch_35_Verses, 'ezk-ch35-verses');

var ezk_ch_36_Verses = [
  {num:1,words:[["O oe foi le atalii o le tagata,", "Also,"], ["ia e vavalo atu i mauga o Isaraelu,", "thou son of man,"], ["ma e fai atu,", "prophesy unto the mountains of Israel, and say,"], ["Mauga o Isaraelu e,", "Ye mountains of Israel,"], ["faalogologo mai ia i le afioga a Ieova.", "hear the word of the LORD:"]]},
  {num:2,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Ua fai mai ia te outou le ua ita mai,", "Because the enemy hath said against you, Aha,"], ["Ue! ua fai mo i matou mea maualuga o le vavau;", "even the ancient high places are our's in possession:"]]},
  {num:3,words:[["o le mea lea ia e vavalo atu ai,", "Therefore prophesy and say,"], ["ma e fai atu,", "Thus saith the Lord GOD;"], ["Ua faapea ona fetalai mai o le Alii o Ieova,", "Because they have made you desolate,"], ["Ua latou faatafunaina outou , ma naunau i le fia maua outou i itu uma,", "and swallowed you up on every side,"], ["ina ia fai outou mo e o totoe o nuu ese,", "that ye might be a possession unto the residue of the heathen,"], ["ma ua ta'uta'uina outou e tagata faitala,", "and ye are taken up in the lips of talkers,"], ["ma ua ta'uleagaina e le nuu;", "and are an infamy of the people:"]]},
  {num:4,words:[["o le mea lava lea,", "Therefore,"], ["mauga o Isaraelu e,", "ye mountains of Israel,"], ["ia outou faalogologo mai ai i le afioga a le Alii o Ieova,", "hear the word of the Lord GOD;"], ["Ua faapea ona fetalai mai o le Alii o Ieova i mauga,", "Thus saith the Lord GOD to the mountains,"], ["ma mauga iti, ma vaitafe,", "and to the hills,"], ["ma vanu,", "to the rivers,"], ["ma mea gaogao ua faatafunaina,", "and to the valleys,"], ["ma aai ua tuufua,", "to the desolate wastes,"], ["ua faoa,", "and to the cities that are forsaken,"], ["ma ua tauemua e i latou ua totoe o nuu ese i itu uma.", "which became a prey and derision to the residue of the heathen that are round about;"]]},
  {num:5,words:[["O le mea lea ua faapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["O le afi lava o lo'u fuā ua ou fai atu ai i e ua totoe o nuu ese,", "Surely in the fire of my jealousy have I spoken against the residue of the heathen,"], ["atoa ma Etoma uma, o e ua avea lo'u laueleele e fai mo latou,", "and against all Idumea,"], ["ma le fiafia o le loto atoa,", "which have appointed my land into their possession with the joy of all their heart,"], ["ma le 'ino'ino o loto,", "with despiteful minds,"], ["ina ia faoa e fai ma vete.", "to cast it out for a prey."]]},
  {num:6,words:[["O le mea lea ia e vavalo atu ai i le laueleele o Isaraelu,", "Prophesy therefore concerning the land of Israel,"], ["ma fai atu i mauga,", "and say unto the mountains,"], ["ma mauga iti,", "and to the hills,"], ["ma vaitafe,", "to the rivers,"], ["ma vanu,", "and to the valleys,"], ["O loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Faauta,", "Behold,"], ["o lo'u fuā ma lo'u ita tele ua ou tautala atu ai;", "I have spoken in my jealousy and in my fury,"], ["auā ua oo ia te outou le faamasiasiga o nuu ese.", "because ye have borne the shame of the heathen:"]]},
  {num:7,words:[["O le mea lea ua faapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["Ua ou sii lo'u lima,", "I have lifted up mine hand,"], ["ua faapea, O nuu ese o vagavagai ia te outou,", "Surely the heathen that are about you,"], ["e masiasi lava i latou.", "they shall bear their shame."]]},
  {num:8,words:[["A o outou mauga o Isaraelu e,", "But ye,"], ["e tutupu o outou la laau,", "O mountains of Israel,"], ["e fua mai foi a outou fua mā lo'u nuu o Isaraelu;", "ye shall shoot forth your branches, and yield your fruit to my people of Israel;"], ["auā ua latalata ona latou o mai.", "for they are at hand to come."]]},
  {num:9,words:[["Auā faauta,", "For,"], ["ou te i ai ia te outou,", "behold,"], ["ou te faasaga atu foi ia te outou,", "I am for you, and I will turn unto you,"], ["ona galueaiina lea outou ma faatoaina.", "and ye shall be tilled and sown:"]]},
  {num:10,words:[["Ou te faauluolaina foi tagata ia te outou,", "And I will multiply men upon you,"], ["o le aiga uma o Isaraelu,", "all the house of Israel,"], ["o lona atoatoa lava;", "even all of it:"], ["e āina foi aai,", "and the cities shall be inhabited,"], ["e atiina ae foi mea ua faatafunaina.", "and the wastes shall be builded:"]]},
  {num:11,words:[["Ou te faauluolaina o tagata atoa ma manu ia te outou;", "And I will multiply upon you man and beast;"], ["e uluola lava i latou ma fananau;", "and they shall increase and bring fruit:"], ["o a'u e āinaina ai outou e pei o ona tuga tuai ia te outou,", "and I will settle you after your old estates,"], ["ou te agalelei foi ia te outou e sili i lo outou uluai āina;", "and will do better unto you than at your beginnings:"], ["ona outou iloa ai lea o a'u lava o Ieova.", "and ye shall know that I am the LORD."]]},
  {num:12,words:[["Ou te faafeoaiina tagata i luga ia te outou,", "Yea,"], ["o lo'u lava nuu o Isaraelu;", "I will cause men to walk upon you,"], ["e fai oe mo latou,", "even my people Israel; and they shall possess thee,"], ["e fai foi oe mo latou tofi,", "and thou shalt be their inheritance,"], ["e te le toe faaumatia lava tagata ai ia te i latou.", "and thou shalt no more henceforth bereave them of men."]]},
  {num:13,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Ua latou faapea atu ia te outou,", "Because they say unto you,"], ["O oe ua e 'ai tagata,", "Thou land devourest up men,"], ["ma ua e faaumatia tagata o ou nuu;", "and hast bereaved thy nations;"]]},
  {num:14,words:[["o le mea lea e te le toe 'ai tagata ai lava,", "Therefore thou shalt devour men no more,"], ["e te le toe faaumatia foi tagata ai ou nuu,", "neither bereave thy nations any more,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:15,words:[["O a'u foi e le toe lagona ai le faamasiasiga o nuu ese,", "Neither will I cause men to hear in thee the shame of the heathen any more,"], ["e le toe oo atu lava ia te oe le faaluma mai o tagata,", "neither shalt thou bear the reproach of the people any more,"], ["e le toe faatausuaiina foi ou nuu,", "neither shalt thou cause thy nations to fall any more,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:16,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "Moreover the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:17,words:[["Le atalii e o le tagata,", "Son of man,"], ["sa mau le aiga o Isaraelu i lo latou lava laueleele,", "when the house of Israel dwelt in their own land,"], ["ona leaga ai lea ia te i latou i a latou amio ma a latou mea na fai;", "they defiled it by their own way and by their doings:"], ["sa tusa a latou amio i o'u luma ma le leaga o le fafine ua nofo ese.", "their way was before me as the uncleanness of a removed woman."]]},
  {num:18,words:[["O le mea lea na ou sasaa ai lo'u ita i luga ia te i latou, ona o le toto na latou faamaligiina i luga o le eleele,", "Wherefore I poured my fury upon them for the blood that they had shed upon the land,"], ["ona o a latou tupua foi na latou faaleagaina ai le nuu .", "and for their idols wherewith they had polluted it:"]]},
  {num:19,words:[["Na ou faataapeape foi ia te i latou i nuu ese,", "And I scattered them among the heathen,"], ["ma faasalalauina i latou i nuu eseese; na ou faasala foi ia te i latou e tusa ma o latou ala,", "and they were dispersed through the countries:"], ["e tusa foi ma a latou mea na fai.", "according to their way and according to their doings I judged them."]]},
  {num:20,words:[["Ua latou oo atu i nuu ese,", "And when they entered unto the heathen,"], ["na latou o i ai,", "whither they went,"], ["ona ta'uvaleina ai lea o lo'u igoa paia ona o i latou,", "they profaned my holy name,"], ["ina ua faapea ane ia te i latou,", "when they said to them,"], ["O le nuu lea o Ieova,", "These are the people of the LORD,"], ["ua latou o mai nai lona laueleele.", "and are gone forth out of his land."]]},
  {num:21,words:[["A e peitai na ou alofa ona o lo'u igoa paia,", "But I had pity for mine holy name, which the house of Israel had profaned among the heathen,"], ["o le na ta'uvaleina e le aiga o Isaraelu i nuu ese na latou o i ai.", "whither they went."]]},
  {num:22,words:[["O le mea lea ia e fai atu ai i le aiga o Isaraelu,", "Therefore say unto the house of Israel,"], ["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD; I do not this for your sakes,"], ["Ou te le faia lea mea ona o outou,", "O house of Israel,"], ["le aiga o Isaraelu e,", "but for mine holy name's sake, which ye have profaned among the heathen,"], ["a o lo'u igoa paia o le ua outou ta'uvaleina i nuu ese ua outou o i ai.", "whither ye went."]]},
  {num:23,words:[["Ou te faapaiaina lo'u igoa mamalu ua ta'uvaleina i nuu ese,", "And I will sanctify my great name,"], ["o le ua ta'uvaleina lava e outou i totonu ia te i latou;", "which was profaned among the heathen,"], ["e iloa ai foi e nuu ese o a'u lava o Ieova,", "which ye have profaned in the midst of them; and the heathen shall know that I am the LORD,"], ["o loo fetalai mai ai le Alii o Ieova,", "saith the Lord GOD,"], ["pe a ta'upaiaina o a'u ia te outou i o outou luma.", "when I shall be sanctified in you before their eyes."]]},
  {num:24,words:[["Auā ou te avea outou ai nuu ese,", "For I will take you from among the heathen,"], ["ma ou faapotopotoina outou mai nuu eseese uma,", "and gather you out of all countries,"], ["ma ou aumaia outou i lo outou laueleele.", "and will bring you into your own land."]]},
  {num:25,words:[["Ona ou sausauina lea o outou i le vai manino,", "Then will I sprinkle clean water upon you,"], ["ona mamā ai lea o outou;", "and ye shall be clean:"], ["ou te faamamāina foi outou i lo outou leaga uma,", "from all your filthiness, and from all your idols,"], ["ma a outou tupua uma.", "will I cleanse you."]]},
  {num:26,words:[["Ou te avatu foi ia te outou le loto fou,", "A new heart also will I give you,"], ["ma ou tuu i totonu ia te outou le agaga fou;", "and a new spirit will I put within you:"], ["ou te aveesea le loto maaa ai o outou tino,", "and I will take away the stony heart out of your flesh,"], ["ma ou avatu ia te outou le loto aano.", "and I will give you an heart of flesh."]]},
  {num:27,words:[["Ou te tuuina atu lo'u Agaga i totonu ia te outou,", "And I will put my spirit within you,"], ["tou te savavali ai i a'u tulafono,", "and cause you to walk in my statutes,"], ["tou te anaana foi i a'u faamasinoga,", "and ye shall keep my judgments,"], ["ma outou faia.", "and do them."]]},
  {num:28,words:[["Tou te nonofo foi i le nuu na ou foaiina atu i o outou tamā;", "And ye shall dwell in the land that I gave to your fathers;"], ["e fai foi outou mo'u nuu,", "and ye shall be my people,"], ["e fai foi a'u mo outou Atua.", "and I will be your God."]]},
  {num:29,words:[["Ou te faaolaina foi outou ai lo outou leaga uma;", "I will also save you from all your uncleannesses:"], ["ou te valaau foi i le saito,", "and I will call for the corn,"], ["ma ou faatuputeleina,", "and will increase it,"], ["a e ou te le tuu atu se oge ia te outou.", "and lay no famine upon you."]]},
  {num:30,words:[["Ou te faatuputeleina foi fua o laau,", "And I will multiply the fruit of the tree,"], ["ma mea e tutupu i le eleele,", "and the increase of the field,"], ["ina ia le toe oo ia te outou le faaluma mai o nuu ese ona o le oge.", "that ye shall receive no more reproach of famine among the heathen."]]},
  {num:31,words:[["Ona outou manatunatu ai lea i o outou lava ala leaga ma mea sa outou faia e le o i ai se lelei,", "Then shall ye remember your own evil ways,"], ["tou te 'ino'ino ai lava outou ia te outou ona o a outou amio leaga,", "and your doings that were not good,"], ["atoa ma a outou mea e inosia.", "and shall lothe yourselves in your own sight for your iniquities and for your abominations."]]},
  {num:32,words:[["O loo fetalai mai le Alii o Ieova,", "Not for your sakes do I this,"], ["Ia iloa e outou ou te le faia ia mea ona o outou;", "saith the Lord GOD,"], ["ia outou mamā ma ia outou masiasi ona o outou ala,", "be it known unto you: be ashamed and confounded for your own ways,"], ["le aiga o Isaraelu.", "O house of Israel."]]},
  {num:33,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["O le aso ou te faamamāina ai outou i a outou amio leaga uma, o a'u e āina ai a outou aai,", "In the day that I shall have cleansed you from all your iniquities I will also cause you to dwell in the cities,"], ["e atiina ae foi mea ua faatafunaina.", "and the wastes shall be builded."]]},
  {num:34,words:[["E galueaiina foi le laueleele sa faaatafunaina,", "And the desolate land shall be tilled,"], ["sa faatafunaina lava i luma o i latou uma e na ui ane ai.", "whereas it lay desolate in the sight of all that passed by."]]},
  {num:35,words:[["Ona latou fai ane lea, O lenei laueleele sa faatafunaina,", "And they shall say,"], ["ua avea e pei o le faatoaga o Etena; o aai foi sa gaogao,", "This land that was desolate is become like the garden of Eden;"], ["ma faatafunaina,", "and the waste and desolate and ruined cities are become fenced,"], ["ma lepetia, ua nofo 'olo i latou ua āina.", "and are inhabited."]]},
  {num:36,words:[["Ona iloa ai lea e nuu ese o e totoe i o outou itu uma,", "Then the heathen that are left round about you shall know that I the LORD build the ruined places,"], ["o a'u o Ieova ua ou atiina ae mea sa lepetia,", "and plant that that was desolate:"], ["ma faatoaina le mea sa faatafunaina; o a'u o Ieova ua ou fai atu ai,", "I the LORD have spoken it,"], ["ou te faia lava.", "and I will do it."]]},
  {num:37,words:[["O loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["E ui i lea,", "I will yet for this be enquired of by the house of Israel,"], ["a e sailia mai pea o a'u e le aiga o Isaraelu, ia faia ia mea mo i latou;", "to do it for them;"], ["ou te faatoateleina foi i latou e pei se lafu tagata.", "I will increase them with men like a flock."]]},
  {num:38,words:[["E pei o le lafu paia,", "As the holy flock,"], ["e pei o le lafu o Ierusalema i ona tausamiga,", "as the flock of Jerusalem in her solemn feasts;"], ["e faapea ona faatutumuina o aai gaogao i lafu tagata;", "so shall the waste cities be filled with flocks of men:"], ["latou te iloa ai o a'u lava o Ieova.", "and they shall know that I am the LORD."]]},
];
renderVerseSet(ezk_ch_36_Verses, 'ezk-ch36-verses');

var ezk_ch_37_Verses = [
  {num:1,words:[["Na i luga ia te au le aao o Ieova;", "The hand of the LORD was upon me,"], ["na ia aveina atu a'u i le Agaga o Ieova, ma na tuuina a'u i le fanua laugatasi,", "and carried me out in the spirit of the LORD,"], ["ua tumu i ivi.", "and set me down in the midst of the valley which was full of bones,"]]},
  {num:2,words:[["Ua ia ta'ita'iina ane ai a'u ia faataamilomilo ai lava;", "And caused me to pass by them round about:"], ["faauta foi,", "and, behold,"], ["ua matuā tele lava i le fogāeleele;", "there were very many in the open valley;"], ["faauta foi,", "and, lo,"], ["ua matuā mamago lava.", "they were very dry."]]},
  {num:3,words:[["Ona fai mai lea o ia ia te au,", "And he said unto me,"], ["Le atalii e o le tagata,", "Son of man,"], ["e mafai ea ona toe ola o ia ivi? Ona ou tali atu ai lea,", "can these bones live? And I answered,"], ["Le Alii e Ieova e,", "O Lord GOD,"], ["ua e silafia lava oe.", "thou knowest."]]},
  {num:4,words:[["Ona fetalai mai ai lea o ia ia te au,", "Again he said unto me,"], ["Ia e vavalo atu i na ivi,", "Prophesy upon these bones,"], ["ma fai atu i ai,", "and say unto them,"], ["Ivi mamago e,", "O ye dry bones,"], ["faalogologo mai ia i le afioga a Ieova.", "hear the word of the LORD."]]},
  {num:5,words:[["Ua faapea ona fetalai mai o le Alii o Ieova i na ivi;", "Thus saith the Lord GOD unto these bones;"], ["Faauta,", "Behold,"], ["ou te faaulu ane le mānava i totonu ia te outou,", "I will cause breath to enter into you,"], ["ona outou ola ai lea;", "and ye shall live:"]]},
  {num:6,words:[["ou te avane foi ua ia te outou,", "And I will lay sinews upon you,"], ["ma ou faatupuina ae aano ia te outou,", "and will bring up flesh upon you,"], ["ma ufiufi ia te outou i pa'u,", "and cover you with skin,"], ["ou te tuuina atu foi le mānava i totonu ia te outou,", "and put breath in you,"], ["e ola foi outou;", "and ye shall live;"], ["ona outou iloa ai lea o a'u lava o Ieova.", "and ye shall know that I am the LORD."]]},
  {num:7,words:[["Ona ou vavalo atu ai lea e pei ona poloaiina o a'u;", "So I prophesied as I was commanded:"], ["ua ou vavalo atu,", "and as I prophesied,"], ["a e gāsēsē; faauta foi,", "there was a noise,"], ["o le gaoioi,", "and behold a shaking,"], ["ona fesootai lea o ivi,", "and the bones came together,"], ["o le ivi i lona ivi.", "bone to his bone."]]},
  {num:8,words:[["Ua ou vaai atu,", "And when I beheld,"], ["faauta,", "lo,"], ["ua tupu ae ua ma aano ia te i latou,", "the sinews and the flesh came up upon them,"], ["ua ufitia foi i latou i pa'u;", "and the skin covered them above:"], ["a ua leai se mānava i totonu ia te i latou.", "but there was no breath in them."]]},
  {num:9,words:[["Ona fetalai mai lea o ia ia te au,", "Then said he unto me,"], ["Vavalo atu ia i le mānava le atalii e o le tagata,", "Prophesy unto the wind,"], ["ina vavalo atu ia,", "prophesy,"], ["ma ē faapea atu i le mānava,", "son of man,"], ["O loo faapea ona fetalai mai o le Alii o Ieova,", "and say to the wind, Thus saith the Lord GOD;"], ["Mānava e,", "Come from the four winds,"], ["ina sau ia mai matāmatagi e fa,", "O breath,"], ["ma ia mānava atu i ia tagata fāsia,", "and breathe upon these slain,"], ["ia latou ola ai.", "that they may live."]]},
  {num:10,words:[["Ona ou vavalo atu lea e pei ona poloaiina o a'u,", "So I prophesied as he commanded me,"], ["ona ulu ane lea o le mānava i totonu ia te i latou,", "and the breath came into them,"], ["ona latou ola ai lea,", "and they lived,"], ["ma tutū i luga i o latou vae,", "and stood up upon their feet,"], ["o le itu taua e matuā tele lava.", "an exceeding great army."]]},
  {num:11,words:[["Ona fetalai mai lea o ia ia te au,", "Then he said unto me,"], ["Le atalii e o le tagata,", "Son of man,"], ["o ia ivi o le aiga uma ia o Isaraelu;", "these bones are the whole house of Israel:"], ["faauta,", "behold,"], ["ua latou fai mai,", "they say,"], ["Ua mamago o matou ivi,", "Our bones are dried,"], ["ua faaumatia lo matou faamoemoe;", "and our hope is lost:"], ["ua fano lava i matou.", "we are cut off for our parts."]]},
  {num:12,words:[["O le mea lea ia e vavalo atu ai,", "Therefore prophesy and say unto them,"], ["ia faapea atu ia te i latou,", "Thus saith the Lord GOD;"], ["Ua faapea ona fetalai mai o le Alii o Ieova,", "Behold,"], ["Faauta, lo'u nuu e,", "O my people,"], ["ou te lagaina o outou tuugamau,", "I will open your graves,"], ["ou te avae outou ai o outou tuugamau,", "and cause you to come up out of your graves,"], ["ma aumaia outou i le laueleele o Isaraelu.", "and bring you into the land of Israel."]]},
  {num:13,words:[["Lo'u nuu e,", "And ye shall know that I am the LORD,"], ["tou te iloa o a'u lava o Ieova,", "when I have opened your graves,"], ["pe a ou lagaina o outou tuugamau,", "O my people,"], ["ma avae outou ai o outou tuugamau.", "and brought you up out of your graves,"]]},
  {num:14,words:[["Ou te tuuina atu foi lo'u Agaga i totonu ia te outou,", "And shall put my spirit in you,"], ["e ola ai foi outou,", "and ye shall live,"], ["ou te faanofofilemuina foi outou i lo outou lava laueleele; ona outou iloa ai lea o a'u lava o Ieova,", "and I shall place you in your own land:"], ["ua ou fai atu ai,", "then shall ye know that I the LORD have spoken it,"], ["ou te faia foi,", "and performed it,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:15,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "The word of the LORD came again unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:16,words:[["O oe na foi,", "Moreover,"], ["le atalii o le tagata,", "thou son of man,"], ["ia e avane se laau e tasi,", "take thee one stick,"], ["ma tusi ai,", "and write upon it,"], ["Mo Iuta,", "For Judah,"], ["ma le fanauga a Isaraelu o e 'au ia te ia;", "and for the children of Israel his companions:"], ["i le e avane foi se tasi laau,", "then take another stick,"], ["ma tusi ai,", "and write upon it,"], ["Mo Iosefa,", "For Joseph,"], ["o le laau a Efaraima,", "the stick of Ephraim,"], ["atoa ma le aiga uma o Isaraelu o e 'au ia te ia.", "and for all the house of Israel his companions:"]]},
  {num:17,words:[["Ia e faaopoopoina le tasi i le tasi ia fai ma laau e tasi mo oe;", "And join them one to another into one stick;"], ["ona avea lea o i laua ma laau e tasi i lou lima.", "and they shall become one in thine hand."]]},
  {num:18,words:[["A fai mai foi tagata o lou nuu ia te oe,", "And when the children of thy people shall speak unto thee,"], ["e faapea mai,", "saying,"], ["E te le faaali mai ea ia te i matou le uiga o ia mea?", "Wilt thou not shew us what thou meanest by these?"]]},
  {num:19,words:[["ia e fai atu ia te i latou,", "Say unto them,"], ["O loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Faauta,", "Behold,"], ["ou te ave le laau o Iosefa,", "I will take the stick of Joseph,"], ["o le ua i le lima o Efaraima,", "which is in the hand of Ephraim,"], ["ma itu aiga o Isaraelu o e 'au ia te ia,", "and the tribes of Israel his fellows,"], ["ma ou tuuina i latou e faatasi ma ia,", "and will put them with him,"], ["e faatasi lava ma le laau o Iuta,", "even with the stick of Judah,"], ["e avea foi i latou ma laau e tasi,", "and make them one stick,"], ["e fai foi ma laau e tasi i lo'u lima.", "and they shall be one in mine hand."]]},
  {num:20,words:[["O laau foi e te tusi ai, e i ai ia i lou lima i o latou luma.", "And the sticks whereon thou writest shall be in thine hand before their eyes."]]},
  {num:21,words:[["Ia e fai atu foi ia te i latou,", "And say unto them,"], ["O loo faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Faauta,", "Behold, I will take the children of Israel from among the heathen,"], ["ou te aveina atu le fanauga a Isaraelu ai nuu ese ua latou ō i ai,", "whither they be gone,"], ["ma ou faapotopotoina mai i latou ai lea itu ma lea itu,", "and will gather them on every side,"], ["ma ou aumaia i latou i lo latou lava laueleele.", "and bring them into their own land:"]]},
  {num:22,words:[["Ou te faia foi i latou ma nuu e tasi i le laueleele i mauga o Isaraelu;", "And I will make them one nation in the land upon the mountains of Israel;"], ["o le tupu foi e tasi e fai ma tupu ia te i latou uma;", "and one king shall be king to them all:"], ["e le toe avea i latou ma nuu e lua,", "and they shall be no more two nations,"], ["e le toe vaeluaina lava i latou e fai ma malo e lua.", "neither shall they be divided into two kingdoms any more at all:"]]},
  {num:23,words:[["E le toe leaga lava i latou ia te i latou i a latou tupua,", "Neither shall they defile themselves any more with their idols,"], ["po o a latou mea inosia,", "nor with their detestable things,"], ["po o se tasi o latou solitulafono;", "nor with any of their transgressions:"], ["a e ou te faaolaina i latou ai mea uma latou te nonofo ai,", "but I will save them out of all their dwellingplaces,"], ["ua latou fai ai le agasala,", "wherein they have sinned,"], ["ou te faamamāina foi i latou;", "and will cleanse them:"], ["e fai i latou mo'u nuu,", "so shall they be my people,"], ["e fai foi a'u mo latou Atua.", "and I will be their God."]]},
  {num:24,words:[["O la'u auauna foi o Tavita e fai o ia ma tupu ia te i latou;", "And David my servant shall be king over them;"], ["e tasi foi le leoleo mamoe ia te i latou uma;", "and they all shall have one shepherd:"], ["e savavali foi i latou i a'u faamasinoga,", "they shall also walk in my judgments,"], ["ma tausi i a'u tulafono,", "and observe my statutes,"], ["ma latou faia.", "and do them."]]},
  {num:25,words:[["Latou te nonofo foi i le nuu na ou foaiina ia Iakopo la'u auauna,", "And they shall dwell in the land that I have given unto Jacob my servant,"], ["sa mau ai o outou tamā;", "wherein your fathers have dwelt;"], ["latou te mau ai,", "and they shall dwell therein,"], ["o i latou,", "even they,"], ["ma a latou fanau,", "and their children,"], ["ma le fanau a latou fanau e oo i le faavavau;", "and their children's children for ever:"], ["e fai foi la'u auauna o Tavita mo latou alii sili e faavavau.", "and my servant David shall be their prince for ever."]]},
  {num:26,words:[["Ou te osia foi ma i latou le feagaiga e manuia ai;", "Moreover I will make a covenant of peace with them;"], ["e fai foi ma feagaiga ia te i latou e faavavau;", "it shall be an everlasting covenant with them:"], ["ou te faanofomauina i latou,", "and I will place them,"], ["ma faatoateleina i latou,", "and multiply them,"], ["ou te tuu foi lo'u malumalu ia te i latou e faavavau.", "and will set my sanctuary in the midst of them for evermore."]]},
  {num:27,words:[["E i ai foi lo'u fale ia te i latou;", "My tabernacle also shall be with them:"], ["e fai foi a'u mo latou Atua,", "yea, I will be their God,"], ["e fai foi i latou mo'u nuu.", "and they shall be my people."]]},
  {num:28,words:[["E iloa ai foi e nuu ese o a'u lava o Ieova o lē faapaiaina Isaraelu,", "And the heathen shall know that I the LORD do sanctify Israel,"], ["pe a i ai lo'u malumalu i totonu ia te i latou e faavavau.", "when my sanctuary shall be in the midst of them for evermore."]]},
];
renderVerseSet(ezk_ch_37_Verses, 'ezk-ch37-verses');

var ezk_ch_38_Verses = [
  {num:1,words:[["Ua oo mai foi le afioga a Ieova ia te au,", "And the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Le atalii e o le tagata,", "Son of man,"], ["ia e faasaga atu ia Koku, o le nuu o Makoku,", "set thy face against Gog,"], ["le alii sili o Rosi,", "the land of Magog,"], ["ma Meseko, ma Tupalu,", "the chief prince of Meshech and Tubal,"], ["ma vavalo atu ia te ia,", "and prophesy against him,"]]},
  {num:3,words:[["ma e fai atu,", "And say,"], ["Ua faapea ona fetalai mai o le Alii o Ieova, Faauta,", "Thus saith the Lord GOD;"], ["ua fai oe mo'u fili,", "Behold,"], ["Koku e,", "I am against thee,"], ["o le alii sili o Rosi, ma Meseko,", "O Gog,"], ["ma Tupalu.", "the chief prince of Meshech and Tubal:"]]},
  {num:4,words:[["Ou te faafoi ia te oe,", "And I will turn thee back,"], ["ma tuuina mama i ou auvae, ma ou ta'ita'i atu ia te oe,", "and put hooks into thy jaws,"], ["ma lau itu taua uma,", "and I will bring thee forth,"], ["o solofanua, ma e o tietie i solofanua,", "and all thine army,"], ["o i latou uma o oofu i ofutau atoatoa,", "horses and horsemen,"], ["o le vao tagata e toatele lava,", "all of them clothed with all sorts of armour,"], ["ma talita, ma talipupuni,", "even a great company with bucklers and shields,"], ["ua 'u'u i latou uma i pelu;", "all of them handling swords:"]]},
  {num:5,words:[["o Peresia,", "Persia,"], ["ma Aitiope,", "Ethiopia,"], ["ma Futu, faatasi ma i latou;", "and Libya with them;"], ["ua tofu i latou uma ma le talipupuni ma le puloutau;", "all of them with shield and helmet:"]]},
  {num:6,words:[["o Komeru ma ana 'au uma;", "Gomer, and all his bands;"], ["o le aiga foi o Tokaremo mai le itu i matu ma ana 'au uma,", "the house of Togarmah of the north quarters,"], ["o nuu e tele lava e faatasi ma oe.", "and all his bands: and many people with thee."]]},
  {num:7,words:[["Sauni ia,", "Be thou prepared,"], ["ina e sauni ia oe,", "and prepare for thyself,"], ["o oe ma lou vao tagata uma,", "thou,"], ["o e ua faapotopoto mai ia te oe,", "and all thy company that are assembled unto thee,"], ["ia fai foi oe ma leoleo ia te i latou.", "and be thou a guard unto them."]]},
  {num:8,words:[["A mavae aso e tele ona asia ai lea o oe;", "After many days thou shalt be visited:"], ["o ona tausaga amuli e te sau ai i le nuu ua faafoisia nai le pelu,", "in the latter years thou shalt come into the land that is brought back from the sword,"], ["ua faapotopotoina nai nuu e tele i mauga o Isaraelu,", "and is gathered out of many people, against the mountains of Israel,"], ["ua faatafunaina pea lava;", "which have been always waste:"], ["a e aumaia mai nuu eseese,", "but it is brought forth out of the nations,"], ["latou te nonofo ma le filemu o i latou uma.", "and they shall dwell safely all of them."]]},
  {num:9,words:[["E te alu ae,", "Thou shalt ascend and come like a storm,"], ["e te oo mai e pei o se afā;", "thou shalt be like a cloud to cover the land,"], ["e tusa oe ma le ao e ufitia ai le nuu, o oe,", "thou,"], ["ma au 'au uma,", "and all thy bands,"], ["ma nuu e tele e faatasi ma oe.", "and many people with thee."]]},
  {num:10,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["O ona po lava ia,", "It shall also come to pass,"], ["e tutupu ai mea i lou loto,", "that at the same time shall things come into thy mind,"], ["e te mafaufau foi i se manatu leaga;", "and thou shalt think an evil thought:"]]},
  {num:11,words:[["e te faapea ifo,", "And thou shalt say,"], ["Ou te alu ae i le nuu o aai e le nofo 'olo;", "I will go up to the land of unwalled villages;"], ["ou te alu ia te i latou o e o fifilemu,", "I will go to them that are at rest,"], ["o e nonofo faatalanoa,", "that dwell safely,"], ["o i latou uma o nonofo ua leai so latou pa,", "all of them dwelling without walls,"], ["e leai foi ni a latou faamaufaalava,", "and having neither bars nor gates,"]]},
  {num:12,words:[["po o puipui,", "To take a spoil,"], ["ina ia avea le vete, ia avea foi mea e faoa;", "and to take a prey;"], ["e faasaga lou lima i mea sa faatafunaina,", "to turn thine hand upon the desolate places that are now inhabited,"], ["o loo āina,", "and upon the people that are gathered out of the nations,"], ["o le nuu foi ua faapotopotoina nai nuu ese, ua i ai manu ma oloa,", "which have gotten cattle and goods,"], ["o loo o nonofo i le totonugalemu o le lalolagi.", "that dwell in the midst of the land."]]},
  {num:13,words:[["O Seepa,", "Sheba,"], ["ma Titana,", "and Dedan,"], ["ma e faatauoa o Tasesa,", "and the merchants of Tarshish,"], ["ma ana leona taanoa uma,", "with all the young lions thereof,"], ["e fai atu latou ia te oe,", "shall say unto thee,"], ["Ua e sau ea e ave vete? ua e faapotopotoina ea au 'au e ave mea ua fao? e ave ario ma auro,", "Art thou come to take a spoil? hast thou gathered thy company to take a prey? to carry away silver and gold,"], ["e ave manu ma oloa,", "to take away cattle and goods,"], ["e ave ai le vete tele?", "to take a great spoil?"]]},
  {num:14,words:[["O le mea lea,", "Therefore,"], ["le atalii e o le tagata,", "son of man,"], ["ia e vavalo atu ai, ma ia e fai atu ia Koku,", "prophesy and say unto Gog,"], ["Ua faapea ona fetalai mai ai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["O ona po o nonofo ai ma le filemu lo'u nuu o Isaraelu,", "In that day when my people of Israel dwelleth safely,"], ["e te le iloa ea?", "shalt thou not know it?"]]},
  {num:15,words:[["E sau lava oe ai lou nuu i le itu i matu,", "And thou shalt come from thy place out of the north parts,"], ["o oe ma nuu e tele e faatasi ma oe,", "thou,"], ["o tietie uma i latou i solofanua,", "and many people with thee, all of them riding upon horses,"], ["o le vao tagata e toatele lava,", "a great company,"], ["ma le itu taua e matuā tele.", "and a mighty army:"]]},
  {num:16,words:[["E te alu ae foi e tau ma lo'u nuu o Isaraelu,", "And thou shalt come up against my people of Israel,"], ["e pei o le ao e ufitia ai le nuu;", "as a cloud to cover the land;"], ["o ona aso amuli e taunuu ai;", "it shall be in the latter days,"], ["ou te aumaia foi oe i lo'u laueleele,", "and I will bring thee against my land, that the heathen may know me,"], ["ina ia iloa ai a'u i nuu ese,", "when I shall be sanctified in thee,"], ["pe a faapaiaina a'u ia te oe Koku e,", "O Gog,"], ["i o latou luma.", "before their eyes."]]},
  {num:17,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["E le o oe ea o le na ou fai atu ai anamua i a'u auauna o le au perofeta o Isaraelu, o e na vavalo i ia ona po o tausaga,", "Art thou he of whom I have spoken in old time by my servants the prophets of Israel,"], ["Ou te au mai ai oe e tau ma i latou?", "which prophesied in those days many years that I would bring thee against them?"]]},
  {num:18,words:[["O loo fetalai mai foi le Alii o Ieova,", "And it shall come to pass at the same time when Gog shall come against the land of Israel,"], ["O ia lava ona po e alu atu ai Koku i le laueleele o Isaraelu,", "saith the Lord GOD,"], ["e matuā tupu ai lo'u ita tele.", "that my fury shall come up in my face."]]},
  {num:19,words:[["O lo'u fuā foi, o le afi lava o lo'u ita ua ou fai atu ai,", "For in my jealousy and in the fire of my wrath have I spoken,"], ["O le aso lea e i ai lava le mafuie tele i le nuu o Isaraelu;", "Surely in that day there shall be a great shaking in the land of Israel;"]]},
  {num:20,words:[["ona gatete ai lea i o'u luma o i'a o le sami,", "So that the fishes of the sea,"], ["ma manu felelei,", "and the fowls of the heaven,"], ["ma manu feai o le vao,", "and the beasts of the field,"], ["ma mea fetolofi uma e fetolofi i le eleele,", "and all creeping things that creep upon the earth,"], ["atoa ma tagata uma o i le fogāeleele,", "and all the men that are upon the face of the earth, shall shake at my presence,"], ["e solo foi mauga,", "and the mountains shall be thrown down,"], ["e mafuli foi mea matomato,", "and the steep places shall fall,"], ["e sōloia foi pa uma e oo i le eleele.", "and every wall shall fall to the ground."]]},
  {num:21,words:[["Ou te valaau foi i le pelu i o'u mauga uma ia oo ia te ia,", "And I will call for a sword against him throughout all my mountains,"], ["o loo fetalai mai ai le Alii o Ieova;", "saith the Lord GOD:"], ["e taitoatasi foi ma faasaga lana pelu i le tasi.", "every man's sword shall be against his brother."]]},
  {num:22,words:[["Ou te faasala foi ia te ia i le faamai ma le toto;", "And I will plead against him with pestilence and with blood;"], ["ou te faatotō ifo foi i luga ia te ia ma ana 'au,", "and I will rain upon him,"], ["atoa ma nuu e tele ua ia te ia,", "and upon his bands,"], ["le timuga tetele,", "and upon the many people that are with him, an overflowing rain,"], ["ma uato'a tetele,", "and great hailstones,"], ["o le afi,", "fire,"], ["ma le teio.", "and brimstone."]]},
  {num:23,words:[["Ou te faasilisiliina o a'u e a'u,", "Thus will I magnify myself,"], ["ma ou faapaiaina o a'u;", "and sanctify myself;"], ["e iloa foi a'u i luma o nuu e tele,", "and I will be known in the eyes of many nations,"], ["e iloa ai lava e i latou o a'u lava o Ieova.", "and they shall know that I am the LORD."]]},
];
renderVerseSet(ezk_ch_38_Verses, 'ezk-ch38-verses');

var ezk_ch_39_Verses = [
  {num:1,words:[["O oefoi le atalii o le tagata,", "Therefore,"], ["ia e vavalo atu ia Koku,", "thou son of man,"], ["ma fai atu,", "prophesy against Gog,"], ["O loo faapea ona fetalai mai o le Alii o Ieova,", "and say,"], ["Faauta,", "Thus saith the Lord GOD;"], ["ou te fai oe mo'u fili Koku e,", "Behold,"], ["le alii sili o Rosi,", "I am against thee,"], ["ma Meseko,", "O Gog,"], ["ma Tupalu;", "the chief prince of Meshech and Tubal:"]]},
  {num:2,words:[["ou te faafoisia oe ma ou ta'ita'iina oe,", "And I will turn thee back,"], ["ou te faaae mai foi ia te oe ai le itu i matu,", "and leave but the sixth part of thee, and will cause thee to come up from the north parts,"], ["ma aumai ia te oe i mauga o Isaraelu;", "and will bring thee upon the mountains of Israel:"]]},
  {num:3,words:[["ou te ta foi lau aufana ia paū ese i lou lima tauagavale,", "And I will smite thy bow out of thy left hand,"], ["ma ou faapaūeseina au u fanafana i lou lima taumatau.", "and will cause thine arrows to fall out of thy right hand."]]},
  {num:4,words:[["E te paū i mauga o Isaraelu,", "Thou shalt fall upon the mountains of Israel,"], ["o oe,", "thou,"], ["ma au 'au uma, ma nuu o loo ia te oe;", "and all thy bands,"], ["ou te tuuina atu oe i manu feai felelei uiga eseese,", "and the people that is with thee:"], ["ma manu feai o le vao,", "I will give thee unto the ravenous birds of every sort,"], ["ia 'aina ai lava oe.", "and to the beasts of the field to be devoured."]]},
  {num:5,words:[["E te paū lava i le fogāeleele;", "Thou shalt fall upon the open field:"], ["auā o a'u lava ua ou fai atu,", "for I have spoken it,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:6,words:[["Ou te lafo atu foi se afi ia Makoku,", "And I will send a fire on Magog,"], ["atoa ma e o nonofo faatalanoa i nuu tu matafaga;", "and among them that dwell carelessly in the isles:"], ["latou te iloa ai o a'u lava o Ieova.", "and they shall know that I am the LORD."]]},
  {num:7,words:[["Ou te faailoa atu foi lo'u igoa paia i totonu o lo'u nuu o Isaraelu;", "So will I make my holy name known in the midst of my people Israel;"], ["ou te le toe mafai ona ia faaleagaina lo'u igoa paia;", "and I will not let them pollute my holy name any more:"], ["e iloa foi e nuu ese o a'u lava o Ieova,", "and the heathen shall know that I am the LORD,"], ["o le Paia o i Isaraelu.", "the Holy One in Israel."]]},
  {num:8,words:[["Faauta,", "Behold,"], ["ua oo mai,", "it is come,"], ["ua uma ona fai,", "and it is done,"], ["o loo fetalai mai ai le Alii o Ieova;", "saith the Lord GOD;"], ["o le aso lava lea na ou fai atu ai.", "this is the day whereof I have spoken."]]},
  {num:9,words:[["E o atu foi e o nonofo i aai o Isaraelu,", "And they that dwell in the cities of Israel shall go forth,"], ["ma latou faamu ma susunu le auupega, o talita,", "and shall set on fire and burn the weapons,"], ["ma talipupuni,", "both the shields and the bucklers,"], ["o aufana foi,", "the bows and the arrows,"], ["ma u fanafana,", "and the handstaves,"], ["o tao foi, ma tao e velo;", "and the spears,"], ["latou te faamuina ai i le afi i tausaga e fitu.", "and they shall burn them with fire seven years:"]]},
  {num:10,words:[["Latou te le ave foi ni laau ai le vao,", "So that they shall take no wood out of the field,"], ["latou te le ta foi ni laau i le vao matua;", "neither cut down any out of the forests;"], ["auā latou te faamu le auupega i le afi;", "for they shall burn the weapons with fire:"], ["latou te vetea foi mea a latou o e sa vetea a latou mea,", "and they shall spoil those that spoiled them,"], ["latou te fao foi mea a e sa faoa a latou mea,", "and rob those that robbed them,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:11,words:[["O lea aso foi ou te tuu atu ai ia Koku i lea lava mea se mea e fai ma tuugamau i Isaraelu,", "And it shall come to pass in that day,"], ["o le vanu e ui ai tagata i le itu i sasae o le sami;", "that I will give unto Gog a place there of graves in Israel,"], ["e punitia ai e o ui atu ai;", "the valley of the passengers on the east of the sea:"], ["latou te tatanu foi ia Koku ma lona vao tagata uma i lea mea;", "and it shall stop the noses of the passengers:"], ["latou te faaigoa ai foi,", "and there shall they bury Gog and all his multitude:"], ["O le vanu o Hamona-Koku.", "and they shall call it The valley of Hamon-gog."]]},
  {num:12,words:[["E fitu masina e tatanu ai i latou e le aiga o Isaraelu,", "And seven months shall the house of Israel be burying of them,"], ["ina ia faamamāina ai le laueleele.", "that they may cleanse the land."]]},
  {num:13,words:[["E tatanu foi i latou e tagata uma o le nuu;", "Yea,"], ["e fai foi ma mea e ta'ua ai i latou,", "all the people of the land shall bury them;"], ["o le aso foi e viia ai a'u,", "and it shall be to them a renown the day that I shall be glorified,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:14,words:[["Latou te tofia foi isi tagata e fai mo latou faiva ona feoai solo i le nuu,", "And they shall sever out men of continual employment,"], ["latou te faatasi ma e ui ane latou te tanumia e o totoe i le fogāeleele,", "passing through the land to bury with the passengers those that remain upon the face of the earth,"], ["ia faamamāina ai;", "to cleanse it:"], ["a mavae masina e fitu ona latou suesue lea.", "after the end of seven months shall they search."]]},
  {num:15,words:[["A o atu foi ē ui ane i le nuu,", "And the passengers that pass through the land,"], ["a iloa e se tasi se ivi o se tagata,", "when any seeth a man's bone,"], ["ona faatuina ai lea e ia se faailoga,", "then shall he set up a sign by it,"], ["seia tanu ai e i latou o e tanumia tagata i le vanu o Hamona-Koku.", "till the buriers have buried it in the valley of Hamon-gog."]]},
  {num:16,words:[["E igoa foi le aai ia Hamona. Latou te faamamāina ai foi le nuu.", "And also the name of the city shall be Hamonah. Thus shall they cleanse the land."]]},
  {num:17,words:[["Ua faapea foi ona fetalai mai o le Alii o Ieova,", "And,"], ["O oe le atalii o le tagata,", "thou son of man,"], ["ia e fai atu i manu felelei uiga eseese,", "thus saith the Lord GOD; Speak unto every feathered fowl,"], ["ma manu feai uma o le vao,", "and to every beast of the field,"], ["Ia aofai mai outou,", "Assemble yourselves,"], ["ina o mai ia,", "and come;"], ["faapotopoto mai ia outou i itu uma i la'u faigaai ou te faia ma outou,", "gather yourselves on every side to my sacrifice that I do sacrifice for you, even a great sacrifice upon the mountains of Israel,"], ["o le faigaai tele i mauga o Isaraelu,", "that ye may eat flesh,"], ["tou te aai ai tino ma inu toto.", "and drink blood."]]},
  {num:18,words:[["Tou te aai tino o e malolosi,", "Ye shall eat the flesh of the mighty,"], ["ma inu le toto o alii sili o le lalolagi,", "and drink the blood of the princes of the earth,"], ["o mamoe poa,", "of rams,"], ["ma tamai mamoe,", "of lambs,"], ["ma 'oti poa,", "and of goats,"], ["ma povi poa,", "of bullocks,"], ["o manu pepeti o Vasana i latou uma.", "all of them fatlings of Bashan."]]},
  {num:19,words:[["Tou te aai ga'o seia outou maoona,", "And ye shall eat fat till ye be full, and drink blood till ye be drunken,"], ["ma outou inu toto seia outou malilie i la'u faigaai ou te saunia ma outou.", "of my sacrifice which I have sacrificed for you."]]},
  {num:20,words:[["Tou te maoona ai i la'u laoai i solofanua,", "Thus ye shall be filled at my table with horses and chariots,"], ["ma e tau i kariota,", "with mighty men,"], ["ma e malolosi, atoa foi ma le 'au tau uma lava,", "and with all men of war,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:21,words:[["Ou te faailoa atu foi lo'u mamalu i luma o nuu ese;", "And I will set my glory among the heathen,"], ["e iloa foi e nuu uma la'u faamasinoga ua ou faia,", "and all the heathen shall see my judgment that I have executed,"], ["ma lo'u lima ua ou faaoo ia te i latou.", "and my hand that I have laid upon them."]]},
  {num:22,words:[["E iloa ai foi le aiga o Isaraelu, o a'u o Ieova lo latou Atua, e amata i lea aso e faapea lava pea.", "So the house of Israel shall know that I am the LORD their God from that day and forward."]]},
  {num:23,words:[["E iloa foi e nuu ese,", "And the heathen shall know that the house of Israel went into captivity for their iniquity:"], ["na tāfea le aiga o Isaraelu ona o a latou amio leaga,", "because they trespassed against me,"], ["ina ua latou agasala mai ia te au, o le mea lea na 'alo ai o'u mata ia te i latou,", "therefore hid I my face from them,"], ["ma ou tuuina atu i latou i lima o e na ita ia te i latou;", "and gave them into the hand of their enemies:"], ["na oti foi i latou uma i le pelu.", "so fell they all by the sword."]]},
  {num:24,words:[["Ua ou faia ia te i latou e tusa ma lo latou leaga, ma o latou solitulafono,", "According to their uncleanness and according to their transgressions have I done unto them,"], ["ua 'alo ai foi o'u mata ia te i latou.", "and hid my face from them."]]},
  {num:25,words:[["O le mea lea ua faapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["Ou te faafoisia nei le tafeaga a Iakopo,", "Now will I bring again the captivity of Jacob,"], ["ou te alofa foi i le aiga uma o Isaraelu,", "and have mercy upon the whole house of Israel,"], ["ou te fuā foi ona o lo'u igoa paia;", "and will be jealous for my holy name;"]]},
  {num:26,words:[["ina ua uma ona tauave e i latou lo latou faamasiasiga,", "After that they have borne their shame,"], ["ma a latou amio leaga uma na latou agaleaga mai ai ia te au,", "and all their trespasses whereby they have trespassed against me,"], ["ina o latou nonofo ma le filemu i lo latou laueleele,", "when they dwelt safely in their land,"], ["e leai foi se na faamata'u ia te i latou .", "and none made them afraid."]]},
  {num:27,words:[["A oo ina ou faafoisia mai i latou i nuu ese,", "When I have brought them again from the people,"], ["ma ou faapotopotoina i latou ai nuu o e na fai i latou mo latou fili,", "and gathered them out of their enemies' lands,"], ["a faapaiaina foi a'u ia te i latou i luma o nuu e tele,", "and am sanctified in them in the sight of many nations;"]]},
  {num:28,words:[["ona latou iloa ai lea o a'u lava o Ieova lo latou Atua,", "Then shall they know that I am the LORD their God,"], ["o le na tāfea ai i latou i nuu ese,", "which caused them to be led into captivity among the heathen:"], ["ma ou faapotopotoina i latou i lo latou lava laueleele,", "but I have gathered them unto their own land,"], ["ma ou le toe tuua lava so latou i ia mea.", "and have left none of them any more there."]]},
  {num:29,words:[["E le toe 'alo lava o'u mata ia te i latou,", "Neither will I hide my face any more from them:"], ["ina ua ou liligi ifo lo'u Agaga i luga o le aiga o Isaraelu,", "for I have poured out my spirit upon the house of Israel,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
];
renderVerseSet(ezk_ch_39_Verses, 'ezk-ch39-verses');

var ezk_ch_40_Verses = [
  {num:1,words:[["O lona lua o sefulu ma le lima o tausaga o la matou tafeaga,", "In the five and twentieth year of our captivity,"], ["o le amataga o le tausaga,", "in the beginning of the year,"], ["o le aso e sefulu o le masina, o le tausaga e sefulu ma le fa talu ona malaia o le aai,", "in the tenth day of the month,"], ["o lena lava aso,", "in the fourteenth year after that the city was smitten,"], ["na i ai le aao o Ieova i luga ia te au,", "in the selfsame day the hand of the LORD was upon me,"], ["ma na aveina atu i ai o a'u.", "and brought me thither."]]},
  {num:2,words:[["O faaaliga mai le Atua na ia aveina ai a'u i le nuu o Isaraelu,", "In the visions of God brought he me into the land of Israel,"], ["ma tuuina ai a'u i luga o le mauga maualuga lava,", "and set me upon a very high mountain,"], ["o i ai i le itu i toga se fale e peiseai se aai.", "by which was as the frame of a city on the south."]]},
  {num:3,words:[["Na ia aveina atu ai a'u,", "And he brought me thither,"], ["faauta foi,", "and,"], ["o le tagata,", "behold,"], ["o lona tino mai ua pei o le tino o le 'apa memea,", "there was a man, whose appearance was like the appearance of brass,"], ["sa i lona lima le manoa lino,", "with a line of flax in his hand,"], ["ma le u e fua a'i,", "and a measuring reed;"], ["o tu o ia i le faitotoa.", "and he stood in the gate."]]},
  {num:4,words:[["Ua fai mai foi le tagata ia te au,", "And the man said unto me,"], ["Le atalii e o le tagata,", "Son of man,"], ["ia vaavaai ou mata,", "behold with thine eyes,"], ["ma ia faalogologo ou taliga,", "and hear with thine ears,"], ["ia e tuu foi i lou loto o mea uma ou te faaali atu ai ia te oe;", "and set thine heart upon all that I shall shew thee;"], ["auā ua aumaia oe iinei ina ia ou faaali atu ai ia te oe;", "for to the intent that I might shew them unto thee art thou brought hither:"], ["ia e ta'u atu i le aiga o Isaraelu o mea uma e te iloa.", "declare all that thou seest to the house of Israel."]]},
  {num:5,words:[["Faauta foi,", "And behold a wall on the outside of the house round about,"], ["o le pa ua soo ai le fale i fafo, o i ai foi i le lima o le tagata le u e fua a'i,", "and in the man's hand a measuring reed of six cubits long by the cubit and an hand breadth:"], ["e ono kupita lona umi ,", "so he measured the breadth of the building,"], ["o kupita e i ai le kupita,", "one reed;"], ["ma le alofilima; ua ia fua le lautele o le pa e tasi le u,", "and the height,"], ["ma lona maualuga e tasi le u.", "one reed."]]},
  {num:6,words:[["Ona alu ane lea o ia i le faitotoa o loo faasaga i sasae,", "Then came he unto the gate which looketh toward the east,"], ["ma alu ae i lona ala faaapefai;", "and went up the stairs thereof,"], ["ua ia fuatia foi le faitotoa,", "and measured the threshold of the gate,"], ["o le u e tasi lona lautele;", "which was one reed broad;"], ["ma le tasi faitotoa,", "and the other threshold of the gate,"], ["e tasi foi le u lona lautele.", "which was one reed broad."]]},
  {num:7,words:[["O potu foi taitasi e tasi le u lona umi,", "And every little chamber was one reed long,"], ["e tasi le u foi lona lautele;", "and one reed broad;"], ["o le va foi o potu e lima kupita ia;", "and between the little chambers were five cubits;"], ["o le faitotoa foi i tala ane o le faapaologa o le fale i totonu e tasi lona u.", "and the threshold of the gate by the porch of the gate within was one reed."]]},
  {num:8,words:[["Ua ia fuatia foi le faapaologa o le fale i totonu,", "He measured also the porch of the gate within,"], ["o le u e tasi.", "one reed."]]},
  {num:9,words:[["Ona fuatia lea e ia le faapaologa o le puipui,", "Then measured he the porch of the gate,"], ["e valu ona kupita,", "eight cubits;"], ["ma ona pou e lua ona kupita;", "and the posts thereof, two cubits;"], ["na u i totonu foi le faapaologa o le puipui.", "and the porch of the gate was inward."]]},
  {num:10,words:[["O potu foi o le faitotoa i sasae sa taitolu i itu;", "And the little chambers of the gate eastward were three on this side,"], ["ua gatasitasi le fua o ia potu e tolu;", "and three on that side; they three were of one measure:"], ["ua gatasitasi foi le fua o pou i le tasi itu ma le tasi itu.", "and the posts had one measure on this side and on that side."]]},
  {num:11,words:[["Ua ia fuatia le lautele o le puipui e sefulu ona kupita;", "And he measured the breadth of the entry of the gate, ten cubits;"], ["o lona umi foi o le puipui e sefulu ma le tolu ona kupita.", "and the length of the gate, thirteen cubits."]]},
  {num:12,words:[["Sa i ai foi le mea avanoa i luma o potu i itu taitasi e tasi lona kupita;", "The space also before the little chambers was one cubit on this side, and the space was one cubit on that side:"], ["o potu foi taiono kupita i lea itu ma lea itu.", "and the little chambers were six cubits on this side, and six cubits on that side."]]},
  {num:13,words:[["Ona fuatia lea e ia le puipui mai le falealuga o le tasi potu e oo i le falealuga o le tasi;", "He measured then the gate from the roof of one little chamber to the roof of another:"], ["o lona lautele e lua sefulu ma le lima o kupita ia;", "the breadth was five and twenty cubits,"], ["ua faafesagai faitotoa.", "door against door."]]},
  {num:14,words:[["Ua ia fai foi pou e onogafulu o kupita;", "He made also posts of threescore cubits,"], ["ua oo foi i le pou o le lotoā o le puipui e soo ai.", "even unto the post of the court round about the gate."]]},
  {num:15,words:[["E afua mai foi i luma o le puipui e ulu atu ai e oo i luma o le faapaologa o le puipui i totonu, e lima sefulu o ona kupita.", "And from the face of the gate of the entrance unto the face of the porch of the inner gate were fifty cubits."]]},
  {num:16,words:[["Na i ai foi o faamalama puipuia i potu,", "And there were narrow windows to the little chambers,"], ["sa i ai foi i pou i totonu o le puipui ua soo ai,", "and to their posts within the gate round about,"], ["ua faapea foi ma faapaologa;", "and likewise to the arches:"], ["na i ai faamalama ua soo ai i totonu;", "and windows were round about inward:"], ["na i ai foi pama i pou.", "and upon each post were palm trees."]]},
  {num:17,words:[["Ua ia au mai foi ia te au i le lotoā aupito i tua,", "Then brought he me into the outward court, and,"], ["faauta foi,", "lo,"], ["o potu ma le paepae ua faia mo le lotoā ia soo ai;", "there were chambers,"], ["e tolu sefulu o potu na i le paepae.", "and a pavement made for the court round about: thirty chambers were upon the pavement."]]},
  {num:18,words:[["O le paepae foi i tafatafa o puipui na feagai ma le umi o puipui, o le paepae aupitoalalo lea.", "And the pavement by the side of the gates over against the length of the gates was the lower pavement."]]},
  {num:19,words:[["Ona fuatia lea e ia o le lautele, e afua mai i luma o le puipui aupitoalalo e oo i ona luma o le lotoā tuloto i ona tua mai,", "Then he measured the breadth from the forefront of the lower gate unto the forefront of the inner court without,"], ["e selau ona kupita i sasae atoa foi ma le itu i matu.", "an hundred cubits eastward and northward."]]},
  {num:20,words:[["Ua ia fuatia foi le umi ma le lautele o le puipui o le lotoā aupito i tua,", "And the gate of the outward court that looked toward the north, he measured the length thereof,"], ["o lē faasaga i le itu i matu.", "and the breadth thereof."]]},
  {num:21,words:[["O ona potu foi sa taitolu i lea itu ma lea itu;", "And the little chambers thereof were three on this side and three on that side;"], ["o ona pou foi ma ona faapaologa sa tusa ma le fua o le uluai puipui,", "and the posts thereof and the arches thereof were after the measure of the first gate:"], ["e lima sefulu o kupita, o lona umi lea,", "the length thereof was fifty cubits,"], ["e lua sefulu ma le lima o kupita o lona lautele lea.", "and the breadth five and twenty cubits."]]},
  {num:22,words:[["O ona faamalama foi,", "And their windows,"], ["ma ona faapaologa,", "and their arches,"], ["ma ona pama,", "and their palm trees,"], ["sa tutusa ma le fua o le puipui o lē faasaga i sasae;", "were after the measure of the gate that looketh toward the east;"], ["na latou o ae foi i ai i tulaga e fitu o le ala faaapefai;", "and they went up unto it by seven steps;"], ["sa i ai foi ona faapaologa i o latou luma.", "and the arches thereof were before them."]]},
  {num:23,words:[["O le puipui foi o le lotoā tuloto,", "And the gate of the inner court was over against the gate toward the north,"], ["na faafesagai ma le puipui i le itu i matu ma le itu i sasae;", "and toward the east;"], ["ua ia fuatia foi e afua mai i le tasi puipui e oo i le tasi puipui e selau ona kupita.", "and he measured from gate to gate an hundred cubits."]]},
  {num:24,words:[["Ua ia ta'ita'iina foi a'u i le itu i toga,", "After that he brought me toward the south,"], ["faauta foi, o le puipui o faasaga i le itu i toga;", "and behold a gate toward the south:"], ["ua ia fuatia foi ona pou ma ona faapaologa e tusa ma ia fua.", "and he measured the posts thereof and the arches thereof according to these measures."]]},
  {num:25,words:[["O faamalama foi sa i ai atoa mona faapaologa e soo ai e pei o ia faamalama;", "And there were windows in it and in the arches thereof round about,"], ["o lona umi e lima sefulu o kupita,", "like those windows: the length was fifty cubits,"], ["o lona lautele e lua sefulu ma le lima o kupita.", "and the breadth five and twenty cubits."]]},
  {num:26,words:[["E fitu foi tulaga faaapefai e ui ae ai,", "And there were seven steps to go up to it, and the arches thereof were before them:"], ["o ona faapaologa foi o i o latou luma;", "and it had palm trees, one on this side,"], ["na i ai foi pama e taitasi i itu i ona pou.", "and another on that side, upon the posts thereof."]]},
  {num:27,words:[["Na i ai foi le puipui i le lotoā tuloto o faasaga i le itu i toga; na ia fuatia foi,", "And there was a gate in the inner court toward the south:"], ["e afua mai i le tasi puipui e oo i le tasi puipui ua faasaga i le itu i toga, e selau ona kupita.", "and he measured from gate to gate toward the south an hundred cubits."]]},
  {num:28,words:[["Ua ia au mai foi ia te au i le lotoā tuloto o le puipui i le itu i toga;", "And he brought me to the inner court by the south gate:"], ["ua ia fuatia foi le puipui i le itu i toga e tusa ma ia fua;", "and he measured the south gate according to these measures;"]]},
  {num:29,words:[["o ona potu foi,", "And the little chambers thereof,"], ["ma ona pou,", "and the posts thereof,"], ["ma ona faapaologa,", "and the arches thereof,"], ["sa tutusa ma ia fua; o faamalama foi sa i ai atoa ma ona faapaologa e soo ai;", "according to these measures:"], ["e lima sefulu o kupita,", "and there were windows in it and in the arches thereof round about:"], ["o lona umi lea,", "it was fifty cubits long,"], ["e lua sefulu ma le lima o kupita o lona lautele lea.", "and five and twenty cubits broad."]]},
  {num:30,words:[["O faapaologa foi e soo ai e lua sefulu ma le lima o kupita o lona umi lea,", "And the arches round about were five and twenty cubits long,"], ["e lima kupita foi o lona lautele lea.", "and five cubits broad."]]},
  {num:31,words:[["O ona faapaologa na faasaga i le lotoā aupito i tua;", "And the arches thereof were toward the utter court;"], ["na i ai foi pama i ona pou;", "and palm trees were upon the posts thereof:"], ["e valu foi tulaga faaapefai e ui ae ai.", "and the going up to it had eight steps."]]},
  {num:32,words:[["Ua ia aumaia foi a'u i le lotoā tuloto o faasaga i sasae;", "And he brought me into the inner court toward the east:"], ["ona fuatia lea e ia o le puipui e tusa ma ia fua.", "and he measured the gate according to these measures."]]},
  {num:33,words:[["O ona potu foi,", "And the little chambers thereof,"], ["ma ona pou, ma ona faapaologa,", "and the posts thereof,"], ["sa tutusa ma ia fua;", "and the arches thereof,"], ["o faamalama foi sa i ai,", "were according to these measures:"], ["ma ona faapaologa e soo ai,", "and there were windows therein and in the arches thereof round about:"], ["e lima sefulu o kupita, o lona umi lea,", "it was fifty cubits long,"], ["e lua sefulu ma le lima o kupita o lona lautele lea.", "and five and twenty cubits broad."]]},
  {num:34,words:[["Na faasaga ona faapaologa i le lotoā aupito i tua;", "And the arches thereof were toward the outward court;"], ["na i ai foi pama i ona pou i lea itu,", "and palm trees were upon the posts thereof,"], ["ma lea itu;", "on this side, and on that side:"], ["e valu foi tulaga faaapefai e ui ae ai.", "and the going up to it had eight steps."]]},
  {num:35,words:[["Ua ia au mai foi ia te au i le puipui i le itu i matu,", "And he brought me to the north gate,"], ["ma na fuatia ai e tusa ma ia fua.", "and measured it according to these measures;"]]},
  {num:36,words:[["O ona potu,", "The little chambers thereof,"], ["ma ona pou,", "the posts thereof,"], ["ma ona faapaologa,", "and the arches thereof,"], ["ma ona faamalama e soo ai,", "and the windows to it round about:"], ["e limagafulu o kupita o lona umi lea,", "the length was fifty cubits,"], ["o lona lautele e lua sefulu ma le lima o kupita.", "and the breadth five and twenty cubits."]]},
  {num:37,words:[["O ona pou foi na faasaga ia i le lotoā aupito i tua;", "And the posts thereof were toward the utter court; and palm trees were upon the posts thereof,"], ["na i ai pama i ona pou i lea itu ma lea itu;", "on this side,"], ["e valu tulaga faaapefai na ui ae ai.", "and on that side: and the going up to it had eight steps."]]},
  {num:38,words:[["O potu ma o latou ala, sa i tafatafa o pou ia o faitotoa,", "And the chambers and the entries thereof were by the posts of the gates,"], ["na latou mulumulu ai le taulaga mu.", "where they washed the burnt offering."]]},
  {num:39,words:[["Na i ai foi i le faapaologa o le puipui o laulau e lua i le tasi itu,", "And in the porch of the gate were two tables on this side,"], ["ma laulau e lua i le isi itu e fasi ai le taulaga mu, ma le taulaga mo le agasala,", "and two tables on that side,"], ["ma le taulaga mo le sese.", "to slay thereon the burnt offering and the sin offering and the trespass offering."]]},
  {num:40,words:[["O i le itu foi i tua e ui ae ai le ala o le faitotoa i le itu i matu na i ai laulau e lua;", "And at the side without, as one goeth up to the entry of the north gate, were two tables;"], ["o i le tasi itu foi i le faapaologa o le puipui na i ai laulau e lua.", "and on the other side, which was at the porch of the gate, were two tables."]]},
  {num:41,words:[["E fa laulau na i le tasi itu,", "Four tables were on this side, and four tables on that side,"], ["e fa foi laulau i le isi itu i tafatafa o le puipui;", "by the side of the gate;"], ["e valu ia laulau na latou fasi ai taulaga i o latou luga.", "eight tables, whereupon they slew their sacrifices."]]},
  {num:42,words:[["O laulau ia e fa mo le taulaga mu,", "And the four tables were of hewn stone for the burnt offering,"], ["o maa talai na fai a'i, e tasi le kupita ma le vaeluagalemu o le kupita ,", "of a cubit and an half long,"], ["o le umi lea,", "and a cubit and an half broad,"], ["e tasi foi le kupita ma le vaeluagalemu o le kupita o le lautele lea, o le kupita e tasi o le maualuga lea;", "and one cubit high:"], ["na latou faaee ai foi mea ua latou fasi ai taulaga mu ma isi taulaga.", "whereupon also they laid the instruments wherewith they slew the burnt offering and the sacrifice."]]},
  {num:43,words:[["Na i ai foi tafatafa e faamauina ai ua faasaga i totonu,", "And within were hooks,"], ["ua soo ai,", "an hand broad,"], ["e tasi le alofilima o latou lautele;", "fastened round about:"], ["sa i luga foi o laulau tufaaga o le taulaga.", "and upon the tables was the flesh of the offering."]]},
  {num:44,words:[["O potu o le au pepese sa i ai ia i tua o le puipui tuloto i le lotoā tuloto,", "And without the inner gate were the chambers of the singers in the inner court,"], ["i tafatafa o le puipui i le itu i matu,", "which was at the side of the north gate;"], ["na faasaga foi ia i le itu i toga; o le tasi i tafatafa o le puipui i sasae,", "and their prospect was toward the south:"], ["ua faasaga i le itu i matu.", "one at the side of the east gate having the prospect toward the north."]]},
  {num:45,words:[["Ona faapea mai lea o ia ia te au,", "And he said unto me, This chamber,"], ["O lenei potu o lē faasaga i le itu i toga,", "whose prospect is toward the south,"], ["mo le au ositaulaga lea o e anaana i le tausiga o le fale.", "is for the priests, the keepers of the charge of the house."]]},
  {num:46,words:[["A o le potu o lē faasaga i le itu i matu,", "And the chamber whose prospect is toward the north is for the priests,"], ["mo le au ositaulaga lea o e anaana i tausiga o le fata faitaulaga,", "the keepers of the charge of the altar:"], ["o le fanauga ia a Satoka e o le fanauga a Levi,", "these are the sons of Zadok among the sons of Levi,"], ["o e faalatalata ia Ieova e auauna ia te ia.", "which come near to the LORD to minister unto him."]]},
  {num:47,words:[["Na ia fuatia le lotoā,", "So he measured the court,"], ["o lona umi e selau kupita,", "an hundred cubits long,"], ["e selau kupita foi o lona lautele lea,", "and an hundred cubits broad,"], ["na gatasitasi ona itu e fa;", "foursquare;"], ["o le fata faitaulaga foi na i lumā fale.", "and the altar that was before the house."]]},
  {num:48,words:[["Ua ia au mai foi ia te au i le faapaologa o le fale,", "And he brought me to the porch of the house,"], ["ua ia fuatia pou o le faapaologa,", "and measured each post of the porch,"], ["e lima kupita i le tasi itu,", "five cubits on this side,"], ["e lima foi kupita i le isi itu;", "and five cubits on that side:"], ["o le lautele foi o le puipui e tolu kupita i le tasi itu,", "and the breadth of the gate was three cubits on this side,"], ["e tolu foi kupita i le isi itu.", "and three cubits on that side."]]},
  {num:49,words:[["O le umi o le faapaologa e lua sefulu kupita lea,", "The length of the porch was twenty cubits,"], ["o lona lautele foi e sefulu ma le tasi kupita;", "and the breadth eleven cubits;"], ["ua ia au mai foi ia te au i le tulaga o le ala faaapefai na latou ui ae ai;", "and he brought me by the steps whereby they went up to it:"], ["na i ai foi pou i tafatafa o pou,", "and there were pillars by the posts,"], ["o le tasi i le tasi itu,", "one on this side,"], ["o le tasi foi i le isi itu.", "and another on that side."]]},
];
renderVerseSet(ezk_ch_40_Verses, 'ezk-ch40-verses');

var ezk_ch_41_Verses = [
  {num:1,words:[["Ona aumaia lea o a'u e ia i le malumalu,", "Afterward he brought me to the temple,"], ["ma ia fuatia pou,", "and measured the posts,"], ["e ono kupita o lona lautele i le tasi itu,", "six cubits broad on the one side,"], ["e ono foi kupita o lona lautele i le isi itu,", "and six cubits broad on the other side,"], ["o le lautele lea o le fale fetafai.", "which was the breadth of the tabernacle."]]},
  {num:2,words:[["O le lautele foi o le faitotoa e sefulu ona kupita;", "And the breadth of the door was ten cubits;"], ["o ona itu foi o le faitotoa e lima kupita i le tasi itu,", "and the sides of the door were five cubits on the one side,"], ["e lima foi kupita i le isi itu;", "and five cubits on the other side: and he measured the length thereof,"], ["ua ia fuatia foi le umi o le malumalu,", "forty cubits:"], ["e fagafulu o kupita,", "and the breadth,"], ["ma lona lautele e lua sefulu o kupita.", "twenty cubits."]]},
  {num:3,words:[["Ona alu ane lea o ia i totonu,", "Then went he inward,"], ["ua ia fuatia le pou o le faitotoa,", "and measured the post of the door, two cubits;"], ["e lua ona kupita;", "and the door,"], ["ma le faitotoa foi e ono ona kupita,", "six cubits; and the breadth of the door,"], ["ma le lautele o le faitotoa e fitu ona kupita.", "seven cubits."]]},
  {num:4,words:[["Ua ia fuatia foi lona umi e lua sefulu ona kupita,", "So he measured the length thereof,"], ["ma le lautele e lua sefulu ona kupita,", "twenty cubits; and the breadth,"], ["i luma o le malumalu;", "twenty cubits,"], ["ua ia fai mai foi ia te au,", "before the temple: and he said unto me,"], ["O le mea e sili ona paia lenei.", "This is the most holy place."]]},
  {num:5,words:[["Ona ia fuatia lea o le pa o le fale,", "After he measured the wall of the house,"], ["e ono ona kupita;", "six cubits;"], ["ma le lautele o potu i itu,", "and the breadth of every side chamber,"], ["e fa ona kupita,", "four cubits,"], ["ua soo ai le fale i itu uma.", "round about the house on every side."]]},
  {num:6,words:[["O potu i itu,", "And the side chambers were three,"], ["e atu tolu ia, taitasi i luga o le tasi,", "one over another,"], ["e taitolugafulu i itu;", "and thirty in order;"], ["na latou sosoo ane i le pa o le fale mo potu i itu,", "and they entered into the wall which was of the house for the side chambers round about,"], ["na soo ai, ina ia faamauina ai,", "that they might have hold,"], ["a ua le faamauina i le pa o le fale.", "but they had not hold in the wall of the house."]]},
  {num:7,words:[["Na i ai foi le ala faataamilomilo i potu i itu,", "And there was an enlarging,"], ["ua āu ina lautele i lona alu ae;", "and a winding about still upward to the side chambers:"], ["auā ua alu ae pea le ala faataamilomilo i le fale e faataamilomilo ai i le fale; o le mea lea na āu ai ina lautele o le fale i lona alu ae i luga,", "for the winding about of the house went still upward round about the house:"], ["e afua i le fogāfale aupitoalalo,", "therefore the breadth of the house was still upward,"], ["e oo i le aupitoaluga e ui ai i le ogaloto.", "and so increased from the lowest chamber to the highest by the midst."]]},
  {num:8,words:[["Na ou iloa foi le maualuga o le fale i ona itu uma; o faavae o potu i itu,", "I saw also the height of the house round about:"], ["o le u atoa lea, e i ai kupita tetele e ono.", "the foundations of the side chambers were a full reed of six great cubits."]]},
  {num:9,words:[["O le mafiafia o le pa sa i le potu o itu i tuāfafo,", "The thickness of the wall,"], ["e lima ona kupita;", "which was for the side chamber without, was five cubits:"], ["sa i ai i totonu le mea na toe i potu o itu sa i le fale.", "and that which was left was the place of the side chambers that were within."]]},
  {num:10,words:[["O le va foi o potu, e lua sefulu o kupita ia, ua soo ai lava le fale i itu uma.", "And between the chambers was the wideness of twenty cubits round about the house on every side."]]},
  {num:11,words:[["O faitotoa foi o potu o itu na faasaga ia i le mea na toe,", "And the doors of the side chambers were toward the place that was left,"], ["o le tasi faitotoa na faasaga i le itu i matu,", "one door toward the north,"], ["a o le tasi faitotoa na faasaga i le itu i toga, o le lautele foi o le mea na toe,", "and another door toward the south:"], ["e lima ona kupita i itu uma.", "and the breadth of the place that was left was five cubits round about."]]},
  {num:12,words:[["A o le fale na i luma o le mea na vavaeeseina i le itu i sisifo,", "Now the building that was before the separate place at the end toward the west was seventy cubits broad;"], ["e fitu sefulu o kupita lona lautele; o le pa foi o le fale e lima kupita lona mafiafia i itu uma,", "and the wall of the building was five cubits thick round about,"], ["o lona umi foi e ivagafulu o ona kupita.", "and the length thereof ninety cubits."]]},
  {num:13,words:[["Ua ia fuatia lava le fale,", "So he measured the house,"], ["e selau kupita, o lona umi lea;", "an hundred cubits long;"], ["o le mea na vavaeeseina foi,", "and the separate place,"], ["ma le fale atoa,", "and the building,"], ["ma ona pa, e selau kupita,", "with the walls thereof,"], ["o lona umi lea.", "an hundred cubits long;"]]},
  {num:14,words:[["O le lautele foi o lona lumāfale,", "Also the breadth of the face of the house,"], ["ma le mea na vavaeina i le itu i sasae,", "and of the separate place toward the east,"], ["e selau ona kupita.", "an hundred cubits."]]},
  {num:15,words:[["Ua ia fuatia foi le umi o le fale i luma o le mea na vavaeina,", "And he measured the length of the building over against the separate place which was behind it,"], ["o lē i ona tua,", "and the galleries thereof on the one side and on the other side,"], ["ma fogāfale i le tasi itu ma le tasi itu,", "an hundred cubits,"], ["e selau ona kupita,", "with the inner temple,"], ["o le malumalu tuloto foi ma faapaologa o le lotoā.", "and the porches of the court;"]]},
  {num:16,words:[["O faitotoa foi,", "The door posts,"], ["ma faamalama puipuia;", "and the narrow windows,"], ["ma fogāfale e soo ai o latou pae fale e tolu,", "and the galleries round about on their three stories,"], ["o feagai ma le faitotoa, na tapapa i laupapa,", "over against the door,"], ["na soo ai,", "cieled with wood round about,"], ["na afua mai i lalo e oo ae i faamalama,", "and from the ground up to the windows,"], ["na tapapa foi faamalama.", "and the windows were covered;"]]},
  {num:17,words:[["O ona luga ae foi o le faitotoa,", "To that above the door,"], ["e oo i totonu o le fale tuloto,", "even unto the inner house,"], ["atoa ma fafo,", "and without, and by all the wall round about within and without,"], ["o le pa uma foi e soo ai i totonu ma fafo na fuatia lava.", "by measure."]]},
  {num:18,words:[["Na fai foi kerupi ma pama,", "And it was made with cherubims and palm trees,"], ["na i ai foi pama taitasi i va o kerupi;", "so that a palm tree was between a cherub and a cherub;"], ["taitasi foi kerupi ma ona mata e lua;", "and every cherub had two faces;"]]},
  {num:19,words:[["ua feagai foi mata o le tagata ma le pama i le tasi itu,", "So that the face of a man was toward the palm tree on the one side,"], ["ua feagai foi mata o le leona taanoa ma le pama i le isi itu;", "and the face of a young lion toward the palm tree on the other side:"], ["ua faia i le fale uma i ona itu uma.", "it was made through all the house round about."]]},
  {num:20,words:[["E afua mai i lalo e oo i ona luga ae o le faitotoa, atoa ma le pa o le malumalu,", "From the ground unto above the door were cherubims and palm trees made,"], ["sa fai ai kerupi ma pama.", "and on the wall of the temple."]]},
  {num:21,words:[["Sa faatafafa foi o pou o le faitotoa o le malumalu;", "The posts of the temple were squared,"], ["o lona lumāfale foi o le mea paia,", "and the face of the sanctuary;"], ["ua tino mai e pei ona tino mai anamua .", "the appearance of the one as the appearance of the other."]]},
  {num:22,words:[["O le fata laau e fai ai taulaga e tolu kupita lona maualuga,", "The altar of wood was three cubits high,"], ["o lona umi foi e lua kupita lea;", "and the length thereof two cubits;"], ["o ona tulimanu foi,", "and the corners thereof,"], ["ma lona umi,", "and the length thereof,"], ["ma ona itu,", "and the walls thereof,"], ["o laau ia;", "were of wood:"], ["ua ia faapea mai foi ia te au,", "and he said unto me,"], ["O le laulau lenei o loo i luma o Ieova.", "This is the table that is before the LORD."]]},
  {num:23,words:[["Sa i ai puipui e lua i le malumalu ma le mea paia.", "And the temple and the sanctuary had two doors."]]},
  {num:24,words:[["Sa tailua foi puipui i faitotoa,", "And the doors had two leaves apiece,"], ["o puipui feafeai;", "two turning leaves;"], ["e lua puipui mo le tasi faitotoa,", "two leaves for the one door,"], ["e lua foi mo le isi.", "and two leaves for the other door."]]},
  {num:25,words:[["Na fai foi i puipui o le malumalu o kerupi ma pama,", "And there were made on them, on the doors of the temple,"], ["e pei ona faia i pa;", "cherubims and palm trees,"], ["na i ai foi laupapa mafiafia i luma o le faapaologa i fafo.", "like as were made upon the walls; and there were thick planks upon the face of the porch without."]]},
  {num:26,words:[["Na i ai foi faamalama puipuia,", "And there were narrow windows and palm trees on the one side and on the other side,"], ["ma pama i le tasi itu ma le isi itu,", "on the sides of the porch,"], ["i itu o le faapaologa, ma potu i itu o le fale,", "and upon the side chambers of the house,"], ["ma laupapa mafiafia.", "and thick planks."]]},
];
renderVerseSet(ezk_ch_41_Verses, 'ezk-ch41-verses');

var ezk_ch_42_Verses = [
  {num:1,words:[["Ona ia aumaia lea o a'u i le lotoā aupito i tua,", "Then he brought me forth into the utter court,"], ["i le ala e faasaga i le itu i matu;", "the way toward the north:"], ["na ia au mai foi ia te au i le potu i luma o le mea vavaeina,", "and he brought me into the chamber that was over against the separate place,"], ["na i luma o le fale i le itu i matu.", "and which was before the building toward the north."]]},
  {num:2,words:[["O lona umi o le mea e oo atu i le faitotoa i le itu i matu e selau ona kupita,", "Before the length of an hundred cubits was the north door,"], ["o le lautele foi e limagafulu ona kupita.", "and the breadth was fifty cubits."]]},
  {num:3,words:[["E feagai ma kupita e lua sefulu sa i ai i le lotoā tuloto,", "Over against the twenty cubits which were for the inner court,"], ["e feagai foi ma le paepae sa i le lotoā aupito i tua,", "and over against the pavement which was for the utter court,"], ["sa i ai fogāfale o feagai ma fogāfale e taitolu o pae fale .", "was gallery against gallery in three stories."]]},
  {num:4,words:[["Na i ai i luma o potu le mea e fealuai ai e sefulu ona kupita lona lautele o faasaga i totonu,", "And before the chambers was a walk of ten cubits breadth inward,"], ["o le ala e tasi le kupita;", "a way of one cubit;"], ["o latou faitotoa foi ua faasaga i le itu i matu.", "and their doors toward the north."]]},
  {num:5,words:[["A ua maulalo potu aupitoaluga;", "Now the upper chambers were shorter:"], ["auā o fogāfale ua faaitiitiina ai i latou o e na aupitoalalo,", "for the galleries were higher than these, than the lower,"], ["ma e na i le ogaloto o le fale.", "and than the middlemost of the building."]]},
  {num:6,words:[["Auā e tolu pae fale i latou,", "For they were in three stories,"], ["a e leai ni o latou pou e pei o pou o lotoā; o le mea lea na sili ai ona faavāiti i latou i e aupitoalalo,", "but had not pillars as the pillars of the courts:"], ["ma e na i le ogaloto e fua mai i lalo.", "therefore the building was straitened more than the lowest and the middlemost from the ground."]]},
  {num:7,words:[["O le pa foi na i tua e lata ane i potu,", "And the wall that was without over against the chambers,"], ["ua faasaga i le lotoā aupito i tua i luma o potu, e limagafulu o kupita,", "toward the utter court on the forepart of the chambers,"], ["o lona umi lea.", "the length thereof was fifty cubits."]]},
  {num:8,words:[["Auā o le umi o potu na i le lotoā aupito i tua e limagafulu ona kupita ia;", "For the length of the chambers that were in the utter court was fifty cubits:"], ["faauta foi,", "and, lo,"], ["e selau kupita i luma o le malumalu.", "before the temple were an hundred cubits."]]},
  {num:9,words:[["Na i ai foi le ala i le itu i sasae i lalo o ia potu,", "And from under these chambers was the entry on the east side,"], ["i le mea e ui atu i ai pe a sau mai le lotoā aupito i tua.", "as one goeth into them from the utter court."]]},
  {num:10,words:[["Na i ai potu i le mafiafia o le pa o le lotoā i le itu i sasae,", "The chambers were in the thickness of the wall of the court toward the east,"], ["i luma o le mea vavaeeseina,", "over against the separate place,"], ["i luma foi o le fale.", "and over against the building."]]},
  {num:11,words:[["O le ala foi i o latou luma e pei ona tino mai o potu sa faasaga i le itu i matu,", "And the way before them was like the appearance of the chambers which were toward the north,"], ["e tusa ma ia lona umi,", "as long as they,"], ["e tusa ma ia foi lona lautele;", "and as broad as they:"], ["o latou ala uma e ui atu ai e tusa ma o latou uiga,", "and all their goings out were both according to their fashions,"], ["e tusa foi ma o latou faitotoa.", "and according to their doors."]]},
  {num:12,words:[["E tusa foi ma faitotoa o potu sa faasaga i le itu i toga;", "And according to the doors of the chambers that were toward the south was a door in the head of the way,"], ["na i ai le faitotoa i le mea e amata mai ai le ala, o le ala i luma tonu o le pa e faasaga i sasae,", "even the way directly before the wall toward the east,"], ["pe a ulu atu ai i latou.", "as one entereth into them."]]},
  {num:13,words:[["Ona fai mai lea o ia ia te au,", "Then said he unto me,"], ["O potu o i le itu i matu,", "The north chambers and the south chambers,"], ["ma potu i le itu i toga ua i luma o le mea ua vavaeeseina,", "which are before the separate place,"], ["o potu paia ia e aai ai i mea e sili ona paia e le au ositaulaga o e faalatalata ia Ieova;", "they be holy chambers,"], ["e tuu ai foi e i latou mea e sili ona paia,", "where the priests that approach unto the LORD shall eat the most holy things: there shall they lay the most holy things,"], ["ma le taulaga i mea e 'ai,", "and the meat offering,"], ["ma le taulaga mo le agasala,", "and the sin offering,"], ["ma le taulaga mo le sese;", "and the trespass offering;"], ["auā e paia lea mea.", "for the place is holy."]]},
  {num:14,words:[["A ulufale atu ai ositaulaga,", "When the priests enter therein,"], ["ona latou le o ese lea i le mea paia e o atu ai i le lotoā aupito i tua,", "then shall they not go out of the holy place into the utter court,"], ["a e latou te tuuina ai o latou ofu latou te auauna a'i;", "but there they shall lay their garments wherein they minister;"], ["auā na paia ia;", "for they are holy;"], ["latou te oofu foi i nisi ofu,", "and shall put on other garments,"], ["ma latou faalatalata i mea e fai ma le nuu.", "and shall approach to those things which are for the people."]]},
  {num:15,words:[["Ua uma ona fuatia e ia o le fale tuloto,", "Now when he had made an end of measuring the inner house,"], ["ona ia aumaia lea o a'u i le ala i le puipui e faasaga i sasae;", "he brought me forth toward the gate whose prospect is toward the east,"], ["ua ia fuatia foi ona itu uma.", "and measured it round about."]]},
  {num:16,words:[["Ua ia fuatia le itu i sasae i le u e fua a'i,", "He measured the east side with the measuring reed,"], ["e lima selau o u i le u e fua a'i,", "five hundred reeds,"], ["ua soo ai.", "with the measuring reed round about."]]},
  {num:17,words:[["Ua ia fuatia le itu i matu,", "He measured the north side,"], ["e lima selau o u i le u e fua a'i,", "five hundred reeds,"], ["ua soo ai.", "with the measuring reed round about."]]},
  {num:18,words:[["Ua ia fuatia le itu i toga,", "He measured the south side, five hundred reeds,"], ["e lima selau o u i le u e fua a'i.", "with the measuring reed."]]},
  {num:19,words:[["Ua ia liliu ane i le itu i sisifo,", "He turned about to the west side,"], ["ua ia fuatia ai o u e lima selau i le u e fua a'i.", "and measured five hundred reeds with the measuring reed."]]},
  {num:20,words:[["Ua ia fuatia ona itu e fa;", "He measured it by the four sides:"], ["na i ai le pa e soo ai e lima selau lona umi,", "it had a wall round about,"], ["e lima selau foi lona lautele,", "five hundred reeds long, and five hundred broad,"], ["e va a'i le mea e paia ma le mea e le paia.", "to make a separation between the sanctuary and the profane place."]]},
];
renderVerseSet(ezk_ch_42_Verses, 'ezk-ch42-verses');

var ezk_ch_43_Verses = [
  {num:1,words:[["Ua ia ta'ita'i foi ia te au i le puipui,", "Afterward he brought me to the gate,"], ["o le puipui lea ua faasaga i sasae;", "even the gate that looketh toward the east:"]]},
  {num:2,words:[["faauta foi,", "And,"], ["o le pupula o le Atua o Isaraelu ua afio mai mai sasae;", "behold,"], ["o lona siufofoga foi e pei o le taalili o le vai e tele;", "the glory of the God of Israel came from the way of the east: and his voice was like a noise of many waters:"], ["ua malamalama foi le lalolagi i lona pupula.", "and the earth shined with his glory."]]},
  {num:3,words:[["E pei ona tino mai o le faaaliga na ou iloa,", "And it was according to the appearance of the vision which I saw,"], ["e pei o le faaaliga lava na ou iloa ina ua ou sau e faaumatia le aai;", "even according to the vision that I saw when I came to destroy the city:"], ["o faaaliga foi e pei o le faaaliga na ou iloa i le vaitafe o Kepara;", "and the visions were like the vision that I saw by the river Chebar;"], ["ona ou faapaūfao ai lea.", "and I fell upon my face."]]},
  {num:4,words:[["Ua afio mai foi le pupula o Ieova i le fale na ala mai i le faitotoa e faasaga i sasae.", "And the glory of the LORD came into the house by the way of the gate whose prospect is toward the east."]]},
  {num:5,words:[["Ona siitia lea o a'u e le Agaga,", "So the spirit took me up,"], ["ua ia au mai foi ia te au i le lotoā tuloto;", "and brought me into the inner court;"], ["faauta foi,", "and, behold,"], ["ua tumu le fale i le pupula o Ieova.", "the glory of the LORD filled the house."]]},
  {num:6,words:[["Ona ou faalogo atu lea, ua tŭlei mai lona siufofoga ia te au ai totonu o le fale;", "And I heard him speaking unto me out of the house;"], ["ua tu mai foi le tagata i o'u tafatafa,", "and the man stood by me."]]},
  {num:7,words:[["ua ia faapea mai foi ia te au,", "And he said unto me,"], ["Le atalii e o le tagata,", "Son of man, the place of my throne,"], ["o le mea e i ai lo'u nofoālii,", "and the place of the soles of my feet,"], ["ma le mea e tutū ai o'u alofivae,", "where I will dwell in the midst of the children of Israel for ever, and my holy name,"], ["ou te nofo ai e faatasi ma le fanauga a Isaraelu e faavavau,", "shall the house of Israel no more defile,"], ["e le toe faaleagaina foi lo'u igoa paia e le aiga o Isaraelu,", "neither they,"], ["o i latou ma o latou tupu i a latou faitaaga,", "nor their kings, by their whoredom,"], ["e le toe leaga foi i tino oti o latou tupu i a latou mea maualuluga,", "nor by the carcases of their kings in their high places."]]},
  {num:8,words:[["i o latou tuuina o lo latou faitotoa i tafatafa o o'u faitotoa,", "In their setting of their threshold by my thresholds,"], ["ma la latou pou o le faitotoa i tafatafa o a'u pou,", "and their post by my posts,"], ["o le pa foi na va a'i i latou ma a'u,", "and the wall between me and them,"], ["ua faaleagaina foi lo'u igoa paia i a latou mea e inosia ua latou faia;", "they have even defiled my holy name by their abominations that they have committed:"], ["o le mea lea ua ou faaumatia ai i latou i lo'u ita.", "wherefore I have consumed them in mine anger."]]},
  {num:9,words:[["O lenei,", "Now let them put away their whoredom,"], ["ia latou lafoai a latou faitaaga,", "and the carcases of their kings,"], ["ma tino oti o latou tupu, ia mamao ia te au,", "far from me,"], ["ona ou nofo ai lea faatasi ma i latou e faavavau.", "and I will dwell in the midst of them for ever."]]},
  {num:10,words:[["O oe na le atalii o le tagata,", "Thou son of man,"], ["ia e faaali atu le fale i le aiga o Isaraelu,", "shew the house to the house of Israel,"], ["ina ia latou masiasi i a latou amio leaga;", "that they may be ashamed of their iniquities:"], ["ia latou fuatia foi lena faatusa.", "and let them measure the pattern."]]},
  {num:11,words:[["Afai foi e masiasi i latou ona o mea uma ua latou faia,", "And if they be ashamed of all that they have done,"], ["ina faailoa atu ia ia te i latou le tino o le fale,", "shew them the form of the house,"], ["ma lona faatusa,", "and the fashion thereof,"], ["ma ona ala e ulufafo ai,", "and the goings out thereof,"], ["ma ona ala e ulufale mai ai,", "and the comings in thereof,"], ["ma ona tino mai uma,", "and all the forms thereof,"], ["ma ona sauniga uma,", "and all the ordinances thereof,"], ["ma ona tino mai uma,", "and all the forms thereof,"], ["ma ana tulafono uma;", "and all the laws thereof:"], ["ia e tusi ai i o latou luma,", "and write it in their sight,"], ["ina ia latou tausia lona tino mai uma,", "that they may keep the whole form thereof,"], ["ma ona sauniga uma,", "and all the ordinances thereof,"], ["ma latou faia.", "and do them."]]},
  {num:12,words:[["O le tulafono lenei o le fale, O le tumutumu o le mauga,", "This is the law of the house;"], ["o ona tuaoi uma e faataamilomilo ai, e matuā paia lava ia.", "Upon the top of the mountain the whole limit thereof round about shall be most holy."], ["Faauta,", "Behold,"], ["o le tulafono lea o le fale.", "this is the law of the house."]]},
  {num:13,words:[["O fua nei o le fata faitaulaga i kupita;", "And these are the measures of the altar after the cubits:"], ["o le kupita e i ai le kupita ma le alofilima;", "The cubit is a cubit and an hand breadth;"], ["e tasi le kupita o le taele, o lona lautele foi e tasi le kupita,", "even the bottom shall be a cubit,"], ["o le pale foi e siosioina ai ona tafatafa,", "and the breadth a cubit,"], ["e tasi le āga;", "and the border thereof by the edge thereof round about shall be a span:"], ["o le mea aupitoaluga lea o le fata faitaulaga.", "and this shall be the higher place of the altar."]]},
  {num:14,words:[["E afua mai i le taele i le eleele, e oo i le tafatafa faasili aupitoalalo,", "And from the bottom upon the ground even to the lower settle shall be two cubits,"], ["e lua kupita, o lona lautele foi e tasi le kupita;", "and the breadth one cubit;"], ["e afua mai foi i le tafatafa faasili aupito itiiti,", "and from the lesser settle even to the greater settle shall be four cubits,"], ["e oo i le tafatafa faasili aupito tele e fa kupita, o lona lautele foi e tasi le kupita.", "and the breadth one cubit."]]},
  {num:15,words:[["O le fata faitaulaga foi e fa ona kupita;", "So the altar shall be four cubits;"], ["e fa foi nifo e tutū ae i le fata faitaulaga.", "and from the altar and upward shall be four horns."]]},
  {num:16,words:[["O le umi foi o le fata faitaulaga e sefulu ma le lua ona kupita ,", "And the altar shall be twelve cubits long,"], ["o lona lautele e sefulu ma le lua,", "twelve broad,"], ["e gatasitasi ona itu e fa.", "square in the four squares thereof."]]},
  {num:17,words:[["O le tafatafa faasili foi e sefulu ma le fa o kupita lona umi, e sefulu ma le fa lona lautele i ona itu e fa;", "And the settle shall be fourteen cubits long and fourteen broad in the four squares thereof;"], ["o lona tafatafa foi e siosioina ai,", "and the border about it shall be half a cubit;"], ["o le vaeluagalemu lea o le kupita,", "and the bottom thereof shall be a cubit about;"], ["ma lona taele e tasi le kupita e soo ai; o lona ala faapefai foi e faasaga i sasae.", "and his stairs shall look toward the east."]]},
  {num:18,words:[["Ua fai mai foi o ia ia te au,", "And he said unto me,"], ["Le atalii e o le tagata,", "Son of man,"], ["o loo faapea ona fetalai mai o le Alii o Ieova,", "thus saith the Lord GOD; These are the ordinances of the altar in the day when they shall make it,"], ["O tulafono ia i le fata faitaulaga i le aso latou te faia ai e sauni ai taulaga i ona luga,", "to offer burnt offerings thereon,"], ["e sausau foi toto i ona luga.", "and to sprinkle blood thereon."]]},
  {num:19,words:[["E te avatu se povi poa taanoa i ositaulaga o sa Levi,", "And thou shalt give to the priests the Levites that be of the seed of Zadok,"], ["o le fanauga a Satoka o e faalatalata mai ia te au e auauna ia te au,", "which approach unto me,"], ["e fai ma taulaga mo le agasala,", "to minister unto me, saith the Lord GOD,"], ["ua fetalai mai ai le Alii o Ieova.", "a young bullock for a sin offering."]]},
  {num:20,words:[["E te ave foi nisi o lona toto,", "And thou shalt take of the blood thereof,"], ["ma tuu ai i ona nifo e fa, ma tulimanu e fa,", "and put it on the four horns of it,"], ["o le tafatafa faasili,", "and on the four corners of the settle,"], ["ma le pale e siosio ai; e te faamamāina ai,", "and upon the border round about:"], ["ma fai ai se togiola.", "thus shalt thou cleanse and purge it."]]},
  {num:21,words:[["E te ave foi le povi poa o le taulaga mo le agasala,", "Thou shalt take the bullock also of the sin offering, and he shall burn it in the appointed place of the house,"], ["e susunu ai i le mea sa tofia i le fale i tua o le mea paia.", "without the sanctuary."]]},
  {num:22,words:[["O le aso lua e te avatu ai se tamai 'oti e sao ona lelei,", "And on the second day thou shalt offer a kid of the goats without blemish for a sin offering;"], ["e fai ma taulaga mo le agasala; latou le faamamāina foi le fata faitaulaga,", "and they shall cleanse the altar,"], ["e pei ona latou faamamāina i le povi poa.", "as they did cleanse it with the bullock."]]},
  {num:23,words:[["A uma ona faamamāina,", "When thou hast made an end of cleansing it,"], ["e te avatu se povi poa taanoa e sao ona lelei,", "thou shalt offer a young bullock without blemish,"], ["ma se mamoe poa o le lafu e sao ona lelei.", "and a ram out of the flock without blemish."]]},
  {num:24,words:[["E te avatu ai i luma o Ieova,", "And thou shalt offer them before the LORD,"], ["e luluina i ai foi e ositaulaga se masima,", "and the priests shall cast salt upon them,"], ["ma latou avatu ai e fai ma taulaga mu ia Ieova.", "and they shall offer them up for a burnt offering unto the LORD."]]},
  {num:25,words:[["E fitu aso e te sauni ai se 'oti taitasi i aso e fai ma taulaga mo le agasala;", "Seven days shalt thou prepare every day a goat for a sin offering:"], ["latou te saunia foi se povi poa taanoa,", "they shall also prepare a young bullock, and a ram out of the flock,"], ["ma se mamoe poa o le lafu e sao ona lelei.", "without blemish."]]},
  {num:26,words:[["E fitu aso latou te fai ai le togiola mo le fata faitaulaga, ma faamamā i ai;", "Seven days shall they purge the altar and purify it;"], ["e fai foi le tofia o i latou.", "and they shall consecrate themselves."]]},
  {num:27,words:[["A mavae ia ona aso,", "And when these days are expired, it shall be,"], ["ona faia lea e ositaulaga a outou taulaga mu ma outou taulaga faafetai i luga o le fata faitaulaga,", "that upon the eighth day,"], ["e afua i le aso valu e oo i aso e lumanai;", "and so forward, the priests shall make your burnt offerings upon the altar,"], ["ona ou talia lea o outou,", "and your peace offerings;"], ["ua fetalai mai ai le Alii o Ieova.", "and I will accept you, saith the Lord GOD."]]},
];
renderVerseSet(ezk_ch_43_Verses, 'ezk-ch43-verses');

var ezk_ch_44_Verses = [
  {num:1,words:[["Ona ia toe faafoi mai lea ia te au i le ala o le faitotoa o le mea paia aupito i tua, e faasaga i sasae;", "Then he brought me back the way of the gate of the outward sanctuary which looketh toward the east;"], ["a ua punitia ia.", "and it was shut."]]},
  {num:2,words:[["Ona fetalai mai lea a Ieova ia te au,", "Then said the LORD unto me; This gate shall be shut,"], ["E punitia lenei faitotoa,", "it shall not be opened,"], ["e le tatalaina lava,", "and no man shall enter in by it; because the LORD,"], ["e le ulu atu i ai se tagata;", "the God of Israel,"], ["auā ua ulufale mai ai Ieova le Atua o Isaraelu o le mea lea e punitia ai ia.", "hath entered in by it, therefore it shall be shut."]]},
  {num:3,words:[["Mo le alii sili lea;", "It is for the prince;"], ["o le alii sili e nofo ai o ia e 'ai ai mea e 'ai i luma o Ieova;", "the prince,"], ["na te ulu ane i le ala o le faapaologa o lea faitotoa,", "he shall sit in it to eat bread before the LORD; he shall enter by the way of the porch of that gate,"], ["na te ulufafo foi i lea lava ala.", "and shall go out by the way of the same."]]},
  {num:4,words:[["Ua ia au mai foi ia te au i le ala o le faitotoa i le itu i matu i lumāfale;", "Then brought he me the way of the north gate before the house:"], ["ona ou vaai lea,", "and I looked,"], ["faauta foi,", "and, behold,"], ["ua tumu le fale o Ieova i le pupula o Ieova,", "the glory of the LORD filled the house of the LORD:"], ["ona ou faapaūfao ai lea.", "and I fell upon my face."]]},
  {num:5,words:[["Ona fetalai mai lea o Ieova ia te au,", "And the LORD said unto me,"], ["Le atalii e o le tagata,", "Son of man,"], ["ia e tuu i lou loto,", "mark well,"], ["ma ia vaavaai ou mata,", "and behold with thine eyes,"], ["ia faalogologo foi ou taliga i mea uma ou te fai atu ai ia te oe i sauniga uma o le fale o Ieova,", "and hear with thine ears all that I say unto thee concerning all the ordinances of the house of the LORD,"], ["ma ana tulafono uma;", "and all the laws thereof;"], ["ia e manatunatu i mea e ulufale mai ai i le fale,", "and mark well the entering in of the house,"], ["atoa ma mea e ulufafo ai i le malumalu.", "with every going forth of the sanctuary."]]},
  {num:6,words:[["E te fai atu foi i e fouvale,", "And thou shalt say to the rebellious,"], ["o le aiga lea o Isaraelu,", "even to the house of Israel,"], ["Ua faapea ona fetalai mai o le Alii o Ieova, Le aiga o Isaraelu e,", "Thus saith the Lord GOD;"], ["soia,", "O ye house of Israel,"], ["ina tuu ia a outou mea e inosia uma,", "let it suffice you of all your abominations,"]]},
  {num:7,words:[["ona ua outou aumaia o tagata ese,", "In that ye have brought into my sanctuary strangers,"], ["o e le peritomeina loto,", "uncircumcised in heart,"], ["e le peritomeina foi tino,", "and uncircumcised in flesh,"], ["ia i ai i lo'u malumalu,", "to be in my sanctuary,"], ["ia faaleagaina ai lo'u lava fale,", "to pollute it, even my house,"], ["ina ua outou aumaia o a'u mea e 'ai,", "when ye offer my bread,"], ["o le ga'o ma le toto,", "the fat and the blood,"], ["ua outou solia foi la'u feagaiga i a outou mea uma e inosia.", "and they have broken my covenant because of all your abominations."]]},
  {num:8,words:[["Ua outou le anaana foi i le tausiga o a'u mea paia;", "And ye have not kept the charge of mine holy things:"], ["a ua outou tofia mo outou lava o e tausia a'u mea e tausia i lo'u malumalu.", "but ye have set keepers of my charge in my sanctuary for yourselves."]]},
  {num:9,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["E le ulufale mai i lo'u malumalu se tagata ese,", "No stranger,"], ["e le peritomeina le loto,", "uncircumcised in heart,"], ["e le peritomeina foi le tino,", "nor uncircumcised in flesh,"], ["o tagata ese uma,", "shall enter into my sanctuary,"], ["o e o i ai i le fanauga a Isaraelu.", "of any stranger that is among the children of Israel."]]},
  {num:10,words:[["O sa Levī foi o e ua o mamao ia te au ina ua o ese o Isaraelu,", "And the Levites that are gone away far from me,"], ["o i latou na o ese ia te au e mulimuli atu i a latou tupua;", "when Israel went astray, which went astray away from me after their idols;"], ["e oo lava ia te i latou le taui o a latou agasala.", "they shall even bear their iniquity."]]},
  {num:11,words:[["A e fai i latou ma auauna i lo'u malumalu,", "Yet they shall be ministers in my sanctuary,"], ["e leoleo i puipui o le fale,", "having charge at the gates of the house,"], ["ma auauna i le fale; latou te fasia le taulaga mu,", "and ministering to the house:"], ["ma le taulaga mo le nuu,", "they shall slay the burnt offering and the sacrifice for the people,"], ["latou te tutū foi i o latou luma e auauna ia te i latou.", "and they shall stand before them to minister unto them."]]},
  {num:12,words:[["Auā na latou auauna ia te i latou i luma o a latou tupua,", "Because they ministered unto them before their idols,"], ["o i latou foi na agasala ai le aiga o Isaraelu;", "and caused the house of Israel to fall into iniquity;"], ["o le mea lea ua ou sii ai i luga lo'u lima ia te i latou,", "therefore have I lifted up mine hand against them,"], ["o loo o fetalai mai ai le Alii o Ieova,", "saith the Lord GOD,"], ["e oo ia te i latou le taui o a latou agasala.", "and they shall bear their iniquity."]]},
  {num:13,words:[["Latou te le faalatalata mai foi ia te au e fai le faiva o le ositaulaga ia te au,", "And they shall not come near unto me, to do the office of a priest unto me,"], ["e le faalatalata foi i latou i se tasi o a'u mea paia i le mea e sili ona paia;", "nor to come near to any of my holy things,"], ["a e i ai ia te i latou lo latou mā,", "in the most holy place:"], ["ma a latou mea e inosia ua latou faia.", "but they shall bear their shame, and their abominations which they have committed."]]},
  {num:14,words:[["A e ou te fai i latou ma e tausi i a'u mea e tausia i lo'u fale i galuega uma o i ai,", "But I will make them keepers of the charge of the house, for all the service thereof,"], ["atoa ma mea uma e fai.", "and for all that shall be done therein."]]},
  {num:15,words:[["A o le au ositaulaga o sa Levī,", "But the priests the Levites,"], ["o le fanauga a Satoka,", "the sons of Zadok,"], ["o e na anaana i le tausiga o lo'u malumalu, ina ua o ese le fanauga a Isaraelu ia te au,", "that kept the charge of my sanctuary when the children of Israel went astray from me,"], ["latou te faalatalata mai ia te au e auauna ia te au,", "they shall come near to me to minister unto me,"], ["e tutū foi i latou i o'u luma e au mai ai ia te au le ga'o ma le toto,", "and they shall stand before me to offer unto me the fat and the blood,"], ["o loo o fetalai mai ai le Alii o Ieova.", "saith the Lord GOD:"]]},
  {num:16,words:[["O i latou ia e ulufale i lo'u malumalu,", "They shall enter into my sanctuary,"], ["o i latou foi e faalatalata mai i la'u laulau e auauna mai ai ia te au,", "and they shall come near to my table, to minister unto me,"], ["latou te tausi foi i a'u mea e tausia.", "and they shall keep my charge."]]},
  {num:17,words:[["A latou ulufale mai i faitotoa o le lotoā tuloto,", "And it shall come to pass, that when they enter in at the gates of the inner court,"], ["e oofu i latou i ofu lino;", "they shall be clothed with linen garments;"], ["e le oofu lava i latou i se ofu fulufulu mamoe pe a latou auauna i totonu o faitotoa o le lotoā tuloto,", "and no wool shall come upon them,"], ["ma totonu o le fale .", "whiles they minister in the gates of the inner court, and within."]]},
  {num:18,words:[["E pulou i latou i pulou lino,", "They shall have linen bonnets upon their heads,"], ["e oofu foi i ofuvae lino;", "and shall have linen breeches upon their loins;"], ["e le fusi i latou i se mea e tupu ai le afu.", "they shall not gird themselves with any thing that causeth sweat."]]},
  {num:19,words:[["A latou o atu i le nuu i le lotoā aupito i tua,", "And when they go forth into the utter court,"], ["o le lotoā lava e aupito i tua,", "even into the utter court to the people,"], ["latou te to ese o latou ofu na latou auauna a'i,", "they shall put off their garments wherein they ministered,"], ["ma tuu ai i potu sa,", "and lay them in the holy chambers,"], ["a e latou oofu i nisi ofu;", "and they shall put on other garments;"], ["latou te le faapaiaina foi le nuu i o latou ofu.", "and they shall not sanctify the people with their garments."]]},
  {num:20,words:[["Latou te le tafi foi o latou ulu,", "Neither shall they shave their heads,"], ["e le tuu foi o latou fuafuati lauulu ia uumi,", "nor suffer their locks to grow long;"], ["latou te sele o latou lau ulu.", "they shall only poll their heads."]]},
  {num:21,words:[["E le inu uaina foi se tasi ositaulaga lava pe a latou ulufale mai i le lotoā tuloto.", "Neither shall any priest drink wine, when they enter into the inner court."]]},
  {num:22,words:[["Latou te le fai avā foi i se fafine ua oti lana tane,", "Neither shall they take for their wives a widow,"], ["po o se fafine ua aleia;", "nor her that is put away:"], ["a e latou te fai avā i taupou o le fanau a le aiga o Isaraelu,", "but they shall take maidens of the seed of the house of Israel,"], ["po o se fafine ua oti lana tane sa nofo i se ositaulaga.", "or a widow that had a priest before."]]},
  {num:23,words:[["Latou te a'oa'o foi i lo'u nuu ia masino mea paia ma mea e le paia,", "And they shall teach my people the difference between the holy and profane,"], ["ina ia latou iloa le mea e le mamā ma le mea e mamā.", "and cause them to discern between the unclean and the clean."]]},
  {num:24,words:[["O finauga foi latou te tutū ai e fai le faamasinoga;", "And in controversy they shall stand in judgment;"], ["latou te faamasino i ai e tusa ma a'u faamasinoga;", "and they shall judge it according to my judgments:"], ["latou te tausia a'u tulafono, ma a'u sauniga i tausamiga uma e fai ia te au;", "and they shall keep my laws and my statutes in all mine assemblies;"], ["latou te faapaiaina foi o'u sapati.", "and they shall hallow my sabbaths."]]},
  {num:25,words:[["Latou te le papai ane i se tagata oti,", "And they shall come at no dead person to defile themselves:"], ["e leaga ai i latou;", "but for father,"], ["a e le sa ona leaga i latou ona o le tamā,", "or for mother,"], ["po o le tinā,", "or for son,"], ["po o se atalii,", "or for daughter,"], ["po o se afafine,", "for brother,"], ["po o se uso,", "or for sister that hath had no husband,"], ["po o se tuafafine e lei nofo tane.", "they may defile themselves."]]},
  {num:26,words:[["A uma ona faamamāina o ia,", "And after he is cleansed,"], ["ona latou faitauina lea ia te ia o aso e fitu.", "they shall reckon unto him seven days."]]},
  {num:27,words:[["O le aso foi na te ulufale ai i le malumalu,", "And in the day that he goeth into the sanctuary,"], ["i le lotoā tuloto,", "unto the inner court,"], ["e auauna i le malumalu,", "to minister in the sanctuary,"], ["na te aumaia lana taulaga mo le agasala,", "he shall offer his sin offering,"], ["o loo o fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:28,words:[["E fai foi lea ma tofi mo i latou;", "And it shall be unto them for an inheritance:"], ["o a'u o lo latou tofi;", "I am their inheritance:"], ["tou te le avatu se tofi ia te i latou i Isaraelu;", "and ye shall give them no possession in Israel:"], ["o a'u lava o lo latou tofi.", "I am their possession."]]},
  {num:29,words:[["Latou te aai le taulaga i mea e 'ai,", "They shall eat the meat offering,"], ["ma le taulaga mo le agasala,", "and the sin offering,"], ["ma le taulaga mo le sese;", "and the trespass offering;"], ["o mea uma foi e faatoina i Isaraelu e fai ia mā latou.", "and every dedicated thing in Israel shall be their's."]]},
  {num:30,words:[["O le faapolopolo o le uluai fua uma i mea uma,", "And the first of all the firstfruits of all things,"], ["ma taulaga uma i mea uma i a outou taulaga uma,", "and every oblation of all,"], ["e fai ia mā ositaulaga;", "of every sort of your oblations, shall be the priest's:"], ["tou te avatu foi a outou uluai palugāfalaoa i le ositaulaga,", "ye shall also give unto the priest the first of your dough,"], ["ina ia faatumauina e ia le manuia i lou aiga.", "that he may cause the blessing to rest in thine house."]]},
  {num:31,words:[["E le aai foi le au ositaulaga se mea e tasi ua mate fua,", "The priests shall not eat of any thing that is dead of itself,"], ["po o se mea ua saeia, o se manu lele,", "or torn,"], ["po o se manu vaefa.", "whether it be fowl or beast."]]},
];
renderVerseSet(ezk_ch_44_Verses, 'ezk-ch44-verses');

var ezk_ch_45_Verses = [
  {num:1,words:[["A outou vaevaeina le laueleele i le vili e fai ma tofi,", "Moreover,"], ["tou te avatua se taulaga ia Ieova,", "when ye shall divide by lot the land for inheritance,"], ["o le mea paia mai le laueleele;", "ye shall offer an oblation unto the LORD,"], ["o lona umi e lua sefulu o afe ma afe e lima o u ,", "an holy portion of the land:"], ["o lona umi lea,", "the length shall be the length of five and twenty thousand reeds,"], ["o lona lautele foi e sefulu afe. E paia foi lea i ona itu uma e soo ai.", "and the breadth shall be ten thousand. This shall be holy in all the borders thereof round about."]]},
  {num:2,words:[["E i ai i lea mea se fasi fanua mo le malumalu,", "Of this there shall be for the sanctuary five hundred in length,"], ["tailima selau o u i ona itu,", "with five hundred in breadth,"], ["e gatasitasi ona itu e fa;", "square round about;"], ["e lima sefulu foi o kupita e fai mona tuāfanua e faataaliolio ai.", "and fifty cubits round about for the suburbs thereof."]]},
  {num:3,words:[["O lenei fua foi e te fuatia mai ai se mea , o lona umi e lua sefulu afe ma afe e lima,", "And of this measure shalt thou measure the length of five and twenty thousand,"], ["a o le lautele e sefulu afe;", "and the breadth of ten thousand:"], ["e i ai le malumalu, o le mea e sili ona paia.", "and in it shall be the sanctuary and the most holy place."]]},
  {num:4,words:[["E fai lenei tofi paia o le laueleele mo le au ositaulaga,", "The holy portion of the land shall be for the priests the ministers of the sanctuary,"], ["o e auauna i le malumalu,", "which shall come near to minister unto the LORD:"], ["o e faalatalata atu e auauna ia Ieova; e fai foi ma mea e tutū ai o latou fale,", "and it shall be a place for their houses,"], ["o le mea paia foi e tu ai le malumalu.", "and an holy place for the sanctuary."]]},
  {num:5,words:[["O le lua sefulu o afe ma afe e lima o lona umi,", "And the five and twenty thousand of length,"], ["ma le sefulu afe o lona lautele,", "and the ten thousand of breadth,"], ["e fai lea mo sa Levī,", "shall also the Levites, the ministers of the house,"], ["o e auauna i le fale,", "have for themselves,"], ["e fai ma tofi e fai ai potu e lua sefulu.", "for a possession for twenty chambers."]]},
  {num:6,words:[["Tou te tuu ane foi le tofi o le aai e lima gaafe lona lautele,", "And ye shall appoint the possession of the city five thousand broad,"], ["e lua sefulu afe ma afe e lima lona umi,", "and five and twenty thousand long,"], ["e faafesagai ma le taulaga o le tofi paia,", "over against the oblation of the holy portion:"], ["e fai foi lea mo le aiga uma o Isaraelu.", "it shall be for the whole house of Israel."]]},
  {num:7,words:[["E i ai foi se tofi mo le alii sili i le tasi itu,", "And a portion shall be for the prince on the one side and on the other side of the oblation of the holy portion,"], ["ma le isi itu o le taulaga o le tofi paia ma le tofi o le aai i luma o le taulaga o le tofi paia i luma foi o le tofi o le aai,", "and of the possession of the city,"], ["e pau mai i le itu i sisifo,", "before the oblation of the holy portion,"], ["e pau mai foi i le itu i sasae;", "and before the possession of the city, from the west side westward,"], ["o lona umi foi e faafeagai lea ma le tasi tofi,", "and from the east side eastward:"], ["e pau mai i le tuaoi i sisifo,", "and the length shall be over against one of the portions,"], ["e pau mai i le tuaoi i sasae.", "from the west border unto the east border."]]},
  {num:8,words:[["E fai lona tofi i le laueleele o Isaraelu;", "In the land shall be his possession in Israel:"], ["e le toe faasaua foi a'u alii i lo'u nuu; o le laueleele foi latou te tuuina atu i le aiga o Isaraelu,", "and my princes shall no more oppress my people;"], ["e faatatau i o latou itu aiga.", "and the rest of the land shall they give to the house of Israel according to their tribes."]]},
  {num:9,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["Soia,", "Let it suffice you,"], ["outou alii o Isaraelu e;", "O princes of Israel:"], ["ina tuu ia le faasaua ma le faasaunoa,", "remove violence and spoil,"], ["a ia fai amio tatau ma amiotonu;", "and execute judgment and justice,"], ["soia tou te tulia o'u tagata,", "take away your exactions from my people,"], ["o loo o fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:10,words:[["Ia ia te outou le fua faatautau e tatau,", "Ye shall have just balances,"], ["ma le efa e tatau,", "and a just ephah,"], ["ma le paita e tatau.", "and a just bath."]]},
  {num:11,words:[["O le efa ma le paita e tasi lo laua fua,", "The ephah and the bath shall be of one measure,"], ["ina ia i ai somera e sefulu i le paita,", "that the bath may contain the tenth part of an homer,"], ["ia i ai foi efa e sefulu i le somera;", "and the ephah the tenth part of an homer:"], ["e faatatauina lona fua i le somera.", "the measure thereof shall be after the homer."]]},
  {num:12,words:[["O le sekeli e lua sefulu o kire ia;", "And the shekel shall be twenty gerahs:"], ["e lua sefulu o sekeli,", "twenty shekels,"], ["e lua sefulu ma le lima o sekeli,", "five and twenty shekels,"], ["e tasi le sefulu ma le lima o sekeli,", "fifteen shekels,"], ["e fai ia mo outou mina.", "shall be your maneh."]]},
  {num:13,words:[["O le taulaga lenei tou te avatua;", "This is the oblation that ye shall offer;"], ["o vaega e ono o le efa ai le somera o saito,", "the sixth part of an ephah of an homer of wheat,"], ["ma vaega e ono o le efa ai le somera o karite.", "and ye shall give the sixth part of an ephah of an homer of barley:"]]},
  {num:14,words:[["O le tulafono foi i le suāuu,", "Concerning the ordinance of oil,"], ["o le paita o suāuu tou te avatua vaega e sefulu o le paita ai le kori,", "the bath of oil,"], ["o le somera e i ai paita e sefulu;", "ye shall offer the tenth part of a bath out of the cor, which is an homer of ten baths;"], ["auā o le sefulu o paita o le somera lea.", "for ten baths are an homer:"]]},
  {num:15,words:[["O se tamai mamoe e tasi mai le lafu mai le lua o selau mai taaga lelei o Isaraelu,", "And one lamb out of the flock,"], ["e fai ia ma taulaga i mea e 'ai,", "out of two hundred, out of the fat pastures of Israel;"], ["ma taulaga mu,", "for a meat offering,"], ["ma taulaga faafetai,", "and for a burnt offering,"], ["e fai foi ma togiola mo i latou,", "and for peace offerings, to make reconciliation for them,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:16,words:[["O tagata uma o le nuu, latou te faia lenei taulaga faatasi i le alii sili o Isaraelu.", "All the people of the land shall give this oblation for the prince in Israel."]]},
  {num:17,words:[["E a le alii sili ona avatu o taulaga mu,", "And it shall be the prince's part to give burnt offerings,"], ["ma taulaga i mea e 'ai,", "and meat offerings,"], ["ma taulaga i mea e inu i tausamiga,", "and drink offerings,"], ["ma masina faatoa vaaia,", "in the feasts,"], ["ma sapati,", "and in the new moons,"], ["ma tausamiga uma o le aiga o Isaraelu;", "and in the sabbaths, in all solemnities of the house of Israel:"], ["na te saunia le taulaga mo le agasala,", "he shall prepare the sin offering,"], ["ma le taulaga i mea e 'ai,", "and the meat offering,"], ["ma le taulaga mu,", "and the burnt offering,"], ["ma taulaga faafetai,", "and the peace offerings,"], ["e fai ai se togiola mo le aiga o Isaraelu.", "to make reconciliation for the house of Israel."]]},
  {num:18,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["O le uluai masina ,", "In the first month,"], ["o le aso muamua o le masina,", "in the first day of the month,"], ["e te ave ai se povi poa taanoa e sao ona lelei,", "thou shalt take a young bullock without blemish,"], ["e te faamamāina ai le malumalu;", "and cleanse the sanctuary:"]]},
  {num:19,words:[["e ave foi e le ositaulaga nisi toto o le taulaga mo le agasala,", "And the priest shall take of the blood of the sin offering,"], ["ma avane ai i pou o le fale,", "and put it upon the posts of the house,"], ["ma tulimanu e fa o le tafatafa faasili o le fata faitaulaga,", "and upon the four corners of the settle of the altar,"], ["ma pou o le faitotoa o le lotoā tuloto.", "and upon the posts of the gate of the inner court."]]},
  {num:20,words:[["E faapea ona e faia i le aso fitu o le masina mo le tagata e sese,", "And so thou shalt do the seventh day of the month for every one that erreth,"], ["atoa ma le ua valea;", "and for him that is simple:"], ["e faapea ona outou fai ai se togiola mo le fale.", "so shall ye reconcile the house."]]},
  {num:21,words:[["O le masina muamua,", "In the first month,"], ["o lona aso e sefulu ma le fa o le masina,", "in the fourteenth day of the month,"], ["tou te fai ai le paseka,", "ye shall have the passover,"], ["o le tausamiga e fitu ona aso;", "a feast of seven days;"], ["tou te aai ai areto e le faafefeteina.", "unleavened bread shall be eaten."]]},
  {num:22,words:[["E saunia e le alii sili i lea aso mo ia, ma tagata uma o le nuu o se povi poa e fai ma taulaga mo le agasala.", "And upon that day shall the prince prepare for himself and for all the people of the land a bullock for a sin offering."]]},
  {num:23,words:[["O aso e fitu o le tausamiga na te sauni ai se taulaga mu ia Ieova,", "And seven days of the feast he shall prepare a burnt offering to the LORD,"], ["o povi poa ma mamoe poa e sao ona lelei, ia taifitu i aso i aso lava e fitu;", "seven bullocks and seven rams without blemish daily the seven days;"], ["ma se tamai 'oti i lea aso ma lea aso e fai ma taulaga mo le agasala.", "and a kid of the goats daily for a sin offering."]]},
  {num:24,words:[["Na te saunia foi le taulaga i mea e 'ai,", "And he shall prepare a meat offering of an ephah for a bullock,"], ["o le efa e tasi i le povi poa, o le efa foi i le 'oti poa,", "and an ephah for a ram,"], ["ma le sinu o suāuu i le efa.", "and an hin of oil for an ephah."]]},
  {num:25,words:[["O le masina e fitu,", "In the seventh month,"], ["o lona aso e sefulu ma le lima o le masina,", "in the fifteenth day of the month,"], ["na te faia e tusa ma ia mea,", "shall he do the like in the feast of the seven days,"], ["i le tausamiga i aso e fitu, e tusa ma le taulaga mo le agasala,", "according to the sin offering,"], ["e tusa foi ma le taulaga mu,", "according to the burnt offering,"], ["e tusa ma le taulaga i mea e 'ai,", "and according to the meat offering,"], ["e tusa foi ma le suāuu.", "and according to the oil."]]},
];
renderVerseSet(ezk_ch_45_Verses, 'ezk-ch45-verses');

var ezk_ch_46_Verses = [
  {num:1,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["O le puipui o le lotoā tuloto le ua faasaga i sasae,", "The gate of the inner court that looketh toward the east shall be shut the six working days;"], ["e punitia ia i aso e ono e fai ai galuega; a o le sapati e avanoa ai,", "but on the sabbath it shall be opened,"], ["atoa ma le aso o le masina faatoa vaaia e avanoa ai.", "and in the day of the new moon it shall be opened."]]},
  {num:2,words:[["E ulufale le alii sili i le ala o le faapaologa o le puipui i fafo,", "And the prince shall enter by the way of the porch of that gate without,"], ["ma tu i le pou o le faitotoa,", "and shall stand by the post of the gate,"], ["e sauni foi e ositaulaga lana taulaga mu, ma ana taulaga faafetai,", "and the priests shall prepare his burnt offering and his peace offerings,"], ["e tapuai foi o ia i tala ane o le faitotoa,", "and he shall worship at the threshold of the gate:"], ["ona alu lea o ia;", "then he shall go forth;"], ["a e le punitia le faitotoa seia oo i le afiafi.", "but the gate shall not be shut until the evening."]]},
  {num:3,words:[["E tapuai foi tagata o le nuu i lenei faitotoa i luma o Ieova i sapati ma masina faatoa vaaia.", "Likewise the people of the land shall worship at the door of this gate before the LORD in the sabbaths and in the new moons."]]},
  {num:4,words:[["O le taualaga mu e avatua e le alii sili ia Ieova i le aso sapati, e ono tamai mamoe ia e sao ona lelei,", "And the burnt offering that the prince shall offer unto the LORD in the sabbath day shall be six lambs without blemish,"], ["ma se mamoe poa e sao ona lelei.", "and a ram without blemish."]]},
  {num:5,words:[["O le taulaga i mea e 'ai,", "And the meat offering shall be an ephah for a ram,"], ["o le efa lea i le mamoe poa, o le taulaga i mea e 'ai i tamai mamoe e faatatau i mea ua ia te ia,", "and the meat offering for the lambs as he shall be able to give,"], ["o le sinu o suāuu foi i le efa.", "and an hin of oil to an ephah."]]},
  {num:6,words:[["O le aso foi o le masina faatoa vaaia e avatu ai le povi poa taanoa e sao ona lelei,", "And in the day of the new moon it shall be a young bullock without blemish,"], ["ma tamai mamoe e ono,", "and six lambs,"], ["ma se mamoe poa;", "and a ram:"], ["e sao ona lelei i latou.", "they shall be without blemish."]]},
  {num:7,words:[["Na te saunia foi le taulauga i mea e 'ai,", "And he shall prepare a meat offering,"], ["o le efa e tasi i le povi poa,", "an ephah for a bullock,"], ["ma le efa foi i le mamoe poa;", "and an ephah for a ram,"], ["a e avane i tamai mamoe e faatatau i mea ua na maua,", "and for the lambs according as his hand shall attain unto,"], ["o le sinu o suāuu foi i le efa.", "and an hin of oil to an ephah."]]},
  {num:8,words:[["A ulufale le alii sili,", "And when the prince shall enter,"], ["na te ui ane i le ala o le faapaologa o lena puipui,", "he shall go in by the way of the porch of that gate,"], ["na te ulufafo ai foi i lena lava ala.", "and he shall go forth by the way thereof."]]},
  {num:9,words:[["A o ane tagata o le nuu i luma o Ieova i tausamiga,", "But when the people of the land shall come before the LORD in the solemn feasts,"], ["o lē ulufale i le ala o le faitotoa i le itu i matu e tapuai, e ulufafo ia i le ala o le faitotoa i le itu i toga;", "he that entereth in by the way of the north gate to worship shall go out by the way of the south gate;"], ["o lē ulufale foi i le faitotoa i le itu i toga,", "and he that entereth by the way of the south gate shall go forth by the way of the north gate:"], ["e ulufafo ia i le ala o le faitotoa i le itu i matu; na te le ulufafo i le ala o le faitoa na ia ulufale ai,", "he shall not return by the way of the gate whereby he came in,"], ["a e ulufafo o ia i le mea e feagai ai.", "but shall go forth over against it."]]},
  {num:10,words:[["A o le alii sili,", "And the prince in the midst of them,"], ["a latou ulufale,", "when they go in,"], ["e ulufale o ia faatasi ma i latou;", "shall go in;"], ["a latou ulufafo,", "and when they go forth,"], ["e ulufafo foi o ia.", "shall go forth."]]},
  {num:11,words:[["O tausamiga ma faapotopotoga e fai ai le taulaga i mea e 'ai,", "And in the feasts and in the solemnities the meat offering shall be an ephah to a bullock,"], ["o le efa lea i le povi poa,", "and an ephah to a ram,"], ["o le efa foi i le mamoe poa, a o tamai mamoe e faatatau i mea ua ia te ia,", "and to the lambs as he is able to give,"], ["o le sinu foi o suāuu i le efa.", "and an hin of oil to an ephah."]]},
  {num:12,words:[["A sauni foi le alii sili se taulaga mu e manatu fua o ia ona fai,", "Now when the prince shall prepare a voluntary burnt offering or peace offerings voluntarily unto the LORD,"], ["po o taulaga faafetai na te manatu fua ona fai ia Ieova,", "one shall then open him the gate that looketh toward the east,"], ["e faaavanoaina mo ia le faitotoa e faasaga i sasae, na te saunia foi lana taulaga mu,", "and he shall prepare his burnt offering and his peace offerings,"], ["ma aua taulaga faafetai e pei ona fai i le aso sapati;", "as he did on the sabbath day:"], ["ona ulufafo ai lea o ia;", "then he shall go forth;"], ["ona punitia lea o le faitotoa ina ua ulufafo atu o ia.", "and after his going forth one shall shut the gate."]]},
  {num:13,words:[["E te sauni foi i aso uma le taulaga mu ia Ieova, o le tamai mamoe e tasi lona tausaga e sao ona lelei,", "Thou shalt daily prepare a burnt offering unto the LORD of a lamb of the first year without blemish:"], ["e te sauni ai i lea taeao ma lea taeao.", "thou shalt prepare it every morning."]]},
  {num:14,words:[["E te sauni ai foi se taulaga i mea e 'ai i lea taeao ma lea taeao,", "And thou shalt prepare a meat offering for it every morning,"], ["o lona vaega e ono o le efa,", "the sixth part of an ephah,"], ["o lona vaega foi e tolu o le sinu o suāuu e palu a'i le falaoa lelei;", "and the third part of an hin of oil,"], ["o le taulaga i mea e 'ai e le aunoa,", "to temper with the fine flour;"], ["o le sauniga ia Ieova e faavavau.", "a meat offering continually by a perpetual ordinance unto the LORD."]]},
  {num:15,words:[["Latou te saunia lava le tamai mamoe,", "Thus shall they prepare the lamb,"], ["ma le taulaga i mea e 'ai,", "and the meat offering,"], ["ma le suāuu i lea taeao ma lea taeao,", "and the oil,"], ["o le taulaga mu e le aunoa.", "every morning for a continual burnt offering."]]},
  {num:16,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["A avatu e le alii sili se mea alofa i se tasi o ona atalii e fai lea ma tofi o ona atalii;", "If the prince give a gift unto any of his sons, the inheritance thereof shall be his sons';"], ["e fai lea mo i latou ona o le tofiga.", "it shall be their possession by inheritance."]]},
  {num:17,words:[["A e afai na te avatu se mea alofa ai lona tofi i se tasi o ana auauna,", "But if he give a gift of his inheritance to one of his servants,"], ["e fai lea mona seia oo i le tausaga e sa'oloto ai,", "then it shall be his to the year of liberty;"], ["ona toe iu ane lea i le alii sili; a o lona tofi e fai lea mona atalii,", "after it shall return to the prince:"], ["o i latou lava.", "but his inheritance shall be his sons' for them."]]},
  {num:18,words:[["E le avea foi e le alii sili se mea ai le tofi o le nuu,", "Moreover the prince shall not take of the people's inheritance by oppression,"], ["e tuli ese ai i latou i lo latou tofi;", "to thrust them out of their possession;"], ["a e na te avane tofi o ona atalii ai ana lava mea ua maua;", "but he shall give his sons inheritance out of his own possession:"], ["ina ia le faataapeapeina ai lo'u nuu i o latou tofi.", "that my people be not scattered every man from his possession."]]},
  {num:19,words:[["Ona ia au mai lea ia te au i le ala o i le tafatafa o le faitotoa i potu paia o le au ositaulaga e faasaga i le itu i matu;", "After he brought me through the entry, which was at the side of the gate,"], ["faauta foi,", "into the holy chambers of the priests, which looked toward the north: and,"], ["o i ai le tasi mea i itu e lua i sisifo.", "behold, there was a place on the two sides westward."]]},
  {num:20,words:[["Ona fai mai lea o ia ia te au,", "Then said he unto me,"], ["O le mea lenei e tunu ai e ositaulaga le taulaga mo le sese,", "This is the place where the priests shall boil the trespass offering and the sin offering,"], ["ma le taulaga mo le agasala,", "where they shall bake the meat offering;"], ["latou te tao ai foi le taulaga i mea e 'ai;", "that they bear them not out into the utter court,"], ["ina ia latou le avatu ai i le lotoā aupito i tua e faapaiaina ai le nuu.", "to sanctify the people."]]},
  {num:21,words:[["Ona ia aumaia lea o a'u i le lotoā aupito i tua,", "Then he brought me forth into the utter court,"], ["ua ia ta'ita'i foi ia te au i pito lotoā e fa;", "and caused me to pass by the four corners of the court;"], ["faauta foi,", "and, behold,"], ["ua taitasi le pito lotoā ma se lotoā.", "in every corner of the court there was a court."]]},
  {num:22,words:[["O pito e fa o le lotoā, sa i ai lotoā ua sosoo ai,", "In the four corners of the court there were courts joined of forty cubits long and thirty broad:"], ["e fagafulu o kupita lona umi, e tolugafulu o kupita lona lautele; o ia pito e fa e tasi lo latou fua.", "these four corners were of one measure."]]},
  {num:23,words:[["Na i ai foi le aupa ua soo ai,", "And there was a row of building round about in them,"], ["ua soo ai lava ia lotoā e fa,", "round about them four,"], ["na fai foi mea e tunu ai mea i lalo ifo o aupa ua soo ai.", "and it was made with boiling places under the rows round about."]]},
  {num:24,words:[["Ona fai mai lea o ia ia te au,", "Then said he unto me,"], ["O mea ia a latou o e tutunu mea,", "These are the places of them that boil,"], ["e tutunu ai taulaga a le nuu e i latou o e auauna i le fale.", "where the ministers of the house shall boil the sacrifice of the people."]]},
];
renderVerseSet(ezk_ch_46_Verses, 'ezk-ch46-verses');

var ezk_ch_47_Verses = [
  {num:1,words:[["Ona toe faafoi lea o ia ia te au i le faitotoa o le fale;", "Afterward he brought me again unto the door of the house;"], ["faauta foi,", "and,"], ["ua alu ae le vai i lalo o le faitotoa o le fale i sasae;", "behold, waters issued out from under the threshold of the house eastward:"], ["auā na faasaga ona lumā fale i sasae,", "for the forefront of the house stood toward the east,"], ["na alu ifo foi le vai na i lalo,", "and the waters came down from under from the right side of the house,"], ["mai le itu taumatau o le fale i le itu i toga o le fata faitaulaga.", "at the south side of the altar."]]},
  {num:2,words:[["Ona ia aveina atu lea o a'u i le ala o le faitotoa i le itu i matu,", "Then brought he me out of the way of the gate northward,"], ["na ia ta'ita'i faataamilo ia te au i le ala i tua i le faitotoa aupito i tua i le ala e faasaga i sasae;", "and led me about the way without unto the utter gate by the way that looketh eastward;"], ["faauta foi,", "and, behold,"], ["ua tafe atu ai le vai i le itu taumatau.", "there ran out waters on the right side."]]},
  {num:3,words:[["Ua alu ane i le itu i sasae le tagata sa i lona lima le manoa,", "And when the man that had the line in his hand went forth eastward,"], ["ona ia fuatia lea o kupita e afe,", "he measured a thousand cubits,"], ["ona ia ta'ita'iina lea o a'u i le tasi itu o le vai;", "and he brought me through the waters;"], ["ua gata le vai i tapuvae.", "the waters were to the ancles."]]},
  {num:4,words:[["Ua ia toe fuatia se afe o kupita ,", "Again he measured a thousand,"], ["ona ia ta'ita'iina lea o a'u i le tasi itu o le vai;", "and brought me through the waters;"], ["ua gata le vai i tulivae. Ua ia toe fuatia se afe o kupita ,", "the waters were to the knees. Again he measured a thousand,"], ["ua ia ta'ita'iina foi o a'u i le tasi itu;", "and brought me through;"], ["ua gata le vai i le sulugatiti.", "the waters were to the loins."]]},
  {num:5,words:[["Ua ia toe fuatia se afe o kupita;", "Afterward he measured a thousand;"], ["ua avea ma vaitafe ou te le toe mafai ona asa;", "and it was a river that I could not pass over:"], ["auā ua loloto le vai,", "for the waters were risen,"], ["o le vai e aau ai,", "waters to swim in,"], ["o le vaitafe e le mafai ona asa.", "a river that could not be passed over."]]},
  {num:6,words:[["Ua ia fai mai foi ia te au,", "And he said unto me,"], ["Le atalii e o le tagata,", "Son of man,"], ["ua e iloa ea? Ona ia ta'ita'iina lea o a'u,", "hast thou seen this? Then he brought me,"], ["ma faafoi mai ia te au i le auvai o le vaitafe.", "and caused me to return to the brink of the river."]]},
  {num:7,words:[["Ua ou toe foi, faauta,", "Now when I had returned,"], ["o laau e tele lava i le auvai o le vaitafe,", "behold,"], ["o i le tasi itu, ma le isi itu.", "at the bank of the river were very many trees on the one side and on the other."]]},
  {num:8,words:[["Ona fai mai lea o ia ia te au,", "Then said he unto me,"], ["E tafe atu ia vai i le itu i sasae,", "These waters issue out toward the east country,"], ["ma tafe ifo i le laueleele mafolafola,", "and go down into the desert,"], ["ma oo i le sami;", "and go into the sea:"], ["a oo atu i le sami,", "which being brought forth into the sea,"], ["ona faamagaloina ai lea o le suāsami.", "the waters shall be healed."]]},
  {num:9,words:[["O mea ola uma foi,", "And it shall come to pass,"], ["e fetolofi i mea uma e oo i ai le vaitafe,", "that every thing that liveth, which moveth,"], ["e ola ia;", "whithersoever the rivers shall come,"], ["e matuā tele foi i'a;", "shall live:"], ["auā e oo i ai ia vai,", "and there shall be a very great multitude of fish,"], ["ma faamagaloina ai;", "because these waters shall come thither: for they shall be healed;"], ["e ola ai foi mea uma e oo atu i ai le vaitafe.", "and every thing shall live whither the river cometh."]]},
  {num:10,words:[["E tutū ai foi ē fai faiva,", "And it shall come to pass,"], ["e pau mai i Enokati e oo i Enokelima;", "that the fishers shall stand upon it from En-gedi even unto En-eglaim;"], ["e fai ma mea e fofola ai upega;", "they shall be a place to spread forth nets;"], ["o ona i'a foi e uiga eseese,", "their fish shall be according to their kinds,"], ["e pei o i'a o le sami tele,", "as the fish of the great sea,"], ["e matuā tele lava.", "exceeding many."]]},
  {num:11,words:[["A o ana mea e palapalā ma ona fusi e le toe faamagaloina;", "But the miry places thereof and the marishes thereof shall not be healed;"], ["a e tuuina atu i le masima.", "they shall be given to salt."]]},
  {num:12,words:[["O le auvai o le vaitafe i lea itu ma lea itu,", "And by the river upon the bank thereof,"], ["e tutupu ai laau uma e 'aina,", "on this side and on that side,"], ["e le mamae o latou lau,", "shall grow all trees for meat,"], ["e le uma lava o latou fua;", "whose leaf shall not fade,"], ["taitasi le masina ma lona fuata,", "neither shall the fruit thereof be consumed: it shall bring forth new fruit according to his months,"], ["auā e tafe atu o latou vai ai le malumalu;", "because their waters they issued out of the sanctuary:"], ["e fai foi o latou fua ma mea e 'ai,", "and the fruit thereof shall be for meat,"], ["ma o latou lau e fai ma vailaau.", "and the leaf thereof for medicine."]]},
  {num:13,words:[["Ua faapea ona fetalai mai o le Alii o Ieova,", "Thus saith the Lord GOD;"], ["O le tuaoi lenei tou te totofi ai mo outou le laueleele,", "This shall be the border,"], ["e faatatau i itu aiga e sefulu ma le lua o Isaraelu;", "whereby ye shall inherit the land according to the twelve tribes of Israel:"], ["e lua tofi mo Iosefa.", "Joseph shall have two portions."]]},
  {num:14,words:[["Tou te fai tofi ai,", "And ye shall inherit it,"], ["o le tasi e tusa ma le tasi,", "one as well as another:"], ["o le mea na ou sii ai lo'u lima ou te foai atu ai i o outou tamā;", "concerning the which I lifted up mine hand to give it unto your fathers:"], ["e maua foi e outou lenei laueleele e fai mo outou tofi.", "and this land shall fall unto you for inheritance."]]},
  {num:15,words:[["O le tuaoi foi lenei o le laueleele i le itu i matu,", "And this shall be the border of the land toward the north side,"], ["e amata mai i le sami tele i le ala o Hetelona,", "from the great sea, the way of Hethlon,"], ["i le mea e ui atu ai i Setata;", "as men go to Zedad;"]]},
  {num:16,words:[["o Amato,", "Hamath,"], ["o Perota,", "Berothah,"], ["o Seperimo,", "Sibraim,"], ["o loo i le va o le tuaoi o Tamaseko ma le tuaoi o Amato,", "which is between the border of Damascus and the border of Hamath;"], ["o Hasaratikona,", "Hazar-hatticon,"], ["o loo i le tuaoi o Haurana.", "which is by the coast of Hauran."]]},
  {num:17,words:[["O lona tuaoi,", "And the border from the sea shall be Hazar-enan,"], ["e pau mai i le sami o Hasarenana le tuaoi o Tamaseko,", "the border of Damascus,"], ["mai le itu i matu e faasaga i le itu i matu,", "and the north northward,"], ["ma le tuaoi o Amato.", "and the border of Hamath. And this is the north side."]]},
  {num:18,words:[["O le itu i matu lea . O le itu i sasae foi tou te fuatia,", "And the east side ye shall measure from Hauran,"], ["e amata mai i Haurana,", "and from Damascus,"], ["ma Tamaseko, ma Kiliata,", "and from Gilead,"], ["ma le laueleele o Isaraelu i Ioritana,", "and from the land of Israel by Jordan,"], ["e pau mai i le tuaoi i le sami i sasae. O le itu i sasae lea .", "from the border unto the east sea. And this is the east side."]]},
  {num:19,words:[["O le itu i toga e faasaga i le itu i toga,", "And the south side southward,"], ["e pau mai i Tamara,", "from Tamar even to the waters of strife in Kadesh,"], ["e pau mai i le vai o Meripa i Katesa i le alia e oo i le sami tele. O le itu lea i le itu i toga.", "the river to the great sea. And this is the south side southward."]]},
  {num:20,words:[["O le itu i sisifo, o le sami tele lea,", "The west side also shall be the great sea from the border,"], ["e pau mai i le tuaoi e oo i le mea e feagai ma le ala e ui atu ai i Amato.", "till a man come over against Hamath."], ["O le itu i sisifo lea .", "This is the west side."]]},
  {num:21,words:[["Tou te vaevaeina lena laueleele ia te outou, e faatatau i itu aiga o Isaraelu.", "So shall ye divide this land unto you according to the tribes of Israel."]]},
  {num:22,words:[["Tou te vaevaeina ai i le vili e fai ma tofi mo outou,", "And it shall come to pass,"], ["atoa ma tagata ese o e āumau ia te outou,", "that ye shall divide it by lot for an inheritance unto you,"], ["o e fanaua tama i lo outou nuu;", "and to the strangers that sojourn among you, which shall beget children among you:"], ["e avea foi i latou ia te outou e tusa ma tama a le eleele i le fanauga a Isaraelu,", "and they shall be unto you as born in the country among the children of Israel;"], ["latou te fai tofi faatasi ma itu aiga o Isaraelu.", "they shall have inheritance with you among the tribes of Israel."]]},
  {num:23,words:[["O le itu aiga e āumau ai le tagata ese,", "And it shall come to pass,"], ["tou te avatu ai ia te ia lona tofi,", "that in what tribe the stranger sojourneth, there shall ye give him his inheritance,"], ["o loo fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
];
renderVerseSet(ezk_ch_47_Verses, 'ezk-ch47-verses');

var ezk_ch_48_Verses = [
  {num:1,words:[["O igoa ia o itu aiga. E pau mai i le tuluiga o le itu i le itu i matu,", "Now these are the names of the tribes. From the north end to the coast of the way of Hethlon,"], ["e oo atu i le auala o Hetelona,", "as one goeth to Hamath,"], ["e ui atu ai i Amato,", "Hazar-enan,"], ["o Hasarenana o le tuaoi o Tamaseko i le itu i matu,", "the border of Damascus northward,"], ["e oo atu i tala ane o Amato;", "to the coast of Hamath;"], ["o ona itu ia i sasae ma sisifo,", "for these are his sides east and west;"], ["o le tofi lea o Tanu.", "a portion for Dan."]]},
  {num:2,words:[["E soo foi tuaoi ma Tanu,", "And by the border of Dan,"], ["e pau mai i le itu i sasae, e pau mai i le itu i sisifo,", "from the east side unto the west side,"], ["o le tofi lea o Asera.", "a portion for Asher."]]},
  {num:3,words:[["E soo foi tuaoi ma Asera,", "And by the border of Asher,"], ["e pau mai i le itu i sasae, e pau mai i le itu i sisifo,", "from the east side even unto the west side,"], ["o le tofi lea o Nafatali.", "a portion for Naphtali."]]},
  {num:4,words:[["E soo foi tuaoi ma Nafatali,", "And by the border of Naphtali,"], ["e pau mai i le itu i sasae, e pau mai i le itu i sisifo,", "from the east side unto the west side,"], ["o le tofi lea o Manase.", "a portion for Manasseh."]]},
  {num:5,words:[["E soo foi tuaoi ma Manase,", "And by the border of Manasseh,"], ["e pau mai i le itu i sasae, e pau mai i le itu i sisifo,", "from the east side unto the west side,"], ["o le tofi lea o Efaraima.", "a portion for Ephraim."]]},
  {num:6,words:[["E soo foi tuaoi ma Efaraima,", "And by the border of Ephraim,"], ["e pau mai i le itu i sasae, e pau mai i le itu i sisifo,", "from the east side even unto the west side,"], ["o le tofi lea o Reupena.", "a portion for Reuben."]]},
  {num:7,words:[["E soo foi tuaoi ma Reupena,", "And by the border of Reuben,"], ["e pau mai i le itu i sasae, e oo i le itu i sisifo,", "from the east side unto the west side,"], ["o le tofi lea o Iuta.", "a portion for Judah."]]},
  {num:8,words:[["E soo foi tuaoi ma Iuta, e pau mai i le itu i sasae,", "And by the border of Judah,"], ["e pau mai i le itu i sisifo,", "from the east side unto the west side,"], ["e i ai le taulaga tou te avatu,", "shall be the offering which ye shall offer of five and twenty thousand reeds in breadth,"], ["e lua sefulu afe ma afe e lima o u lona lautele, o lona umi foi e pei o isi tofi,", "and in length as one of the other parts,"], ["e pau mai i le itu i sasae, e pau mai i le itu i sisifo;", "from the east side unto the west side:"], ["e tu loto ai le malumalu.", "and the sanctuary shall be in the midst of it."]]},
  {num:9,words:[["O le taulaga tou te avatu ia Ieova, o lona umi e lua sefulu afe ma afe e lima o u ,", "The oblation that ye shall offer unto the LORD shall be of five and twenty thousand in length,"], ["o lona lautele e sefulu afe.", "and of ten thousand in breadth."]]},
  {num:10,words:[["E faia foi lea ma taulaga paia mo le au ositaulaga;", "And for them,"], ["o lona umi i le itu i matu e lua sefulu afe ma afe e lima o u ,", "even for the priests,"], ["o lona lautele i le itu i sisifo,", "shall be this holy oblation;"], ["e sefulu afe,", "toward the north five and twenty thousand in length,"], ["o lona lautele i le itu i sasae,", "and toward the west ten thousand in breadth,"], ["e sefulu afe,", "and toward the east ten thousand in breadth,"], ["o lona umi i le itu i toga e lua sefulu afe ma afe e lima;", "and toward the south five and twenty thousand in length:"], ["e tu loto ai le malumalu o Ieova.", "and the sanctuary of the LORD shall be in the midst thereof."]]},
  {num:11,words:[["E fai ia mo le au ositaulaga,", "It shall be for the priests that are sanctified of the sons of Zadok;"], ["o e ua faapaiaina o le fanauga a Satoka,", "which have kept my charge,"], ["o e na tausi i a'u mea e tausia, o e na le o ese ina ua o ese le fanauga a Isaraelu,", "which went not astray when the children of Israel went astray,"], ["e pei o sa Levī ona o ese.", "as the Levites went astray."]]},
  {num:12,words:[["O le taulaga o le laueleele ua avatua, e avea ma mea e matuā paia lava ia te i latou, e soo tuaoi ma sa Levī.", "And this oblation of the land that is offered shall be unto them a thing most holy by the border of the Levites."]]},
  {num:13,words:[["E feagai ma le tuaoi o le au ositaulaga se mea a sa Levī,", "And over against the border of the priests the Levites shall have five and twenty thousand in length,"], ["o lona umi e lua sefulu afe ma afe e lima o u ,", "and ten thousand in breadth:"], ["o lona lautele e sefulu afe; o lona umi atoa e lua sefulu afe ma afe e lima,", "all the length shall be five and twenty thousand,"], ["o lona lautele foi e sefulu afe.", "and the breadth ten thousand."]]},
  {num:14,words:[["Latou te le faatauina atu ai lava sina fasi fanua ,", "And they shall not sell of it,"], ["pe fesuiaiina,", "neither exchange,"], ["pe avea le faapolopolo o le laueleele;", "nor alienate the firstfruits of the land:"], ["auā ua paia ia ia Ieova.", "for it is holy unto the LORD."]]},
  {num:15,words:[["O le lima gaafe ua totoe i le lautele i luma o le lua sefulu afe ma afe e lima,", "And the five thousand,"], ["e fai lea ma mea tataga mo le aai,", "that are left in the breadth over against the five and twenty thousand,"], ["e fai ma mea e nonofo ai,", "shall be a profane place for the city, for dwelling,"], ["e fai foi ma tuāfanua;", "and for suburbs:"], ["e tu loto ai le aai.", "and the city shall be in the midst thereof."]]},
  {num:16,words:[["O ona fua foi nei;", "And these shall be the measures thereof;"], ["o le itu i matu e fa gaafe ma le lima o selau,", "the north side four thousand and five hundred,"], ["o le itu i toga e fa gaafe ma le lima o selau,", "and the south side four thousand and five hundred,"], ["o le itu i sasae e fa gaafe ma le lima o selau,", "and on the east side four thousand and five hundred,"], ["o le itu i sisifo e fa gaafe ma le lima o selau.", "and the west side four thousand and five hundred."]]},
  {num:17,words:[["O tuāfanua o le aai e lua selau ma le limagafulu i le itu i matu,", "And the suburbs of the city shall be toward the north two hundred and fifty,"], ["e lua selau ma le limagafulu i le itu i toga,", "and toward the south two hundred and fifty,"], ["e lua selau ma le limagafulu i le itu i sasae,", "and toward the east two hundred and fifty,"], ["e lua selau ma le limagafulu foi i le itu i sisifo.", "and toward the west two hundred and fifty."]]},
  {num:18,words:[["O lona toe e tuaoi ma le taulaga o le tofi paia,", "And the residue in length over against the oblation of the holy portion shall be ten thousand eastward,"], ["e sefulu afe lona umi i sasae,", "and ten thousand westward:"], ["e sefulu afe foi i sisifo, e feagai foi ia ma le taulaga o le tofi paia;", "and it shall be over against the oblation of the holy portion;"], ["o mea e tutupu ai e fai lea ma mea e 'ai mā e auauna i le aai.", "and the increase thereof shall be for food unto them that serve the city."]]},
  {num:19,words:[["O e auauna i le aai latou te auauna i ai mai itu aiga uma o Isaraelu.", "And they that serve the city shall serve it out of all the tribes of Israel."]]},
  {num:20,words:[["O le taulaga atoa, e lua sefulu afe ma afe e lima i le tasi itu,", "All the oblation shall be five and twenty thousand by five and twenty thousand:"], ["e lua sefulu afe foi ma afe e lima i le isi itu;", "ye shall offer the holy oblation foursquare,"], ["tou te avatu le taulaga paia e gatasitasi uma ona itu e fa, e faatasi ma le tofi o le aai.", "with the possession of the city."]]},
  {num:21,words:[["E fai foi le mea ua toe mo le alii sili i le tasi itu ma le isi itu o le taulaga paia,", "And the residue shall be for the prince,"], ["ma le tofi o le aai i luma o le lua sefulu afe ma afe e lima o le taulaga i le tuaoi i le itu i sasae,", "on the one side and on the other of the holy oblation, and of the possession of the city,"], ["ma le itu i sisifo i luma o le lua sefulu afe ma afe e lima i le tuaoi i le itu i sisifo,", "over against the five and twenty thousand of the oblation toward the east border,"], ["e feagai ma tofi o le alii sili;", "and westward over against the five and twenty thousand toward the west border,"], ["e fai foi ia ma taulaga paia;", "over against the portions for the prince: and it shall be the holy oblation;"], ["e tu loto ai le malumalu o le fale.", "and the sanctuary of the house shall be in the midst thereof."]]},
  {num:22,words:[["E pau mai i le tofi o sa Levī,", "Moreover from the possession of the Levites,"], ["e pau mai foi i le tofi o le aai,", "and from the possession of the city,"], ["(e i ai le tofi o le alii sili,", "being in the midst of that which is the prince's,"], [") i le va o le tuaoi o Iuta ma le tuaoi o Peniamina,", "between the border of Judah and the border of Benjamin,"], ["e fai lea mo le alii sili.", "shall be for the prince."]]},
  {num:23,words:[["O itu aiga foi o totoe,", "As for the rest of the tribes,"], ["e pau mai i le itu i sasae, e pau mai i le itu i sisifo,", "from the east side unto the west side,"], ["o le tofi lea o Peniamina.", "Benjamin shall have a portion."]]},
  {num:24,words:[["E soo foi tuaoi ma Peniamina,", "And by the border of Benjamin,"], ["e pau mai i le itu i sasae e pau mai i le itu i sisifo,", "from the east side unto the west side,"], ["o le tofi lea o Simeona.", "Simeon shall have a portion."]]},
  {num:25,words:[["E soo foi tuaoi ma Simeona,", "And by the border of Simeon,"], ["e pau mai i le itu i sasae, e pau mai i le itu i sisifo,", "from the east side unto the west side,"], ["o le tofi lea o Isakara.", "Issachar a portion."]]},
  {num:26,words:[["E soo foi tuaoi ma Isakara,", "And by the border of Issachar,"], ["e pau mai i le itu i sasae, e pau mai i le itu i sisifo,", "from the east side unto the west side,"], ["o le tofi lea o Sepulona.", "Zebulun a portion."]]},
  {num:27,words:[["E soo foi tuaoi ma Sepulona,", "And by the border of Zebulun,"], ["e pau mai i le itu i sasae, e pau mai i le itu i sisifo,", "from the east side unto the west side,"], ["o le tofi lea o Kato.", "Gad a portion."]]},
  {num:28,words:[["E soo foi tuaoi ma Kato i le itu i toga,", "And by the border of Gad,"], ["e faasaga i le itu i toga,", "at the south side southward,"], ["e pau mai i le tuaoi i Tamara, e pau mai i le vai o Meripa-Katesa,", "the border shall be even from Tamar unto the waters of strife in Kadesh,"], ["ma le alia e oo i le sami tele.", "and to the river toward the great sea."]]},
  {num:29,words:[["O le laueleele lea tou te vaevaeina i le vili i itu aiga o Isaraelu e fai ma tofi,", "This is the land which ye shall divide by lot unto the tribes of Israel for inheritance,"], ["o latou tofi foi ia,", "and these are their portions,"], ["ua fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:30,words:[["O mea ia e o atu ai le aai;", "And these are the goings out of the city on the north side,"], ["o le itu i matu e fa afe ma le lima selau o lona fua lea .", "four thousand and five hundred measures."]]},
  {num:31,words:[["O puipui foi o le aai e igoa ia i igoa o itu aiga o Isaraelu;", "And the gates of the city shall be after the names of the tribes of Israel:"], ["e tolu puipui i le itu i matu;", "three gates northward;"], ["o le puipui o Reupena o le tasi lea,", "one gate of Reuben,"], ["o le puipui o Iuta o le tasi lea,", "one gate of Judah,"], ["o le puipui o Levi o le tasi lea.", "one gate of Levi."]]},
  {num:32,words:[["O le itu i sasae e fa gaafe ma le lima o selau o lona fua lea;", "And at the east side four thousand and five hundred:"], ["e tolu foi puipui;", "and three gates;"], ["o le puipui o Iosefa o le tasi lea,", "and one gate of Joseph,"], ["o le puipui o Peniamina o le tasi lea,", "one gate of Benjamin,"], ["o le puipui o Tanu o le tasi lea.", "one gate of Dan."]]},
  {num:33,words:[["O le itu i toga,", "And at the south side four thousand and five hundred measures:"], ["e fa gaafe ma le lima o selau o lona fua lea;", "and three gates;"], ["e tolu foi puipui; o le puipui o Simeona o le tasi lea,", "one gate of Simeon,"], ["o le puipui o Isakara o le tasi lea,", "one gate of Issachar,"], ["o le puipui o Sepulona o le tasi lea.", "one gate of Zebulun."]]},
  {num:34,words:[["O le itu i sisifo e fa gaafe ma le lima selau o lona fua lea ma o latou puipui e tolu;", "At the west side four thousand and five hundred,"], ["o le puipui o Kato o le tasi lea,", "with their three gates;"], ["o le puipui o Asera o le tasi lea,", "one gate of Gad, one gate of Asher,"], ["o le puipui o Nafatali o le tasi lea.", "one gate of Naphtali."]]},
  {num:35,words:[["O lona faataamilosaga, e sefulu afe ma afe e valu o lona fua lea;", "It was round about eighteen thousand measures:"], ["o le igoa foi o le aai,", "and the name of the city from that day shall be,"], ["e afua mai i lea aso, O loo afio ai Ieova .", "The LORD is there."]]},
];
renderVerseSet(ezk_ch_48_Verses, 'ezk-ch48-verses');

